namespace SimpleATM
{
    class Program
    {
        static void Main(string[] args)
        {
            int userPin = 1234;
            double accountBalance = 1000.00;
            double dailyWithdrawalLimit = 500.00;
            double totalWithdrawnToday = 0.00;

