                Console.Write("Please enter your PIN: ");
                int enteredPin = Convert.ToInt32(Console.ReadLine());

                if (enteredPin == userPin)
                {
                    break;
                }
                else
                {
                    Console.WriteLine("Invalid PIN, please try again.");
                }
            }

            while (true)
            {
                Console.WriteLine("\nSelect an option:");
                Console.WriteLine("1. Check balance");
                Console.WriteLine("2. Deposit money");
                Console.WriteLine("3. Withdraw money");
                Console.WriteLine("4. Exit");

                int option = Convert.ToInt32(Console.ReadLine());

                switch (option)
                {
                    case 1:
                        Console.WriteLine($"Your current balance is ${accountBalance}");
                        break;
                    case 2:
                        Console.Write("Enter the amount you want to deposit: ");
                        double depositAmount = Convert.ToDouble(Console.ReadLine());
                        accountBalance += depositAmount;
                        Console.WriteLine($"You have successfully deposited ${depositAmount}. Your new balance is ${accountBalance}.");
                        break;
                    case 3:
                        Console.Write("Enter the amount you want to withdraw: ");
                        double withdrawalAmount = Convert.ToDouble(Console.ReadLine());

                        if (withdrawalAmount > accountBalance)
                        {
                            Console.WriteLine("Insufficient funds. Please enter a lower amount.");
                        }
                        else if (totalWithdrawnToday + withdrawalAmount > dailyWithdrawalLimit)
                        {
                            Console.WriteLine($"Daily withdrawal limit of ${dailyWithdrawalLimit} has been reached. Please try again tomorrow.");
                        }
                        else
                        {
                            accountBalance -= withdrawalAmount;
                            totalWithdrawnToday += withdrawalAmount;
                            Console.WriteLine($"You have successfully withdrawn ${withdrawalAmount}. Your new balance is ${accountBalance}.");
                        }
                        break;
                    case 4:
                        Console.WriteLine("Thank you for using Simple ATM! Goodbye!");
                        return;
                    default:
                        Console.WriteLine("Invalid option, please select a valid option.");
                        break;
                }
            }
        }
    }
}
