            }
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

Here's a Java program that calculates the shortest path between two nodes in a directed, weighted graph using Dijkstra's algorithm. The graph is represented using adjacency lists.

```java
import java.util.*;

class Edge {
    int dest;
    int weight;

    public Edge(int dest, int weight) {
        this.dest = dest;
        this.weight = weight;
    }
}

public class DijkstraShortestPath {

    private static final int INF = Integer.MAX_VALUE;

    public static void main(String[] args) {
        List<List<Edge>> graph = new ArrayList<>();
        int numVertices = 5;

        for (int i = 0; i < numVertices; i++) {
            graph.add(new ArrayList<>());
        }

        addEdge(graph, 0, 1, 10);
        addEdge(graph, 0, 4, 3);
        addEdge(graph, 1, 2, 2);
        addEdge(graph, 1, 4, 4);
        addEdge(graph, 2, 3, 9);
        addEdge(graph, 3, 2, 7);
        addEdge(graph, 4, 1, 1);
        addEdge(graph, 4, 2, 8);
        addEdge(graph, 4, 3, 2);

        int source = 0;
        int destination = 3;

        int[] dist = dijkstra(graph, source);

        System.out.println("The shortest distance from node " + source + " to node " + destination + " is: " + dist[destination]);
    }

    private static void addEdge(List<List<Edge>> graph, int src, int dest, int weight) {
        graph.get(src).add(new Edge(dest, weight));
    }

    private static int[] dijkstra(List<List<Edge>> graph, int src) {
        int numVertices = graph.size();
        int[] dist = new int[numVertices];
        boolean[] visited = new boolean[numVertices];

        Arrays.fill(dist, INF);
        dist[src] = 0;

        PriorityQueue<Edge> pq = new PriorityQueue<>(Comparator.comparingInt(e -> e.weight));
        pq.add(new Edge(src, 0));

        while (!pq.isEmpty()) {
            int u = pq.poll().dest;

            if (visited[u]) continue;
            visited[u] = true;

            for (Edge edge : graph.get(u)) {
                int v = edge.dest;
                int weight = edge.weight;

                if (!visited[v] && dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight;
                    pq.add(new Edge(v, dist[v]));
                }
            }
        }

        return dist;
    }
}
```

This program creates a directed, weighted graph with 5 vertices and adds edges between them. It then calculates the shortest path from node 0 to node 3 using Dijkstra's algorithm and prints the result. You can modify the graph and source/destination nodes as needed.

To create a simple chat server and client using WebSockets in Golang, we will use the "github.com/gorilla/websocket" package. First, you need to install this package by running:

```bash
go get github.com/gorilla/websocket
```

Now let's create the server and client code.

**Server (server.go):**

```go
package main

import (
	"fmt"
	"log"
	"net/http"

	"github.com/gorilla/websocket"
)

var clients = make(map[*websocket.Conn]bool)
var broadcast = make(chan Message)

var upgrader = websocket.Upgrader{
	CheckOrigin: func(r *http.Request) bool {
		return true
	},
}

type Message struct {
	Message string `json:"message"`
}

func main() {
	http.HandleFunc("/ws", handleConnections)

	go handleMessages()

	log.Println("Listening on :8080...")
	err := http.ListenAndServe(":8080", nil)
	if err != nil {
		log.Fatal("ListenAndServe: ", err)
	}
}

func handleConnections(w http.ResponseWriter, r *http.Request) {
	ws, err := upgrader.Upgrade(w, r, nil)
	if err != nil {
		log.Fatal(err)
	}
	defer ws.Close()

	clients[ws] = true

	for {
		var msg Message
		err := ws.ReadJSON(&msg)
		if err != nil {
			delete(clients, ws)
			break
		}

		broadcast <- msg
	}
}

func handleMessages() {
	for {
		msg := <-broadcast
		for client := range clients {
			err := client.WriteJSON(msg)
			if err != nil {
				log.Printf("Error: %v", err)
				client.Close()
				delete(clients, client)
			}
		}
	}
}
```

