#include <iostream>
#include <algorithm>

class Node {
public:
    int key;
    unsigned char height;
    Node* left;
    Node* right;

    Node(int k) : key(k), height(1), left(nullptr), right(nullptr) {}
};

unsigned char getHeight(Node* node) {
    return node ? node->height : 0;
}

int getBalanceFactor(Node* node) {
    return getHeight(node->right) - getHeight(node->left);
}

void fixHeight(Node* node) {
    node->height = std::max(getHeight(node->left), getHeight(node->right)) + 1;
}

Node* rotateRight(Node* p) {
    Node* q = p->left;
    p->left = q->right;
    q->right = p;
    fixHeight(p);
    fixHeight(q);
    return q;
}

Node* rotateLeft(Node* q) {
    Node* p = q->right;
    q->right = p->left;
    p->left = q;
    fixHeight(q);
    fixHeight(p);
    return p;
}

Node* balance(Node* node) {
    fixHeight(node);

    if (getBalanceFactor(node) == 2) {
        if (getBalanceFactor(node->right) < 0)
            node->right = rotateRight(node->right);
        return rotateLeft(node);
    }

    if (getBalanceFactor(node) == -2) {
        if (getBalanceFactor(node->left) > 0)
            node->left = rotateLeft(node->left);
        return rotateRight(node);
    }

    return node;
}

Node* insert(Node* node, int key) {
    if (!node) return new Node(key);

    if (key < node->key)
        node->left = insert(node->left, key);
    else
        node->right = insert(node->right, key);

    return balance(node);
}

Node* findMin(Node* node) {
    return node->left ? findMin(node->left) : node;
}

Node* removeMin(Node* node) {
    if (!node->left)
        return node->right;

    node->left = removeMin(node->left);
    return balance(node);
}

Node* remove(Node* node, int key) {
    if (!node) return nullptr;

    if (key < node->key)
        node->left = remove(node->left, key);
    else if (key > node->key)
        node->right = remove(node->right, key);
    else {
        Node* q = node->left;
        Node* r = node->right;
        delete node;

        if (!r) return q;
        Node* min = findMin(r);
        min->right = removeMin(r);
        min->left = q;
        return balance(min);
    }

    return balance(node);
}

bool search(Node* node, int key) {
    while (node) {
        if (key == node->key)
            return true;
        else if (key < node->key)
            node = node->left;
        else
            node = node->right;
    }
    return false;
}

void printInOrder(Node* node) {
    if (!node) return;

    printInOrder(node->left);
    std::cout << node->key << " ";
    printInOrder(node->right);
}

int main() {
    Node* root = nullptr;

    // Insert elements
    root = insert(root, 10);
    root = insert(root, 20);
    root = insert(root, 30);
    root = insert(root, 40);
    root = insert(root, 50);

    // Print elements in order
    printInOrder(root);
    std::cout << std::endl;

    // Search for an element
    std::cout << "Search 20: " << (search(root, 20) ? "Found" : "Not Found") << std::endl;
    std::cout << "Search 25: " << (search(root, 25) ? "Found" : "Not Found") << std::endl;

    // Remove an element
    root = remove(root, 20);

    // Print elements in order after removal
    printInOrder(root);
    std::cout << std::endl;

    return 0;
}

Below is a simple example of a Go program that interacts with a MariaDB database. It uses the `go-sql-driver/mysql` package to connect to the database.

```go
package main

import (
	"database/sql"
	"fmt"
	"log"

	_ "github.com/go-sql-driver/mysql"
)

type User struct {
	ID       int    `json:"id"`
	Name     string `json:"name"`
	Email    string `json:"email"`
	Password string `json:"password"`
}

var db *sql.DB

func main() {
	var err error
	db, err = sql.Open("mysql", "user:password@tcp(127.0.0.1:3306)/dbname")
	if err != nil {
		log.Fatal(err)
	}
	defer db.Close()

	err = db.Ping()
	if err != nil {
		log.Fatal(err)
	}

	fmt.Println("Successfully connected!")

	// Perform CRUD operations here...
}

func createUser(user User) (int64, error) {
	result, err := db.Exec(`INSERT INTO users(name, email, password) VALUES (?, ?, ?)`, user.Name, user.Email, user.Password)
	if err != nil {
		return 0, err
	}

	id, err := result.LastInsertId()
	if err != nil {
		return 0, err
	}

	return id, nil
}

func getUser(id int) (*User, error) {
	user := &User{}
	row := db.QueryRow(`SELECT id, name, email, password FROM users WHERE id = ?`, id)
	err := row.Scan(&user.ID, &user.Name, &user.Email, &user.Password)
	if err != nil {
		return nil, err
	}

	return user, nil
}

func updateUser(user User) error {
	_, err := db.Exec(`UPDATE users SET name = ?, email = ?, password = ? WHERE id = ?`, user.Name, user.Email, user.Password, user.ID)
	return err
}

func deleteUser(id int) error {
	_, err := db.Exec(`DELETE FROM users WHERE id = ?`, id)
	return err
}
```

Please replace `"user:password@tcp(127.0.0.1:3306)/dbname"` with your actual database connection details. The functions `createUser`, `getUser`, `updateUser`, and `deleteUser` perform the basic CRUD operations on the 'users' table.

