import argparse
import boto3
from botocore.exceptions import NoCredentialsError

def upload_to_s3(file_path, bucket_name):
    s3 = boto3.client('s3')
    try:
        s3.upload_file(file_path, bucket_name, file_path)
        print(f"File {file_path} uploaded successfully.")
    except FileNotFoundError:
        print("The file was not found")
    except NoCredentialsError:
        print("Credentials not available")

def download_from_s3(file_path, bucket_name):
    s3 = boto3.resource('s3')
    try:
        s3.Bucket(bucket_name).download_file(file_path, file_path)
        print(f"File {file_path} downloaded successfully.")
    except FileNotFoundError:
        print("The file was not found")
    except NoCredentialsError:
        print("Credentials not available")

def list_files_in_bucket(bucket_name):
    s3 = boto3.client('s3')
    try:
        response = s3.list_objects_v2(Bucket=bucket_name)
        for content in response.get('Contents', []):
            print(content['Key'])
    except NoCredentialsError:
        print("Credentials not available")

if __name__ == "__main__":
    parser = argparse.ArgumentParser(description="Interact with an Amazon S3 bucket")
    parser.add_argument("action", choices=["upload", "download", "list"], help="Specify the desired action (upload, download, or list)")
    parser.add_argument("bucket_name", help="Name of the S3 bucket")
    parser.add_argument("--file_path", help="Path of the file to upload or download")

    args = parser.parse_args()

    if args.action == "upload":
        if not args.file_path:
            print("Please provide a file path for uploading.")
        else:
            upload_to_s3(args.file_path, args.bucket_name)
    elif args.action == "download":
        if not args.file_path:
            print("Please provide a file path for downloading.")
        else:
            download_from_s3(args.file_path, args.bucket_name)
