Here's a JavaScript function that returns the Longest Increasing Subsequence (LIS) using dynamic programming:

```javascript
function longestIncreasingSubsequence(arr) {
  const n = arr.length;
  if (n === 0) return [];

  // Initialize LIS values for all indexes
  const lis = Array(n).fill(1);

  // Compute optimized LIS values in bottom-up manner
  for (let i = 1; i < n; i++) {
    for (let j = 0; j < i; j++) {
      if (arr[i] > arr[j] && lis[i] < lis[j] + 1) {
        lis[i] = lis[j] + 1;
      }
    }
  }

  // Find the maximum value and its index in the LIS array
  let max = lis[0];
  let maxIndex = 0;
  for (let i = 1; i < n; i++) {
    if (lis[i] > max) {
      max = lis[i];
      maxIndex = i;
    }
  }

  // Construct the LIS by iterating through the array from the maxIndex to the beginning
  const result = [];
  let temp = arr[maxIndex];
  let maxLength = max;

  for (let i = maxIndex; i >= 0; i--) {
    if (lis[i] === maxLength && arr[i] <= temp) {
      result.unshift(arr[i]);
      maxLength--;
      temp = arr[i];
    }
  }

  return result;
}

// Example usage:
const inputArray = [10, 22, 9, 33, 21, 50, 41, 60, 80];
console.log(longestIncreasingSubsequence(inputArray)); // Output: [10, 22, 33, 50, 60, 80]
```

This function first calculates the length of the LIS for each element in the input array using dynamic programming. Then, it constructs the actual LIS by iterating through the array from the index with the maximum LIS length to the beginning.

using System;

namespace GeometricShapes
{
    public abstract class Shape
    {
        public abstract double CalculateArea();
        public abstract double CalculatePerimeter();
    }

    public class Circle : Shape
    {
        public double Radius { get; set; }

        public Circle(double radius)
        {
            Radius = radius;
        }

        public override double CalculateArea()
        {
            return Math.PI * Math.Pow(Radius, 2);
        }

        public override double CalculatePerimeter()
        {
            return 2 * Math.PI * Radius;
        }
    }

    public class Rectangle : Shape
    {
        public double Length { get; set; }
        public double Width { get; set; }

        public Rectangle(double length, double width)
        {
            Length = length;
            Width = width;
        }

        public override double CalculateArea()
        {
            return Length * Width;
        }

        public override double CalculatePerimeter()
        {
            return 2 * (Length + Width);
        }
    }

    public class Triangle : Shape
    {
        public double Base { get; set; }
        public double Height { get; set; }
        public double SideA { get; set; }
        public double SideB { get; set; }

        public Triangle(double baseLength, double height, double sideA, double sideB)
        {
            Base = baseLength;
            Height = height;
            SideA = sideA;
            SideB = sideB;
        }

        public override double CalculateArea()
        {
            return 0.5 * Base * Height;
        }

        public override double CalculatePerimeter()
        {
            return Base + SideA + SideB;
        }
    }

    class Program
    {
        static void Main(string[] args)
        {
            Console.WriteLine("Enter the shape type (circle, rectangle, triangle):");
