        try (Connection conn = DriverManager.getConnection(DB_URL);
             PreparedStatement pstmt = conn.prepareStatement("INSERT INTO accounts(account_number, balance) VALUES(?, ?)")) {

            pstmt.setInt(1, accountNumber);
            pstmt.setDouble(2, 0.0);
