public class MathProblems {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        Random random = new Random();
        int score = 0;
        int numberOfQuestions = 10;

        for (int i = 0; i < numberOfQuestions; i++) {
            int num1 = random.nextInt(50) + 1;
            int num2 = random.nextInt(50) + 1;
            int operation = random.nextInt(4);

            System.out.println("Solve the following problem:");
            int correctAnswer = 0;

            switch (operation) {
                case 0:
                    System.out.printf("%d + %d = ", num1, num2);
                    correctAnswer = num1 + num2;
                    break;
                case 1:
                    System.out.printf("%d - %d = ", num1, num2);
                    correctAnswer = num1 - num2;
                    break;
                case 2:
                    System.out.printf("%d * %d = ", num1, num2);
                    correctAnswer = num1 * num2;
                    break;
                case 3:
                    while (num2 == 0) {
                        num2 = random.nextInt(50) + 1;
                    }
                    System.out.printf("%d / %d = ", num1, num2);
                    correctAnswer = num1 / num2;
                    break;
            }

            int userAnswer = scanner.nextInt();

            if (userAnswer == correctAnswer) {
                System.out.println("Correct!");
                score++;
            } else {
                System.out.println("Incorrect. The correct answer is " + correctAnswer);
            }

            System.out.println("Your current score is: " + score);
        }

        System.out.println("Your final score is: " + score + " out of " + numberOfQuestions);
    }
}

Here's a Node.js script that reads a JSON file containing an array of employees and calculates the average age of employees in each department:

```javascript
const fs = require('fs');

// Read the JSON file
fs.readFile('employees.json', 'utf8', (err, data) => {
  if (err) {
    console.error(err);
    return;
  }

  // Parse the JSON data into an array of employee objects
  const employees = JSON.parse(data);

  // Calculate the average age of employees in each department
  const departmentAges = {};
  const departmentCounts = {};

  for (const employee of employees) {
    const { department, age } = employee;

    if (!departmentAges[department]) {
      departmentAges[department] = 0;
      departmentCounts[department] = 0;
    }

    departmentAges[department] += age;
    departmentCounts[department]++;
  }

  const departmentAverages = {};

  for (const department in departmentAges) {
    departmentAverages[department] =
      departmentAges[department] / departmentCounts[department];
  }

  // Log the results
  console.log(departmentAverages);
});
