using System;

public class BinarySearchTree {
    public Node root;

    public class Node {
        public int data;
        public Node left, right;

        public Node(int item) {
            data = item;
            left = right = null;
        }
    }

    public BinarySearchTree() {
        root = null;
    }

    // Insert operation
    public void Insert(int data) {
        root = InsertRec(root, data);
    }

    private Node InsertRec(Node root, int data) {
        if (root == null) {
            root = new Node(data);
            return root;
        }

        if (data < root.data)
            root.left = InsertRec(root.left, data);
        else if (data > root.data)
            root.right = InsertRec(root.right, data);

        return root;
    }

    // Delete operation
    public void Delete(int data) {
        root = DeleteRec(root, data);
    }

    private Node DeleteRec(Node root, int data) {
        if (root == null) return root;

        if (data < root.data)
            root.left = DeleteRec(root.left, data);
        else if (data > root.data)
            root.right = DeleteRec(root.right, data);
        else {
            if (root.left == null)
                return root.right;
            else if (root.right == null)
                return root.left;

            root.data = MinValue(root.right);
            root.right = DeleteRec(root.right, root.data);
        }

        return root;
    }

    private int MinValue(Node root) {
        int minValue = root.data;
        while (root.left != null) {
            minValue = root.left.data;
            root = root.left;
        }
        return minValue;
    }

    // Search operation
    public bool Search(int data) {
        return SearchRec(root, data);
    }

    private bool SearchRec(Node root, int data) {
        if (root == null)
            return false;

        if (data < root.data)
            return SearchRec(root.left, data);
        else if (data > root.data)
            return SearchRec(root.right, data);

        return true;
    }
}

public class MainClass {
    public static void Main(string[] args) {
        BinarySearchTree tree = new BinarySearchTree();

        tree.Insert(50);
        tree.Insert(30);
        tree.Insert(20);
        tree.Insert(40);
        tree.Insert(70);
        tree.Insert(60);
        tree.Insert(80);

        Console.WriteLine("Search 40: " + tree.Search(40));
        Console.WriteLine("Search 90: " + tree.Search(90));

        tree.Delete(20);
        tree.Delete(30);
        tree.Delete(50);

        Console.WriteLine("Search 20 after deletion: " + tree.Search(20));
        Console.WriteLine("Search 30 after deletion: " + tree.Search(30));
        Console.WriteLine("Search 50 after deletion: " + tree.Search(50));
    }
}

