Here is a simple GoLang application that uses goroutines to download multiple web pages concurrently. The URLs are read from a text file provided via command-line argument.

```go
package main

import (
	"bufio"
	"fmt"
	"io/ioutil"
	"net/http"
	"os"
	"sync"
)

func main() {
	if len(os.Args) != 2 {
		fmt.Println("Please provide a file containing urls")
		os.Exit(1)
	}

	file, err := os.Open(os.Args[1])
	if err != nil {
		fmt.Println(err)
		os.Exit(1)
	}
	defer file.Close()

	var wg sync.WaitGroup
	scanner := bufio.NewScanner(file)
	for scanner.Scan() {
		wg.Add(1)
		go func(url string) {
			defer wg.Done()
			res, err := http.Get(url)
			if err != nil {
				fmt.Printf("Failed to fetch %s: %v\n", url, err)
				return
			}
			defer res.Body.Close()
			body, err := ioutil.ReadAll(res.Body)
			if err != nil {
				fmt.Printf("Failed to read response body for %s: %v\n", url, err)
				return
			}
			fmt.Printf("Fetched URL: %s Content Length: %d\n", url, len(body))
		}(scanner.Text())
	}

	if err := scanner.Err(); err != nil {
		fmt.Println(err)
		os.Exit(1)
	}

	wg.Wait()
}
```

To run this program, you need to create a text file with the list of URLs (one per line), and then pass it as an argument when running the program:

```bash
$ go run main.go urls.txt
```

