To create a Node.js Express server with two endpoints for uploading and resizing JPEG images, follow these steps:

1. Install the required packages: express, multer (for handling file uploads), and sharp (for image processing).

```bash
npm init -y
npm install express multer sharp
```

2. Create an `app.js` file to set up your Express server.

```javascript
const express = require('express');
const multer = require('multer');
const sharp = require('sharp');
const path = require('path');
const fs = require('fs');

// Set up storage for uploaded images using Multer
const storage = multer.diskStorage({
  destination: './uploads/',
  filename: function (req, file, cb) {
    cb(null, Date.now() + '-' + file.originalname);
  },
});

const upload = multer({ storage: storage });

// Create the Express app
const app = express();
const port = process.env.PORT || 3000;

// Upload endpoint
app.post('/upload', upload.single('image'), async (req, res) => {
  try {
    if (!req.file) {
      return res.status(400).send('No image provided.');
    }
    res.send(`Image uploaded successfully: ${req.file.filename}`);
  } catch (error) {
    console.error(error);
    res.status(500).send('Internal Server Error');
  }
});

// Resize endpoint
app.post('/resize', upload.single('image'), async (req, res) => {
  try {
    if (!req.file) {
      return res.status(400).send('No image provided.');
    }

    const width = parseInt(req.body.width);
    const height = parseInt(req.body.height);

    if (!width || !height) {
      return res.status(400).send('Invalid width or height.');
    }

    // Create resized folder if it doesn't exist
    const resizedFolderPath = './resized/';
    if (!fs.existsSync(resizedFolderPath)) {
      fs.mkdirSync(resizedFolderPath);
    }

    // Resize the image using Sharp and save it to the resized folder
    const outputPath = path.join(
      resizedFolderPath,
      `resized-${width}x${height}-${req.file.filename}`
    );

    await sharp(req.file.path)
      .resize(width, height, { fit: 'inside' })
      .toFile(outputPath);

    res.send(`Image resized successfully: ${outputPath}`);
  } catch (error) {
    console.error(error);
    res.status(500).send('Internal Server Error');
  }
});

// Start the server
app.listen(port, () => {
  console.log(`Server is running on port ${port}`);
});
```

3. Run your Express server.

```bash
node app.js
```

Now you have an Express server with two endpoints:

- `/upload`: Uploads a JPEG image to the `uploads` folder.
- `/resize`: Resizes the uploaded image to the specified width and height while maintaining the aspect ratio, then saves the resized image in the `resized` folder.

You can test these endpoints using tools like Postman or curl. Make sure to send the image as form-data with the key "image" for both endpoints. For the resize endpoint, also include the desired width and height as form-data.

