class Node:
    def __init__(self, data=None):
        self.data = data
        self.next = None

class SinglyLinkedList:
    def __init__(self):
        self.head = None

    def add_element(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
        else:
            current = self.head
            while current.next:
                current = current.next
            current.next = new_node

    def remove_element(self, data):
        if not self.head:
            return "List is empty"

        if self.head.data == data:
            self.head = self.head.next
            return f"Removed {data} from the list"

        current = self.head
        while current.next:
            if current.next.data == data:
                current.next = current.next.next
                return f"Removed {data} from the list"
            current = current.next

        return f"{data} not found in the list"

    def search_element(self, data):
        if not self.head:
            return "List is empty"

        current = self.head
        index = 0
        while current:
            if current.data == data:
                return f"{data} found at position {index}"
            current = current.next
            index += 1

        return f"{data} not found in the list"

    def display_list(self):
        elements = []
        current = self.head
        while current:
            elements.append(current.data)
            current = current.next
        return elements


if __name__ == "__main__":
    sll = SinglyLinkedList()
    sll.add_element(5)
    sll.add_element(10)
    sll.add_element(15)

    print("Linked List: ", sll.display_list())
    print(sll.search_element(10))
    print(sll.remove_element(10))
    print("Linked List after removing 10: ", sll.display_list())
