package main

import (
	"fmt"
	"strconv"
	"os"
)

// Recursive function to calculate factorial
func factorial(n int) int {
	if n == 0 {
		return 1
	}
	return n * factorial(n-1)
}

func main() {
	if len(os.Args) != 2 {
		fmt.Println("Usage: go run factorial.go <positive_integer>")
		os.Exit(1)
	}

	n, err := strconv.Atoi(os.Args[1])
	if err != nil || n < 0 {
		fmt.Println("Error: Please provide a valid positive integer")
		os.Exit(1)
	}

	result := factorial(n)
	fmt.Printf("Factorial of %d is %d\n", n, result)
}

package main

import (
	"fmt"
	"net/http"

	"github.com/gin-gonic/gin"
	"golang.org/x/oauth2"
	"golang.org/x/oauth2/google"
	oauth2api "google.golang.org/api/oauth2/v2"
)

var (
	googleOauthConfig = &oauth2.Config{
		ClientID:     "YOUR_CLIENT_ID",
		ClientSecret: "YOUR_CLIENT_SECRET",
		RedirectURL:  "http://localhost:8080/auth/callback",
		Scopes:       []string{"https://www.googleapis.com/auth/userinfo.profile"},
		Endpoint:     google.Endpoint,
	}
)

func main() {
	r := gin.Default()

	r.LoadHTMLGlob("templates/*")

	r.GET("/", func(c *gin.Context) {
		c.HTML(http.StatusOK, "index.html", nil)
	})

	r.GET("/login", func(c *gin.Context) {
		url := googleOauthConfig.AuthCodeURL("state")
		c.Redirect(http.StatusTemporaryRedirect, url)
	})

	r.GET("/auth/callback", func(c *gin.Context) {
		code := c.Query("code")

		token, err := googleOauthConfig.Exchange(oauth2.NoContext, code)
		if err != nil {
			fmt.Printf("Error exchanging token: %s\n", err.Error())
			c.AbortWithStatus(http.StatusInternalServerError)
			return
		}

		oauth2Service, err := oauth2api.New(token.Client(oauth2.NoContext))
		if err != nil {
			fmt.Printf("Error creating OAuth2 service: %s\n", err.Error())
			c.AbortWithStatus(http.StatusInternalServerError)
			return
		}

		userinfo, err := oauth2Service.Userinfo.Get().Do()
		if err != nil {
			fmt.Printf("Error getting user info: %s\n", err.Error())
			c.AbortWithStatus(http.StatusInternalServerError)
			return
		}

		c.HTML(http.StatusOK, "dashboard.html", gin.H{
			"Name":  userinfo.Name,
			"Email": userinfo.Email,
			"Image": userinfo.Picture,
		})
	})

	r.Run(":8080")
}

