import java.util.Scanner;

public class CommandLineCalculator {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("Enter an expression like '5 + 3' or '12 / 4':");
        String input = scanner.nextLine();
        scanner.close();

        String[] tokens = input.split(" ");
        if (tokens.length != 3) {
            System.out.println("Invalid input. Please enter an expression like '5 + 3' or '12 / 4'.");
            return;
        }

        double num1, num2, result;
        try {
            num1 = Double.parseDouble(tokens[0]);
            num2 = Double.parseDouble(tokens[2]);
        } catch (NumberFormatException e) {
            System.out.println("Invalid numbers entered.");
            return;
        }

        char operator = tokens[1].charAt(0);

        switch (operator) {
            case '+':
                result = num1 + num2;
                break;
            case '-':
                result = num1 - num2;
                break;
            case '*':
                result = num1 * num2;
                break;
            case '/':
                if (num2 == 0) {
                    System.out.println("Cannot divide by zero.");
                    return;
                }
                result = num1 / num2;
                break;
            default:
                System.out.println("Invalid operator entered.");
                return;
        }

        System.out.printf("%.2f %c %.2f = %.2f%n", num1, operator, num2, result);
    }
}

Here's a Java program that reads a CSV file containing information about students (name, age, grade) and sorts them by age in ascending order. The program then writes the sorted list to a new CSV file.

```java
import java.io.BufferedReader;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;
import java.util.List;

class Student {
    String name;
    int age;
    String grade;

    public Student(String name, int age, String grade) {
        this.name = name;
        this.age = age;
        this.grade = grade;
    }
}

public class SortStudentsByAge {

    public static void main(String[] args) {
        List<Student> students = readCSVFile("students.csv");
        Collections.sort(students, Comparator.comparingInt(student -> student.age));
        writeCSVFile("sorted_students.csv", students);
    }

    private static List<Student> readCSVFile(String fileName) {
        List<Student> students = new ArrayList<>();
        try (BufferedReader br = new BufferedReader(new FileReader(fileName))) {
            String line;
            while ((line = br.readLine()) != null) {
                String[] values = line.split(",");
                if (values.length == 3) {
                    students.add(new Student(values[0], Integer.parseInt(values[1]), values[2]));
                }
            }
        } catch (IOException e) {
            System.err.println("Error reading CSV file: " + e.getMessage());
        }
        return students;
    }

    private static void writeCSVFile(String fileName, List<Student> students) {
        try (FileWriter fw = new FileWriter(fileName)) {
            for (Student student : students) {
                fw.write(student.name + "," + student.age + "," + student.grade + "\n");
            }
        } catch (IOException e) {
            System.err.println("Error writing CSV file: " + e.getMessage());
        }
    }
}
```

