using System.Data.SQLite;

class Program
{
    static SQLiteConnection sqlite_conn;
    static SQLiteCommand sqlite_cmd;

    static void Main(string[] args)
    {
        sqlite_conn = new SQLiteConnection("Data Source=database.db;Version=3;");
        sqlite_conn.Open();

        sqlite_cmd = sqlite_conn.CreateCommand();

        while (true)
        {
            Console.WriteLine("\n1. Create\n2. Read\n3. Update\n4. Delete\n5. Exit");
            int choice = Convert.ToInt32(Console.ReadLine());

            switch (choice)
            {
                case 1:
                    Create();
                    break;
                case 2:
                    Read();
                    break;
                case 3:
                    Update();
                    break;
                case 4:
                    Delete();
                    break;
                case 5:
                    sqlite_conn.Close();
                    return;
            }
        }
    }

    static void Create()
    {
        Console.Write("Enter Name: ");
        string name = Console.ReadLine();
        Console.Write("Enter Position: ");
        string position = Console.ReadLine();
        Console.Write("Enter Salary: ");
        double salary = Convert.ToDouble(Console.ReadLine());

        sqlite_cmd.CommandText = "INSERT INTO Employees (Name, Position, Salary) VALUES ('" + name + "', '" + position + "', " + salary + ");";
        sqlite_cmd.ExecuteNonQuery();
    }

    static void Read()
    {
        sqlite_cmd.CommandText = "SELECT * FROM Employees;";
        SQLiteDataReader sqlite_datareader = sqlite_cmd.ExecuteReader();

        while (sqlite_datareader.Read())
        {
            string Id = sqlite_datareader.GetString(0);
            string Name = sqlite_datareader.GetString(1);
            string Position = sqlite_datareader.GetString(2);
            string Salary = sqlite_datareader.GetString(3);

            Console.WriteLine("ID: {0} | Name: {1} | Position: {2} | Salary: {3}", Id, Name, Position, Salary);
        }
    }

    static void Update()
    {
        Console.Write("Enter ID of the employee to update: ");
        string id = Console.ReadLine();
        Console.Write("Enter New Name: ");
        string name = Console.ReadLine();
        Console.Write("Enter New Position: ");
        string position = Console.ReadLine();
        Console.Write("Enter New Salary: ");
        double salary = Convert.ToDouble(Console.ReadLine());

        sqlite_cmd.CommandText = "UPDATE Employees SET Name='" + name + "', Position='" + position + "', Salary=" + salary + " WHERE Id=" + id + ";";
        sqlite_cmd.ExecuteNonQuery();
    }

    static void Delete()
    {
        Console.Write("Enter ID of the employee to delete: ");
        string id = Console.ReadLine();

        sqlite_cmd.CommandText = "DELETE FROM Employees WHERE Id=" + id + ";";
        sqlite_cmd.ExecuteNonQuery();
    }
}

