class Node:
    def __init__(self, data=None):
        self.data = data
        self.next = None

class SinglyLinkedList:
    def __init__(self):
        self.head = None

    def add_at_beginning(self, data):
        new_node = Node(data)
        new_node.next = self.head
        self.head = new_node

    def add_at_end(self, data):
        new_node = Node(data)

        if not self.head:
            self.head = new_node
            return

        last_node = self.head
        while last_node.next:
            last_node = last_node.next

        last_node.next = new_node

    def add_at_index(self, index, data):
        if index == 0:
            self.add_at_beginning(data)
            return

        new_node = Node(data)
        current_node = self.head
        position = 0

        while current_node and position < index - 1:
            current_node = current_node.next
            position += 1

        if not current_node:
            raise IndexError("Index out of range")

        new_node.next = current_node.next
        current_node.next = new_node

    def remove_by_value(self, value):
        if not self.head:
            raise ValueError("List is empty")

        if self.head.data == value:
            self.head = self.head.next
            return

        current_node = self.head
        while current_node.next and current_node.next.data != value:
            current_node = current_node.next

        if not current_node.next:
            raise ValueError("Value not found in the list")

        current_node.next = current_node.next.next

    def print_list(self):
        current_node = self.head
        while current_node:
            print(current_node.data, end=" -> ")
            current_node = current_node.next
        print("None")

if __name__ == "__main__":
    sll = SinglyLinkedList()
    sll.add_at_beginning(1)
    sll.add_at_end(2)
    sll.add_at_index(1, 3)
    sll.print_list()  # Output: 1 -> 3 -> 2 -> None
    sll.remove_by_value(3)
    sll.print_list()  # Output: 1 -> 2 -> None

