class Node:
    def __init__(self, key):
        self.left = None
        self.right = None
        self.val = key

class BinarySearchTree:
    def __init__(self):
        self.root = None

    def insert(self, key):
        if self.root is None:
            self.root = Node(key)
        else:
            self._insert_recursive(self.root, key)

    def _insert_recursive(self, node, key):
        if key < node.val:
            if node.left is None:
                node.left = Node(key)
            else:
                self._insert_recursive(node.left, key)
        else:
            if node.right is None:
                node.right = Node(key)
            else:
                self._insert_recursive(node.right, key)

    def delete(self, key):
        self.root = self._delete_recursive(self.root, key)

    def _delete_recursive(self, root, key):
        if root is None:
            return root

        if key < root.val:
            root.left = self._delete_recursive(root.left, key)
        elif key > root.val:
            root.right = self._delete_recursive(root.right, key)
        else:
            if root.left is None:
                return root.right
            elif root.right is None:
                return root.left

            root.val = self._find_min_value(root.right)
            root.right = self._delete_recursive(root.right, root.val)

        return root

    def _find_min_value(self, node):
        min_value = node.val
        while node.left is not None:
            min_value = node.left.val
            node = node.left
        return min_value

    def search(self, key):
        return self._search_recursive(self.root, key)

    def _search_recursive(self, node, key):
        if node is None or node.val == key:
            return node

        if key < node.val:
            return self._search_recursive(node.left, key)

        return self._search_recursive(node.right, key)

package main

import (
	"fmt"
	"io/ioutil"
	"log"
	"net/http"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"time"

	"github.com/gorilla/mux"
	"golang.org/x/time/rate"
)

const (
	staticDir    = "./static" // directory to serve static files from
	maxUploadSize = 10 << 20   // 10 MB
)

var (
	rateLimiter *rate.Limiter
	mutex       sync.Mutex
)

func init() {
	rateLimiter = rate.NewLimiter(1, 5) // allow 1 request per second with a burst of 5 requests
}

func main() {
	router := mux.NewRouter()

	router.HandleFunc("/upload", uploadHandler).Methods("POST")
	router.HandleFunc("/delete/{filename}", deleteHandler).Methods("DELETE")
	router.PathPrefix("/").Handler(http.FileServer(http.Dir(staticDir)))

	http.Handle("/", router)
	log.Fatal(http.ListenAndServe(":8080", nil))
}

func rateLimit(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		mutex.Lock()
		defer mutex.Unlock()

		if !rateLimiter.Allow() {
			http.Error(w, "Too many requests. Please try again later.", http.StatusTooManyRequests)
			return
		}
		next.ServeHTTP(w, r)
	})
}

func uploadHandler(w http.ResponseWriter, r *http.Request) {
	err := r.ParseMultipartForm(maxUploadSize)
	if err != nil {
		http.Error(w, "Error parsing form data", http.StatusBadRequest)
		return
	}

	file, header, err := r.FormFile("file")
	if err != nil {
		http.Error(w, "Error retrieving file from form data", http.StatusBadRequest)
		return
	}
	defer file.Close()

	fileBytes, err := ioutil.ReadAll(file)
	if err != nil {
		http.Error(w, "Error reading file", http.StatusInternalServerError)
		return
	}

	filename := header.Filename
	newPath := filepath.Join(staticDir, filename)

	err = ioutil.WriteFile(newPath, fileBytes, 0644)
	if err != nil {
		http.Error(w, "Error saving file", http.StatusInternalServerError)
		return
	}

	fmt.Fprintf(w, "File uploaded successfully: %s\n", filename)
}

func deleteHandler(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	filename := vars["filename"]

	path := filepath.Join(staticDir, filename)

	if !strings.HasPrefix(path, staticDir) {
		http.Error(w, "Invalid file path", http.StatusBadRequest)
		return
	}

	err := os.Remove(path)
	if err != nil {
		http.Error(w, "Error deleting file", http.StatusInternalServerError)
		return
	}

	fmt.Fprintf(w, "File deleted successfully: %s\n", filename)
}

import org.apache.http.HttpEntity;
import org.apache.http.client.methods.CloseableHttpResponse;
import org.apache.http.client.methods.HttpGet;
import org.apache.http.impl.client.CloseableHttpClient;
import org.apache.http.impl.client.HttpClients;
import org.apache.http.util.EntityUtils;
import org.apache.kafka.clients.producer.KafkaProducer;
import org.apache.kafka.clients.producer.Producer;
import org.apache.kafka.clients.producer.ProducerRecord;
import org.json.JSONArray;
import org.json.JSONObject;

import java.io.IOException;
import java.util.Properties;

public class JsonApiToKafka {

    public static void main(String[] args) {
        // Replace with your JSON API URL
        String apiUrl = "https://jsonplaceholder.typicode.com/todos";

        try {
            JSONArray jsonArray = fetchJsonArrayFromApi(apiUrl);
            processAndSendData(jsonArray);
        } catch (IOException e) {
            System.err.println("Error fetching data from the API: " + e.getMessage());
        }
    }

    private static JSONArray fetchJsonArrayFromApi(String apiUrl) throws IOException {
        CloseableHttpClient httpClient = HttpClients.createDefault();
        HttpGet httpGet = new HttpGet(apiUrl);
        CloseableHttpResponse response = httpClient.execute(httpGet);

        try {
            HttpEntity entity = response.getEntity();
            if (entity != null) {
                String result = EntityUtils.toString(entity);
                return new JSONArray(result);
            }
        } finally {
            response.close();
        }

        throw new IOException("Failed to fetch data from the API");
    }

    private static void processAndSendData(JSONArray jsonArray) {
        Properties props = new Properties();
        props.put("bootstrap.servers", "localhost:9092"); // Replace with your Kafka broker address
        props.put("key.serializer", "org.apache.kafka.common.serialization.StringSerializer");
        props.put("value.serializer", "org.apache.kafka.common.serialization.StringSerializer");

        Producer<String, String> producer = new KafkaProducer<>(props);

        for (int i = 0; i < jsonArray.length(); i++) {
            JSONObject jsonObject = jsonArray.getJSONObject(i);

            // Process the data as needed. In this example, we'll just send it directly to Kafka.
            String key = Integer.toString(jsonObject.getInt("id"));
            String value = jsonObject.toString();

            ProducerRecord<String, String> record = new ProducerRecord<>("my-topic", key, value);
            producer.send(record);
        }

        producer.close();
    }
}

