go get -u github.com/jinzhu/gorm
go get -u github.com/jinzhu/gorm/dialects/postgres
```

2. Create main.go file
Create a `main.go` file with the following content:

```go
package main

import (
	"github.com/gin-gonic/gin"
	"github.com/jinzhu/gorm"
	_ "github.com/jinzhu/gorm/dialects/postgres"
)

var db *gorm.DB
var err error

type Item struct {
	ID       uint   `json:"id"`
	Name     string `json:"name" binding:"required"`
	Quantity int    `json:"quantity" binding:"required"`
	Price    float64 `json:"price" binding:"required"`
}

func main() {
	// Connect to PostgreSQL database
	db, err = gorm.Open("postgres", "host=localhost user=your_user dbname=inventory_db sslmode=disable password=your_password")
	if err != nil {
		panic("failed to connect database")
	}
	defer db.Close()

	// Migrate the schema
	db.AutoMigrate(&Item{})

	r := gin.Default()

	// Routes
	r.GET("/items", GetItems)
	r.GET("/items/:id", GetItem)
	r.POST("/items", AddItem)
	r.PUT("/items/:id", UpdateItem)
	r.DELETE("/items/:id", DeleteItem)

	// Run the server
	r.Run(":8080")
}

func GetItems(c *gin.Context) {
	var items []Item
	if err := db.Find(&items).Error; err != nil {
		c.AbortWithStatus(404)
	} else {
		c.JSON(200, items)
	}
}

func GetItem(c *gin.Context) {
	id := c.Params.ByName("id")
	var item Item
	if err := db.Where("id = ?", id).First(&item).Error; err != nil {
		c.AbortWithStatus(404)
	} else {
		c.JSON(200, item)
	}
}

func AddItem(c *gin.Context) {
	var item Item
	if err := c.ShouldBindJSON(&item); err == nil {
		db.Create(&item)
		c.JSON(201, item)
	} else {
		c.JSON(400, gin.H{"error": err.Error()})
	}
}

func UpdateItem(c *gin.Context) {
	var item Item
	id := c.Params.ByName("id")

	if err := db.Where("id = ?", id).First(&item).Error; err != nil {
		c.AbortWithStatus(404)
		return
	}

	if err := c.ShouldBindJSON(&item); err == nil {
		db.Save(&item)
		c.JSON(200, item)
	} else {
		c.JSON(400, gin.H{"error": err.Error()})
	}
}

func DeleteItem(c *gin.Context) {
	id := c.Params.ByName("id")
	var item Item

	if err := db.Where("id = ?", id).Delete(&item).Error; err != nil {
		c.AbortWithStatus(404)
	} else {
		c.JSON(204, gin.H{"id #" + id: "deleted"})
	}
}
```

