// longestCommonPrefix finds the longest common prefix among an array of strings.
func longestCommonPrefix(strs []string) string {
	if len(strs) == 0 {
		return ""
	}

	prefix := strs[0]

	for _, str := range strs {
		for len(prefix) > 0 && len(str) >= len(prefix) && str[:len(prefix)] != prefix {
			prefix = prefix[:len(prefix)-1]
		}
		if len(prefix) == 0 {
			break
		}
	}

	return prefix
}

func main() {
	strs := []string{"flower", "flow", "flight"}
	fmt.Println(longestCommonPrefix(strs)) // Output: "fl"

	strs2 := []string{"dog", "racecar", "car"}
	fmt.Println(longestCommonPrefix(strs2)) // Output: ""

	strs3 := []string{"ab", "abc", "abcd"}
	fmt.Println(longestCommonPrefix(strs3)) // Output: "ab"
}

