            double averageAge = calculateAverageAge(students);
            double averageGrade = calculateAverageGrade(students);

            // Print average age and grade
            System.out.println("Average Age: " + averageAge);
            System.out.println("Average Grade: " + averageGrade);

            // Print names of students with a grade above the average
            System.out.println("\nStudents with a grade above the average:");
            for (Student student : students) {
                if (student.grade > averageGrade) {
                    System.out.println(student.name);
                }
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
