    private static double calculateAverageAge(ArrayList<Student> students) {
        double sum = 0;
        for (Student student : students) {
            sum += student.age;
        }
        return sum / students.size();
    }

    // Method to calculate average grade
    private static double calculateAverageGrade(ArrayList<Student> students) {
        double sum = 0;
        for (Student student : students) {
            sum += student.grade;
        }
        return sum / students.size();
    }
}

Here's a simple Golang application that calculates the factorial of a given non-negative integer using recursion:

```go
package main

import (
	"fmt"
	"strconv"
	"os"
)

// Factorial function to calculate the factorial using recursion
func Factorial(n int) (int, error) {
	if n < 0 {
		return -1, fmt.Errorf("invalid input: %d is negative", n)
	}
	if n == 0 || n == 1 {
		return 1, nil
	}

	factorial, err := Factorial(n - 1)
	if err != nil {
		return -1, err
	}

	return n * factorial, nil
}

func main() {
	if len(os.Args) != 2 {
		fmt.Println("Usage: go run factorial.go [non-negative integer]")
		os.Exit(1)
	}

	n, err := strconv.Atoi(os.Args[1])
	if err != nil {
		fmt.Printf("Error: %s is not an integer\n", os.Args[1])
		os.Exit(1)
	}

	result, err := Factorial(n)
	if err != nil {
		fmt.Println(err)
		os.Exit(1)
	}

	fmt.Printf("Factorial of %d is %d\n", n, result)
}
```

