class ShoppingCart {
public:
    void addItem(const Product& product) {
        items.push_back(product);
    }

    void removeItem(int index) {
        if (index >= 0 && index < items.size()) {
            items.erase(items.begin() + index);
        } else {
            std::cout << "Invalid item index." << std::endl;
        }
    }

    double getTotalPrice(Customer::Type customerType) const {
        double totalPrice = 0.0;

        for (const auto& item : items) {
            totalPrice += item.getPrice();
        }

        if (customerType == Customer::Type::Premium) {
            totalPrice *= 0.9; // Apply a 10% discount for premium customers.
        }

        return totalPrice;
    }

    void displayItems() const {
        int index = 1;
        for (const auto& item : items) {
            std::cout << index++ << ". " << item.getName() << ": $" << item.getPrice() << std::endl;
        }
    }

private:
    std::vector<Product> items;
};

int main() {
    Product apple("Apple", 0.5);
    Product banana("Banana", 0.3);
    Product orange("Orange", 0.7);

