import java.io.BufferedWriter;
import java.io.FileWriter;
import java.io.IOException;
import java.util.List;

public class TweetSearch {

    public static void main(String[] args) {
        if (args.length != 3) {
            System.out.println("Usage: java TweetSearch <keywords> <output_file_path> <max_tweets>");
            return;
        }

        String keywords = args[0];
        String outputPath = args[1];
        int maxTweets = Integer.parseInt(args[2]);

        ConfigurationBuilder cb = new ConfigurationBuilder();
        cb.setDebugEnabled(true)
                .setOAuthConsumerKey("YOUR_CONSUMER_KEY")
                .setOAuthConsumerSecret("YOUR_CONSUMER_SECRET")
                .setOAuthAccessToken("YOUR_ACCESS_TOKEN")
                .setOAuthAccessTokenSecret("YOUR_ACCESS_TOKEN_SECRET");

        TwitterFactory tf = new TwitterFactory(cb.build());
        Twitter twitter = tf.getInstance();

        try {
            Query query = new Query(keywords);
            query.setCount(maxTweets);

            BufferedWriter writer = new BufferedWriter(new FileWriter(outputPath));

            int remainingTweets = maxTweets;
            while (remainingTweets > 0) {
                List<Status> tweets = twitter.search(query).getTweets();
                for (Status tweet : tweets) {
                    if (remainingTweets <= 0) break;

                    writer.write(tweet.getText() + "\n");
                    System.out.println("Tweet saved: " + tweet.getText());

                    remainingTweets--;
                }

                if (query.getMaxId() != -1) {
                    query.setMaxId(query.getMaxId() - 1);
                } else {
                    break;
                }
            }

            writer.close();
            System.out.println("All tweets saved to file: " + outputPath);

        } catch (TwitterException | IOException e) {
            e.printStackTrace();
        }
    }
}

import java.io.BufferedInputStream;
import java.io.FileOutputStream;
import java.io.IOException;
import java.net.URL;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public class MultiThreadedDownloader {

    public static void main(String[] args) {
        if (args.length == 0) {
            System.out.println("Please provide URLs as command-line arguments.");
            return;
        }

        ExecutorService executor = Executors.newFixedThreadPool(args.length);
        for (String url : args) {
            executor.submit(() -> downloadFile(url));
        }
        executor.shutdown();
    }

    private static void downloadFile(String fileUrl) {
        try {
            URL url = new URL(fileUrl);
            String fileName = url.getFile().substring(url.getFile().lastIndexOf('/') + 1);

            BufferedInputStream inputStream = new BufferedInputStream(url.openStream());
            FileOutputStream outputStream = new FileOutputStream(fileName);

            byte[] buffer = new byte[1024];
            int bytesRead;
            long totalBytesRead = 0;
            while ((bytesRead = inputStream.read(buffer, 0, 1024)) != -1) {
                outputStream.write(buffer, 0, bytesRead);
                totalBytesRead += bytesRead;
                System.out.printf("%s: %d bytes downloaded%n", fileName, totalBytesRead);
            }

            outputStream.close();
            inputStream.close();

            System.out.printf("%s: Download complete%n", fileName);
        } catch (IOException e) {
            System.err.printf("Error downloading file from %s: %s%n", fileUrl, e.getMessage());
        }
    }
}

