import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"log"
	"net/http"
	"os"
	"path/filepath"
	"strconv"
	"strings"
)

type FileResult struct {
	Name string `json:"name"`
	Path string `json:"path"`
}

func main() {
	http.Handle("/", http.FileServer(http.Dir("./static")))
	http.HandleFunc("/api/search", searchHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}

func searchHandler(w http.ResponseWriter, r *http.Request) {
	query := r.URL.Query()
	filename := query.Get("filename")
	pageStr := query.Get("page")
	resultsPerPageStr := query.Get("results_per_page")

	if filename == "" {
		http.Error(w, "Missing 'filename' parameter", http.StatusBadRequest)
		return
	}

	page, err := strconv.Atoi(pageStr)
	if err != nil || page < 1 {
		page = 1
	}

	resultsPerPage, err := strconv.Atoi(resultsPerPageStr)
	if err != nil || resultsPerPage < 1 {
		resultsPerPage = 10
	}

	files, err := searchFiles("./static", filename)
	if err != nil {
		http.Error(w, "Error searching files", http.StatusInternalServerError)
		return
	}

	startIndex := (page - 1) * resultsPerPage
	endIndex := startIndex + resultsPerPage
	if endIndex > len(files) {
		endIndex = len(files)
	}
	paginatedFiles := files[startIndex:endIndex]

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(paginatedFiles)
}

func searchFiles(rootDir, filename string) ([]FileResult, error) {
	var results []FileResult
	err := filepath.Walk(rootDir, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if !info.IsDir() && strings.Contains(info.Name(), filename) {
			results = append(results, FileResult{Name: info.Name(), Path: path})
		}
		return nil
	})

	if err != nil {
		return nil, err
	}

	return results, nil
}

