    let currentEvent = events[i];
    let isOverlapping = false;

    // Check if the current event overlaps with any of the non-overlapping events
    for (let j = 0; j < nonOverlappingEvents.length; j++) {
      let previousEvent = nonOverlappingEvents[j];

      if (
        (currentEvent.start >= previousEvent.start && currentEvent.start <= previousEvent.end) ||
        (currentEvent.end >= previousEvent.start && currentEvent.end <= previousEvent.end)
      ) {
        isOverlapping = true;
        break;
      }
    }

    // If the current event doesn't overlap with any non-overlapping events, add it to the result array
    if (!isOverlapping) {
      nonOverlappingEvents.push(currentEvent);
    }
  }

  return nonOverlappingEvents;
}
```

