Here's a Java program that does exactly what you asked for. It reads a text file containing a list of URLs, downloads the content of each URL concurrently using threads, and saves the downloaded content to separate output files.

```java
import java.io.BufferedReader;
import java.io.File;
import java.io.FileOutputStream;
import java.io.FileReader;
import java.io.IOException;
import java.io.InputStream;
import java.net.URL;
import java.util.ArrayList;
import java.util.List;

public class DownloadFiles {

    public static void main(String[] args) {
        if (args.length != 1) {
            System.err.println("Usage: java DownloadFiles <input_file>");
            System.exit(1);
        }

        List<String> urls = readUrlsFromFile(args[0]);

        // Create a thread for each URL and start downloading
        List<Thread> threads = new ArrayList<>();
        int count = 1;
        for (String url : urls) {
            Thread t = new Thread(new UrlDownloader(url, "output" + count + ".txt"));
            t.start();
            threads.add(t);
            count++;
        }

        // Wait for all threads to finish
        for (Thread t : threads) {
            try {
                t.join();
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        }

        System.out.println("All files have been downloaded.");
    }

    private static List<String> readUrlsFromFile(String fileName) {
        List<String> urls = new ArrayList<>();

        try (BufferedReader br = new BufferedReader(new FileReader(fileName))) {
            String line;
            while ((line = br.readLine()) != null) {
                urls.add(line.trim());
            }
        } catch (IOException e) {
            e.printStackTrace();
        }

        return urls;
    }

    static class UrlDownloader implements Runnable {
        private final String url;
        private final String outputFile;

        public UrlDownloader(String url, String outputFile) {
            this.url = url;
            this.outputFile = outputFile;
        }

        @Override
        public void run() {
            try (InputStream in = new URL(url).openStream();
                 FileOutputStream out = new FileOutputStream(new File(outputFile))) {

                byte[] buffer = new byte[4096];
                int bytesRead;

                while ((bytesRead = in.read(buffer)) != -1) {
                    out.write(buffer, 0, bytesRead);
                }

                System.out.println("Downloaded " + url + " to " + outputFile);

            } catch (IOException e) {
                System.err.println("Error downloading file from " + url + ": " + e.getMessage());
            }
        }
    }
}
```

