Here's a Java program that reads a text file and counts the frequency of each word in the file, printing the results in descending order of frequency:

```java
import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.util.HashMap;
import java.util.LinkedHashMap;
import java.util.Map;
import java.util.stream.Collectors;

public class WordFrequencyCounter {

    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Please provide a file path as an argument.");
            return;
        }

        String filePath = args[0];
        Map<String, Integer> wordCountMap = new HashMap<>();

        try (BufferedReader reader = new BufferedReader(new FileReader(filePath))) {
            String line;
            while ((line = reader.readLine()) != null) {
                String[] words = line.toLowerCase().split("\\W+");
                for (String word : words) {
                    if (!word.isEmpty()) {
                        wordCountMap.put(word, wordCountMap.getOrDefault(word, 0) + 1);
                    }
                }
            }
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
            return;
        }

        Map<String, Integer> sortedWordCountMap = wordCountMap.entrySet().stream()
                .sorted(Map.Entry.<String, Integer>comparingByValue().reversed())
                .collect(Collectors.toMap(Map.Entry::getKey, Map.Entry::getValue,
                        (e1, e2) -> e1, LinkedHashMap::new));

        for (Map.Entry<String, Integer> entry : sortedWordCountMap.entrySet()) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }
    }
}
```

To run this program, save it to a file named `WordFrequencyCounter.java`, compile it using `javac WordFrequencyCounter.java`, and then run it with `java WordFrequencyCounter <file_path>`, where `<file_path>` is the path to the text file you want to analyze.

Here's a simple Java application that simulates a bank account system using classes for accounts, transactions, and customers. This example demonstrates object-oriented programming principles and includes methods for depositing, withdrawing, and transferring funds between accounts.

```java
import java.util.ArrayList;
import java.util.List;

public class BankAccountSystem {

    public static void main(String[] args) {
        Customer customer1 = new Customer("John Doe");
        Account account1 = new Account(customer1);
        account1.deposit(1000);

        Customer customer2 = new Customer("Jane Smith");
        Account account2 = new Account(customer2);
        account2.deposit(2000);

        System.out.println(account1);
        System.out.println(account2);

        account1.transfer(account2, 500);

        System.out.println(account1);
        System.out.println(account2);
    }
}

class Customer {
    private String name;

    public Customer(String name) {
        this.name = name;
    }

    public String getName() {
        return name;
    }

    public void setName(String name) {
        this.name = name;
    }
}

class Account {
    private static int nextId = 1;
    private int id;
    private double balance;
    private Customer customer;
    private List<Transaction> transactions;

    public Account(Customer customer) {
        this.id = nextId++;
        this.customer = customer;
        this.transactions = new ArrayList<>();
    }

    public void deposit(double amount) {
        if (amount > 0) {
            balance += amount;
            transactions.add(new Transaction(amount, "Deposit"));
        } else {
            System.err.println("Invalid deposit amount.");
        }
    }

    public void withdraw(double amount) {
        if (amount > 0 && amount <= balance) {
            balance -= amount;
            transactions.add(new Transaction(-amount, "Withdrawal"));
        } else {
            System.err.println("Invalid withdrawal amount.");
        }
    }

    public void transfer(Account toAccount, double amount) {
        if (amount > 0 && amount <= balance) {
            withdraw(amount);
            toAccount.deposit(amount);
            transactions.add(new Transaction(-amount, "Transfer to account " + toAccount.id));
            toAccount.transactions.add(new Transaction(amount, "Transfer from account " + this.id));
        } else {
            System.err.println("Invalid transfer amount.");
        }
    }

    @Override
    public String toString() {
        return "Account{" +
                "id=" + id +
                ", balance=" + balance +
                ", customer=" + customer.getName() +
                '}';
    }
}

class Transaction {
    private double amount;
    private String description;

    public Transaction(double amount, String description) {
        this.amount = amount;
        this.description = description;
    }

    public double getAmount() {
        return amount;
    }

    public void setAmount(double amount) {
        this.amount = amount;
    }

    public String getDescription() {
        return description;
    }

    public void setDescription(String description) {
        this.description = description;
    }
}
```

This application defines classes for `Customer`, `Account`, and `Transaction`. The main method creates two customers and their accounts, deposits money into the accounts, and then transfers funds between them. It also prints out the account information before and after the transfer.

You can expand this example by adding more features such as handling multiple currencies, tracking transaction history, or implementing a user interface.

package main

import (
	"fmt"
	"os"
)

func main() {
	if len(os.Args) != 3 {
		fmt.Println("Usage: levenshtein string1 string2")
		os.Exit(1)
	}

	string1 := os.Args[1]
	string2 := os.Args[2]

	distance := levenshteinDistance(string1, string2)
	fmt.Printf("Levenshtein distance between '%s' and '%s': %d\n", string1, string2, distance)
}

// levenshteinDistance calculates the Levenshtein distance between two strings
func levenshteinDistance(s1, s2 string) int {
	lenS1 := len(s1)
	lenS2 := len(s2)

	matrix := make([][]int, lenS1+1)
	for i := range matrix {
		matrix[i] = make([]int, lenS2+1)
	}

	for i := 0; i <= lenS1; i++ {
		matrix[i][0] = i
	}
	for j := 0; j <= lenS2; j++ {
		matrix[0][j] = j
	}

	for i := 1; i <= lenS1; i++ {
		for j := 1; j <= lenS2; j++ {
			cost := 1
			if s1[i-1] == s2[j-1] {
				cost = 0
			}

			matrix[i][j] = min(
				matrix[i-1][j]+1,
				matrix[i][j-1]+1,
				matrix[i-1][j-1]+cost,
			)
		}
	}

	return matrix[lenS1][lenS2]
}

// min returns the minimum of three integers
func min(a, b, c int) int {
	if a < b && a < c {
		return a
	} else if b < a && b < c {
		return b
	}
	return c
}

To create a C++ application that uses the OpenCV library to capture webcam video, apply a real-time filter (e.g., grayscale or edge detection), and display the filtered video in a window, follow these steps:

1. Install OpenCV: Download and install the OpenCV library from https://opencv.org/releases/. Make sure you have the appropriate version for your operating system and compiler.

2. Set up your development environment: Configure your IDE or build system to include the OpenCV headers and link against the OpenCV libraries. The process varies depending on your development environment.

3. Create a new C++ project and add the following code:

```cpp
#include <iostream>
#include <opencv2/opencv.hpp>

using namespace cv;
using namespace std;

int main(int argc, char** argv)
{
    // Open the default camera
    VideoCapture cap(0);
    if (!cap.isOpened()) {
        cerr << "ERROR! Unable to open camera\n";
        return -1;
    }

    // Get the camera's resolution
    int frame_width = static_cast<int>(cap.get(CAP_PROP_FRAME_WIDTH));
    int frame_height = static_cast<int>(cap.get(CAP_PROP_FRAME_HEIGHT));

    cout << "Camera resolution: " << frame_width << "x" << frame_height << endl;

    // Create windows to display the original and filtered video
    namedWindow("Original Video", WINDOW_NORMAL);
    namedWindow("Filtered Video", WINDOW_NORMAL);

    Mat frame, gray_frame, edges;

    while (true) {
        // Capture a new frame
        cap >> frame;
        if (frame.empty()) {
            cerr << "ERROR! Blank frame grabbed\n";
            break;
        }

        // Convert the frame to grayscale
        cvtColor(frame, gray_frame, COLOR_BGR2GRAY);

        // Apply an edge detection filter
        Canny(gray_frame, edges, 50, 150);

        // Display the original and filtered video
        imshow("Original Video", frame);
        imshow("Filtered Video", edges);

        // Exit the loop if the user presses 'q'
        if (waitKey(10) == 'q') {
            break;
        }
    }

    // Release resources and close windows
    cap.release();
    destroyAllWindows();

    return 0;
}
```

4. Build and run the application. You should see two windows: one displaying the original webcam video and another showing the filtered video with edge detection applied.

Note that this example uses the Canny edge detection filter. You can replace it with other filters or apply additional processing steps as needed.

package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"net/http"
	"os"

	"github.com/urfave/cli/v2"
)

const baseURL = "http://api.openweathermap.org/data/2.5/weather?q=%s&appid=%s&units=metric"

type WeatherData struct {
	Main struct {
		Temp     float64 `json:"temp"`
		Humidity int     `json:"humidity"`
	} `json:"main"`

	Weather []struct {
		Description string `json:"description"`
	} `json:"weather"`
}

func main() {
	app := &cli.App{
		Name:  "weather",
		Usage: "Get current weather information for a city",

		Flags: []cli.Flag{
			&cli.StringFlag{
				Name:     "city",
				Aliases:  []string{"c"},
				Required: true,
				Usage:    "City name to fetch the weather data",
			},
			&cli.StringFlag{
				Name:     "apikey",
				Aliases:  []string{"a"},
				Required: true,
				Usage:    "API Key for OpenWeatherMap",
			},
		},

		Action: func(c *cli.Context) error {
			city := c.String("city")
			apiKey := c.String("apikey")

			url := fmt.Sprintf(baseURL, city, apiKey)

			resp, err := http.Get(url)
			if err != nil {
				return fmt.Errorf("error fetching weather data: %v", err)
			}
			defer resp.Body.Close()

			body, err := ioutil.ReadAll(resp.Body)
			if err != nil {
				return fmt.Errorf("error reading response body: %v", err)
			}

			var weatherData WeatherData
			err = json.Unmarshal(body, &weatherData)
			if err != nil {
				return fmt.Errorf("error unmarshalling JSON: %v", err)
			}

			fmt.Printf("City: %s\n", city)
			fmt.Printf("Temperature: %.2f°C\n", weatherData.Main.Temp)
			fmt.Printf("Humidity: %d%%\n", weatherData.Main.Humidity)
			fmt.Printf("Conditions: %s\n", weatherData.Weather[0].Description)

			return nil
		},
	}

	err := app.Run(os.Args)
	if err != nil {
		fmt.Fprintln(os.Stderr, err)
		os.Exit(1)
	}
}

