// checkWebsite sends an HTTP GET request to the given URL and returns the status code and response time
func checkWebsite(url string) (int, time.Duration) {
	start := time.Now()
	resp, err := http.Get(url)
	if err != nil {
		return 0, 0
	}
	defer resp.Body.Close()

	duration := time.Since(start)
	return resp.StatusCode, duration
}

// logResults logs the website's URL, status code, and response time to a file named "results.log"
func logResults(url string, statusCode int, responseTime time.Duration) {
	file, err := os.OpenFile("results.log", os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
	if err != nil {
		log.Fatal(err)
	}
	defer file.Close()

	log.SetOutput(file)
	log.Printf("%s - Status Code: %d - Response Time: %v\n", url, statusCode, responseTime)
}

func main() {
	data, err := ioutil.ReadFile("config.json")
	if err != nil {
		log.Fatalf("Error reading config file: %v", err)
	}

	var config Config
	err = json.Unmarshal(data, &config)
	if err != nil {
		log.Fatalf("Error unmarshalling config data: %v", err)
	}

	for {
		for _, website := range config.Websites {
			statusCode, responseTime := checkWebsite(website)
			fmt.Printf("%s - Status Code: %d - Response Time: %v\n", website, statusCode, responseTime)
			logResults(website, statusCode, responseTime)
		}
		time.Sleep(60 * time.Second)
	}
}

#include <iostream>
#include <queue>
#include <mutex>
#include <condition_variable>
#include <thread>
#include <chrono>
#include <random>

std::queue<int> buffer;
const unsigned int bufferSize = 10;

std::mutex mtx;
std::condition_variable cvProducer, cvConsumer;

bool finishedProducing = false;

void producer() {
    std::default_random_engine generator;
    std::uniform_int_distribution<int> distribution(1, 100);

    for (int i = 0; i < 20; ++i) {
        int randomNumber = distribution(generator);
        std::unique_lock<std::mutex> lock(mtx);

        // Wait until there is space in the buffer to add a new number
        cvProducer.wait(lock, [] { return buffer.size() < bufferSize; });

        buffer.push(randomNumber);
        std::cout << "Produced: " << randomNumber << std::endl;

        lock.unlock();
        cvConsumer.notify_one();

        std::this_thread::sleep_for(std::chrono::milliseconds(50));
    }

    finishedProducing = true;
}

void consumer() {
    int sum = 0;

    while (!finishedProducing || !buffer.empty()) {
        std::unique_lock<std::mutex> lock(mtx);

        // Wait until there is a number available in the buffer
        cvConsumer.wait(lock, [] { return !buffer.empty(); });

        if (!buffer.empty()) {
            int num = buffer.front();
            buffer.pop();
            sum += num;
            std::cout << "Consumed: " << num << ", Sum: " << sum << std::endl;
        }

        lock.unlock();
        cvProducer.notify_one();

        std::this_thread::sleep_for(std::chrono::milliseconds(50));
    }
}

int main() {
    std::thread producerThread(producer);
    std::thread consumerThread(consumer);

    producerThread.join();
    consumerThread.join();

    return 0;
}

package com.example;

import com.amazonaws.auth.AWSStaticCredentialsProvider;
import com.amazonaws.auth.BasicAWSCredentials;
import com.amazonaws.regions.Regions;
import com.amazonaws.services.ec2.AmazonEC2;
import com.amazonaws.services.ec2.AmazonEC2ClientBuilder;
import com.amazonaws.services.ec2.model.*;

import java.util.List;

public class EC2Manager {

    private AmazonEC2 ec2Client;

    public EC2Manager(String accessKey, String secretKey, Regions region) {
        BasicAWSCredentials awsCreds = new BasicAWSCredentials(accessKey, secretKey);
        this.ec2Client = AmazonEC2ClientBuilder.standard()
                .withCredentials(new AWSStaticCredentialsProvider(awsCreds))
                .withRegion(region)
                .build();
    }

    public void listInstances() {
        DescribeInstancesResult result = ec2Client.describeInstances();
        List<Reservation> reservations = result.getReservations();

        for (Reservation reservation : reservations) {
            List<Instance> instances = reservation.getInstances();
            for (Instance instance : instances) {
                System.out.println("ID: " + instance.getInstanceId() +
                        ", State: " + instance.getState().getName() +
                        ", Type: " + instance.getInstanceType());
            }
        }
    }

    public void startInstance(String instanceId) {
        StartInstancesRequest request = new StartInstancesRequest().withInstanceIds(instanceId);
        ec2Client.startInstances(request);
        System.out.println("Starting instance: " + instanceId);
    }

    public void stopInstance(String instanceId) {
        StopInstancesRequest request = new StopInstancesRequest().withInstanceIds(instanceId);
        ec2Client.stopInstances(request);
        System.out.println("Stopping instance: " + instanceId);
    }

    public void createInstance(String amiId, String instanceType, int minCount, int maxCount) {
        RunInstancesRequest runInstancesRequest = new RunInstancesRequest()
                .withImageId(amiId)
                .withInstanceType(instanceType)
                .withMinCount(minCount)
                .withMaxCount(maxCount);

        RunInstancesResult result = ec2Client.runInstances(runInstancesRequest);
        Instance instance = result.getReservation().getInstances().get(0);
        System.out.println("Created instance with ID: " + instance.getInstanceId());
    }
}

