To create this application, you'll need to install libcurl and an HTML parser library. In this example, we will use Gumbo for parsing the HTML content.

1. Install libcurl:

```bash
sudo apt-get install libcurl4-openssl-dev
```

2. Install gumbo-parser:

```bash
sudo apt-get install libgumbo-dev
```

3. Create a new C++ file (main.cpp) and add the following code:

```cpp
#include <iostream>
#include <string>
#include <curl/curl.h>
#include <gumbo.h>

size_t WriteCallback(void* contents, size_t size, size_t nmemb, void* userp)
{
    ((std::string*)userp)->append((char*)contents, size * nmemb);
    return size * nmemb;
}

void search_for_links(GumboNode* node, std::vector<std::string>& links)
{
    if (node->type != GUMBO_NODE_ELEMENT)
        return;

    GumboAttribute* href = nullptr;
    if (node->v.element.tag == GUMBO_TAG_A &&
        (href = gumbo_get_attribute(&node->v.element.attributes, "href")))
    {
        links.push_back(href->value);
    }

    GumboVector* children = &node->v.element.children;
    for (unsigned int i = 0; i < children->length; ++i)
        search_for_links(static_cast<GumboNode*>(children->data[i]), links);
}

int main(int argc, char** argv)
{
    if (argc != 2)
    {
        std::cerr << "Usage: " << argv[0] << " <URL>" << std::endl;
        return 1;
    }

    CURL* curl = curl_easy_init();
    if (!curl)
    {
        std::cerr << "Failed to initialize curl" << std::endl;
        return 1;
    }

    std::string html_content;
    curl_easy_setopt(curl, CURLOPT_URL, argv[1]);
    curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, WriteCallback);
    curl_easy_setopt(curl, CURLOPT_WRITEDATA, &html_content);

    CURLcode res = curl_easy_perform(curl);
    if (res != CURLE_OK)
    {
        std::cerr << "Failed to download URL: " << curl_easy_strerror(res) << std::endl;
        curl_easy_cleanup(curl);
        return 1;
    }

    curl_easy_cleanup(curl);

    GumboOutput* output = gumbo_parse(html_content.c_str());
    std::vector<std::string> links;
    search_for_links(output->root, links);

    for (const auto& link : links)
        std::cout << link << std::endl;

    gumbo_destroy_output(&kGumboDefaultOptions, output);

    return 0;
}
```

