```java
import java.util.Scanner;

public class VendingMachine {
    private int[] productPrices = {100, 200, 300, 400, 500};
    private String[] productNames = {"Coke", "Pepsi", "Soda", "Tea", "Coffee"};
    private int credit;

    public void start() {
        Scanner scanner = new Scanner(System.in);
        while (true) {
            System.out.println("Please insert coins:");
            int coin = scanner.nextInt();
            this.credit += coin;
            System.out.println("You have inserted: " + this.credit);

            System.out.println("Available products:");
            for (int i = 0; i < productNames.length; i++) {
                System.out.println((i+1) + ". " + productNames[i] + ": " + productPrices[i]);
            }

            System.out.println("Please select a product:");
            int choice = scanner.nextInt();

            if (choice >= 1 && choice <= productNames.length) {
                if (this.credit >= productPrices[choice-1]) {
                    this.credit -= productPrices[choice-1];
                    System.out.println("You bought: " + productNames[choice-1]);
                    System.out.println("Your remaining credit is: " + this.credit);
                } else {
                    System.out.println("Not enough money to buy: " + productNames[choice-1]);
                }
            } else {
                System.out.println("Invalid selection");
            }

            System.out.println("Do you want to continue? (yes/no)");
            String cont = scanner.next();
            if (!cont.equalsIgnoreCase("yes")) {
                break;
            }
        }

        System.out.println("Your change is: " + this.credit);
        scanner.close();
    }

    public static void main(String[] args) {
        VendingMachine vm = new VendingMachine();
        vm.start();
    }
}
```

