package main

import (
	"fmt"
	"log"
	"net/http"

	"github.com/gorilla/websocket"
)

var clients = make(map[*websocket.Conn]bool) // Connected clients
var broadcast = make(chan Message)          // Broadcast channel for messages

// Upgrader to upgrade HTTP connection to WebSocket
var upgrader = websocket.Upgrader{
	CheckOrigin: func(r *http.Request) bool {
		return true
	},
}

// Message struct to hold the username and message content
type Message struct {
	Username string `json:"username"`
	Message  string `json:"message"`
}

func main() {
	fs := http.FileServer(http.Dir("public"))
	http.Handle("/", fs)

	http.HandleFunc("/ws", handleConnections)

	go handleMessages()

	log.Println("Listening on :8080...")
	err := http.ListenAndServe(":8080", nil)
	if err != nil {
		log.Fatal("ListenAndServe: ", err)
	}
}

// Handle WebSocket connections from clients
func handleConnections(w http.ResponseWriter, r *http.Request) {
	ws, err := upgrader.Upgrade(w, r, nil)
	if err != nil {
		log.Fatal(err)
	}
	defer ws.Close()

	clients[ws] = true

	for {
		var msg Message
		err := ws.ReadJSON(&msg)
		if err != nil {
			delete(clients, ws)
			break
		}

		broadcast <- msg
	}
}

// Handle incoming messages and broadcast them to all connected clients
func handleMessages() {
	for {
		msg := <-broadcast
		fmt.Printf("%s: %s\n", msg.Username, msg.Message)

		for client := range clients {
			err := client.WriteJSON(msg)
			if err != nil {
				log.Printf("Error: %v", err)
				client.Close()
				delete(clients, client)
			}
		}
	}
}

Here's a Java program that implements a singly linked list data structure with basic operations such as insertion, deletion, and traversal:

```java
public class SinglyLinkedList {
    // Node class to represent the elements in the linked list
    static class Node {
        int data;
        Node next;

        public Node(int data) {
            this.data = data;
            this.next = null;
        }
    }

    private Node head;

    public SinglyLinkedList() {
        head = null;
    }

    // Insert an element at the beginning of the list
    public void insertAtBeginning(int data) {
        Node newNode = new Node(data);
        newNode.next = head;
        head = newNode;
    }

    // Insert an element at the end of the list
    public void insertAtEnd(int data) {
        Node newNode = new Node(data);

        if (head == null) {
            head = newNode;
            return;
        }

        Node currentNode = head;
        while (currentNode.next != null) {
            currentNode = currentNode.next;
        }
        currentNode.next = newNode;
    }

    // Delete the first occurrence of an element from the list
    public void delete(int data) {
        if (head == null) {
            System.out.println("List is empty");
            return;
        }

        if (head.data == data) {
            head = head.next;
            return;
        }

        Node currentNode = head;
        while (currentNode.next != null && currentNode.next.data != data) {
            currentNode = currentNode.next;
        }

        if (currentNode.next != null) {
            currentNode.next = currentNode.next.next;
        } else {
            System.out.println("Element not found");
        }
    }

    // Traverse and print the elements in the list
    public void traverse() {
        Node currentNode = head;
        while (currentNode != null) {
            System.out.print(currentNode.data + " -> ");
            currentNode = currentNode.next;
        }
        System.out.println("null");
    }

    public static void main(String[] args) {
        SinglyLinkedList list = new SinglyLinkedList();

        // Insert elements
        list.insertAtBeginning(1);
        list.insertAtEnd(2);
        list.insertAtEnd(3);
        list.insertAtBeginning(0);

        // Traverse and print the list
        list.traverse(); // Output: 0 -> 1 -> 2 -> 3 -> null

        // Delete an element
        list.delete(1);

        // Traverse and print the updated list
        list.traverse(); // Output: 0 -> 2 -> 3 -> null
    }
}
```

This program defines a `SinglyLinkedList` class with basic operations such as insertion, deletion, and traversal. The `Node` class is used to represent the elements in the linked list. The `insertAtBeginning`, `insertAtEnd`, `delete`, and `traverse` methods are implemented for the required operations.

Here's a simple Java program that simulates a basic file system with support for creating, reading, updating, and deleting files and directories. The program implements commands like "mkdir", "touch", "rm", "cd", and "ls" using a command-line interface.

```java
import java.io.File;
import java.util.Scanner;

public class SimpleFileSystem {

    private static File currentDirectory = new File(System.getProperty("user.dir"));

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        String input;

        while (true) {
            System.out.print(currentDirectory.getAbsolutePath() + "> ");
            input = scanner.nextLine();
            processCommand(input);
        }
    }

    private static void processCommand(String input) {
        String[] tokens = input.split("\\s+");
        String command = tokens[0];

        switch (command) {
            case "mkdir":
                mkdir(tokens);
                break;
            case "touch":
                touch(tokens);
                break;
            case "rm":
                rm(tokens);
                break;
            case "cd":
                cd(tokens);
                break;
            case "ls":
                ls();
                break;
            case "exit":
                System.exit(0);
                break;
            default:
                System.out.println("Invalid command");
        }
    }

    private static void mkdir(String[] tokens) {
        if (tokens.length != 2) {
            System.out.println("Usage: mkdir <directory>");
            return;
        }

        File dir = new File(currentDirectory, tokens[1]);
        if (!dir.mkdir()) {
            System.out.println("Failed to create directory");
        }
    }

    private static void touch(String[] tokens) {
        if (tokens.length != 2) {
            System.out.println("Usage: touch <file>");
            return;
        }

        File file = new File(currentDirectory, tokens[1]);
        try {
            if (!file.createNewFile()) {
                System.out.println("Failed to create file");
            }
        } catch (Exception e) {
            System.out.println("Error: " + e.getMessage());
        }
    }

    private static void rm(String[] tokens) {
        if (tokens.length != 2) {
            System.out.println("Usage: rm <file/directory>");
            return;
        }

        File file = new File(currentDirectory, tokens[1]);
        if (!file.exists()) {
            System.out.println("No such file or directory");
            return;
        }

        deleteRecursively(file);
    }

    private static void deleteRecursively(File file) {
        if (file.isDirectory()) {
            for (File child : file.listFiles()) {
                deleteRecursively(child);
            }
        }

        if (!file.delete()) {
            System.out.println("Failed to delete " + file.getAbsolutePath());
        }
    }

    private static void cd(String[] tokens) {
        if (tokens.length != 2) {
            System.out.println("Usage: cd <directory>");
            return;
        }

        File dir = new File(currentDirectory, tokens[1]);
        if (!dir.exists() || !dir.isDirectory()) {
            System.out.println("No such directory");
            return;
        }

        currentDirectory = dir;
    }

    private static void ls() {
        File[] files = currentDirectory.listFiles();
        for (File file : files) {
            System.out.println(file.getName());
        }
    }
}
```

