// Function to convert the first letter of each word in a string to uppercase
function capitalizeFirstLetter(string) {
    // Split the input string into an array of words
    let words = string.split(' ');

    // Iterate over each word in the array
    for (let i = 0; i < words.length; i++) {
        // Capitalize the first letter of the current word, and add it back to the rest of the word
        words[i] = words[i].charAt(0).toUpperCase() + words[i].slice(1);
    }

    // Join the words back together into a single string, with spaces between them
    return words.join(' ');
}

import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import java.io.FileInputStream;
import java.io.FileOutputStream;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.security.NoSuchAlgorithmException;

public class FileEncryption {

    public static void main(String[] args) {
        try {
            // Generate a secret key for AES-256 encryption
            KeyGenerator keyGen = KeyGenerator.getInstance("AES");
            keyGen.init(256);
            SecretKey secretKey = keyGen.generateKey();

            // Encrypt a file
            String inputFile = "input.txt";
            String encryptedFile = "encrypted.aes";
            encryptFile(secretKey, inputFile, encryptedFile);

            // Decrypt the encrypted file
            String decryptedFile = "decrypted.txt";
            decryptFile(secretKey, encryptedFile, decryptedFile);

        } catch (NoSuchAlgorithmException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    private static void encryptFile(SecretKey secretKey, String inputFile, String outputFile) {
        processFile(Cipher.ENCRYPT_MODE, secretKey, inputFile, outputFile);
    }

    private static void decryptFile(SecretKey secretKey, String inputFile, String outputFile) {
        processFile(Cipher.DECRYPT_MODE, secretKey, inputFile, outputFile);
    }

    private static void processFile(int mode, SecretKey secretKey, String inputFile, String outputFile) {
        try {
            Cipher cipher = Cipher.getInstance("AES");
            cipher.init(mode, secretKey);

            byte[] inputBytes = Files.readAllBytes(Paths.get(inputFile));
            byte[] outputBytes = cipher.doFinal(inputBytes);

            try (FileOutputStream outputStream = new FileOutputStream(outputFile)) {
                outputStream.write(outputBytes);
            }

        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}

