Then, create a new file called `upload-download.js` and paste the following code into it:

```javascript
const { BlobServiceClient } = require('@azure/storage-blob');
const fs = require('fs');

// Replace with your own Azure Storage account connection string
const AZURE_STORAGE_CONNECTION_STRING = 'your_connection_string_here';

// Local file path to upload
const localFilePath = './local-file.txt';

// Container name in Azure Storage
const containerName = 'my-container';

// Name of the blob (file) in Azure Storage
const blobName = 'uploaded-file.txt';

// Name of the file to download from Azure Storage
const downloadFileName = 'downloaded-file.txt';

async function main() {
  const blobServiceClient = BlobServiceClient.fromConnectionString(AZURE_STORAGE_CONNECTION_STRING);

  // Create a container if it doesn't exist
  const containerClient = blobServiceClient.getContainerClient(containerName);
  await containerClient.createIfNotExists();

  // Upload the local file to Azure Storage
  const blockBlobClient = containerClient.getBlockBlobClient(blobName);
  const data = fs.readFileSync(localFilePath);
  await blockBlobClient.uploadData(data);

  console.log(`File "${localFilePath}" uploaded as "${blobName}"`);

  // List all files in the container
  console.log('\nListing blobs...');
  for await (const blob of containerClient.listBlobsFlat()) {
    console.log(` - ${blob.name}`);
  }

  // Download a specific file by name
  const downloadBlockBlobClient = containerClient.getBlockBlobClient(downloadFileName);
  const response = await downloadBlockBlobClient.download(0);
  const downloadedContent = (await streamToBuffer(response.readableStreamBody)).toString();
  fs.writeFileSync(`./${downloadFileName}`, downloadedContent);

  console.log(`\nFile "${downloadFileName}" downloaded successfully`);
}

async function streamToBuffer(readableStream) {
  return new Promise((resolve, reject) => {
    const chunks = [];
    readableStream.on('data', (data) => {
      chunks.push(data instanceof Buffer ? data : Buffer.from(data));
    });
    readableStream.on('end', () => {
      resolve(Buffer.concat(chunks));
    });
    readableStream.on('error', reject);
  });
}

main().catch((err) => {
  console.error('Error running the script:', err.message);
});
```

Replace `'your_connection_string_here'` with your Azure Storage account connection string. Update `localFilePath`, `containerName`, `blobName`, and `downloadFileName` as needed.

Run the script using:

```bash
node upload-download.js
```

