import (
	"context"
	"encoding/csv"
	"flag"
	"fmt"
	"log"
	"os"

	"github.com/Azure/azure-sdk-for-go/sdk/data/azcosmos"
)

var connectionString = flag.String("connection", "", "Cosmos DB connection string")
var dbName = flag.String("db", "", "Database name")
var collName = flag.String("collection", "", "Collection name")

func main() {
	flag.Parse()

	if *connectionString == "" || *dbName == "" || *collName == "" {
		log.Fatal("Please provide all required flags: -connection, -db, and -collection.")
	}

	client, err := azcosmos.NewClient(*connectionString)
	if err != nil {
		log.Fatalf("Failed to create client: %v", err)
	}

	database := client.Database(*dbName)
	container := database.Container(*collName)

	query := fmt.Sprintf(`SELECT * FROM c`)
	options := &azcosmos.QueryRequestOptions{}
	iter, err := container.Items().Query(context.Background(), azcosmos.SqlQuery{QueryText: query}, options)
	if err != nil {
		log.Fatalf("Failed to execute query: %v", err)
	}

	file, err := os.Create("output.csv")
	if err != nil {
		log.Fatalf("Failed to create output file: %v", err)
	}
	defer file.Close()

	writer := csv.NewWriter(file)
	defer writer.Flush()

	for iter.HasMoreResults() {
		response, err := iter.Next()
		if err != nil {
			log.Fatalf("Failed to fetch results: %v", err)
		}

		for _, item := range response.Items {
			var record map[string]interface{}
			err = item.To(&record)
			if err != nil {
				log.Fatalf("Failed to deserialize item: %v", err)
			}

			row := make([]string, 0, len(record))
			for _, value := range record {
				row = append(row, fmt.Sprintf("%v", value))
			}
			writer.Write(row)
		}
	}

	fmt.Println("Data exported to output.csv")
}

