package atm;

import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;

public class Bank {
    private Connection connection;

    public Bank(String databaseURL, String username, String password) throws SQLException {
        try {
            Class.forName("com.mysql.cj.jdbc.Driver");
            connection = DriverManager.getConnection(databaseURL, username, password);
        } catch (ClassNotFoundException e) {
            throw new SQLException("MySQL driver not found", e);
        }
    }

    public void close() throws SQLException {
        if (connection != null && !connection.isClosed()) {
            connection.close();
        }
    }

    public boolean deposit(int accountId, double amount) throws SQLException {
        String query = "UPDATE accounts SET balance = balance + ? WHERE id = ?";
        PreparedStatement statement = connection.prepareStatement(query);
        statement.setDouble(1, amount);
        statement.setInt(2, accountId);

        int rowsAffected = statement.executeUpdate();
        return rowsAffected > 0;
    }

    public boolean withdraw(int accountId, double amount) throws SQLException {
        String query = "UPDATE accounts SET balance = balance - ? WHERE id = ?";
        PreparedStatement statement = connection.prepareStatement(query);
        statement.setDouble(1, amount);
        statement.setInt(2, accountId);

        int rowsAffected = statement.executeUpdate();
        return rowsAffected > 0;
    }

    public double getBalance(int accountId) throws SQLException {
        String query = "SELECT balance FROM accounts WHERE id = ?";
        PreparedStatement statement = connection.prepareStatement(query);
        statement.setInt(1, accountId);

        ResultSet resultSet = statement.executeQuery();
        if (resultSet.next()) {
            return resultSet.getDouble("balance");
        } else {
            throw new SQLException("Account not found");
        }
    }
}

