}

func fahrenheitToKelvin(f float64) float64 {
	return celsiusToKelvin(fahrenheitToCelsius(f))
}

func kelvinToCelsius(k float64) float64 {
	return k - 273.15
}

func kelvinToFahrenheit(k float64) float64 {
	return celsiusToFahrenheit(kelvinToCelsius(k))
}

func main() {
	if len(os.Args) != 3 {
		fmt.Println("Usage: go run temp_converter.go <temperature> <unit>")
		os.Exit(1)
	}

	temp, err := strconv.ParseFloat(os.Args[1], 64)
	if err != nil {
		fmt.Println("Invalid temperature value")
		os.Exit(1)
	}

	unit := os.Args[2]

	switch unit {
	case "C", "c":
		fmt.Printf("%.2f°C = %.2f°F = %.2fK\n", temp, celsiusToFahrenheit(temp), celsiusToKelvin(temp))
	case "F", "f":
		fmt.Printf("%.2f°F = %.2f°C = %.2fK\n", temp, fahrenheitToCelsius(temp), fahrenheitToKelvin(temp))
	case "K", "k":
		fmt.Printf("%.2fK = %.2f°C = %.2f°F\n", temp, kelvinToCelsius(temp), kelvinToFahrenheit(temp))
	default:
		fmt.Println("Invalid temperature unit. Use C, F or K.")
		os.Exit(1)
	}
}
