package main

import (
	"fmt"
	"io/ioutil"
	"net/http"
	"net/url"
	"os"
	"strings"

	"golang.org/x/net/html"
)

func main() {
	if len(os.Args) != 2 {
		fmt.Println("Usage: go run main.go <URL>")
		os.Exit(1)
	}

	inputURL := os.Args[1]

	resp, err := http.Get(inputURL)
	if err != nil {
		fmt.Printf("Error fetching URL: %v\n", err)
		os.Exit(1)
	}
	defer resp.Body.Close()

	pageContent, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		fmt.Printf("Error reading response body: %v\n", err)
		os.Exit(1)
	}

	links := extractLinks(string(pageContent), inputURL)

	err = writeLinksToFile(links, "output.txt")
	if err != nil {
		fmt.Printf("Error writing links to file: %v\n", err)
		os.Exit(1)
	}

	fmt.Println("Links successfully extracted and saved to output.txt.")
}

func extractLinks(content string, baseURL string) []string {
	var links []string
	tokenizer := html.NewTokenizer(strings.NewReader(content))

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			return links
		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()
			if token.Data == "a" {
				for _, attr := range token.Attr {
					if attr.Key == "href" {
						link := resolveLink(attr.Val, baseURL)
						links = append(links, link)
						break
					}
				}
			}
		}
	}
}

func resolveLink(link string, baseURL string) string {
	if strings.HasPrefix(link, "http://") || strings.HasPrefix(link, "https://") {
		return link
	}

	base, err := url.Parse(baseURL)
	if err != nil {
		return ""
	}

	resolvedLink := base.ResolveReference(&url.URL{Path: link})
	return resolvedLink.String()
}

func writeLinksToFile(links []string, filename string) error {
	file, err := os.Create(filename)
	if err != nil {
		return err
	}
	defer file.Close()

	for _, link := range links {
		_, err = file.WriteString(link + "\n")
		if err != nil {
			return err
		}
	}

	return nil
}

Here's an implementation of a binary search tree in JavaScript, including insertion, deletion, and traversal methods (in-order, pre-order, post-order):

```javascript
class Node {
  constructor(data) {
    this.data = data;
    this.left = null;
    this.right = null;
  }
}

class BinarySearchTree {
  constructor() {
    this.root = null;
  }

  insert(data) {
    const newNode = new Node(data);

    if (!this.root) {
      this.root = newNode;
    } else {
      this.insertNode(this.root, newNode);
    }
  }

  insertNode(node, newNode) {
    if (newNode.data < node.data) {
      if (!node.left) {
        node.left = newNode;
      } else {
        this.insertNode(node.left, newNode);
      }
    } else {
      if (!node.right) {
        node.right = newNode;
      } else {
        this.insertNode(node.right, newNode);
      }
    }
  }

  remove(data) {
    this.root = this.removeNode(this.root, data);
  }

  removeNode(node, key) {
    if (!node) {
      return null;
    }

    if (key < node.data) {
      node.left = this.removeNode(node.left, key);
      return node;
    } else if (key > node.data) {
      node.right = this.removeNode(node.right, key);
      return node;
    } else {
      if (!node.left && !node.right) {
        return null;
      }

      if (!node.left) {
        return node.right;
      } else if (!node.right) {
        return node.left;
      }

      node.data = this.findMinNode(node.right).data;
      node.right = this.removeNode(node.right, node.data);
      return node;
    }
  }

  findMinNode(node) {
    if (!node.left) {
      return node;
    } else {
      return this.findMinNode(node.left);
    }
  }

  inOrderTraverse(callback) {
    this.inOrderTraverseNode(this.root, callback);
  }

  inOrderTraverseNode(node, callback) {
    if (node) {
      this.inOrderTraverseNode(node.left, callback);
      callback(node.data);
      this.inOrderTraverseNode(node.right, callback);
    }
  }

  preOrderTraverse(callback) {
    this.preOrderTraverseNode(this.root, callback);
  }

  preOrderTraverseNode(node, callback) {
    if (node) {
      callback(node.data);
      this.preOrderTraverseNode(node.left, callback);
      this.preOrderTraverseNode(node.right, callback);
    }
  }

  postOrderTraverse(callback) {
    this.postOrderTraverseNode(this.root, callback);
  }

  postOrderTraverseNode(node, callback) {
    if (node) {
      this.postOrderTraverseNode(node.left, callback);
      this.postOrderTraverseNode(node.right, callback);
      callback(node.data);
    }
  }
}

// Example usage:
const bst = new BinarySearchTree();
bst.insert(15);
bst.insert(25);
bst.insert(10);
bst.insert(7);
bst.insert(22);
bst.insert(17);
bst.insert(13);
bst.insert(5);
bst.insert(9);
bst.insert(27);

console.log("In-order traversal:");
bst.inOrderTraverse((data) => console.log(data));

console.log("Pre-order traversal:");
bst.preOrderTraverse((data) => console.log(data));

console.log("Post-order traversal:");
bst.postOrderTraverse((data) => console.log(data));

bst.remove(5);
console.log("In-order traversal after removing 5:");
bst.inOrderTraverse((data) => console.log(data));
```

This implementation includes a `Node` class to represent the nodes in the tree and a `BinarySearchTree` class that contains methods for inserting, deleting, and traversing the tree. The traversal methods use callbacks to process the visited nodes.

Here's a simple Java HTTP server that supports GET and POST requests, serves static files from a specified directory, and has an endpoint for uploading files using their MD5 hash as the filename. The server can be configured via command line arguments for port number, IP address, and the static file directory.

```java
import java.io.*;
import java.net.InetSocketAddress;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.security.MessageDigest;
import java.util.List;
import com.sun.net.httpserver.*;

public class SimpleHttpServer {

    private static String ipAddress;
    private static int port;
    private static String staticFileDirectory;

    public static void main(String[] args) throws Exception {
        if (args.length != 3) {
            System.out.println("Usage: java SimpleHttpServer <IP Address> <Port Number> <Static File Directory>");
            return;
        }

        ipAddress = args[0];
        port = Integer.parseInt(args[1]);
        staticFileDirectory = args[2];

        HttpServer server = HttpServer.create(new InetSocketAddress(ipAddress, port), 0);
        server.createContext("/", new RootHandler());
        server.createContext("/upload", new UploadHandler());
        server.setExecutor(null); // creates a default executor
        server.start();
        System.out.println("Server started on " + ipAddress + ":" + port);
    }

    static class RootHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            String requestMethod = exchange.getRequestMethod();

            if (requestMethod.equalsIgnoreCase("GET")) {
                Path filePath = Paths.get(staticFileDirectory, exchange.getRequestURI().getPath());
                if (Files.exists(filePath)) {
                    byte[] fileContent = Files.readAllBytes(filePath);
                    exchange.sendResponseHeaders(200, fileContent.length);
                    OutputStream os = exchange.getResponseBody();
                    os.write(fileContent);
                    os.close();
                } else {
                    String response = "File not found.";
                    exchange.sendResponseHeaders(404, response.length());
                    OutputStream os = exchange.getResponseBody();
                    os.write(response.getBytes());
                    os.close();
                }
            } else if (requestMethod.equalsIgnoreCase("POST")) {
                // Handle POST requests here
            }
        }
    }

    static class UploadHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if (!exchange.getRequestMethod().equalsIgnoreCase("POST")) {
                String response = "Invalid request method. Use POST to upload files.";
                exchange.sendResponseHeaders(405, response.length());
                OutputStream os = exchange.getResponseBody();
                os.write(response.getBytes());
                os.close();
                return;
            }

            InputStream is = exchange.getRequestBody();
            byte[] fileBytes = is.readAllBytes();
            is.close();

            MessageDigest md = MessageDigest.getInstance("MD5");
            byte[] md5Hash = md.digest(fileBytes);

            StringBuilder sb = new StringBuilder();
            for (byte b : md5Hash) {
                sb.append(String.format("%02x", b));
            }
            String fileName = sb.toString();

            Path filePath = Paths.get(staticFileDirectory, fileName);
            Files.write(filePath, fileBytes);

            String response = "File uploaded successfully: " + fileName;
            exchange.sendResponseHeaders(200, response.length());
            OutputStream os = exchange.getResponseBody();
            os.write(response.getBytes());
            os.close();
        }
    }
}
```

To compile and run the server, save the code in a file named `SimpleHttpServer.java` and execute the following commands:

```bash
