#include <iostream>
#include <ctime>
#include <vector>
#include <string>
#include <sstream>
#include <iomanip>
#include <openssl/sha.h>

class Transaction {
public:
    std::string sender;
    std::string receiver;
    double amount;

    Transaction(const std::string& sender, const std::string& receiver, double amount)
        : sender(sender), receiver(receiver), amount(amount) {}
};

class Block {
public:
    int index;
    time_t timestamp;
    std::vector<Transaction> transactions;
    std::string prevHash;
    int nonce;
    std::string hash;

    Block(int index, const std::vector<Transaction>& transactions, const std::string& prevHash)
        : index(index), transactions(transactions), prevHash(prevHash), nonce(0) {
        timestamp = std::time(nullptr);
        hash = calculateHash();
    }

    std::string calculateHash() const {
        std::stringstream ss;
        ss << index << timestamp << transactionString() << prevHash << nonce;
        return sha256(ss.str());
    }

    void mineBlock(int difficulty) {
        std::string target(difficulty, '0');
        while (hash.substr(0, difficulty) != target) {
            nonce++;
            hash = calculateHash();
        }
        std::cout << "Block mined: " << hash << std::endl;
    }

private:
    std::string transactionString() const {
        std::stringstream ss;
        for (const auto& tx : transactions) {
            ss << tx.sender << tx.receiver << tx.amount;
        }
        return ss.str();
    }

    static std::string sha256(const std::string& data) {
        unsigned char digest[SHA256_DIGEST_LENGTH];
        SHA256_CTX ctx;
        SHA256_Init(&ctx);
        SHA256_Update(&ctx, data.c_str(), data.size());
        SHA256_Final(digest, &ctx);

        std::stringstream ss;
        for (int i = 0; i < SHA256_DIGEST_LENGTH; ++i) {
            ss << std::hex << std::setw(2) << std::setfill('0') << static_cast<int>(digest[i]);
        }
        return ss.str();
    }
};

class Blockchain {
public:
    int difficulty;

    Blockchain(int difficulty) : difficulty(difficulty) {
        blocks.push_back(createGenesisBlock());
    }

    void addTransaction(const Transaction& transaction) {
        pendingTransactions.push_back(transaction);
    }

    void minePendingTransactions() {
        Block newBlock(blocks.size(), pendingTransactions, getLastBlock().hash);
        newBlock.mineBlock(difficulty);
        blocks.push_back(newBlock);
        pendingTransactions.clear();
    }

    bool isChainValid() const {
        for (size_t i = 1; i < blocks.size(); ++i) {
            const auto& currentBlock = blocks[i];
            const auto& prevBlock = blocks[i - 1];

            if (currentBlock.hash != currentBlock.calculateHash()) {
                return false;
            }

            if (currentBlock.prevHash != prevBlock.hash) {
                return false;
            }
        }
        return true;
    }

private:
    std::vector<Block> blocks;
    std::vector<Transaction> pendingTransactions;

    Block createGenesisBlock() {
        std::vector<Transaction> genesisTransactions;
        genesisTransactions.emplace_back("genesis", "user1", 100);
        return Block(0, genesisTransactions, "0");
    }

    const Block& getLastBlock() const {
        return blocks.back();
    }
};

