package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"os"
	"strings"
	"text/tabwriter"
)

type Person struct {
	Name string `json:"name"`
	Age  int    `json:"age"`
	City string `json:"city"`
}

func main() {
	fileName := "data.json"

	data, err := ioutil.ReadFile(fileName)
	if err != nil {
		fmt.Println("Error reading file:", err)
		return
	}

	var people []Person
	err = json.Unmarshal(data, &people)
	if err != nil {
		fmt.Println("Error unmarshalling data:", err)
		return
	}

	minAge := 20
	maxAge := 30
	cityFilter := "New York"

	filteredPeople := filter(people, minAge, maxAge, cityFilter)

	printTable(filteredPeople)
}

func filter(people []Person, minAge, maxAge int, cityFilter string) []Person {
	var result []Person
	for _, person := range people {
		if person.Age >= minAge && person.Age <= maxAge && strings.EqualFold(person.City, cityFilter) {
			result = append(result, person)
		}
	}
	return result
}

func printTable(people []Person) {
	w := new(tabwriter.Writer)
	w.Init(os.Stdout, 0, 8, 2, '\t', 0)
	fmt.Fprintln(w, "Name\tAge\tCity")
	fmt.Fprintln(w, "----\t---\t----")

	for _, person := range people {
		fmt.Fprintf(w, "%s\t%d\t%s\n", person.Name, person.Age, person.City)
	}

	w.Flush()
}

#include <iostream>
#include <unordered_map>

class TrieNode {
public:
    char value;
    bool isEndOfWord;
    std::unordered_map<char, TrieNode*> children;

    TrieNode(char ch) : value(ch), isEndOfWord(false) {}
};

class Trie {
private:
    TrieNode* root;

    void deleteHelper(TrieNode* node) {
        for (auto it = node->children.begin(); it != node->children.end(); ++it) {
            deleteHelper(it->second);
        }
        delete node;
    }

public:
    Trie() {
        root = new TrieNode('\0');
    }

    ~Trie() {
        deleteHelper(root);
    }

    void insert(const std::string& word) {
        TrieNode* currentNode = root;
        for (char ch : word) {
            if (currentNode->children.find(ch) == currentNode->children.end()) {
                currentNode->children[ch] = new TrieNode(ch);
            }
            currentNode = currentNode->children[ch];
        }
        currentNode->isEndOfWord = true;
    }

    bool search(const std::string& word) {
        TrieNode* currentNode = root;
        for (char ch : word) {
            if (currentNode->children.find(ch) == currentNode->children.end()) {
                return false;
            }
            currentNode = currentNode->children[ch];
        }
        return currentNode->isEndOfWord;
    }

    bool deleteWord(const std::string& word) {
        return deleteWordHelper(root, word, 0);
    }

    bool deleteWordHelper(TrieNode* currentNode, const std::string& word, int index) {
        if (index == word.size()) {
            if (!currentNode->isEndOfWord) {
                return false;
            }
            currentNode->isEndOfWord = false;
            return currentNode->children.empty();
        }

        char ch = word[index];
        if (currentNode->children.find(ch) == currentNode->children.end()) {
            return false;
        }

        bool shouldDeleteCurrentNode = deleteWordHelper(currentNode->children[ch], word, index + 1);

        if (shouldDeleteCurrentNode) {
            delete currentNode->children[ch];
            currentNode->children.erase(ch);
            return !currentNode->isEndOfWord && currentNode->children.empty();
        }

        return false;
    }
};

int main() {
    Trie trie;

    trie.insert("hello");
    trie.insert("world");

    std::cout << "Searching for 'hello': " << trie.search("hello") << std::endl; // Output: 1
    std::cout << "Searching for 'world': " << trie.search("world") << std::endl; // Output: 1

    trie.deleteWord("hello");
    std::cout << "Searching for 'hello' after deletion: " << trie.search("hello") << std::endl; // Output: 0

    return 0;
}

