    private List<Weather> weather;

    public Main getMain() {
        return main;
    }

    public void setMain(Main main) {
        this.main = main;
    }

    public List<Weather> getWeather() {
        return weather;
    }

    public void setWeather(List<Weather> weather) {
        this.weather = weather;
    }

    public static class Main {
        private double temp;
        private int humidity;

        public double getTemp() {
            return temp;
        }

        public void setTemp(double temp) {
            this.temp = temp;
        }

        public int getHumidity() {
            return humidity;
        }

        public void setHumidity(int humidity) {
            this.humidity = humidity;
        }
    }

    public static class Weather {
        private String description;

        public String getDescription() {
            return description;
        }

        public void setDescription(String description) {
            this.description = description;
        }
    }

    public static class WeatherApiClient {

        private static final String API_KEY = "your_api_key_here";
        private static final String BASE_URL = "https://api.openweathermap.org/data/2.5/weather?q=%s&appid=%s&units=metric";

        private OkHttpClient client;
        private Gson gson;

        public WeatherApiClient() {
            this.client = new OkHttpClient();
            this.gson = new Gson();
        }

        public WeatherData getWeatherData(String city) throws IOException {
            String url = String.format(BASE_URL, city, API_KEY);
            Request request = new Request.Builder().url(url).build();

            try (Response response = client.newCall(request).execute()) {
                if (!response.isSuccessful()) {
                    throw new IOException("Unexpected code " + response);
                }
                String responseBody = response.body().string();
                return gson.fromJson(responseBody, WeatherData.class);
            }
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a city name: ");
        String city = scanner.nextLine();

        WeatherApiClient apiClient = new WeatherApiClient();
        try {
            WeatherData weatherData = apiClient.getWeatherData(city);

            double temperature = weatherData.getMain().getTemp();
            int humidity = weatherData.getMain().getHumidity();
            String description = weatherData.getWeather().get(0).getDescription();

            System.out.printf("Current weather in %s:%n", city);
            System.out.printf("Temperature: %.2f°C%n", temperature);
            System.out.printf("Humidity: %d%%%n", humidity);
            System.out.printf("Description: %s%n", description);

        } catch (IOException e) {
            System.err.println("Error fetching weather data: " + e.getMessage());
        }
    }
}

