To design a chat application using Node.js and Socket.IO, follow these steps:

1. Install the required packages

First, you need to install Node.js on your system if it's not already installed. Then create a new directory for your project and navigate to it in your terminal or command prompt.

Next, initialize a new Node.js project by running `npm init -y`. This will create a package.json file with default settings.

Now, install Express and Socket.IO by running:
```
npm install express socket.io
```

2. Create the server-side code

Create a new file called "server.js" in your project directory and add the following code:

```javascript
const express = require('express');
const app = express();
const http = require('http').createServer(app);
const io = require('socket.io')(http);

app.use(express.static('public'));

io.on('connection', (socket) => {
  console.log('a user connected');

  socket.on('disconnect', () => {
    console.log('user disconnected');
  });

  socket.on('chat message', (msg) => {
    io.emit('chat message', msg);
  });
});

http.listen(3000, () => {
  console.log('listening on *:3000');
});
```

This code sets up an Express server that serves static files from a "public" folder and listens for incoming connections on port 3000. It also initializes Socket.IO and listens for 'connection' events, as well as 'chat message' events sent by clients.

3. Create the client-side code

Create a new folder named "public" in your project directory. Inside this folder, create two files: "index.html" and "client.js".

Add the following code to "index.html":

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Chat App</title>
  <style>
    /* Add your custom styles here */
  </style>
</head>
<body>
  <ul id="messages"></ul>
  <form action="">
    <input id="message-input" autocomplete="off" autofocus /><button>Send</button>
  </form>
  <script src="/socket.io/socket.io.js"></script>
  <script src="client.js"></script>
</body>
</html>
```

Now add the following code to "client.js":

```javascript
const socket = io();
const messageForm = document.querySelector('form');
const messageInput = document.getElementById('message-input');
const messagesList = document.getElementById('messages');

let messageHistory = [];

socket.on('chat message', (msg) => {
  const li = document.createElement('li');
  li.textContent = msg;
  messagesList.appendChild(li);

  // Update message history and keep only the last 10 messages
  messageHistory.push(msg);
  if (messageHistory.length > 10) {
    messageHistory.shift();
    messagesList.removeChild(messagesList.firstChild);
  }
});

messageForm.addEventListener('submit', (e) => {
  e.preventDefault();
  if (messageInput.value) {
    socket.emit('chat message', messageInput.value);
    messageInput.value = '';
  }
});
```

This code connects to the Socket.IO server, listens for incoming 'chat message' events, and updates the DOM with new messages. It also sends chat messages from the user when they submit the form.

4. Start the server

To start the server, run the following command in your terminal or command prompt:

```
node server.js
```

5. Test the application

Open your browser and navigate to http://localhost:3000. You should see the chat application interface. Open another browser window or tab and navigate to the same URL to test real-time communication between multiple users.

That's it! You now have a basic chat application using Node.js and Socket.IO that allows multiple users to connect and send messages in real-time while maintaining a history of the last 10 messages sent.

To implement a simple REST API in Node.js using Express that supports CRUD operations on a collection of books, follow these steps:

1. Install the required packages:
```
npm init -y
npm install express body-parser
```

2. Create an `index.js` file and add the following code to set up the server and basic routes:

```javascript
const express = require('express');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.json());

// In-memory storage for books
let books = [];

// GET all books
app.get('/books', (req, res) => {
  const { author, title } = req.query;

  let filteredBooks = books;

  if (author) {
    filteredBooks = filteredBooks.filter(book => book.author === author);
  }

  if (title) {
    filteredBooks = filteredBooks.filter(book => book.title.includes(title));
  }

  res.send(filteredBooks);
});

// POST a new book
app.post('/books', (req, res) => {
  const { title, author, publicationYear, isbn } = req.body;
  const newBook = { title, author, publicationYear, isbn };
  books.push(newBook);
  res.status(201).send(newBook);
});

// GET a single book by ISBN
app.get('/books/:isbn', (req, res) => {
  const { isbn } = req.params;
  const book = books.find(b => b.isbn === isbn);

  if (!book) {
    return res.status(404).send({ message: 'Book not found' });
  }

  res.send(book);
});

// PUT update a book by ISBN
app.put('/books/:isbn', (req, res) => {
  const { isbn } = req.params;
  const index = books.findIndex(b => b.isbn === isbn);

  if (index === -1) {
    return res.status(404).send({ message: 'Book not found' });
  }

  const updatedBook = { ...books[index], ...req.body };
  books[index] = updatedBook;
  res.send(updatedBook);
});

// DELETE a book by ISBN
app.delete('/books/:isbn', (req, res) => {
  const { isbn } = req.params;
  const index = books.findIndex(b => b.isbn === isbn);

  if (index === -1) {
    return res.status(404).send({ message: 'Book not found' });
  }

  books.splice(index, 1);
  res.status(204).send();
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```

