    private static void calculateAverageSalaries(Connection connection) throws SQLException {
        String query = "SELECT department, AVG(salary) as avg_salary FROM employees GROUP BY department";

        try (Statement statement = connection.createStatement()) {
            ResultSet resultSet = statement.executeQuery(query);

            while (resultSet.next()) {
                String department = resultSet.getString("department");
                double avgSalary = resultSet.getDouble("avg_salary");

                System.out.printf("Department: %s, Average Salary: %.2f%n", department, avgSalary);
            }
        } catch (SQLException e) {
            System.err.println("Error executing the query");
            e.printStackTrace();
        }
    }
}

