Here's a simple Java program that interacts with a MariaDB database to manage an inventory system. Make sure you have the MariaDB JDBC connector added as a dependency in your project.

```java
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.util.Scanner;

public class InventorySystem {
    private static final String DB_URL = "jdbc:mariadb://localhost:3306/inventory";
    private static final String DB_USER = "root";
    private static final String DB_PASSWORD = "your_password";

    public static void main(String[] args) {
        try (Connection connection = DriverManager.getConnection(DB_URL, DB_USER, DB_PASSWORD)) {
            createTableIfNotExists(connection);

            Scanner scanner = new Scanner(System.in);
            boolean exit = false;

            while (!exit) {
                System.out.println("Choose an option:");
                System.out.println("1. Add item");
                System.out.println("2. Update item quantity");
                System.out.println("3. Delete item");
                System.out.println("4. View inventory");
                System.out.println("5. Exit");

                int choice = scanner.nextInt();
                scanner.nextLine();

                switch (choice) {
                    case 1:
                        addItem(scanner, connection);
                        break;
                    case 2:
                        updateItemQuantity(scanner, connection);
                        break;
                    case 3:
                        deleteItem(scanner, connection);
                        break;
                    case 4:
                        viewInventory(connection);
                        break;
                    case 5:
                        exit = true;
                        break;
                    default:
                        System.out.println("Invalid option.");
                }
            }

            scanner.close();
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    private static void createTableIfNotExists(Connection connection) throws SQLException {
        String sql = "CREATE TABLE IF NOT EXISTS items (" +
                "id INT AUTO_INCREMENT PRIMARY KEY," +
                "name VARCHAR(255) NOT NULL," +
                "quantity INT NOT NULL" +
                ")";
        try (PreparedStatement statement = connection.prepareStatement(sql)) {
            statement.execute();
        }
    }

    private static void addItem(Scanner scanner, Connection connection) throws SQLException {
        System.out.print("Enter item name: ");
        String name = scanner.nextLine();

        System.out.print("Enter item quantity: ");
        int quantity = scanner.nextInt();
        scanner.nextLine();

        String sql = "INSERT INTO items (name, quantity) VALUES (?, ?)";
        try (PreparedStatement statement = connection.prepareStatement(sql)) {
            statement.setString(1, name);
            statement.setInt(2, quantity);
            statement.executeUpdate();
        }

        System.out.println("Item added.");
    }

    private static void updateItemQuantity(Scanner scanner, Connection connection) throws SQLException {
        System.out.print("Enter item ID: ");
        int id = scanner.nextInt();

        System.out.print("Enter new item quantity: ");
        int quantity = scanner.nextInt();
        scanner.nextLine();

        String sql = "UPDATE items SET quantity = ? WHERE id = ?";
        try (PreparedStatement statement = connection.prepareStatement(sql)) {
            statement.setInt(1, quantity);
            statement.setInt(2, id);
            int rowsAffected = statement.executeUpdate();

            if (rowsAffected > 0) {
                System.out.println("Item quantity updated.");
            } else {
                System.out.println("Item not found.");
            }
        }
    }

    private static void deleteItem(Scanner scanner, Connection connection) throws SQLException {
        System.out.print("Enter item ID: ");
        int id = scanner.nextInt();
        scanner.nextLine();

        String sql = "DELETE FROM items WHERE id = ?";
        try (PreparedStatement statement = connection.prepareStatement(sql)) {
            statement.setInt(1, id);
            int rowsAffected = statement.executeUpdate();

            if (rowsAffected > 0) {
                System.out.println("Item deleted.");
            } else {
                System.out.println("Item not found.");
            }
        }
    }

    private static void viewInventory(Connection connection) throws SQLException {
        String sql = "SELECT * FROM items";
        try (PreparedStatement statement = connection.prepareStatement(sql);
             ResultSet resultSet = statement.executeQuery()) {

            System.out.println("ID\tName\tQuantity");
            while (resultSet.next()) {
                int id = resultSet.getInt("id");
                String name = resultSet.getString("name");
                int quantity = resultSet.getInt("quantity");

                System.out.printf("%d\t%s\t%d%n", id, name, quantity);
            }
        }
    }
}
```

Before running the program, make sure to replace `your_password` with your MariaDB root password. Also, create a database named `inventory` in your MariaDB server.

