Here's a Golang program that reads a JSON file containing an array of objects with properties "name", "age", and "city". The program filters the objects based on a given age range and city, and then prints the filtered results in a tabular format.

```go
package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"os"
	"strings"
	"text/tabwriter"
)

type Person struct {
	Name string `json:"name"`
	Age  int    `json:"age"`
	City string `json:"city"`
}

func main() {
	fileName := "data.json"

	data, err := ioutil.ReadFile(fileName)
	if err != nil {
		fmt.Println("Error reading file:", err)
		return
	}

	var people []Person
	err = json.Unmarshal(data, &people)
	if err != nil {
		fmt.Println("Error unmarshalling data:", err)
		return
	}

	minAge := 20
	maxAge := 30
	cityFilter := "New York"

	filteredPeople := filter(people, minAge, maxAge, cityFilter)

	printTable(filteredPeople)
}

func filter(people []Person, minAge, maxAge int, cityFilter string) []Person {
	var result []Person
	for _, person := range people {
		if person.Age >= minAge && person.Age <= maxAge && strings.EqualFold(person.City, cityFilter) {
			result = append(result, person)
		}
	}
	return result
}

func printTable(people []Person) {
	w := new(tabwriter.Writer)
	w.Init(os.Stdout, 0, 8, 2, '\t', 0)
	fmt.Fprintln(w, "Name\tAge\tCity")
	fmt.Fprintln(w, "----\t---\t----")

	for _, person := range people {
		fmt.Fprintf(w, "%s\t%d\t%s\n", person.Name, person.Age, person.City)
	}

	w.Flush()
}
```

