func main() {
	dir := flag.String("dir", ".", "Directory to watch")
	logFile := flag.String("log", "monitor.log", "Log file path")

	flag.Parse()

	watcher, err := fsnotify.NewWatcher()
	if err != nil {
		log.Fatal(err)
	}
	defer watcher.Close()

	done := make(chan bool)
	go func() {
		for {
			select {
			case event, ok := <-watcher.Events:
				if !ok {
					return
				}

				f, err := os.OpenFile(*logFile, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
				if err != nil {
					log.Fatal(err)
				}

				msg := fmt.Sprintf("%s: %s\n", event.Name, event.Op.String())
				if _, err = f.WriteString(msg); err != nil {
					log.Fatal(err)
				}
				f.Close()

			case err, ok := <-watcher.Errors:
				if !ok {
					return
				}
				log.Println("error:", err)
			}
		}
	}()

	err = watcher.Add(*dir)
	if err != nil {
		log.Fatal(err)
	}
	<-done
}

function reverseEverySecondChar(str) {
    // Split the string into an array of characters
    let arr = str.split('');

    // Iterate over every second character in the array
    for(let i = 1; i < arr.length; i += 2){
        // Reverse the character by converting it to a unicode value, subtracting it from the sum of 'z' and 'a', then converting it back to a character
        arr[i] = String.fromCharCode('z'.charCodeAt(0) + 'a'.charCodeAt(0) - arr[i].charCodeAt(0));
    }

    // Join the array back into a string and return it
    return arr.join('');
}

