Here's a Java program that reads a CSV file containing information about employees and calculates the average salary per department. The program handles exceptions such as missing or incorrect data.

```java
import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.util.HashMap;
import java.util.Map;

public class EmployeeSalary {

    public static void main(String[] args) {
        String csvFile = "employees.csv";
        String line;
        String separator = ",";
        Map<String, Department> departments = new HashMap<>();

        try (BufferedReader br = new BufferedReader(new FileReader(csvFile))) {
            while ((line = br.readLine()) != null) {
                String[] employeeData = line.split(separator);

                if (employeeData.length < 4) {
                    System.out.println("Incomplete data: " + line);
                    continue;
                }

                String name = employeeData[0].trim();
                int age;
                String departmentName = employeeData[2].trim();
                double salary;

                try {
                    age = Integer.parseInt(employeeData[1].trim());
                } catch (NumberFormatException e) {
                    System.out.println("Invalid age for employee: " + name);
                    continue;
                }

                try {
                    salary = Double.parseDouble(employeeData[3].trim());
                } catch (NumberFormatException e) {
                    System.out.println("Invalid salary for employee: " + name);
                    continue;
                }

                Department department = departments.get(departmentName);
                if (department == null) {
                    department = new Department(departmentName);
                    departments.put(departmentName, department);
                }
                department.addEmployeeSalary(salary);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }

        System.out.println("\nAverage Salary by Department:");
        for (Department department : departments.values()) {
            System.out.printf("%s: %.2f%n", department.getName(), department.getAverageSalary());
        }
    }

    static class Department {
        private String name;
        private double totalSalary;
        private int employeeCount;

        public Department(String name) {
            this.name = name;
            this.totalSalary = 0;
            this.employeeCount = 0;
        }

        public void addEmployeeSalary(double salary) {
            totalSalary += salary;
            employeeCount++;
        }

        public double getAverageSalary() {
            return totalSalary / employeeCount;
        }

        public String getName() {
            return name;
        }
    }
}
```

