#include <iostream>
#include <string>
#include <vector>
#include <thread>
#include <mutex>
#include <curl/curl.h>

std::mutex print_mutex;

size_t write_data(void *ptr, size_t size, size_t nmemb, FILE *stream) {
    size_t written = fwrite(ptr, size, nmemb, stream);
    return written;
}

int progress_callback(void *clientp, curl_off_t dltotal, curl_off_t dlnow, curl_off_t ultotal, curl_off_t ulnow) {
    std::unique_lock<std::mutex> lock(print_mutex);
    int id = *static_cast<int*>(clientp);
    if (dltotal > 0) {
        double progress = static_cast<double>(dlnow) / static_cast<double>(dltotal) * 100.0;
        std::cout << "Thread " << id << ": Download progress: " << progress << "%" << std::endl;
    }
    lock.unlock();
    return 0;
}

void download_file(const std::string &url, const std::string &output_path, int thread_id) {
    CURL *curl;
    FILE *fp;
    CURLcode res;

    curl_global_init(CURL_GLOBAL_DEFAULT);
    curl = curl_easy_init();

    if(curl) {
        fp = fopen(output_path.c_str(), "wb");
        curl_easy_setopt(curl, CURLOPT_URL, url.c_str());
        curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, write_data);
        curl_easy_setopt(curl, CURLOPT_WRITEDATA, fp);
        curl_easy_setopt(curl, CURLOPT_NOPROGRESS, 0L);
        curl_easy_setopt(curl, CURLOPT_PROGRESSFUNCTION, progress_callback);
        curl_easy_setopt(curl, CURLOPT_PROGRESSDATA, &thread_id);

        res = curl_easy_perform(curl);

        if(res != CURLE_OK) {
            std::unique_lock<std::mutex> lock(print_mutex);
            std::cerr << "Thread " << thread_id << ": Download failed: " << curl_easy_strerror(res) << std::endl;
            lock.unlock();
        } else {
            std::unique_lock<std::mutex> lock(print_mutex);
            std::cout << "Thread " << thread_id << ": Download completed." << std::endl;
            lock.unlock();
        }

        fclose(fp);
        curl_easy_cleanup(curl);
    }
    curl_global_cleanup();
}

int main() {
    std::vector<std::string> urls = {
        "https://example.com/file1.zip",
        "https://example.com/file2.zip",
        "https://example.com/file3.zip"
    };

    std::vector<std::string> output_paths = {
        "file1.zip",
        "file2.zip",
        "file3.zip"
    };

    std::vector<std::thread> threads;

    for (size_t i = 0; i < urls.size(); ++i) {
        threads.emplace_back(download_file, urls[i], output_paths[i], static_cast<int>(i + 1));
    }

    for (auto &t : threads) {
        t.join();
    }

    return 0;
}

Here's a TypeScript class representing a simple calculator with methods for addition, subtraction, multiplication, and division. It includes error handling for invalid inputs and division by zero.

```typescript
class SimpleCalculator {
  // Addition method
  add(a: number, b: number): number {
    this.validateInputs(a, b);
    return a + b;
  }

  // Subtraction method
  subtract(a: number, b: number): number {
    this.validateInputs(a, b);
    return a - b;
  }

  // Multiplication method
  multiply(a: number, b: number): number {
    this.validateInputs(a, b);
    return a * b;
  }

  // Division method
  divide(a: number, b: number): number {
    this.validateInputs(a, b);

    if (b === 0) {
      throw new Error("Division by zero is not allowed.");
    }

    return a / b;
  }

  // Validate inputs method
  private validateInputs(a: any, b: any): void {
    if (typeof a !== "number" || typeof b !== "number") {
      throw new Error("Invalid input(s). Both arguments must be numbers.");
    }
  }
}

// Example usage:
const calculator = new SimpleCalculator();
console.log(calculator.add(2, 3)); // Output: 5
console.log(calculator.subtract(7, 4)); // Output: 3
console.log(calculator.multiply(3, 4)); // Output: 12
console.log(calculator.divide(8, 2)); // Output: 4
