const (
	lowercaseLetters = "abcdefghijklmnopqrstuvwxyz"
	uppercaseLetters = "ABCDEFGHIJKLMNOPQRSTUVWXYZ"
	digits           = "0123456789"
	specialChars     = "!@#$%^&*()-_=+,.?/:;{}[]`~"
)

func main() {
	length := flag.Int("length", 8, "Length of the password")
	count := flag.Int("count", 1, "Number of passwords to generate")
	useUppercase := flag.Bool("use-uppercase", true, "Include uppercase letters in the password")
	useLowercase := flag.Bool("use-lowercase", true, "Include lowercase letters in the password")
	useDigits := flag.Bool("use-digits", true, "Include digits in the password")
	useSpecial := flag.Bool("use-special", false, "Include special characters in the password")

	flag.Parse()

	characterSet := ""

	if *useLowercase {
		characterSet += lowercaseLetters
	}

	if *useUppercase {
		characterSet += uppercaseLetters
	}

	if *useDigits {
		characterSet += digits
	}

	if *useSpecial {
		characterSet += specialChars
	}

	if len(characterSet) == 0 {
		fmt.Println("Error: At least one character set must be enabled.")
		return
	}

	rand.Seed(time.Now().UnixNano())

	for i := 0; i < *count; i++ {
		password := generatePassword(*length, characterSet)
		fmt.Println(password)
	}
}

func generatePassword(length int, characterSet string) string {
	var password strings.Builder

	for i := 0; i < length; i++ {
		randomIndex := rand.Intn(len(characterSet))
		password.WriteByte(characterSet[randomIndex])
	}

	return password.String()
}
