import javax.websocket.server.ServerEndpoint;

@ServerEndpoint("/chat")
public class ChatServerEndpoint {

    private static final Set<Session> sessions = Collections.synchronizedSet(new HashSet<>());

    @OnOpen
    public void onOpen(Session session) {
        System.out.println("Client connected: " + session.getId());
        sessions.add(session);
    }

    @OnMessage
    public void onMessage(String message, Session sender) {
        System.out.println("Received message from " + sender.getId() + ": " + message);

        synchronized (sessions) {
            for (Session session : sessions) {
                if (!session.equals(sender)) {
                    try {
                        session.getBasicRemote().sendText(message);
                    } catch (IOException e) {
                        System.err.println("Error sending message to " + session.getId() + ": " + e.getMessage());
                    }
                }
            }
        }
    }

    @OnClose
    public void onClose(Session session) {
        System.out.println("Client disconnected: " + session.getId());
        sessions.remove(session);
    }

    @OnError
    public void onError(Throwable error, Session session) {
        System.err.println("Error in session " + session.getId() + ": " + error.getMessage());
    }
}

