// Function to find the largest and smallest number in an array
function findLargestAndSmallest(arr) {
    // Initialize variables for largest and smallest numbers
    let largest = arr[0];
    let smallest = arr[0];

    // Loop through the array
    for (let i = 1; i < arr.length; i++) {
        // If current element is larger than the largest, update largest
        if (arr[i] > largest) {
            largest = arr[i];
        }
        // If current element is smaller than the smallest, update smallest
        else if (arr[i] < smallest) {
            smallest = arr[i];
        }
    }

    // Return an object with the largest and smallest numbers
    return {largest: largest, smallest: smallest};
}

import java.io.File;
import java.util.Scanner;

public class SimpleFileSystem {

    private static File currentDirectory = new File(System.getProperty("user.dir"));

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        String input;

        while (true) {
            System.out.print(currentDirectory.getAbsolutePath() + "> ");
            input = scanner.nextLine();
            processCommand(input);
        }
    }

    private static void processCommand(String input) {
        String[] tokens = input.split("\\s+");
        String command = tokens[0];

        switch (command) {
            case "mkdir":
                mkdir(tokens);
                break;
            case "touch":
                touch(tokens);
                break;
            case "rm":
                rm(tokens);
                break;
            case "cd":
                cd(tokens);
                break;
            case "ls":
                ls();
                break;
            case "exit":
                System.exit(0);
                break;
            default:
                System.out.println("Invalid command");
        }
    }

    private static void mkdir(String[] tokens) {
        if (tokens.length != 2) {
            System.out.println("Usage: mkdir <directory>");
            return;
        }

        File dir = new File(currentDirectory, tokens[1]);
        if (!dir.mkdir()) {
            System.out.println("Failed to create directory");
        }
    }

    private static void touch(String[] tokens) {
        if (tokens.length != 2) {
            System.out.println("Usage: touch <file>");
            return;
        }

        File file = new File(currentDirectory, tokens[1]);
        try {
            if (!file.createNewFile()) {
                System.out.println("Failed to create file");
            }
        } catch (Exception e) {
            System.out.println("Error: " + e.getMessage());
        }
    }

    private static void rm(String[] tokens) {
        if (tokens.length != 2) {
            System.out.println("Usage: rm <file/directory>");
            return;
        }

        File file = new File(currentDirectory, tokens[1]);
        if (!file.exists()) {
            System.out.println("No such file or directory");
            return;
        }

        deleteRecursively(file);
    }

    private static void deleteRecursively(File file) {
        if (file.isDirectory()) {
            for (File child : file.listFiles()) {
                deleteRecursively(child);
            }
        }

        if (!file.delete()) {
            System.out.println("Failed to delete " + file.getAbsolutePath());
        }
    }

    private static void cd(String[] tokens) {
        if (tokens.length != 2) {
            System.out.println("Usage: cd <directory>");
            return;
        }

        File dir = new File(currentDirectory, tokens[1]);
        if (!dir.exists() || !dir.isDirectory()) {
            System.out.println("No such directory");
            return;
        }

        currentDirectory = dir;
    }

    private static void ls() {
        File[] files = currentDirectory.listFiles();
        for (File file : files) {
            System.out.println(file.getName());
        }
    }
}

