Here's a Java program that generates random math problems and keeps track of the user's score:

```java
import java.util.Scanner;
import java.util.Random;

public class MathProblems {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        Random random = new Random();
        int score = 0;
        int numberOfQuestions = 10;

        for (int i = 0; i < numberOfQuestions; i++) {
            int num1 = random.nextInt(50) + 1;
            int num2 = random.nextInt(50) + 1;
            int operation = random.nextInt(4);

            System.out.println("Solve the following problem:");
            int correctAnswer = 0;

            switch (operation) {
                case 0:
                    System.out.printf("%d + %d = ", num1, num2);
                    correctAnswer = num1 + num2;
                    break;
                case 1:
                    System.out.printf("%d - %d = ", num1, num2);
                    correctAnswer = num1 - num2;
                    break;
                case 2:
                    System.out.printf("%d * %d = ", num1, num2);
                    correctAnswer = num1 * num2;
                    break;
                case 3:
                    while (num2 == 0) {
                        num2 = random.nextInt(50) + 1;
                    }
                    System.out.printf("%d / %d = ", num1, num2);
                    correctAnswer = num1 / num2;
                    break;
            }

            int userAnswer = scanner.nextInt();

            if (userAnswer == correctAnswer) {
                System.out.println("Correct!");
                score++;
            } else {
                System.out.println("Incorrect. The correct answer is " + correctAnswer);
            }

            System.out.println("Your current score is: " + score);
        }

        System.out.println("Your final score is: " + score + " out of " + numberOfQuestions);
    }
}
