func main() {
	watcher, err := fsnotify.NewWatcher()
	if err != nil {
		log.Fatal(err)
	}
	defer watcher.Close()

	done := make(chan bool)
	go func() {
		for {
			select {
			case event, ok := <-watcher.Events:
				if !ok {
					return
				}
				log.Println("event:", event)
				if event.Op&fsnotify.Write == fsnotify.Write {
					log.Println("modified file:", event.Name, "at", time.Now())
				} else if event.Op&fsnotify.Create == fsnotify.Create {
					log.Println("created file:", event.Name, "at", time.Now())
				} else if event.Op&fsnotify.Remove == fsnotify.Remove {
					log.Println("deleted file:", event.Name, "at", time.Now())
				}
			case err, ok := <-watcher.Errors:
				if !ok {
					return
				}
				log.Println("error:", err)
			}
		}
	}()

	err = watcher.Add("/path/to/my/dir")
	if err != nil {
		log.Fatal(err)
	}
	<-done
}

