Here's a Java program that reads a CSV file containing information about employees and calculates the total salary paid by each department. The program outputs the results in descending order of total salary.

```java
import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.util.ArrayList;
import java.util.Collections;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class EmployeeSalary {

    public static void main(String[] args) {
        String csvFile = "employees.csv";
        String line;
        String delimiter = ",";
        Map<String, Double> departmentSalaries = new HashMap<>();

        try (BufferedReader br = new BufferedReader(new FileReader(csvFile))) {
            while ((line = br.readLine()) != null) {
                String[] employeeData = line.split(delimiter);
                String department = employeeData[2];
                double salary = Double.parseDouble(employeeData[3]);

                if (departmentSalaries.containsKey(department)) {
                    departmentSalaries.put(department, departmentSalaries.get(department) + salary);
                } else {
                    departmentSalaries.put(department, salary);
                }
            }

            List<Map.Entry<String, Double>> sortedDepartmentSalaries = new ArrayList<>(departmentSalaries.entrySet());
            Collections.sort(sortedDepartmentSalaries, (o1, o2) -> o2.getValue().compareTo(o1.getValue()));

            for (Map.Entry<String, Double> entry : sortedDepartmentSalaries) {
