import java.util.Scanner;

public class ReverseAndRepeat {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String inputString = scanner.nextLine();

        System.out.print("Enter an integer (N): ");
        int n = scanner.nextInt();

        String reversedString = reverse(inputString);
        String result = repeat(reversedString, n);

        System.out.println("Reversed and repeated string: " + result);
    }

    private static String reverse(String s) {
        StringBuilder sb = new StringBuilder(s);
        return sb.reverse().toString();
    }

    private static String repeat(String s, int n) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < n; i++) {
            sb.append(s);
        }
        return sb.toString();
    }
}

import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.IvParameterSpec;
import java.io.*;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.security.SecureRandom;
import java.util.HashMap;
import java.util.Map;

public class PasswordManager {
    private static final String DATA_FILE = "passwords.dat";
    private SecretKey secretKey;
    private IvParameterSpec iv;

    public PasswordManager() throws Exception {
        KeyGenerator keyGen = KeyGenerator.getInstance("AES");
        keyGen.init(128);
        secretKey = keyGen.generateKey();

        SecureRandom random = new SecureRandom();
        byte[] ivBytes = new byte[16];
        random.nextBytes(ivBytes);
        iv = new IvParameterSpec(ivBytes);
    }

    public void saveCredentials(String service, String username, String password) throws Exception {
        Map<String, Credential> credentials = loadCredentials();
        credentials.put(service, new Credential(username, password));
        saveEncryptedData(credentials);
    }

    public Credential getCredentials(String service) throws Exception {
        Map<String, Credential> credentials = loadCredentials();
        return credentials.get(service);
    }

    public void deleteCredentials(String service) throws Exception {
        Map<String, Credential> credentials = loadCredentials();
        credentials.remove(service);
        saveEncryptedData(credentials);
    }

    private void saveEncryptedData(Map<String, Credential> credentials) throws Exception {
        ByteArrayOutputStream byteStream = new ByteArrayOutputStream();
        ObjectOutputStream objStream = new ObjectOutputStream(byteStream);
        objStream.writeObject(credentials);

        Cipher cipher = Cipher.getInstance("AES/CBC/PKCS5Padding");
        cipher.init(Cipher.ENCRYPT_MODE, secretKey, iv);
        byte[] encryptedData = cipher.doFinal(byteStream.toByteArray());

        Files.write(Paths.get(DATA_FILE), encryptedData);
    }

    private Map<String, Credential> loadCredentials() throws Exception {
        if (!Files.exists(Paths.get(DATA_FILE))) {
            return new HashMap<>();
        }

        byte[] encryptedData = Files.readAllBytes(Paths.get(DATA_FILE));

        Cipher cipher = Cipher.getInstance("AES/CBC/PKCS5Padding");
        cipher.init(Cipher.DECRYPT_MODE, secretKey, iv);
        byte[] decryptedData = cipher.doFinal(encryptedData);

        ByteArrayInputStream byteStream = new ByteArrayInputStream(decryptedData);
        ObjectInputStream objStream = new ObjectInputStream(byteStream);
        return (Map<String, Credential>) objStream.readObject();
    }

    public static class Credential implements Serializable {
        private String username;
        private String password;

        public Credential(String username, String password) {
            this.username = username;
            this.password = password;
        }

        public String getUsername() {
            return username;
        }

        public String getPassword() {
            return password;
        }
    }

    public static void main(String[] args) {
        try {
            PasswordManager manager = new PasswordManager();

            // Add a credential
            manager.saveCredentials("example.com", "user@example.com", "password123");

            // Retrieve the credential
            Credential cred = manager.getCredentials("example.com");
            System.out.println("Username: " + cred.getUsername());
            System.out.println("Password: " + cred.getPassword());

            // Delete the credential
            manager.deleteCredentials("example.com");

        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}

