In this example, we will create a simple event-driven system using the observer pattern. We will have an `Event` class that represents an event and an `EventListener` interface for listeners to implement. The `EventManager` class will manage the events and listeners.

Here's the complete code:

```java
import java.util.ArrayList;
import java.util.List;

// Event class representing an event in our system
class Event {
    private String name;

    public Event(String name) {
        this.name = name;
    }

    public String getName() {
        return name;
    }
}

// EventListener interface for classes interested in listening to events
interface EventListener {
    void onEvent(Event event);
}

// EventManager class managing events and listeners
class EventManager {
    private List<EventListener> listeners = new ArrayList<>();

    public void addListener(EventListener listener) {
        listeners.add(listener);
    }

    public void removeListener(EventListener listener) {
        listeners.remove(listener);
    }

    public void fireEvent(Event event) {
        for (EventListener listener : listeners) {
            listener.onEvent(event);
        }
    }
}

// Sample listener implementation
class MyListener implements EventListener {
    private String name;

    public MyListener(String name) {
        this.name = name;
    }

    @Override
    public void onEvent(Event event) {
        System.out.println(name + " received event: " + event.getName());
    }
}

public class ObserverPatternExample {
    public static void main(String[] args) {
        // Create an event manager instance
        EventManager eventManager = new EventManager();

        // Create some sample listeners
        MyListener listener1 = new MyListener("Listener 1");
        MyListener listener2 = new MyListener("Listener 2");

        // Register the listeners with the event manager
        eventManager.addListener(listener1);
        eventManager.addListener(listener2);

        // Fire some events
        eventManager.fireEvent(new Event("Event 1"));
        eventManager.fireEvent(new Event("Event 2"));

        // Remove a listener and fire another event
        eventManager.removeListener(listener1);
        eventManager.fireEvent(new Event("Event 3"));
    }
}
```

When you run this program, it will output the following:

```
Listener 1 received event: Event 1
Listener 2 received event: Event 1
Listener 1 received event: Event 2
Listener 2 received event: Event 2
Listener 2 received event: Event 3
```

This demonstrates how the observer pattern can be used to implement a simple event-driven system with multiple listeners and events in Java.

class Node:
    def __init__(self, data=None):
        self.data = data
        self.next = None

class SinglyLinkedList:
    def __init__(self):
        self.head = None

    def add_beginning(self, data):
        new_node = Node(data)
        new_node.next = self.head
        self.head = new_node

    def add_end(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
            return
        current = self.head
        while current.next:
            current = current.next
        current.next = new_node

    def add_at_index(self, index, data):
        if index < 0:
            raise ValueError("Index must be non-negative")
        if index == 0:
            self.add_beginning(data)
            return
        new_node = Node(data)
        current = self.head
        for i in range(index - 1):
            if not current:
                raise IndexError("List index out of range")
            current = current.next
        new_node.next = current.next
        current.next = new_node

    def remove_by_value(self, value):
        if not self.head:
            raise ValueError("List is empty")
        if self.head.data == value:
            self.head = self.head.next
            return
        current = self.head
        while current.next and current.next.data != value:
            current = current.next
        if not current.next:
            raise ValueError(f"{value} not found in list")
        current.next = current.next.next

    def remove_by_index(self, index):
        if index < 0:
            raise ValueError("Index must be non-negative")
        if not self.head:
            raise IndexError("List is empty")
        if index == 0:
            self.head = self.head.next
            return
        current = self.head
        for i in range(index - 1):
            if not current.next:
                raise IndexError("List index out of range")
            current = current.next
        if not current.next:
            raise IndexError("List index out of range")
        current.next = current.next.next

    def display(self):
        elements = []
        current = self.head
        while current:
            elements.append(current.data)
            current = current.next
        return elements

Here's a Java program that reads a CSV file containing user information (name, age, email) and writes the data into an SQLite database. The program handles exceptions for missing or incorrect data in the CSV file.

```java
import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.SQLException;

public class CsvToSQLite {

    public static void main(String[] args) {
        String csvFile = "user_data.csv";
        String line;
        String cvsSplitBy = ",";

        // Load SQLite JDBC driver
        try {
            Class.forName("org.sqlite.JDBC");
        } catch (ClassNotFoundException e) {
            System.out.println(e.getMessage());
            return;
        }

        // Connect to SQLite database
        try (Connection conn = DriverManager.getConnection("jdbc:sqlite:user_data.db")) {
            if (conn != null) {
                // Create table for user data
                String createTableQuery = "CREATE TABLE IF NOT EXISTS users ("
                        + "id INTEGER PRIMARY KEY AUTOINCREMENT,"
                        + "name TEXT NOT NULL,"
                        + "age INTEGER,"
                        + "email TEXT);";

                try (PreparedStatement pstmt = conn.prepareStatement(createTableQuery)) {
                    pstmt.execute();
                } catch (SQLException e) {
                    System.out.println(e.getMessage());
                }

                // Read CSV file and insert data into the database
                try (BufferedReader br = new BufferedReader(new FileReader(csvFile))) {
                    while ((line = br.readLine()) != null) {
                        String[] userData = line.split(cvsSplitBy);

                        if (userData.length == 3) {
                            String name = userData[0].trim();
                            int age;
                            try {
                                age = Integer.parseInt(userData[1].trim());
                            } catch (NumberFormatException e) {
                                System.out.println("Invalid age value: " + userData[1].trim());
                                continue;
                            }
                            String email = userData[2].trim();

                            // Insert user data into the database
                            String insertQuery = "INSERT INTO users (name, age, email) VALUES (?, ?, ?);";
                            try (PreparedStatement pstmt = conn.prepareStatement(insertQuery)) {
                                pstmt.setString(1, name);
                                pstmt.setInt(2, age);
                                pstmt.setString(3, email);
                                pstmt.executeUpdate();
                            } catch (SQLException e) {
                                System.out.println(e.getMessage());
                            }
                        } else {
                            System.out.println("Invalid line format: " + line);
                        }
                    }
                } catch (IOException e) {
                    System.out.println(e.getMessage());
                }
            }
        } catch (SQLException e) {
            System.out.println(e.getMessage());
        }
    }
}
```

