    class Student
    {
        public int Id { get; set; }
        public string Name { get; set; }
        public double GPA { get; set; }

        public override string ToString()
        {
            return $"Id: {Id}, Name: {Name}, GPA: {GPA}";
        }
    }

    class Program
    {
        static void Main(string[] args)
        {
            List<Student> students = new List<Student>
            {
                new Student { Id = 1, Name = "John", GPA = 3.5 },
                new Student { Id = 2, Name = "Jane", GPA = 4.0 },
                new Student { Id = 3, Name = "Mike", GPA = 2.8 },
                new Student { Id = 4, Name = "Emma", GPA = 3.9 },
                new Student { Id = 5, Name = "Lucas", GPA = 3.2 }
            };

            // Filter students with GPA greater than or equal to 3.5
            var filteredStudents = from student in students
                                   where student.GPA >= 3.5
                                   select student;

            Console.WriteLine("Filtered Students (GPA >= 3.5):");
            foreach (var student in filteredStudents)
            {
                Console.WriteLine(student);
            }

            // Transform students into a new anonymous type containing only the name and GPA properties
            var transformedStudents = from student in students
                                      select new { student.Name, student.GPA };

            Console.WriteLine("\nTransformed Students (Anonymous Type):");
            foreach (var student in transformedStudents)
            {
                Console.WriteLine($"Name: {student.Name}, GPA: {student.GPA}");
            }

            // Order students by GPA in descending order
            var orderedStudents = from student in students
                                  orderby student.GPA descending
                                  select student;

            Console.WriteLine("\nOrdered Students (Descending GPA):");
            foreach (var student in orderedStudents)
            {
                Console.WriteLine(student);
            }
        }
    }
}
