#include <iostream>

class Node {
public:
    int data;
    Node* next;

    Node(int data) : data(data), next(nullptr) {}
};

class SinglyLinkedList {
public:
    SinglyLinkedList() : head(nullptr), size(0) {}

    ~SinglyLinkedList() {
        while (head != nullptr) {
            Node* temp = head;
            head = head->next;
            delete temp;
        }
    }

    void addAtBeginning(int data) {
        Node* newNode = new Node(data);
        newNode->next = head;
        head = newNode;
        size++;
    }

    void addAtEnd(int data) {
        Node* newNode = new Node(data);

        if (head == nullptr) {
            head = newNode;
        } else {
            Node* current = head;
            while (current->next != nullptr) {
                current = current->next;
            }
            current->next = newNode;
        }
        size++;
    }

    void insertAtPosition(int position, int data) {
        if (position < 0 || position > size) {
            std::cout << "Invalid position" << std::endl;
            return;
        }

        if (position == 0) {
            addAtBeginning(data);
        } else {
            Node* newNode = new Node(data);
            Node* current = head;
            for (int i = 1; i < position; i++) {
                current = current->next;
            }
            newNode->next = current->next;
            current->next = newNode;
            size++;
        }
    }

    void deleteByValue(int value) {
        if (head == nullptr) {
            std::cout << "List is empty" << std::endl;
            return;
        }

        if (head->data == value) {
            Node* temp = head;
            head = head->next;
            delete temp;
            size--;
        } else {
            Node* current = head;
            while (current->next != nullptr && current->next->data != value) {
                current = current->next;
            }

            if (current->next == nullptr) {
                std::cout << "Value not found" << std::endl;
            } else {
                Node* temp = current->next;
                current->next = current->next->next;
                delete temp;
                size--;
            }
        }
    }

    void deleteByPosition(int position) {
        if (position < 0 || position >= size) {
            std::cout << "Invalid position" << std::endl;
            return;
        }

        if (position == 0) {
            Node* temp = head;
            head = head->next;
            delete temp;
        } else {
            Node* current = head;
            for (int i = 1; i < position; i++) {
                current = current->next;
            }
            Node* temp = current->next;
            current->next = current->next->next;
            delete temp;
        }
        size--;
    }

    void display() {
        Node* current = head;
        while (current != nullptr) {
            std::cout << current->data << " -> ";
            current = current->next;
        }
        std::cout << "NULL" << std::endl;
    }

private:
    Node* head;
    int size;
};

int main() {
    SinglyLinkedList list;

    list.addAtBeginning(5);
    list.addAtEnd(10);
    list.insertAtPosition(2, 15);
    list.display(); // Output: 5 -> 10 -> 15 -> NULL

    list.deleteByValue(10);
    list.display(); // Output: 5 -> 15 -> NULL

    list.deleteByPosition(1);
    list.display(); // Output: 5 -> NULL

    return 0;
}

import com.amazonaws.services.lambda.runtime.Context;
import com.amazonaws.services.lambda.runtime.RequestHandler;
import com.amazonaws.services.lambda.runtime.events.S3Event;
import com.amazonaws.services.s3.AmazonS3;
import com.amazonaws.services.s3.AmazonS3ClientBuilder;
import com.amazonaws.services.s3.event.S3EventNotification.S3EventNotificationRecord;

import javax.imageio.ImageIO;
import java.awt.*;
import java.awt.image.BufferedImage;
import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.InputStream;

public class ThumbnailCreator implements RequestHandler<S3Event, String> {

    private static final int THUMBNAIL_WIDTH = 100;
    private static final int THUMBNAIL_HEIGHT = 100;

    @Override
    public String handleRequest(S3Event s3event, Context context) {
        try {
            S3EventNotificationRecord record = s3event.getRecords().get(0);

            String srcBucket = record.getS3().getBucket().getName();
            String srcKey = record.getS3().getObject().getKey();

            AmazonS3 s3Client = AmazonS3ClientBuilder.defaultClient();

            InputStream objectData = s3Client.getObject(srcBucket, srcKey).getObjectContent();
            BufferedImage srcImage = ImageIO.read(objectData);

            int width = THUMBNAIL_WIDTH;
            int height = THUMBNAIL_HEIGHT;

            BufferedImage thumbnail = new BufferedImage(width, height, BufferedImage.TYPE_INT_RGB);
            Graphics2D graphics = thumbnail.createGraphics();
            graphics.setRenderingHint(RenderingHints.KEY_INTERPOLATION,
                    RenderingHints.VALUE_INTERPOLATION_BILINEAR);
            graphics.drawImage(srcImage, 0, 0, width, height, null);

            ByteArrayOutputStream outputStream = new ByteArrayOutputStream();
            ImageIO.write(thumbnail, "jpg", outputStream);
            InputStream thumbnailInputStream = new ByteArrayInputStream(outputStream.toByteArray());

            String dstKey = srcKey.replaceFirst("\\.([^.]+)$", "_thumbnail.jpg");
            s3Client.putObject(srcBucket, dstKey, thumbnailInputStream, null);

            return "Thumbnail created successfully";
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}

