// Function to find the largest number in an array
function findLargestNumber(arr) {
    // Initialize largest number as first element of array
    var largest = arr[0];

    // Loop through each element in the array
    for (var i = 1; i < arr.length; i++) {
        // If current element is larger than largest, update largest
        if (arr[i] > largest) {
            largest = arr[i];
        }
    }

    // Return the largest number
    return largest;
}

from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_marshmallow import Marshmallow
from flask_jwt_extended import JWTManager, jwt_required, create_access_token, get_jwt_identity
from flask_swagger_ui import get_swaggerui_blueprint
import os

# Initialize app
app = Flask(__name__)
basedir = os.path.abspath(os.path.dirname(__file__))

# Database configuration
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///' + os.path.join(basedir, 'db.sqlite')
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False

# Add a secret key for JWT
app.config['JWT_SECRET_KEY'] = 'your-secret-key'

# Initialize database and Marshmallow
db = SQLAlchemy(app)
ma = Marshmallow(app)
jwt = JWTManager(app)

# Note Model
class Note(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    title = db.Column(db.String(100), nullable=False)
    content = db.Column(db.Text, nullable=False)
    user_id = db.Column(db.Integer, nullable=False)

    def __init__(self, title, content, user_id):
        self.title = title
        self.content = content
        self.user_id = user_id

# User Model
class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(50), unique=True, nullable=False)
    password = db.Column(db.String(100), nullable=False)

    def __init__(self, username, password):
        self.username = username
        self.password = password

# Note Schema
class NoteSchema(ma.SQLAlchemyAutoSchema):
    class Meta:
        model = Note

# User Schema
class UserSchema(ma.SQLAlchemyAutoSchema):
    class Meta:
        model = User

note_schema = NoteSchema()
notes_schema = NoteSchema(many=True)
user_schema = UserSchema()
users_schema = UserSchema(many=True)

# Create the database tables
db.create_all()

# Register user
@app.route('/register', methods=['POST'])
def register():
    username = request.json['username']
    password = request.json['password']

    new_user = User(username=username, password=password)
    db.session.add(new_user)
    db.session.commit()

    return user_schema.jsonify(new_user)

# Login user
@app.route('/login', methods=['POST'])
def login():
    username = request.json['username']
    password = request.json['password']

    user = User.query.filter_by(username=username).first()

    if not user or user.password != password:
        return jsonify({'error': 'Invalid credentials'})

    access_token = create_access_token(identity=user.id)
    return jsonify(access_token=access_token)

# CRUD operations for notes

# Create a note
@app.route('/notes', methods=['POST'])
@jwt_required()
def add_note():
    title = request.json['title']
    content = request.json['content']
    user_id = get_jwt_identity()

    new_note = Note(title=title, content=content, user_id=user_id)
    db.session.add(new_note)
    db.session.commit()

    return note_schema.jsonify(new_note)

# Get all notes
@app.route('/notes', methods=['GET'])
@jwt_required()
def get_notes():
    user_id = get_jwt_identity()
    notes = Note.query.filter_by(user_id=user_id).all()
    return notes_schema.jsonify(notes)

# Get single note
@app.route('/notes/<id>', methods=['GET'])
@jwt_required()
def get_note(id):
    user_id = get_jwt_identity()
    note = Note.query.get_or_404(id)

    if note.user_id != user_id:
        return jsonify({'error': 'Not authorized'})

    return note_schema.jsonify(note)

# Update a note
@app.route('/notes/<id>', methods=['PUT'])
@jwt_required()
def update_note(id):
    user_id = get_jwt_identity()
    note = Note.query.get_or_404(id)

    if note.user_id != user_id:
        return jsonify({'error': 'Not authorized'})

    note.title = request.json['title']
    note.content = request.json['content']

    db.session.commit()
    return note_schema.jsonify(note)

# Delete a note
@app.route('/notes/<id>', methods=['DELETE'])
@jwt_required()
def delete_note(id):
    user_id = get_jwt_identity()
    note = Note.query.get_or_404(id)

    if note.user_id != user_id:
        return jsonify({'error': 'Not authorized'})

    db.session.delete(note)
    db.session.commit()

    return note_schema.jsonify(note)

