import com.amazonaws.auth.AWSStaticCredentialsProvider;
import com.amazonaws.auth.BasicAWSCredentials;
import com.amazonaws.services.s3.AmazonS3;
import com.amazonaws.services.s3.AmazonS3ClientBuilder;
import com.amazonaws.services.s3.model.Bucket;
import com.amazonaws.services.s3.model.ObjectListing;
import com.amazonaws.services.s3.model.S3ObjectSummary;

import java.io.File;
import java.nio.file.Paths;

public class S3Example {

    private static final String ACCESS_KEY = "your_access_key";
    private static final String SECRET_KEY = "your_secret_key";
    private static final String REGION = "us-west-2";
    private static final String BUCKET_NAME = "my-example-bucket";
    private static final String FILE_PATH = "/path/to/your/file.txt";
    private static final String KEY = "file.txt";

    public static void main(String[] args) {
        BasicAWSCredentials awsCreds = new BasicAWSCredentials(ACCESS_KEY, SECRET_KEY);
        AmazonS3 s3Client = AmazonS3ClientBuilder.standard()
                .withRegion(REGION)
                .withCredentials(new AWSStaticCredentialsProvider(awsCreds))
                .build();

        // Create a new bucket
        Bucket bucket = s3Client.createBucket(BUCKET_NAME);
        System.out.println("Created bucket: " + bucket.getName());

        // Upload a file to the bucket
        File file = new File(FILE_PATH);
        s3Client.putObject(BUCKET_NAME, KEY, file);
        System.out.println("Uploaded file: " + KEY);

        // List all objects in the bucket
        ObjectListing objectListing = s3Client.listObjects(BUCKET_NAME);
        for (S3ObjectSummary objectSummary : objectListing.getObjectSummaries()) {
            System.out.println(" - " + objectSummary.getKey() + "  " +
                    "(size = " + objectSummary.getSize() + ")");
        }

        // Download a specific object by its key
        String destinationPath = "/path/to/destination/folder/" + KEY;
        s3Client.getObject(BUCKET_NAME, KEY).getObjectContent().transferTo(new File(destinationPath));
        System.out.println("Downloaded file: " + Paths.get(destinationPath).toAbsolutePath());
    }
}

