func main() {
	file, err := os.Open("input.csv")
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	defer file.Close()

	reader := csv.NewReader(file)
	records, err := reader.ReadAll()
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	sum := 0
	for _, record := range records {
		num, err := strconv.Atoi(record[0])
		if err != nil {
			fmt.Printf("Skipping invalid integer: %s\n", record[0])
			continue
		}
		sum += num
	}

	fmt.Printf("Sum of integers in the first column: %d\n", sum)
}

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.net.HttpURLConnection;
import java.net.MalformedURLException;
import java.net.URL;

import org.json.JSONArray;
import org.json.JSONException;
import org.json.JSONObject;

public class JsonApiReader {

    public static void main(String[] args) {
        String apiUrl = "https://jsonplaceholder.typicode.com/todos"; // Replace with your desired API URL

        try {
            URL url = new URL(apiUrl);
            HttpURLConnection connection = (HttpURLConnection) url.openConnection();
            connection.setRequestMethod("GET");
            connection.connect();

            int responseCode = connection.getResponseCode();
            if (responseCode == 200) { // Success
                BufferedReader reader = new BufferedReader(new InputStreamReader(connection.getInputStream()));
                StringBuilder jsonResponse = new StringBuilder();
                String line;
                while ((line = reader.readLine()) != null) {
                    jsonResponse.append(line);
                }
                reader.close();

                printJsonData(jsonResponse.toString());
            } else {
                System.out.println("Error: Unable to connect to the API. Response code: " + responseCode);
            }

            connection.disconnect();
        } catch (MalformedURLException e) {
            System.out.println("Error: Invalid API URL.");
        } catch (IOException e) {
            System.out.println("Error: Unable to connect to the API.");
        } catch (JSONException e) {
            System.out.println("Error: Invalid JSON data received from the API.");
        }
    }

    private static void printJsonData(String jsonData) throws JSONException {
        JSONArray jsonArray = new JSONArray(jsonData);
        for (int i = 0; i < jsonArray.length(); i++) {
            JSONObject jsonObject = jsonArray.getJSONObject(i);
            System.out.println("Item " + (i + 1) + ":");
            System.out.println("ID: " + jsonObject.getInt("id"));
            System.out.println("User ID: " + jsonObject.getInt("userId"));
            System.out.println("Title: " + jsonObject.getString("title"));
            System.out.println("Completed: " + jsonObject.getBoolean("completed"));
            System.out.println();
        }
    }
}

