5. Connect to MongoDB using Mongoose

In `app.js`, add the following code to connect to your MongoDB database:

```javascript
const express = require('express');
const bodyParser = require('body-parser');
const mongoose = require('mongoose');

const app = express();

// Replace <username>, <password>, and <dbname> with your actual credentials
const dbURI = 'mongodb+srv://<username>:<password>@cluster0.mongodb.net/<dbname>?retryWrites=true&w=majority';

