import com.amazonaws.services.lambda.runtime.Context;
import com.amazonaws.services.lambda.runtime.RequestHandler;
import com.amazonaws.services.lambda.runtime.events.S3Event;
import com.amazonaws.services.s3.AmazonS3;
import com.amazonaws.services.s3.AmazonS3ClientBuilder;
import com.amazonaws.services.s3.model.GetObjectRequest;
import com.amazonaws.services.s3.model.ObjectMetadata;
import com.amazonaws.services.s3.model.PutObjectRequest;
import net.coobird.thumbnailator.Thumbnails;

import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.InputStream;

public class ImageResizer implements RequestHandler<S3Event, String> {

    private final AmazonS3 s3 = AmazonS3ClientBuilder.standard().build();

    @Override
    public String handleRequest(S3Event event, Context context) {
        try {
            String bucketName = event.getRecords().get(0).getS3().getBucket().getName();
            String objectKey = event.getRecords().get(0).getS3().getObject().getKey();

            InputStream inputStream = s3.getObject(new GetObjectRequest(bucketName, objectKey)).getObjectContent();
            ByteArrayOutputStream outputStream = new ByteArrayOutputStream();

            // Resize the image to 100x100 pixels
            Thumbnails.of(inputStream)
                    .size(100, 100)
                    .toOutputStream(outputStream);

            byte[] resizedImageBytes = outputStream.toByteArray();
            InputStream resizedImageInputStream = new ByteArrayInputStream(resizedImageBytes);
            ObjectMetadata metadata = new ObjectMetadata();
            metadata.setContentLength(resizedImageBytes.length);

            // Save the resized image back to the S3 bucket with a "resized-" prefix
            s3.putObject(new PutObjectRequest(bucketName, "resized-" + objectKey, resizedImageInputStream, metadata));

            return "Successfully resized image: " + objectKey;
        } catch (IOException e) {
            throw new RuntimeException(e);
        }
    }
}

