    private void PerformOperation(char operation, double num1, double num2)
    {
        double result;

        switch (operation)
        {
            case '+':
                result = num1 + num2;
                break;
            case '-':
                result = num1 - num2;
                break;
            case '*':
                result = num1 * num2;
                break;
            case '/':
                if (num2 == 0)
                {
                    MessageBox.Show("Cannot divide by zero.");
                    return;
                }

                result = num1 / num2;
                break;
            default:
                throw new InvalidOperationException($"Invalid operation: {operation}");
        }

        resultTextBox.Text = result.ToString();
        historyListBox.Items.Add($"{num1} {operation} {num2} = {result}");
    }

