Here is a simple example of how you can interact with PostgreSQL database in GoLang. In this example, we will be using the `pq` package to connect and perform CRUD operations on a table named "users".

```go
package main

import (
	"database/sql"
	"fmt"
	"log"

	_ "github.com/lib/pq"
)

const (
	host     = "localhost"
	port     = 5432
	user     = "postgres"
	password = "your-password"
	dbname   = "test_db"
)

type User struct {
	ID    int
	Name  string
	Email string
}

func main() {
	psqlInfo := fmt.Sprintf("host=%s port=%d user=%s "+
		"password=%s dbname=%s sslmode=disable",
		host, port, user, password, dbname)

	db, err := sql.Open("postgres", psqlInfo)
	if err != nil {
		panic(err)
	}
	defer db.Close()

	err = db.Ping()
	if err != nil {
		panic(err)
	}

	fmt.Println("Successfully connected!")

	// Create
	createUser(db, "John Doe", "johndoe@example.com")

	// Read
	users := getUsers(db)
	for _, user := range users {
		fmt.Printf("ID: %v, Name: %v, Email: %v\n", user.ID, user.Name, user.Email)
	}

	// Update
	updateUser(db, 1, "Jane Doe", "janedoe@example.com")

	// Delete
	deleteUser(db, 1)
}

func createUser(db *sql.DB, name string, email string) {
	sqlStatement := `
	INSERT INTO users (name, email)
	VALUES ($1, $2)`
	_, err := db.Exec(sqlStatement, name, email)
	if err != nil {
		log.Fatalf("Unable to execute the query. %v", err)
	}
	fmt.Println("Inserted a single record")
}

func getUsers(db *sql.DB) []User {
	rows, err := db.Query(`SELECT id, name, email FROM users`)
	if err != nil {
		log.Fatal(err)
	}
	defer rows.Close()

	var users []User
	for rows.Next() {
		var u User
		err := rows.Scan(&u.ID, &u.Name, &u.Email)
		if err != nil {
			log.Fatal(err)
		}
		users = append(users, u)
	}
	return users
}

func updateUser(db *sql.DB, id int, name string, email string) {
	sqlStatement := `
	UPDATE users
	SET name = $2, email = $3
	WHERE id = $1;`
	_, err := db.Exec(sqlStatement, id, name, email)
	if err != nil {
		log.Fatalf("Unable to execute the query. %v", err)
	}
	fmt.Println("Updated a single record")
}

func deleteUser(db *sql.DB, id int) {
	sqlStatement := `
	DELETE FROM users
	WHERE id = $1;`
	_, err := db.Exec(sqlStatement, id)
	if err != nil {
		log.Fatalf("Unable to execute the query. %v", err)
	}
	fmt.Println("Deleted a single record")
}
```

Before running this program, make sure that you have created a table named 'users' in your database.

Note: Replace `"your-password"` with your actual PostgreSQL password. Also, replace `"test_db"` with your actual database name.

import * as Memcached from 'memcached';

const memcached = new Memcached('localhost:11211');

// Function to store key-value pairs in Memcached
function storeKeyValuePair(key: string, value: any): Promise<void> {
  return new Promise((resolve, reject) => {
    memcached.set(key, value, 0, (err) => {
      if (err) {
        reject(err);
      } else {
        resolve();
      }
    });
  });
}

// Function to retrieve values based on keys from Memcached
function getValueByKey(key: string): Promise<any> {
  return new Promise((resolve, reject) => {
    memcached.get(key, (err, data) => {
      if (err) {
        reject(err);
      } else {
        resolve(data);
      }
    });
  });
}

// Main function demonstrating storing and retrieving key-value pairs
async function main() {
  try {
    await storeKeyValuePair('exampleKey', 'exampleValue');
    console.log('Stored key-value pair.');

    const value = await getValueByKey('exampleKey');
    console.log(`Retrieved value by key: ${value}`);
  } catch (error) {
    console.error('Error:', error.message);
  } finally {
    memcached.end();
  }
}

