import (
	"fmt"
	"io/ioutil"
	"net/http"
	"os"
	"strings"
)

func main() {
	fmt.Print("Enter the URL: ")
	var url string
	fmt.Scanln(&url)

	// Add "http://" prefix if not present
	if !strings.HasPrefix(url, "http://") && !strings.HasPrefix(url, "https://") {
		url = "http://" + url
	}

	// Fetch the webpage content
	resp, err := http.Get(url)
	if err != nil {
		fmt.Println("Error fetching the URL:", err)
		return
	}
	defer resp.Body.Close()

	// Check for non-200 status code
	if resp.StatusCode != 200 {
		fmt.Printf("Error: non-200 status code received (%d)\n", resp.StatusCode)
		return
	}

	// Read response body
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		fmt.Println("Error reading response body:", err)
		return
	}

	// Save HTML source code to a local file
	filename := "output.html"
	err = ioutil.WriteFile(filename, body, 0644)
	if err != nil {
		fmt.Println("Error writing to file:", err)
		return
	}

	fmt.Printf("HTML source code saved to %s\n", filename)
}

package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io/ioutil"
	"net/http"

	"github.com/aws/aws-sdk-go/aws"
	"github.com/aws/aws-sdk-go/aws/session"
	"github.com/aws/aws-sdk-go/service/s3"
	"github.com/gorilla/mux"
)

type ErrorResponse struct {
	Message string `json:"message"`
}

func createBucketHandler(s3Client *s3.S3) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		bucketName := r.URL.Query().Get("bucket")

		input := &s3.CreateBucketInput{
			Bucket: aws.String(bucketName),
		}

		_, err := s3Client.CreateBucket(input)
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			json.NewEncoder(w).Encode(ErrorResponse{Message: err.Error()})
			return
		}

		w.WriteHeader(http.StatusOK)
		fmt.Fprintf(w, "Bucket %s created successfully", bucketName)
	}
}

func uploadFileHandler(s3Client *s3.S3) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		bucketName := r.URL.Query().Get("bucket")
		fileName := r.URL.Query().Get("file")

		file, _, err := r.FormFile("file")
		if err != nil {
			w.WriteHeader(http.StatusBadRequest)
			json.NewEncoder(w).Encode(ErrorResponse{Message: err.Error()})
			return
		}
		defer file.Close()

		buffer, err := ioutil.ReadAll(file)
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			json.NewEncoder(w).Encode(ErrorResponse{Message: err.Error()})
			return
		}

		input := &s3.PutObjectInput{
			Bucket: aws.String(bucketName),
			Key:    aws.String(fileName),
			Body:   bytes.NewReader(buffer),
		}

		_, err = s3Client.PutObject(input)
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			json.NewEncoder(w).Encode(ErrorResponse{Message: err.Error()})
			return
		}

		w.WriteHeader(http.StatusOK)
		fmt.Fprintf(w, "File %s uploaded to bucket %s", fileName, bucketName)
	}
}

func downloadFileHandler(s3Client *s3.S3) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		bucketName := r.URL.Query().Get("bucket")
		fileName := r.URL.Query().Get("file")

		input := &s3.GetObjectInput{
			Bucket: aws.String(bucketName),
			Key:    aws.String(fileName),
		}

		result, err := s3Client.GetObject(input)
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			json.NewEncoder(w).Encode(ErrorResponse{Message: err.Error()})
			return
		}
		defer result.Body.Close()

		buffer, err := ioutil.ReadAll(result.Body)
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			json.NewEncoder(w).Encode(ErrorResponse{Message: err.Error()})
			return
		}

		w.Header().Set("Content-Disposition", "attachment; filename="+fileName)
		w.Write(buffer)
	}
}

func deleteFileHandler(s3Client *s3.S3) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		bucketName := r.URL.Query().Get("bucket")
		fileName := r.URL.Query().Get("file")

		input := &s3.DeleteObjectInput{
			Bucket: aws.String(bucketName),
			Key:    aws.String(fileName),
		}

		_, err := s3Client.DeleteObject(input)
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			json.NewEncoder(w).Encode(ErrorResponse{Message: err.Error()})
			return
		}

		w.WriteHeader(http.StatusOK)
		fmt.Fprintf(w, "File %s deleted from bucket %s", fileName, bucketName)
	}
}

func main() {
	sess := session.Must(session.NewSession(&aws.Config{
		Region: aws.String("us-west-2"),
	}))

	s3Client := s3.New(sess)

	router := mux.NewRouter()
	router.HandleFunc("/createBucket", createBucketHandler(s3Client)).Methods("POST")
	router.HandleFunc("/uploadFile", uploadFileHandler(s3Client)).Methods("POST")
	router.HandleFunc("/downloadFile", downloadFileHandler(s3Client)).Methods("GET")
	router.HandleFunc("/deleteFile", deleteFileHandler(s3Client)).Methods("DELETE")

	http.ListenAndServe(":8080", router)
}

import java.io.*;
import java.net.*;
import java.util.*;

public class ChatServer {
    private static final int PORT = 9090;
    private static HashSet<PrintWriter> writers = new HashSet<>();

    public static void main(String[] args) throws IOException {
        System.out.println("Chat Server is running...");
        try (ServerSocket listener = new ServerSocket(PORT)) {
            while (true) {
                new Handler(listener.accept()).start();
            }
        }
    }

    private static class Handler extends Thread {
        private Socket socket;
        private BufferedReader in;
        private PrintWriter out;

        public Handler(Socket socket) {
            this.socket = socket;
        }

        public void run() {
            try {
                in = new BufferedReader(new InputStreamReader(socket.getInputStream()));
                out = new PrintWriter(socket.getOutputStream(), true);

                synchronized (writers) {
                    writers.add(out);
                }

                while (true) {
                    String message = in.readLine();
                    if (message == null) {
                        return;
                    }
                    for (PrintWriter writer : writers) {
                        writer.println(message);
                    }
                }
            } catch (IOException e) {
                System.out.println(e.getMessage());
            } finally {
                if (out != null) {
                    synchronized (writers) {
                        writers.remove(out);
                    }
                }
                try {
                    socket.close();
                } catch (IOException e) {
                }
            }
        }
    }
}

import java.io.*;
import java.net.*;
import java.util.Scanner;

public class ChatClient {
    private static final String SERVER_ADDRESS = "localhost";
    private static final int PORT = 9090;

    public static void main(String[] args) throws IOException {
        try (Socket socket = new Socket(SERVER_ADDRESS, PORT)) {
            BufferedReader in = new BufferedReader(new InputStreamReader(socket.getInputStream()));
            PrintWriter out = new PrintWriter(socket.getOutputStream(), true);

            Thread readThread = new Thread(() -> {
                while (true) {
                    try {
                        System.out.println(in.readLine());
                    } catch (IOException e) {
                        break;
                    }
                }
            });
            readThread.start();

            Scanner scanner = new Scanner(System.in);
            while (scanner.hasNextLine()) {
                out.println(scanner.nextLine());
            }
        }
    }
}

To create a JavaScript/Node.js program that reads a CSV file containing information about employees and inserts this data into a MySQL or MariaDB table, you'll need to follow these steps:

1. Install the required packages: `mysql`, `csv-parser`, and `fs`.
2. Create a connection to your MySQL/MariaDB database.
3. Read the CSV file using the `csv-parser` package.
4. Validate the input data before inserting it into the database.
5. Insert the data into the database.

Here's an example of how you can achieve this:

```javascript
// Import required modules
const mysql = require('mysql');
const fs = require('fs');
const csvParser = require('csv-parser');

// Set up MySQL/MariaDB connection
const connection = mysql.createConnection({
  host: 'localhost',
  user: 'your_username',
  password: 'your_password',
  database: 'your_database'
});

connection.connect((err) => {
  if (err) throw err;
  console.log('Connected to the database!');
});

// Create employees table if not exists
const createTableQuery = `
CREATE TABLE IF NOT EXISTS employees (
  id INT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(255) NOT NULL,
  age INT NOT NULL,
  department VARCHAR(255) NOT NULL
)`;

connection.query(createTableQuery, (err, result) => {
  if (err) throw err;
  console.log('Employees table created or already exists.');
});

// Function to validate employee data
function isValidEmployee(employee) {
  return (
    typeof employee.name === 'string' &&
    !isNaN(parseInt(employee.age)) &&
    typeof employee.department === 'string'
  );
}

// Read CSV file and insert data into the database
fs.createReadStream('employees.csv')
  .pipe(csvParser())
  .on('data', (row) => {
    if (isValidEmployee(row)) {
      const insertQuery = 'INSERT INTO employees SET ?';
      connection.query(insertQuery, row, (err, result) => {
        if (err) throw err;
        console.log(`Inserted employee: ${row.name}`);
      });
    } else {
      console.error(`Invalid employee data: ${JSON.stringify(row)}`);
    }
  })
  .on('end', () => {
    console.log('CSV file processing completed.');
  });
```

Replace `'your_username'`, `'your_password'`, and `'your_database'` with your actual MySQL/MariaDB credentials.

Make sure you have a CSV file named `employees.csv` in the same directory as your script. The CSV file should contain columns for name, age, and department:

```csv
name,age,department
Alice,30,HR
Bob,25,IT
Charlie,35,Finance
```

To run the program, simply execute it using Node.js:

```bash
node import_employees.js
```

This will read the CSV file, validate the input data, and insert the records into the `employees` table in your MySQL or MariaDB database.

You can create a Node.js script using the following code. This script uses memoization to calculate the Fibonacci sequence up to the nth number and accepts user input for the value of n.

```javascript
const readline = require('readline');

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

rl.question('Enter the value of n: ', (n) => {
  const result = fibonacciMemoized(parseInt(n));
  console.log(`The Fibonacci sequence up to the ${n}th number is:`);
  console.log(result);
  rl.close();
});

function fibonacciMemoized(n, memo = {}) {
  if (n <= 0) return [];
  if (n === 1) return [0];
  if (n === 2) return [0, 1];

  if (memo[n]) return memo[n];

  const fibSequence = fibonacciMemoized(n - 1, memo);
  fibSequence.push(fibSequence[fibSequence.length - 1] + fibSequence[fibSequence.length - 2]);
  memo[n] = fibSequence;

  return fibSequence;
}
```

To run this script, save it as `fibonacci_memoized.js` and execute it with Node.js:

```bash
