Here's a simple Golang program that implements a REST API for managing tasks:

```go
package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strconv"

	"github.com/gorilla/mux"
)

type Task struct {
	ID       int    `json:"id"`
	Title    string `json:"title"`
	Status   string `json:"status"`
}

var tasks []Task

func getTasks(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	status := r.URL.Query().Get("status")

	var filteredTasks []Task
	for _, task := range tasks {
		if status == "" || task.Status == status {
			filteredTasks = append(filteredTasks, task)
		}
	}

	json.NewEncoder(w).Encode(filteredTasks)
}

func createTask(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	var newTask Task
	json.NewDecoder(r.Body).Decode(&newTask)
	newTask.ID = len(tasks) + 1
	tasks = append(tasks, newTask)
	json.NewEncoder(w).Encode(newTask)
}

func updateTask(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)
	id, _ := strconv.Atoi(params["id"])

	var updatedTask Task
	json.NewDecoder(r.Body).Decode(&updatedTask)

	for i, task := range tasks {
		if task.ID == id {
			tasks[i].Title = updatedTask.Title
			tasks[i].Status = updatedTask.Status
			json.NewEncoder(w).Encode(tasks[i])
			return
		}
	}

	http.Error(w, "Task not found", http.StatusNotFound)
}

func deleteTask(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)
	id, _ := strconv.Atoi(params["id"])

	for i, task := range tasks {
		if task.ID == id {
			tasks = append(tasks[:i], tasks[i+1:]...)
			break
		}
	}

	json.NewEncoder(w).Encode(tasks)
}

func main() {
	router := mux.NewRouter()

	tasks = append(tasks, Task{ID: 1, Title: "Task One", Status: "pending"})
	tasks = append(tasks, Task{ID: 2, Title: "Task Two", Status: "completed"})

	router.HandleFunc("/tasks", getTasks).Methods("GET")
	router.HandleFunc("/tasks", createTask).Methods("POST")
	router.HandleFunc("/tasks/{id}", updateTask).Methods("PUT")
	router.HandleFunc("/tasks/{id}", deleteTask).Methods("DELETE")

	fmt.Println("Server running on port 8000")
	log.Fatal(http.ListenAndServe(":8000", router))
}
```

To run the program, save it to a file named `main.go` and execute `go run main.go`. The server will start listening on port 8000.

You can use tools like curl or Postman to test the API endpoints. For example:

- To get all tasks: `curl http://localhost:8000/tasks`
- To get completed tasks: `curl http://localhost:8000/tasks?status=completed`
- To create a new task: `curl -X POST -H "Content-Type: application/json" -d '{"title": "New Task", "status": "pending"}' http://localhost:8000/tasks`
- To update a task: `curl -X PUT -H "Content-Type: application/json" -d '{"title": "Updated Task", "status": "completed"}' http://localhost:8000/tasks/1`
