Here's a simple implementation of a singly linked list in Java:

```java
public class SinglyLinkedList {
    private Node head;

    public static class Node {
        int data;
        Node next;

        public Node(int data) {
            this.data = data;
            this.next = null;
        }
    }

    public void add(int data) {
        Node newNode = new Node(data);
        if (head == null) {
            head = newNode;
        } else {
            Node current = head;
            while (current.next != null) {
                current = current.next;
            }
            current.next = newNode;
        }
    }

    public boolean remove(int data) {
        if (head == null) {
            return false;
        }
        if (head.data == data) {
            head = head.next;
            return true;
        }
        Node current = head;
        while (current.next != null) {
            if (current.next.data == data) {
                current.next = current.next.next;
                return true;
            }
            current = current.next;
        }
        return false;
    }

    public boolean search(int data) {
        Node current = head;
        while (current != null) {
            if (current.data == data) {
                return true;
            }
            current = current.next;
        }
        return false;
    }

    public void printList() {
        Node current = head;
        while (current != null) {
            System.out.print(current.data + " -> ");
            current = current.next;
        }
        System.out.println("null");
    }

    public static void main(String[] args) {
        SinglyLinkedList list = new SinglyLinkedList();
        list.add(1);
        list.add(2);
        list.add(3);
        list.add(4);

        System.out.println("Original List:");
        list.printList();

        System.out.println("Search for 3: " + list.search(3));
        System.out.println("Search for 5: " + list.search(5));

        System.out.println("Remove 2:");
        list.remove(2);
        list.printList();

        System.out.println("Remove 1:");
        list.remove(1);
        list.printList();
    }
}
```

This class has a `Node` inner class to represent the elements of the singly linked list. The main class contains methods to add, remove, and search elements within the list. It also includes a `printList()` method to display the contents of the list and a `main()` method to test the functionality.

package main

import (
	"flag"
	"fmt"
	"log"
	"net/http"
	"os"
	"strings"

	"github.com/gorilla/mux"
)

var (
	dir      string
	port     int
	username string
	password string
)

func init() {
	flag.StringVar(&dir, "dir", ".", "Directory to serve")
	flag.IntVar(&port, "port", 8080, "Port to listen on")
	flag.StringVar(&username, "user", "", "Username for basic auth")
	flag.StringVar(&password, "pass", "", "Password for basic auth")
}

func main() {
	flag.Parse()

	if username == "" || password == "" {
		log.Fatal("Please provide both -user and -pass flags.")
		os.Exit(1)
	}

	router := mux.NewRouter()
	router.Use(basicAuthMiddleware)
	router.PathPrefix("/").Handler(http.FileServer(http.Dir(dir)))

	addr := fmt.Sprintf(":%d", port)
	fmt.Printf("Serving %s on %s\n", dir, addr)
	log.Fatal(http.ListenAndServe(addr, router))
}

func basicAuthMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		auth := strings.SplitN(r.Header.Get("Authorization"), " ", 2)

		if len(auth) != 2 || auth[0] != "Basic" {
			http.Error(w, "authorization failed", http.StatusUnauthorized)
			return
		}

		payload, err := base64.StdEncoding.DecodeString(auth[1])
		if err != nil {
			http.Error(w, "authorization failed", http.StatusBadRequest)
			return
		}

		pair := strings.SplitN(string(payload), ":", 2)
		if len(pair) != 2 || !(pair[0] == username && pair[1] == password) {
			http.Error(w, "authorization failed", http.StatusUnauthorized)
			return
		}

		next.ServeHTTP(w, r)
	})
}

