    private static final String USER = "your_username";
    private static final String PASS = "your_password";

    public static void main(String[] args) {
        try (Connection connection = DriverManager.getConnection(DB_URL, USER, PASS)) {
            System.out.println("Connected to the PostgreSQL server successfully.");

            // Create a new table
            createTable(connection);

            // Insert sample data
            insertData(connection);

            // Query the table and display the results
            queryAndDisplayResults(connection);
        } catch (SQLException e) {
            System.err.format("SQL State: %s\n%s", e.getSQLState(), e.getMessage());
        }
    }

    private static void createTable(Connection connection) throws SQLException {
        String createTableSql = "CREATE TABLE IF NOT EXISTS employees (" +
                "id SERIAL PRIMARY KEY," +
                "name VARCHAR(100) NOT NULL," +
                "position VARCHAR(100) NOT NULL" +
                ")";
        try (Statement statement = connection.createStatement()) {
            statement.execute(createTableSql);
        }
    }

    private static void insertData(Connection connection) throws SQLException {
        String insertSql = "INSERT INTO employees (name, position) VALUES (?, ?)";
        try (PreparedStatement preparedStatement = connection.prepareStatement(insertSql)) {
            preparedStatement.setString(1, "John Doe");
            preparedStatement.setString(2, "Software Engineer");
            preparedStatement.executeUpdate();
        }
    }

    private static void queryAndDisplayResults(Connection connection) throws SQLException {
        String querySql = "SELECT * FROM employees";
        try (Statement statement = connection.createStatement()) {
            ResultSet resultSet = statement.executeQuery(querySql);
            System.out.println("ID\tName\tPosition");
            while (resultSet.next()) {
                int id = resultSet.getInt("id");
                String name = resultSet.getString("name");
                String position = resultSet.getString("position");
                System.out.printf("%d\t%s\t%s\n", id, name, position);
            }
        }
    }
}

