#include <iostream>

class Node {
public:
    int data;
    Node* left;
    Node* right;

    Node(int value) : data(value), left(nullptr), right(nullptr) {}
};

class BinarySearchTree {
public:
    Node* root;

    BinarySearchTree() : root(nullptr) {}

    void insert(int value) {
        if (root == nullptr) {
            root = new Node(value);
        } else {
            insertHelper(root, value);
        }
    }

    void remove(int value) {
        root = removeHelper(root, value);
    }

    void inOrderTraversal() {
        inOrderHelper(root);
        std::cout << std::endl;
    }

    void preOrderTraversal() {
        preOrderHelper(root);
        std::cout << std::endl;
    }

    void postOrderTraversal() {
        postOrderHelper(root);
        std::cout << std::endl;
    }

private:
    void insertHelper(Node* node, int value) {
        if (value < node->data) {
            if (node->left == nullptr) {
                node->left = new Node(value);
            } else {
                insertHelper(node->left, value);
            }
        } else {
            if (node->right == nullptr) {
                node->right = new Node(value);
            } else {
                insertHelper(node->right, value);
            }
        }
    }

    Node* removeHelper(Node* node, int value) {
        if (node == nullptr) {
            return node;
        }

        if (value < node->data) {
            node->left = removeHelper(node->left, value);
        } else if (value > node->data) {
            node->right = removeHelper(node->right, value);
        } else {
            if (node->left == nullptr) {
                Node* temp = node->right;
                delete node;
                return temp;
            } else if (node->right == nullptr) {
                Node* temp = node->left;
                delete node;
                return temp;
            }

            node->data = minValue(node->right);
            node->right = removeHelper(node->right, node->data);
        }
        return node;
    }

    int minValue(Node* node) {
        int minValue = node->data;
        while (node->left != nullptr) {
            minValue = node->left->data;
            node = node->left;
        }
        return minValue;
    }

    void inOrderHelper(Node* node) {
        if (node != nullptr) {
            inOrderHelper(node->left);
            std::cout << node->data << " ";
            inOrderHelper(node->right);
        }
    }

    void preOrderHelper(Node* node) {
        if (node != nullptr) {
            std::cout << node->data << " ";
            preOrderHelper(node->left);
            preOrderHelper(node->right);
        }
    }

    void postOrderHelper(Node* node) {
        if (node != nullptr) {
            postOrderHelper(node->left);
            postOrderHelper(node->right);
            std::cout << node->data << " ";
        }
    }
};

int main() {
    BinarySearchTree bst;

    bst.insert(50);
    bst.insert(30);
    bst.insert(20);
    bst.insert(40);
    bst.insert(70);
    bst.insert(60);
    bst.insert(80);

    std::cout << "In-order traversal: ";
    bst.inOrderTraversal();

    std::cout << "Pre-order traversal: ";
    bst.preOrderTraversal();

    std::cout << "Post-order traversal: ";
    bst.postOrderTraversal();

    bst.remove(20);
    std::cout << "In-order traversal after deleting 20: ";
    bst.inOrderTraversal();

    bst.remove(30);
    std::cout << "In-order traversal after deleting 30: ";
    bst.inOrderTraversal();

    bst.remove(50);
    std::cout << "In-order traversal after deleting 50: ";
    bst.inOrderTraversal();

    return 0;
}
