using namespace cv;
using namespace std;

// Function to detect faces in an image using a Haar cascade classifier
void detectFaces(Mat &frame, CascadeClassifier &face_cascade) {
    vector<Rect> faces;
    Mat frame_gray;

    // Convert the image to grayscale and equalize the histogram
    cvtColor(frame, frame_gray, COLOR_BGR2GRAY);
    equalizeHist(frame_gray, frame_gray);

    // Detect faces in the grayscale image
    face_cascade.detectMultiScale(frame_gray, faces, 1.1, 3, 0 | CASCADE_SCALE_IMAGE, Size(30, 30));

    // Draw rectangles around detected faces
    for (size_t i = 0; i < faces.size(); i++) {
        rectangle(frame, faces[i], Scalar(255, 0, 0), 2);
    }
}

int main(int argc, char** argv) {
    if (argc != 2) {
        cout << "Usage: ./image_processor <path_to_image>" << endl;
        return -1;
    }

    String face_cascade_name = "haarcascade_frontalface_alt.xml";
    CascadeClassifier face_cascade;

    // Load the Haar cascade classifier
    if (!face_cascade.load(face_cascade_name)) {
        cout << "Error loading face cascade." << endl;
        return -1;
    }

    // Read the input image
    Mat image = imread(argv[1], IMREAD_COLOR);

    if (image.empty()) {
        cout << "Could not open or find the image." << endl;
        return -1;
    }

    // Detect faces in the image
    detectFaces(image, face_cascade);

    // Apply grayscale filter
    Mat gray_image;
    cvtColor(image, gray_image, COLOR_BGR2GRAY);
    imwrite("gray_image.jpg", gray_image);

    // Apply blur filter
    Mat blurred_image;
    GaussianBlur(image, blurred_image, Size(15, 15), 0);
    imwrite("blurred_image.jpg", blurred_image);

    // Display the original and processed images in separate windows
    namedWindow("Original Image", WINDOW_AUTOSIZE);
    imshow("Original Image", image);

    namedWindow("Gray Image", WINDOW_AUTOSIZE);
    imshow("Gray Image", gray_image);

    namedWindow("Blurred Image", WINDOW_AUTOSIZE);
    imshow("Blurred Image", blurred_image);

    waitKey(0);

    return 0;
}

