#include <iostream>
#include <fstream>
#include <was/storage_account.h>
#include <was/blob.h>

int main(int argc, char* argv[]) {
    if (argc != 5) {
        std::cout << "Usage: ./azure_blob_download <account_name> <access_key> <container_name> <output_file_path>" << std::endl;
        return 1;
    }

    std::string account_name = argv[1];
    std::string access_key = argv[2];
    std::string container_name = argv[3];
    std::string output_file_path = argv[4];

    utility::string_t connection_string = U("DefaultEndpointsProtocol=https;AccountName=") + utility::conversions::to_string_t(account_name) + U(";AccountKey=") + utility::conversions::to_string_t(access_key) + U(";EndpointSuffix=core.windows.net");

    azure::storage::cloud_storage_account storage_account = azure::storage::cloud_storage_account::parse(connection_string);
    azure::storage::cloud_blob_client blob_client = storage_account.create_cloud_blob_client();

    azure::storage::cloud_blob_container container = blob_client.get_container_reference(utility::conversions::to_string_t(container_name));
    container.exists();

    std::ofstream output_file(output_file_path, std::ios::binary);

    for (auto iter = container.list_blobs(); iter != list_blob_item_iterator(); ++iter) {
        if (iter->is_blob()) {
            auto blob = iter->as_blob();

            concurrency::streams::ostream output_stream = concurrency::streams::bytestream::open_ostream<uint8_t>(output_file).get();
            blob.download_to_stream(output_stream);
            output_stream.close().wait();
        }
    }

    output_file.close();
    return 0;
}
