package main

import (
	"fmt"
	"strings"
	"unicode"
)

func countVowelsAndConsonants(s string) (int, int) {
	vowels := 0
	consonants := 0
	for _, runeValue := range s {
		if unicode.IsLetter(runeValue) {
			switch strings.ToLower(string(runeValue)) {
			case "a", "e", "i", "o", "u":
				vowels++
			default:
				consonants++
			}
		}
	}
	return vowels, consonants
}

func main() {
	vowels, consonants := countVowelsAndConsonants("Hello World!")
	fmt.Printf("Vowels: %d, Consonants: %d\n", vowels, consonants)
}
