            // Update guessedWord with correct guesses
            for (size_t i = 0; i < chosenWord.length(); ++i) {
                if (chosenWord[i] == guess) {
                    guessedWord[i] = guess;
                }
            }
        } else {
            --attemptsRemaining;
        }
    }

    // Game over
    if (guessedWord == chosenWord) {
        std::cout << "Congratulations! You guessed the word: " << chosenWord << std::endl;
    } else {
        std::cout << "Sorry, you ran out of attempts. The correct word was: " << chosenWord << std::endl;
    }

    return 0;
}

