// Create directory for storing images if it doesn't exist
const imageDir = 'images';
if (!fs.existsSync(imageDir)) {
  fs.mkdirSync(imageDir);
}

// Function to generate MD5 hash of a file
function md5File(file) {
  const buffer = fs.readFileSync(file.path);
  return crypto.createHash('md5').update(buffer).digest('hex');
}

// Upload endpoint
app.post('/upload', upload.single('image'), (req, res) => {
  if (!req.file) {
    return res.status(400).send('No file uploaded.');
  }

  const allowedMimeTypes = ['image/jpeg', 'image/png'];
  if (!allowedMimeTypes.includes(req.file.mimetype)) {
    fs.unlinkSync(req.file.path); // Delete the temporary file
    return res.status(400).send('Invalid file type. Only JPEG and PNG are allowed.');
  }

  const md5hash = md5File(req.file);
  const ext = path.extname(req.file.originalname);
  const newPath = path.join(imageDir, md5hash + ext);

  fs.renameSync(req.file.path, newPath); // Move the temporary file to the new path
  res.send({ id: md5hash });
});

// Retrieve image endpoint
app.get('/image/:id', (req, res) => {
  const { id } = req.params;
  const imagePathJpeg = path.join(imageDir, id + '.jpeg');
  const imagePathPng = path.join(imageDir, id + '.png');

  if (fs.existsSync(imagePathJpeg)) {
    res.sendFile(path.resolve(imagePathJpeg));
  } else if (fs.existsSync(imagePathPng)) {
    res.sendFile(path.resolve(imagePathPng));
  } else {
