function wordFrequency(str) {
  // Match words and convert to lowercase
  const words = str.toLowerCase().match(/\b\w+\b/g);
  const wordCount = {};

  if (!words) return wordCount;

  // Count the frequency of each unique word
  for (const word of words) {
    if (wordCount[word]) {
      wordCount[word]++;
    } else {
      wordCount[word] = 1;
    }
  }

