            if (node->left == nullptr) {
                node->left = new Node(value);
            } else {
                insertHelper(node->left, value);
            }
        } else {
            if (node->right == nullptr) {
                node->right = new Node(value);
            } else {
                insertHelper(node->right, value);
            }
        }
