import org.json.JSONArray;
import org.json.JSONObject;

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;

public class DataFilter {

    public JSONArray filterByDateAndCategory(JSONArray inputArray, LocalDate startDate, LocalDate endDate, String category) {
        JSONArray filteredArray = new JSONArray();

        for (int i = 0; i < inputArray.length(); i++) {
            JSONObject jsonObject = inputArray.getJSONObject(i);
            LocalDate date = LocalDate.parse(jsonObject.getString("date"), DateTimeFormatter.ISO_DATE);

            if (date.isAfter(startDate) && date.isBefore(endDate) && jsonObject.getString("category").equalsIgnoreCase(category)) {
                filteredArray.put(jsonObject);
            }
        }

        return filteredArray;
    }
}
