import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.util.HashMap;
import java.util.LinkedHashMap;
import java.util.Map;
import java.util.stream.Collectors;

public class WordFrequencyCounter {

    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Please provide a file path as an argument.");
            return;
        }

        String filePath = args[0];
        Map<String, Integer> wordCountMap = new HashMap<>();

        // Read the file and count the frequency of each word
        try (BufferedReader reader = new BufferedReader(new FileReader(filePath))) {
            String line;
            while ((line = reader.readLine()) != null) {
                String[] words = line.toLowerCase().split("\\W+");
                for (String word : words) {
                    if (!word.isEmpty()) {
                        wordCountMap.put(word, wordCountMap.getOrDefault(word, 0) + 1);
                    }
                }
            }
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
            return;
        }

        // Sort the word count map by frequency in descending order
        Map<String, Integer> sortedWordCountMap = wordCountMap.entrySet().stream()
                .sorted(Map.Entry.<String, Integer>comparingByValue().reversed())
                .collect(Collectors.toMap(Map.Entry::getKey, Map.Entry::getValue,
                        (e1, e2) -> e1, LinkedHashMap::new));

        // Print the results
        for (Map.Entry<String, Integer> entry : sortedWordCountMap.entrySet()) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }
    }
}

import java.io.*;
import java.net.ServerSocket;
import java.net.Socket;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.text.SimpleDateFormat;
import java.util.Date;

public class SimpleHttpServer {

    private final int port;
    private final String rootDirectory;
    private final String logFile;

    public SimpleHttpServer(int port, String rootDirectory, String logFile) {
        this.port = port;
        this.rootDirectory = rootDirectory;
        this.logFile = logFile;
    }

    public void start() throws IOException {
        try (ServerSocket serverSocket = new ServerSocket(port)) {
            System.out.println("Server started on port " + port);

            while (true) {
                Socket clientSocket = serverSocket.accept();
                handleRequest(clientSocket);
            }
        }
    }

    private void handleRequest(Socket socket) {
        try (BufferedReader in = new BufferedReader(new InputStreamReader(socket.getInputStream()));
             PrintWriter out = new PrintWriter(socket.getOutputStream());
             BufferedWriter logWriter = new BufferedWriter(new FileWriter(logFile, true))) {

            String requestLine = in.readLine();

            if (requestLine == null || requestLine.isEmpty()) {
                return;
            }

            // Log the request
            SimpleDateFormat dateFormat = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss");
            String timestamp = dateFormat.format(new Date());
            logWriter.write(timestamp + " - " + requestLine);
            logWriter.newLine();

            String[] tokens = requestLine.split(" ");
            String method = tokens[0];
            String requestedPath = tokens[1];

            if (!method.equals("GET")) {
                sendResponse(out, 405, "Method Not Allowed", "");
                return;
            }

            Path filePath = Paths.get(rootDirectory, requestedPath.substring(1));
            if (!Files.exists(filePath) || Files.isDirectory(filePath)) {
                sendResponse(out, 404, "Not Found", "");
                return;
            }

            String contentType = Files.probeContentType(filePath);
            byte[] fileContent = Files.readAllBytes(filePath);

            out.print("HTTP/1.1 200 OK\r\n");
            out.print("Content-Type: " + contentType + "\r\n");
            out.print("Content-Length: " + fileContent.length + "\r\n");
            out.print("\r\n");
            out.flush();

            socket.getOutputStream().write(fileContent);
            socket.getOutputStream().flush();
        } catch (IOException e) {
            System.err.println("Error handling request: " + e.getMessage());
        }
    }

    private void sendResponse(PrintWriter out, int statusCode, String statusMessage, String body) {
        out.print("HTTP/1.1 " + statusCode + " " + statusMessage + "\r\n");
        out.print("Content-Type: text/plain\r\n");
        out.print("Content-Length: " + body.length() + "\r\n");
        out.print("\r\n");
        out.print(body);
        out.flush();
    }

    public static void main(String[] args) throws IOException {
        if (args.length != 3) {
            System.out.println("Usage: java SimpleHttpServer <port> <root_directory> <log_file>");
            return;
        }

        int port = Integer.parseInt(args[0]);
        String rootDirectory = args[1];
        String logFile = args[2];

        SimpleHttpServer server = new SimpleHttpServer(port, rootDirectory, logFile);
        server.start();
    }
}

