type Node struct {
	data int
	next *Node
}

type LinkedList struct {
	head *Node
	size int
}

func (list *LinkedList) AddAtBeginning(value int) {
	newNode := &Node{data: value}
	if list.head == nil {
		list.head = newNode
	} else {
		newNode.next = list.head
		list.head = newNode
	}
	list.size++
}

func (list *LinkedList) AddAtEnd(value int) {
	newNode := &Node{data: value}
	if list.head == nil {
		list.head = newNode
	} else {
		current := list.head
		for current.next != nil {
			current = current.next
		}
		current.next = newNode
	}
	list.size++
}

func (list *LinkedList) AddAtPosition(position, value int) {
	if position < 0 || position > list.size {
		fmt.Println("Invalid position")
		return
	}

	if position == 0 {
		list.AddAtBeginning(value)
		return
	}

	newNode := &Node{data: value}
	current := list.head
	index := 1
	for index < position {
		current = current.next
		index++
	}
	newNode.next = current.next
	current.next = newNode
	list.size++
}

func (list *LinkedList) RemoveByValue(value int) {
	if list.head == nil {
		return
	}

	if list.head.data == value {
		list.head = list.head.next
		list.size--
		return
	}

	current := list.head
	for current.next != nil && current.next.data != value {
		current = current.next
	}

	if current.next != nil {
		current.next = current.next.next
		list.size--
	}
}

func (list *LinkedList) Display() {
	current := list.head
	for current != nil {
		fmt.Printf("%d -> ", current.data)
		current = current.next
	}
	fmt.Println("nil")
}

func main() {
	list := &LinkedList{}
	list.AddAtBeginning(1)
	list.AddAtEnd(2)
	list.AddAtEnd(3)
	list.Display()

	list.AddAtPosition(0, 0)
	list.AddAtPosition(4, 4)
	list.Display()

	list.RemoveByValue(0)
	list.RemoveByValue(4)
	list.Display()
}
