This Golang program implements a singly linked list data structure with methods for adding elements at the beginning, end, and at a specific position, as well as removing elements by value and displaying the contents of the list. The `main` function demonstrates how to use these methods to manipulate the linked list.

class Node:
    def __init__(self, data=None):
        self.data = data
        self.next = None

class SinglyLinkedList:
    def __init__(self):
        self.head = None

    def insert_at_beginning(self, data):
        new_node = Node(data)
        new_node.next = self.head
        self.head = new_node

    def insert_at_end(self, data):
        new_node = Node(data)

        if not self.head:
            self.head = new_node
            return

        last_node = self.head
        while last_node.next:
            last_node = last_node.next

        last_node.next = new_node

    def insert_at_position(self, position, data):
        if position < 0:
            raise ValueError("Position must be a non-negative integer")

        if position == 0:
            self.insert_at_beginning(data)
            return

        new_node = Node(data)
        current_node = self.head
        for _ in range(position - 1):
            if not current_node:
                raise IndexError("Position out of range")
            current_node = current_node.next

        new_node.next = current_node.next
        current_node.next = new_node

    def delete_by_value(self, value):
        if not self.head:
            raise ValueError("List is empty")

        if self.head.data == value:
            self.head = self.head.next
            return

        current_node = self.head
        while current_node.next and current_node.next.data != value:
            current_node = current_node.next

        if not current_node.next:
            raise ValueError(f"Value {value} not found in the list")

        current_node.next = current_node.next.next

    def display(self):
        elements = []
        current_node = self.head
        while current_node:
            elements.append(current_node.data)
            current_node = current_node.next
        return elements

if __name__ == "__main__":
    sll = SinglyLinkedList()
    sll.insert_at_beginning(1)
    sll.insert_at_end(2)
    sll.insert_at_position(1, 3)
    print(sll.display())  # Output: [1, 3, 2]
    sll.delete_by_value(3)
    print(sll.display())  # Output: [1, 2]

package main

import (
	"compress/gzip"
	"flag"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strings"
)

func main() {
	var input string
	var output string
	var level int
	var decompress bool

	flag.StringVar(&input, "i", "", "Input file or directory")
	flag.StringVar(&output, "o", "", "Output file or directory")
	flag.IntVar(&level, "l", gzip.DefaultCompression, "Compression level (0-9)")
	flag.BoolVar(&decompress, "d", false, "Decompress mode")

	flag.Parse()

	if input == "" || output == "" {
		fmt.Println("Please specify both input and output paths.")
		os.Exit(1)
	}

	err := filepath.Walk(input, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}

		if !info.IsDir() {
			outPath := strings.Replace(path, input, output, 1)

			if decompress {
				err = decompressFile(path, outPath)
			} else {
				err = compressFile(path, outPath, level)
			}

			if err != nil {
				return err
			}
		}

		return nil
	})

	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}
}

func compressFile(src, dest string, level int) error {
	srcFile, err := os.Open(src)
	if err != nil {
		return err
	}
	defer srcFile.Close()

	err = os.MkdirAll(filepath.Dir(dest), 0755)
	if err != nil {
		return err
	}

	destFile, err := os.Create(dest + ".gz")
	if err != nil {
		return err
	}
	defer destFile.Close()

	gw, err := gzip.NewWriterLevel(destFile, level)
	if err != nil {
		return err
	}
	defer gw.Close()

	_, err = io.Copy(gw, srcFile)
	return err
}

func decompressFile(src, dest string) error {
	srcFile, err := os.Open(src)
	if err != nil {
		return err
	}
	defer srcFile.Close()

	gr, err := gzip.NewReader(srcFile)
	if err != nil {
		return err
	}
	defer gr.Close()

	err = os.MkdirAll(filepath.Dir(dest), 0755)
	if err != nil {
		return err
	}

	destFile, err := os.Create(strings.TrimSuffix(dest, ".gz"))
	if err != nil {
		return err
	}
	defer destFile.Close()

	_, err = io.Copy(destFile, gr)
	return err
}

Here's a Golang program that monitors a specified directory for changes and sends notifications to a specified email address using an SMTP server when changes are detected. Make sure to replace the placeholders with your own information.

