package main

import (
	"flag"
	"fmt"
	"math/rand"
	"time"
)

const (
	lowercaseLetters = "abcdefghijklmnopqrstuvwxyz"
	uppercaseLetters = "ABCDEFGHIJKLMNOPQRSTUVWXYZ"
	digits           = "0123456789"
	specialChars     = "!@#$%^&*()-_=+{}[]|;:,.<>?/~`"
	allChars         = lowercaseLetters + uppercaseLetters + digits + specialChars
)

func main() {
	length := flag.Int("length", 8, "Password length")
	flag.Parse()

	if *length < 4 {
		fmt.Println("Error: Password length must be at least 4.")
		return
	}

	rand.Seed(time.Now().UnixNano())
	password := generateRandomPassword(*length)
	fmt.Printf("Generated password: %s\n", password)
}

func generateRandomPassword(length int) string {
	password := make([]byte, length)

	// Ensure there is at least one character from each required set.
	password[0] = lowercaseLetters[rand.Intn(len(lowercaseLetters))]
	password[1] = uppercaseLetters[rand.Intn(len(uppercaseLetters))]
	password[2] = digits[rand.Intn(len(digits))]
	password[3] = specialChars[rand.Intn(len(specialChars))]

	// Fill the rest of the password with random characters.
	for i := 4; i < length; i++ {
		password[i] = allChars[rand.Intn(len(allChars))]
	}

	// Shuffle the password to mix up the required characters.
	for i := range password {
		j := rand.Intn(i + 1)
		password[i], password[j] = password[j], password[i]
	}

	return string(password)
}

import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Statement;

public class EmployeeDatabase {

    private static final String DB_URL = "jdbc:postgresql://localhost:5432/your_database";
    private static final String DB_USER = "your_username";
    private static final String DB_PASSWORD = "your_password";

    public static void main(String[] args) {
        try {
            // Load the PostgreSQL JDBC driver
            Class.forName("org.postgresql.Driver");

            // Connect to the database
            Connection connection = DriverManager.getConnection(DB_URL, DB_USER, DB_PASSWORD);

            // Perform CRUD operations
            int newEmployeeId = createEmployee(connection, "John Doe", "Software Engineer", 80000);
            System.out.println("Created new employee with ID: " + newEmployeeId);

            updateEmployee(connection, newEmployeeId, "Senior Software Engineer", 90000);
            System.out.println("Updated employee's job title and salary");

            Employee employee = readEmployee(connection, newEmployeeId);
            System.out.println("Retrieved employee: " + employee);

            deleteEmployee(connection, newEmployeeId);
            System.out.println("Deleted employee with ID: " + newEmployeeId);

            connection.close();
        } catch (ClassNotFoundException | SQLException e) {
            e.printStackTrace();
        }
    }

    private static int createEmployee(Connection connection, String name, String jobTitle, double salary) throws SQLException {
        String sql = "INSERT INTO employees (name, job_title, salary) VALUES (?, ?, ?)";
        PreparedStatement statement = connection.prepareStatement(sql, Statement.RETURN_GENERATED_KEYS);
        statement.setString(1, name);
        statement.setString(2, jobTitle);
        statement.setDouble(3, salary);
        statement.executeUpdate();

        ResultSet generatedKeys = statement.getGeneratedKeys();
        if (generatedKeys.next()) {
            return generatedKeys.getInt(1);
        } else {
            throw new SQLException("Creating employee failed, no ID obtained.");
        }
    }

    private static Employee readEmployee(Connection connection, int id) throws SQLException {
        String sql = "SELECT * FROM employees WHERE id = ?";
        PreparedStatement statement = connection.prepareStatement(sql);
        statement.setInt(1, id);
        ResultSet resultSet = statement.executeQuery();

        if (resultSet.next()) {
            String name = resultSet.getString("name");
            String jobTitle = resultSet.getString("job_title");
            double salary = resultSet.getDouble("salary");
            return new Employee(id, name, jobTitle, salary);
        } else {
            return null;
        }
    }

    private static void updateEmployee(Connection connection, int id, String newJobTitle, double newSalary) throws SQLException {
        String sql = "UPDATE employees SET job_title = ?, salary = ? WHERE id = ?";
        PreparedStatement statement = connection.prepareStatement(sql);
        statement.setString(1, newJobTitle);
        statement.setDouble(2, newSalary);
        statement.setInt(3, id);
        statement.executeUpdate();
    }

    private static void deleteEmployee(Connection connection, int id) throws SQLException {
        String sql = "DELETE FROM employees WHERE id = ?";
        PreparedStatement statement = connection.prepareStatement(sql);
        statement.setInt(1, id);
        statement.executeUpdate();
    }
}

