      // If it's a directory, recursively search inside
      if (file.isDirectory()) {
        findFilesWithPattern(fullPath, pattern);
      } else {
        // Read the file and check if it contains the pattern
        fs.readFile(fullPath, 'utf8', (err, data) => {
