// uploadHandler handles the image uploading and calls createThumbnail function
func uploadHandler(w http.ResponseWriter, r *http.Request) {
	r.ParseMultipartForm(10 << 20) // Limit file size to 10MB

	file, header, err := r.FormFile("file")
	if err != nil {
		fmt.Println("Error retrieving file from form data")
		fmt.Println(err)
		return
	}
	defer file.Close()

	tempFile, err := ioutil.TempFile(imageDir, "upload-*.jpg")
	if err != nil {
		fmt.Println(err)
		return
	}
	defer tempFile.Close()

	fileBytes, err := ioutil.ReadAll(file)
	if err != nil {
		fmt.Println(err)
		return
	}

	tempFile.Write(fileBytes)

	createThumbnail(tempFile.Name(), header.Filename)

	fmt.Fprintf(w, "Successfully uploaded and thumbnail created")
}

// createThumbnail generates a thumbnail of the uploaded image using nfnt/resize library
func createThumbnail(imagePath string, imageName string) {
	file, err := os.Open(imagePath)
	if err != nil {
		log.Fatal(err)
	}
	defer file.Close()

	img, err := jpeg.Decode(file)
	if err != nil {
		log.Fatal(err)
	}

	thumb := resize.Thumbnail(thumbnailSize, thumbnailSize, img, resize.Lanczos3)

	out, err := os.Create(thumbnailDir + imageName)
	if err != nil {
		log.Fatal(err)
	}
	defer out.Close()

	jpeg.Encode(out, thumb, &jpeg.Options{Quality: 80})
}
