#include <iostream>
#include <queue>
#include <mutex>
#include <condition_variable>
#include <thread>
#include <chrono>
#include <random>

std::queue<int> buffer;
const unsigned int bufferSize = 10;

std::mutex mtx;
std::condition_variable cvProducer, cvConsumer;

bool finishedProducing = false;

void producer() {
    std::default_random_engine generator;
    std::uniform_int_distribution<int> distribution(1, 100);

    for (int i = 0; i < 20; ++i) {
        int randomNumber = distribution(generator);
        std::unique_lock<std::mutex> lock(mtx);

        // Wait until there is space in the buffer to add a new number
        cvProducer.wait(lock, [] { return buffer.size() < bufferSize; });

        buffer.push(randomNumber);
        std::cout << "Produced: " << randomNumber << std::endl;

        lock.unlock();
        cvConsumer.notify_one();

        std::this_thread::sleep_for(std::chrono::milliseconds(50));
    }

    finishedProducing = true;
}

void consumer() {
    int sum = 0;

    while (!finishedProducing || !buffer.empty()) {
        std::unique_lock<std::mutex> lock(mtx);

        // Wait until there is a number available in the buffer
        cvConsumer.wait(lock, [] { return !buffer.empty(); });

        if (!buffer.empty()) {
            int num = buffer.front();
            buffer.pop();
            sum += num;
            std::cout << "Consumed: " << num << ", Sum: " << sum << std::endl;
        }

        lock.unlock();
        cvProducer.notify_one();

        std::this_thread::sleep_for(std::chrono::milliseconds(50));
    }
}

int main() {
    std::thread producerThread(producer);
    std::thread consumerThread(consumer);

    producerThread.join();
    consumerThread.join();

    return 0;
}
```

This C++ program simulates a producer-consumer scenario using multithreading. The `producer` function generates random numbers and adds them to the shared buffer, while the `consumer` function removes the numbers from the buffer and calculates their sum.

The program uses a mutex (`mtx`) and two condition variables (`cvProducer` and `cvConsumer`) for synchronization between the threads. The producer thread waits until there is space in the buffer before adding a new number, and the consumer thread waits until there is a number available in the buffer before consuming it.

The main function creates the producer and consumer threads and joins them at the end of execution.

