async function uploadFileAndGetPublicUrl(bucketName: string, filePath: string): Promise<string> {
  try {
    // Upload the local file to the specified bucket
    const response = await storage.bucket(bucketName).upload(filePath);

    // Get the uploaded file's metadata
    const metadata = response[0].metadata;

    // Check if the file is publicly accessible
    if (metadata && metadata.accessControl) {
      for (const acl of metadata.accessControl) {
        if (acl.entity === 'allUsers' && acl.role === 'READER') {
          return metadata.mediaLink;
        }
      }
    }

    // If not publicly accessible, make it so and return the public URL
    await storage.bucket(bucketName).file(metadata.name).makePublic();
    return metadata.mediaLink;
  } catch (error) {
    console.error('Error uploading file:', error);
    throw error;
  }
}

