void generate_sales_report(pqxx::connection &conn, const std::string &start_date, const std::string &end_date) {
    try {
        pqxx::work txn(conn);

        // Query to get total sales amount grouped by product category within the specified date range
        std::string query = "SELECT product_category, SUM(sales_amount) "
                            "FROM sales "
                            "WHERE sale_date >= '" + start_date + "' AND sale_date <= '" + end_date + "' "
                            "GROUP BY product_category;";

        pqxx::result res = txn.exec(query);

        std::cout << "Product Category\tTotal Sales Amount\n";
        for (const auto &row : res) {
            std::cout << row[0].as<std::string>() << "\t" << row[1].as<double>() << std::endl;
        }

        txn.commit();
    } catch (const std::exception &e) {
        std::cerr << e.what() << std::endl;
    }
}

