// uploadHandler handles file uploads
func uploadHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method == "POST" {
		file, header, err := r.FormFile("file")
		if err != nil {
			w.WriteHeader(http.StatusBadRequest)
			fmt.Fprintln(w, "Error retrieving file from form-data")
			return
		}
		defer file.Close()

		out, err := os.Create(filepath.Join(staticDir, header.Filename))
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			fmt.Fprintln(w, "Error creating file on server")
			return
		}
		defer out.Close()

		_, err = io.Copy(out, file)
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			fmt.Fprintln(w, "Error saving file to server")
			return
		}

		w.WriteHeader(http.StatusCreated)
		fmt.Fprintf(w, "File uploaded successfully: %s", header.Filename)
	} else {
		w.WriteHeader(http.StatusMethodNotAllowed)
		fmt.Fprintln(w, "Only POST method is allowed")
	}
}

// listHandler lists all available files in the static directory
func listHandler(w http.ResponseWriter, r *http.Request) {
	files, err := ioutil.ReadDir(staticDir)
	if err != nil {
		w.WriteHeader(http.StatusInternalServerError)
		fmt.Fprintln(w, "Error reading files from server")
		return
	}

	w.WriteHeader(http.StatusOK)
	for _, file := range files {
		fmt.Fprintln(w, file.Name())
	}
}

