            Socket serverSocket = new Socket(AddressFamily.InterNetwork, SocketType.Stream, ProtocolType.Tcp);
            IPEndPoint endPoint = new IPEndPoint(ipAddress, port);

            serverSocket.Bind(endPoint);
            serverSocket.Listen(10);

            Console.WriteLine("Chat server started on port " + port);

            while (true)
            {
                Socket clientSocket = serverSocket.Accept();
                lock (_lock)
                {
                    _clients.Add(clientSocket);
                }
                Thread thread = new Thread(HandleClient);
                thread.Start(clientSocket);
            }
        }

        public static void HandleClient(object obj)
        {
            Socket clientSocket = (Socket)obj;
            byte[] buffer = new byte[1024];

            try
            {
                while (true)
                {
                    int receivedBytes = clientSocket.Receive(buffer);
                    string message = Encoding.ASCII.GetString(buffer, 0, receivedBytes);

                    Console.WriteLine("Received message: " + message);

                    lock (_lock)
                    {
                        foreach (Socket client in _clients)
                        {
                            if (client != clientSocket)
                            {
                                client.Send(Encoding.ASCII.GetBytes(message));
                            }
                        }
                    }
                }
            }
            catch (SocketException ex)
            {
                Console.WriteLine("Client disconnected");
            }
            finally
            {
                lock (_lock)
                {
                    _clients.Remove(clientSocket);
                }
                clientSocket.Close();
            }
        }

        static void Main(string[] args)
        {
            StartServer();
        }
    }
}

You can create a Node.js script that reads all files in a given directory, compresses them using gzip, and saves the compressed files in a separate output directory. Here's an example of how you can do this:

1. First, make sure you have Node.js installed on your system. You can download it from https://nodejs.org/.

2. Create a new file called `compress-files.js` and open it in your favorite text editor.

3. Add the following code to `compress-files.js`:

```javascript
const fs = require('fs');
const path = require('path');
const zlib = require('zlib');

function compressFile(inputPath, outputPath) {
  const gzip = zlib.createGzip();
  const inputStream = fs.createReadStream(inputPath);
  const outputStream = fs.createWriteStream(outputPath);

  inputStream.pipe(gzip).pipe(outputStream);
}

function main() {
  if (process.argv.length < 4) {
    console.error('Usage: node compress-files.js inputDirectory outputDirectory');
    process.exit(1);
  }

  const inputDir = process.argv[2];
  const outputDir = process.argv[3];

  if (!fs.existsSync(outputDir)) {
    fs.mkdirSync(outputDir);
  }

  fs.readdir(inputDir, (err, files) => {
    if (err) {
      console.error(`Error reading directory: ${inputDir}`);
      process.exit(1);
    }

    files.forEach(file => {
      const inputPath = path.join(inputDir, file);
      const outputPath = path.join(outputDir, `${file}.gz`);

      compressFile(inputPath, outputPath);
    });
  });
}

main();
```

This script uses the built-in `fs`, `path`, and `zlib` modules to read files, handle paths, and compress files with gzip, respectively.

4. Save the `compress-files.js` file.

5. Open a terminal or command prompt and navigate to the directory where you saved `compress-files.js`.

6. Run the script by providing the input and output directories as command-line arguments:

```bash
node compress-files.js /path/to/input/directory /path/to/output/directory
```

This will read all files in the input directory, compress them using gzip, and save the compressed files in the output directory. If the output directory does not exist, it will be created automatically.

