#include <iostream>
#include <fstream>
#include <queue>
#include <unordered_map>
#include <bitset>

struct Node {
    char ch;
    int freq;
    Node* left;
    Node* right;

    Node(char ch, int freq) : ch(ch), freq(freq), left(nullptr), right(nullptr) {}
};

struct CompareFreq {
    bool operator()(Node* l, Node* r) {
        return l->freq > r->freq;
    }
};

void encode(Node* root, std::string str, std::unordered_map<char, std::string> &huffmanCode) {
    if (root == nullptr)
        return;

    if (!root->left && !root->right) {
        huffmanCode[root->ch] = str;
    }

    encode(root->left, str + "0", huffmanCode);
    encode(root->right, str + "1", huffmanCode);
}

void decode(Node* root, int &index, std::string str, std::ofstream& outputFile) {
    if (root == nullptr)
        return;

    if (!root->left && !root->right) {
        outputFile << root->ch;
        return;
    }

    index++;

    if (str[index] == '0')
        decode(root->left, index, str, outputFile);
    else
        decode(root->right, index, str, outputFile);
}

void compress(std::ifstream& inputFile, std::ofstream& outputFile) {
    std::priority_queue<Node*, std::vector<Node*>, CompareFreq> pq;
    std::unordered_map<char, int> freq;
    std::unordered_map<char, std::string> huffmanCode;
    std::string text;

    while (inputFile) {
        char ch;
        inputFile.get(ch);
        if (!inputFile.eof()) {
            freq[ch]++;
            text += ch;
        }
    }

    for (auto pair : freq) {
        pq.push(new Node(pair.first, pair.second));
    }

    while (pq.size() != 1) {
        Node* left = pq.top(); pq.pop();
        Node* right = pq.top(); pq.pop();

        int sum = left->freq + right->freq;
        Node* newNode = new Node('\0', sum);
        newNode->left = left;
        newNode->right = right;
        pq.push(newNode);
    }

    Node* root = pq.top();

    encode(root, "", huffmanCode);

    std::string encodedText;
    for (char ch : text) {
        encodedText += huffmanCode[ch];
    }

    outputFile << huffmanCode.size() << '\n';
    for (auto pair : huffmanCode) {
        outputFile << pair.first << ' ' << pair.second << '\n';
    }

    outputFile << encodedText.length() << '\n';

    for (int i = 0; i < encodedText.length(); i += 8) {
        std::bitset<8> byte(encodedText.substr(i, 8));
        outputFile.put(static_cast<char>(byte.to_ulong()));
    }
}

void decompress(std::ifstream& inputFile, std::ofstream& outputFile) {
    int numCodes;
    inputFile >> numCodes;

    std::unordered_map<std::string, char> reverseHuffmanCode;
    for (int i = 0; i < numCodes; ++i) {
        char ch;
        std::string code;
        inputFile >> ch >> code;
        reverseHuffmanCode[code] = ch;
    }

    int encodedTextLength;
    inputFile >> encodedTextLength;

    std::string encodedText;
    while (inputFile) {
        char ch;
        inputFile.get(ch);
        if (!inputFile.eof()) {
            std::bitset<8> byte(ch);
            encodedText += byte.to_string();
        }
    }

    Node* root = nullptr;
    for (auto pair : reverseHuffmanCode) {
        Node** currentNode = &root;
        for (char bit : pair.first) {
            if (bit == '0') {
                if (!(*currentNode)) *currentNode = new Node('\0', 0);
                currentNode = &((*currentNode)->left);
            } else {
                if (!(*currentNode)) *currentNode = new Node('\0', 0);
                currentNode = &((*currentNode)->right);
            }
        }
        (*currentNode) = new Node(pair.second, 0);
    }

    int index = -1;
    while (index < encodedText.length() - 2) {
        decode(root, index, encodedText, outputFile);
    }
}

int main(int argc, char* argv[]) {
    if (argc != 4) {
        std::cerr << "Usage: huffman [compress|decompress] input_file output_file" << std::endl;
        return 1;
    }

    std::ifstream inputFile(argv[2], std::ios::binary);
    std::ofstream outputFile(argv[3], std::ios::binary);

    if (!inputFile || !outputFile) {
        std::cerr << "Error opening file." << std::endl;
        return 1;
    }

    std::string mode(argv[1]);
    if (mode == "compress") {
        compress(inputFile, outputFile);
    } else if (mode == "decompress") {
        decompress(inputFile, outputFile);
    } else {
        std::cerr << "Invalid mode. Use 'compress' or 'decompress'." << std::endl;
        return 1;
    }

    inputFile.close();
    outputFile.close();

    return 0;
}

public class QuickSortStrings {

    public static void main(String[] args) {
        String[] arr = {"apple", "banana", "kiwi", "mango", "pear", "orange", "avocado"};

        System.out.println("Before Sorting:");
        printArray(arr);

        quickSort(arr, 0, arr.length - 1);

        System.out.println("\nAfter Sorting:");
        printArray(arr);
    }

    public static void quickSort(String[] arr, int low, int high) {
        if (low < high) {
            int pivotIndex = partition(arr, low, high);

            quickSort(arr, low, pivotIndex - 1);
            quickSort(arr, pivotIndex + 1, high);
        }
    }

    private static int partition(String[] arr, int low, int high) {
        String pivot = arr[high];
        int i = low - 1;

        for (int j = low; j <= high - 1; j++) {
            if (arr[j].compareTo(pivot) < 0) {
                i++;
                swap(arr, i, j);
            }
        }
        swap(arr, i + 1, high);
        return i + 1;
    }

    private static void swap(String[] arr, int i, int j) {
        String temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }

    private static void printArray(String[] arr) {
        for (String s : arr) {
            System.out.print(s + " ");
        }
        System.out.println();
    }
}

