To build a Node.js application that connects to a PostgreSQL database and performs complex queries, you'll need the following:

1. A PostgreSQL database with tables containing user activity data.
2. The `pg` package for connecting to the PostgreSQL database from your Node.js application.

First, let's set up a simple PostgreSQL schema for our example:

```sql
CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  username VARCHAR(255) NOT NULL UNIQUE
);

CREATE TABLE activities (
  id SERIAL PRIMARY KEY,
  user_id INTEGER REFERENCES users(id),
  action VARCHAR(255) NOT NULL,
  timestamp TIMESTAMP NOT NULL
);
```

Now, let's create a new Node.js project and install the required dependencies:

```bash
mkdir node-pg-report
cd node-pg-report
npm init -y
npm install pg dotenv
touch index.js .env
```

Add your PostgreSQL connection string to the `.env` file:

```
DATABASE_URL=postgres://username:password@localhost/dbname
```

Next, update the `index.js` file with the following code:

```javascript
const { Client } = require('pg');
const dotenv = require('dotenv');

// Load environment variables from .env file
dotenv.config();

async function main() {
  // Connect to the PostgreSQL database
  const client = new Client({ connectionString: process.env.DATABASE_URL });
  await client.connect();

  // Perform a complex query involving multiple tables, joins, and aggregations
  const result = await client.query(`
    SELECT u.username, COUNT(a.id) AS activity_count, MIN(a.timestamp) AS first_activity, MAX(a.timestamp) AS last_activity
    FROM users u
    JOIN activities a ON u.id = a.user_id
    GROUP BY u.id
    ORDER BY activity_count DESC;
  `);

  console.log('User Activity Report:');
  console.table(result.rows);

  // Close the database connection
  await client.end();
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
```

This example code connects to a PostgreSQL database, performs a complex query involving multiple tables, joins, and aggregations, and outputs a report on user activity within an application.

To run the script, execute:

```bash
node index.js
```

You should see the User Activity Report printed in your terminal. Make sure you have some data in your `users` and `activities` tables for this to work correctly.

package main

import (
	"fmt"
	"io/ioutil"
	"log"
	"net/http"
	"net/url"
	"os"
	"strings"

	"github.com/PuerkitoBio/goquery"
)

// extractLinks fetches all links from the given URL
func extractLinks(url string) ([]string, error) {
	var links []string

	resp, err := http.Get(url)
	if err != nil {
		return links, err
	}
	defer resp.Body.Close()

	doc, err := goquery.NewDocumentFromReader(resp.Body)
	if err != nil {
		return links, err
	}

	doc.Find("a").Each(func(_ int, s *goquery.Selection) {
		href, exists := s.Attr("href")
		if exists {
			links = append(links, href)
		}
	})

	return links, nil
}

// filterLinks separates internal and external links based on the baseURL
func filterLinks(baseURL string, links []string) ([]string, []string) {
	var internalLinks, externalLinks []string

	u, err := url.Parse(baseURL)
	if err != nil {
		log.Fatal(err)
	}

	for _, link := range links {
		linkURL, err := url.Parse(link)
		if err != nil {
			continue
		}

		if linkURL.Host == "" || linkURL.Host == u.Host {
			internalLinks = append(internalLinks, link)
		} else {
			externalLinks = append(externalLinks, link)
		}
	}

	return internalLinks, externalLinks
}

// saveToFile writes data to a file with the specified filename
func saveToFile(filename string, data []string) error {
	file, err := os.Create(filename)
	if err != nil {
		return err
	}
	defer file.Close()

	for _, line := range data {
		file.WriteString(line + "\n")
	}

	return nil
}

