public class MariaDBExample {

    public static void main(String[] args) {
        String url = "jdbc:mariadb://localhost:3306/your_database_name";
        String user = "your_username";
        String password = "your_password";

        try {
            // Connect to the MariaDB database
            Connection connection = DriverManager.getConnection(url, user, password);
            Statement statement = connection.createStatement();

            // Create the "employees" table
            String createTableSql = "CREATE TABLE IF NOT EXISTS employees (" +
                    "id INT AUTO_INCREMENT PRIMARY KEY," +
                    "first_name VARCHAR(50)," +
                    "last_name VARCHAR(50))";
            statement.executeUpdate(createTableSql);

            // Insert sample employee records
            String insertEmployee1 = "INSERT INTO employees (first_name, last_name) VALUES ('John', 'Doe')";
            String insertEmployee2 = "INSERT INTO employees (first_name, last_name) VALUES ('Jane', 'Smith')";
            statement.executeUpdate(insertEmployee1);
            statement.executeUpdate(insertEmployee2);

            // Retrieve all records from the "employees" table sorted by last name
            String selectEmployeesSql = "SELECT * FROM employees ORDER BY last_name";
            ResultSet resultSet = statement.executeQuery(selectEmployeesSql);

            // Print the retrieved records
            System.out.println("Employees:");
            while (resultSet.next()) {
                int id = resultSet.getInt("id");
                String firstName = resultSet.getString("first_name");
                String lastName = resultSet.getString("last_name");

                System.out.printf("%d: %s %s%n", id, firstName, lastName);
            }

            // Close resources
            resultSet.close();
            statement.close();
            connection.close();

        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

import java.util.ArrayList;
import java.util.List;

public class PrimeFinder implements Runnable {
    private int start, end;
    private static List<Integer> primes = new ArrayList<>();

    public PrimeFinder(int start, int end) {
        this.start = start;
        this.end = end;
    }

    @Override
    public void run() {
        for (int i = start; i <= end; i++) {
            if (isPrime(i)) {
                synchronized (primes) {
                    primes.add(i);
                }
            }
        }
    }

    private boolean isPrime(int num) {
        if (num <= 1) return false;
        for (int i = 2; i * i <= num; i++) {
            if (num % i == 0) return false;
        }
        return true;
    }

    public static void main(String[] args) throws InterruptedException {
        if (args.length < 1) {
            System.out.println("Please provide a limit as command line argument.");
            System.exit(1);
        }

        int limit = Integer.parseInt(args[0]);
        int cores = Runtime.getRuntime().availableProcessors();
        Thread[] threads = new Thread[cores];
        int range = limit / cores;

        long startTime = System.currentTimeMillis();

        for (int i = 0; i < cores; i++) {
            int start = i * range + 1;
            int end = i == cores - 1 ? limit : start + range - 1;
            threads[i] = new Thread(new PrimeFinder(start, end));
            threads[i].start();
        }

        for (Thread thread : threads) {
            thread.join();
        }

        long endTime = System.currentTimeMillis();

        System.out.println("Total prime numbers found: " + primes.size());
        System.out.println("Execution time: " + (endTime - startTime) + " milliseconds");
    }
}

