Below is a simple example of a Golang REST API server with three endpoints for creating, updating, and deleting users. This example uses the Gorilla Mux router package to handle routing and stores user data in-memory using a map.

```go
package main

import (
	"encoding/json"
	"fmt"
	"github.com/gorilla/mux"
	"log"
	"net/http"
	"strconv"
)

type User struct {
	ID       int    `json:"id"`
	Username string `json:"username"`
	Email    string `json:"email"`
	Password string `json:"password"`
}

var users = make(map[int]User)
var userIDCounter = 1

func createUser(w http.ResponseWriter, r *http.Request) {
	var newUser User
	err := json.NewDecoder(r.Body).Decode(&newUser)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	newUser.ID = userIDCounter
	users[userIDCounter] = newUser
	userIDCounter++
	json.NewEncoder(w).Encode(newUser)
}

func updateUser(w http.ResponseWriter, r *http.Request) {
	idStr := mux.Vars(r)["id"]
	id, err := strconv.Atoi(idStr)
	if err != nil {
		http.Error(w, "Invalid user ID", http.StatusBadRequest)
		return
	}

	var updatedUser User
	err = json.NewDecoder(r.Body).Decode(&updatedUser)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	if _, exists := users[id]; !exists {
		http.Error(w, "User not found", http.StatusNotFound)
		return
	}

	updatedUser.ID = id
	users[id] = updatedUser
	json.NewEncoder(w).Encode(updatedUser)
}

func deleteUser(w http.ResponseWriter, r *http.Request) {
	idStr := mux.Vars(r)["id"]
	id, err := strconv.Atoi(idStr)
	if err != nil {
		http.Error(w, "Invalid user ID", http.StatusBadRequest)
		return
	}

	if _, exists := users[id]; !exists {
		http.Error(w, "User not found", http.StatusNotFound)
		return
	}

	delete(users, id)
	fmt.Fprintf(w, "User %d deleted", id)
}

func main() {
	router := mux.NewRouter()
	router.HandleFunc("/users", createUser).Methods("POST")
	router.HandleFunc("/users/{id}", updateUser).Methods("PUT")
	router.HandleFunc("/users/{id}", deleteUser).Methods("DELETE")

	log.Fatal(http.ListenAndServe(":8080", router))
}
```

To run this example:

1. Install the Gorilla Mux package if you haven't already: `go get -u github.com/gorilla/mux`
2. Save the code above in a file named `main.go`.
3. Run the server with `go run main.go`.

You can now use an API client like Postman or curl to test the endpoints.

- To create a new user: POST request to `http://localhost:8080/users` with JSON body containing username, email, and password.
- To update a user: PUT request to `http://localhost:8080/users/{id}` with JSON body containing updated fields (username, email, and/or password).
- To delete a user: DELETE request to `http://localhost:8080/users/{id}`.

