package main

import (
	"bufio"
	"fmt"
	"io/ioutil"
	"net"
	"os"
	"strings"
)

func main() {
	listener, err := net.Listen("tcp", "localhost:8080")
	if err != nil {
		fmt.Println(err)
		return
	}
	defer listener.Close()

	for {
		conn, err := listener.Accept()
		if err != nil {
			fmt.Println(err)
			continue
		}

		go handleConnection(conn)
	}
}

func handleConnection(conn net.Conn) {
	defer conn.Close()

	reader := bufio.NewReader(conn)
	command, _ := reader.ReadString('\n')
	parts := strings.Split(strings.TrimSpace(command), " ")

	switch parts[0] {
	case "UPLOAD":
		handleUpload(parts[1:], reader, conn)
	case "DOWNLOAD":
		handleDownload(parts[1:], conn)
	case "LIST":
		handleList(conn)
	case "DELETE":
		handleDelete(parts[1:], conn)
	default:
		conn.Write([]byte("Invalid command\n"))
	}
}

func handleUpload(parts []string, reader *bufio.Reader, conn net.Conn) {
	if len(parts) < 1 {
		conn.Write([]byte("Filename required for upload\n"))
		return
	}

	file, err := os.Create(parts[0])
	if err != nil {
		conn.Write([]byte(fmt.Sprintf("Error creating file: %s\n", err)))
		return
	}
	defer file.Close()

	content, _ := reader.ReadString('\n')
	file.WriteString(content)

	conn.Write([]byte("File uploaded successfully\n"))
}

func handleDownload(parts []string, conn net.Conn) {
	if len(parts) < 1 {
		conn.Write([]byte("Filename required for download\n"))
		return
	}

	data, err := ioutil.ReadFile(parts[0])
	if err != nil {
		conn.Write([]byte(fmt.Sprintf("Error reading file: %s\n", err)))
		return
	}

	conn.Write(data)
}

func handleList(conn net.Conn) {
	files, err := ioutil.ReadDir(".")
	if err != nil {
		conn.Write([]byte(fmt.Sprintf("Error listing files: %s\n", err)))
		return
	}

	for _, file := range files {
		conn.Write([]byte(file.Name() + "\n"))
	}
}

func handleDelete(parts []string, conn net.Conn) {
	if len(parts) < 1 {
		conn.Write([]byte("Filename required for delete\n"))
		return
	}

	err := os.Remove(parts[0])
	if err != nil {
		conn.Write([]byte(fmt.Sprintf("Error deleting file: %s\n", err)))
		return
	}

	conn.Write([]byte("File deleted successfully\n"))
}

import com.twitter.hbc.ClientBuilder;
import com.twitter.hbc.core.Client;
import com.twitter.hbc.core.Constants;
import com.twitter.hbc.core.endpoint.StatusesFilterEndpoint;
import com.twitter.hbc.core.processor.StringDelimitedProcessor;
import com.twitter.hbc.httpclient.auth.Authentication;
import com.twitter.hbc.httpclient.auth.OAuth1;

import java.io.BufferedWriter;
import java.io.FileWriter;
import java.io.IOException;
import java.util.Arrays;
import java.util.concurrent.BlockingQueue;
import java.util.concurrent.LinkedBlockingQueue;

public class TwitterKeywordSearch {

    private static final String CONSUMER_KEY = "your_consumer_key";
    private static final String CONSUMER_SECRET = "your_consumer_secret";
    private static final String ACCESS_TOKEN = "your_access_token";
    private static final String ACCESS_TOKEN_SECRET = "your_access_token_secret";

    public static void main(String[] args) {
        if (args.length == 0) {
            System.out.println("Please provide keyword(s) as command-line arguments.");
            return;
        }

        // Create a blocking queue to store tweets
        BlockingQueue<String> queue = new LinkedBlockingQueue<>(10000);

        // Set up the endpoint with the specified keywords
        StatusesFilterEndpoint endpoint = new StatusesFilterEndpoint();
        endpoint.trackTerms(Arrays.asList(args));

        // Authenticate using OAuth1
        Authentication auth = new OAuth1(CONSUMER_KEY, CONSUMER_SECRET, ACCESS_TOKEN, ACCESS_TOKEN_SECRET);

        // Build and connect the client
        Client client = new ClientBuilder()
                .hosts(Constants.STREAM_HOST)
                .endpoint(endpoint)
                .authentication(auth)
                .processor(new StringDelimitedProcessor(queue))
                .build();

        client.connect();

        // Save fetched tweets into a text file
        try (BufferedWriter writer = new BufferedWriter(new FileWriter("tweets.txt"))) {
            while (!client.isDone()) {
                try {
                    String tweet = queue.take();
                    writer.write(tweet);
                    writer.newLine();
                    System.out.println("Saved tweet: " + tweet);
                } catch (InterruptedException e) {
                    e.printStackTrace();
                }
            }
        } catch (IOException e) {
            e.printStackTrace();
        }

        // Stop the client
        client.stop();
    }
}

