import java.io.BufferedReader;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;

class Person {
    String name;
    int age;

    public Person(String name, int age) {
        this.name = name;
        this.age = age;
    }
}

public class SortCSVByAge {

    public static void main(String[] args) {
        String inputFilePath = "input.csv";
        String outputFilePath = "output.csv";

        ArrayList<Person> peopleList = new ArrayList<>();

        // Read the CSV file and store the data in an ArrayList
        try (BufferedReader br = new BufferedReader(new FileReader(inputFilePath))) {
            String line;
            while ((line = br.readLine()) != null) {
                String[] values = line.split(",");
                if (values.length == 2) {
                    String name = values[0].trim();
                    int age = Integer.parseInt(values[1].trim());
                    peopleList.add(new Person(name, age));
                } else {
                    System.out.println("Invalid data format: " + line);
                }
            }
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
            return;
        } catch (NumberFormatException e) {
            System.err.println("Invalid age value: " + e.getMessage());
            return;
        }

        // Sort the ArrayList by age in descending order
        Collections.sort(peopleList, new Comparator<Person>() {
            @Override
            public int compare(Person p1, Person p2) {
                return Integer.compare(p2.age, p1.age);
            }
        });

        // Write the sorted data to a new CSV file
        try (FileWriter fw = new FileWriter(outputFilePath)) {
            for (Person person : peopleList) {
                fw.write(person.name + "," + person.age + "\n");
            }
        } catch (IOException e) {
            System.err.println("Error writing to file: " + e.getMessage());
        }

        System.out.println("Sorted data written to " + outputFilePath);
    }
}

function sieveOfEratosthenes(n) {
    let primes = [];
    for (let i = 0; i <= n; i++) {
        primes[i] = true;
    }
    primes[0] = false;
    primes[1] = false;

    for (let i = 2; i <= Math.sqrt(n); i++) {
        for(let j = 2; i * j <= n; j++) {
            primes[i * j] = false;
        }
    }

    let result = [];
    for (let i = 0; i < primes.length; i++) {
        if (primes[i]) result.push(i);
    }

    return result;
}

