namespace DijkstrasAlgorithm
{
    class Program
    {
        static void Main(string[] args)
        {
            int[,] graph = new int[,]
            {
                { 0, 10, 0, 5, 0 },
                { 0, 0, 1, 2, 0 },
                { 0, 0, 0, 0, 4 },
                { 0, 3, 9, 0, 2 },
                { 7, 0, 6, 0, 0 }
            };

            int sourceNode = 0;
            int destinationNode = 4;

            var result = Dijkstra(graph, sourceNode, destinationNode);

            Console.WriteLine($"Shortest path from node {sourceNode} to node {destinationNode}:");
            foreach (var node in result.Path)
            {
                Console.Write($"{node} ");
            }

            Console.WriteLine($"\nTotal weight: {result.Distance}");
        }

        public static (int[] Path, int Distance) Dijkstra(int[,] graph, int sourceNode, int destinationNode)
        {
            int n = graph.GetLength(0);
            int[] distances = new int[n];
            bool[] visited = new bool[n];
            int[] previous = new int[n];

            for (int i = 0; i < n; i++)
            {
                distances[i] = int.MaxValue;
                previous[i] = -1;
            }

            distances[sourceNode] = 0;

            for (int i = 0; i < n - 1; i++)
            {
                int minDistance = int.MaxValue;
                int currentNode = -1;

                for (int j = 0; j < n; j++)
                {
                    if (!visited[j] && distances[j] < minDistance)
                    {
                        minDistance = distances[j];
                        currentNode = j;
                    }
                }

                visited[currentNode] = true;

                for (int j = 0; j < n; j++)
                {
                    int edgeWeight = graph[currentNode, j];

                    if (edgeWeight > 0 && !visited[j])
                    {
                        int newDistance = distances[currentNode] + edgeWeight;

                        if (newDistance < distances[j])
                        {
                            distances[j] = newDistance;
                            previous[j] = currentNode;
                        }
                    }
                }
            }

            int[] path = new int[n];
            int pathIndex = 0;
            int currentPathNode = destinationNode;

            while (currentPathNode != -1)
            {
                path[pathIndex++] = currentPathNode;
                currentPathNode = previous[currentPathNode];
            }

            Array.Reverse(path, 0, pathIndex);

            return (path: path[..pathIndex], Distance: distances[destinationNode]);
        }
    }
}

