const sentiment = new Sentiment();

// Function to fetch tweets and perform sentiment analysis
async function analyzeTweets(hashtag) {
  try {
    const response = await T.get('search/tweets', { q: `#${hashtag}`, count: 100 });
    const tweets = response.data.statuses;

    let totalSentimentScore = 0;
    let mostPositiveTweet = { text: '', score: -Infinity };
    let mostNegativeTweet = { text: '', score: Infinity };

    tweets.forEach((tweet) => {
      const analysis = sentiment.analyze(tweet.text);
      totalSentimentScore += analysis.score;

      if (analysis.score > mostPositiveTweet.score) {
        mostPositiveTweet = { text: tweet.text, score: analysis.score };
      }

      if (analysis.score < mostNegativeTweet.score) {
        mostNegativeTweet = { text: tweet.text, score: analysis.score };
      }
    });

    console.log(`Overall Sentiment Score: ${totalSentimentScore}`);
    console.log(`Most Positive Tweet: "${mostPositiveTweet.text}" (Score: ${mostPositiveTweet.score})`);
    console.log(`Most Negative Tweet: "${mostNegativeTweet.text}" (Score: ${mostNegativeTweet.score})`);

  } catch (error) {
    console.error('Error fetching tweets:', error);
  }
}

