import java.util.Scanner;

public class FactorialCalculator {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a non-negative integer: ");
        int n = scanner.nextInt();

        if (n < 0) {
            System.out.println("Invalid input. Please enter a non-negative integer.");
        } else {
            long iterativeResult = iterativeFactorial(n);
            long recursiveResult = recursiveFactorial(n);

            System.out.println("Iterative approach result: " + iterativeResult);
            System.out.println("Recursive approach result: " + recursiveResult);
        }
    }

    // Calculate factorial using an iterative approach
    private static long iterativeFactorial(int n) {
        long result = 1;
        for (int i = 2; i <= n; i++) {
            result *= i;
        }
        return result;
    }

    // Calculate factorial using a recursive approach
    private static long recursiveFactorial(int n) {
        if (n == 0 || n == 1) {
            return 1;
        }
        return n * recursiveFactorial(n - 1);
    }
}

