import java.util.Scanner;

public interface JsonPlaceholderApi {
    @GET("posts")
    Call<List<Post>> getPosts();
}

class Post {
    private int userId;
    private int id;
    private String title;
    private String body;

    // Getters and setters
}

class DatabaseManager {
    private static final String DB_URL = "jdbc:sqlite:my_database.db";

    public void initializeDatabase() {
        try (Connection connection = DriverManager.getConnection(DB_URL)) {
            Statement statement = connection.createStatement();
            statement.execute("CREATE TABLE IF NOT EXISTS posts (id INTEGER PRIMARY KEY, userId INTEGER, title TEXT, body TEXT)");
        } catch (SQLException e) {
            System.err.println("Error initializing database: " + e.getMessage());
        }
    }

    public void insertPosts(List<Post> posts) {
        String sql = "INSERT INTO posts (id, userId, title, body) VALUES (?, ?, ?, ?)";

        try (Connection connection = DriverManager.getConnection(DB_URL);
             PreparedStatement preparedStatement = connection.prepareStatement(sql)) {

            for (Post post : posts) {
                preparedStatement.setInt(1, post.getId());
                preparedStatement.setInt(2, post.getUserId());
                preparedStatement.setString(3, post.getTitle());
                preparedStatement.setString(4, post.getBody());

                preparedStatement.addBatch();
            }

            preparedStatement.executeBatch();

        } catch (SQLException e) {
            System.err.println("Error inserting posts: " + e.getMessage());
        }
    }

    public List<Post> getAllPosts() {
        List<Post> posts = new ArrayList<>();

        try (Connection connection = DriverManager.getConnection(DB_URL);
             Statement statement = connection.createStatement()) {

            ResultSet resultSet = statement.executeQuery("SELECT * FROM posts");

            while (resultSet.next()) {
                Post post = new Post();
                post.setId(resultSet.getInt("id"));
                post.setUserId(resultSet.getInt("userId"));
                post.setTitle(resultSet.getString("title"));
                post.setBody(resultSet.getString("body"));

                posts.add(post);
            }

        } catch (SQLException e) {
            System.err.println("Error fetching all posts: " + e.getMessage());
        }

        return posts;
    }
}

class ApiManager {
    private static final String BASE_URL = "https://jsonplaceholder.typicode.com/";

    public List<Post> fetchPosts() throws IOException {
        Retrofit retrofit = new Retrofit.Builder()
                .baseUrl(BASE_URL)
                .addConverterFactory(GsonConverterFactory.create())
                .build();

        JsonPlaceholderApi api = retrofit.create(JsonPlaceholderApi.class);

        return api.getPosts().execute().body();
    }
}

public class Main {
    public static void main(String[] args) {
        DatabaseManager databaseManager = new DatabaseManager();
        databaseManager.initializeDatabase();

        ApiManager apiManager = new ApiManager();

        try {
            List<Post> posts = apiManager.fetchPosts();
            databaseManager.insertPosts(posts);
        } catch (IOException e) {
            System.err.println("Error fetching posts from API: " + e.getMessage());
        }

        Scanner scanner = new Scanner(System.in);

        while (true) {
            System.out.println("Enter 'list' to list all posts or 'exit' to quit:");
            String input = scanner.nextLine();

            if ("list".equalsIgnoreCase(input)) {
                List<Post> posts = databaseManager.getAllPosts();

                for (Post post : posts) {
                    System.out.println(post.getId() + ": " + post.getTitle());
                }
            } else if ("exit".equalsIgnoreCase(input)) {
                break;
            } else {
                System.out.println("Invalid command.");
            }
        }

        scanner.close();
    }
}

