// logRequest logs the request method, URL, and headers to a file
func logRequest(w http.ResponseWriter, r *http.Request) {
	log.Printf("Method: %s\nURL: %s\nHeaders:\n", r.Method, r.URL)
	for k, v := range r.Header {
		log.Printf("%s: %v\n", k, v)
	}
}

func main() {
	portPtr := flag.Int("port", 8080, "Port to listen on")
	filePathPtr := flag.String("logfile", "requests.log", "Log file path")

	flag.Parse()

	f, err := os.OpenFile(*filePathPtr, os.O_WRONLY|os.O_CREATE|os.O_APPEND, 0644)
	if err != nil {
		log.Fatalf("Error opening log file: %v", err)
	}
	defer f.Close()

	log.SetOutput(f)

	http.HandleFunc("/", logRequest)

	addr := fmt.Sprintf(":%d", *portPtr)
	fmt.Printf("Listening on %s...\n", addr)
	err = http.ListenAndServe(addr, nil)
	if err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

Here's a simple implementation of a chat server using WebSockets in TypeScript. You can use this code as a starting point and modify it according to your requirements.

First, you need to install the necessary packages:

```bash
npm init -y
npm install typescript ts-node @types/node --save-dev
npm install ws express --save
```

Next, create a `tsconfig.json` file with the following content:

```json
{
  "compilerOptions": {
    "target": "es6",
    "module": "commonjs",
    "strict": true,
    "esModuleInterop": true,
    "skipLibCheck": true,
    "forceConsistentCasingInFileNames": true
  },
  "include": ["src"]
}
```

Now, create a `src` folder and inside it, create a file named `chat-server.ts`. Add the following code to the file:

```typescript
import * as express from 'express';
import { Server } from 'ws';

const app = express();
const port = process.env.PORT || 3000;

// Serve static files from the 'public' directory.
app.use(express.static('public'));

// Start an HTTP server and upgrade incoming WebSocket connections.
const server = app.listen(port, () => {
  console.log(`Chat server listening on http://localhost:${port}`);
});

const wss = new Server({ server });

wss.on('connection', (ws) => {
  console.log('Client connected');

  // Broadcast messages to all connected clients.
  const broadcast = (message: string) => {
    wss.clients.forEach((client) => {
      if (client.readyState === client.OPEN) {
        client.send(message);
      }
    });
  };

  ws.on('message', (message: string) => {
    console.log(`Received message: ${message}`);
    broadcast(message);
  });

  ws.on('close', () => {
    console.log('Client disconnected');
  });
});
```

Finally, you can run the chat server using `ts-node`:

```bash
npx ts-node src/chat-server.ts
```

This will start a simple chat server on port 3000. Clients can connect to it using WebSocket and send messages. The server will broadcast received messages to all connected clients.

You can create an HTML file with JavaScript code in the 'public' directory to test the chat server from a browser. Here's a simple example of how to do that:

Create a new folder named "public" in your project root directory, then create a new file inside the public folder called "index.html":

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Chat</title>
</head>
<body>
  <input type="text" id="message" placeholder="Type your message...">
  <button onclick="sendMessage()">Send</button>
  <ul id="messages"></ul>

  <script>
    const socket = new WebSocket(`ws://${location.host}`);
    const messageInput = document.getElementById('message');
    const messagesList = document.getElementById('messages');

    socket.addEventListener('message', (event) => {
      const li = document.createElement('li');
      li.textContent = event.data;
      messagesList.appendChild(li);
    });

    function sendMessage() {
      const message = messageInput.value.trim();
      if (message) {
        socket.send(message);
        messageInput.value = '';
      }
    }
  </script>
</body>
</html>
```

Now, when you run the chat server, you can open multiple browser windows at http://localhost:3000 and see the chat functionality in action.

public class BankAccount
{
    private decimal balance;

    public decimal Balance 
    {
        get { return balance; }
        private set 
        {
            if (value < 0)
                throw new Exception("Balance cannot be negative.");
            balance = value;
        }
    }

    public BankAccount(decimal initialBalance)
    {
        if (initialBalance < 0)
            throw new ArgumentException("Initial balance cannot be negative.");
        this.Balance = initialBalance;
    }

    public void Deposit(decimal amount)
    {
        if (amount <= 0)
            throw new ArgumentException("Deposit amount must be positive.");
        this.Balance += amount;
    }

    public void Withdraw(decimal amount)
    {
        if (amount <= 0)
            throw new ArgumentException("Withdrawal amount must be positive.");
        if (this.Balance < amount)
            throw new InvalidOperationException("Insufficient funds for this withdrawal.");
        this.Balance -= amount;
    }
}

public class SinglyLinkedList {
    // Node class to represent the elements in the linked list
    static class Node {
        int data;
        Node next;

        public Node(int data) {
            this.data = data;
            this.next = null;
        }
    }

    private Node head;

    public SinglyLinkedList() {
        head = null;
    }

    // Insert an element at the beginning of the list
    public void insertAtBeginning(int data) {
        Node newNode = new Node(data);
        newNode.next = head;
        head = newNode;
    }

    // Insert an element at the end of the list
    public void insertAtEnd(int data) {
        Node newNode = new Node(data);

        if (head == null) {
            head = newNode;
            return;
        }

        Node currentNode = head;
        while (currentNode.next != null) {
            currentNode = currentNode.next;
        }
        currentNode.next = newNode;
    }

    // Delete the first occurrence of an element from the list
    public void delete(int data) {
        if (head == null) {
            System.out.println("List is empty");
            return;
        }

        if (head.data == data) {
            head = head.next;
            return;
        }

        Node currentNode = head;
        while (currentNode.next != null && currentNode.next.data != data) {
            currentNode = currentNode.next;
        }

        if (currentNode.next != null) {
            currentNode.next = currentNode.next.next;
        } else {
            System.out.println("Element not found");
        }
    }

    // Traverse and print the elements in the list
    public void traverse() {
        Node currentNode = head;
        while (currentNode != null) {
            System.out.print(currentNode.data + " -> ");
            currentNode = currentNode.next;
        }
        System.out.println("null");
    }

    public static void main(String[] args) {
        SinglyLinkedList list = new SinglyLinkedList();

        // Insert elements
        list.insertAtBeginning(1);
        list.insertAtEnd(2);
        list.insertAtEnd(3);
        list.insertAtBeginning(0);

        // Traverse and print the list
        list.traverse(); // Output: 0 -> 1 -> 2 -> 3 -> null

        // Delete an element
        list.delete(1);

        // Traverse and print the updated list
        list.traverse(); // Output: 0 -> 2 -> 3 -> null
    }
}

To design a Golang RESTful API server that supports CRUD operations for notes, we'll follow these steps:

1. Create the necessary data structures and utility functions.
2. Implement the main function to set up the HTTP server.
3. Define handlers for each endpoint (Create, Read, Update, Delete).
4. Set up routing for the endpoints.

Here's an example implementation:

```go
package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"log"
	"net/http"
	"os"
	"time"

	"github.com/gorilla/mux"
)

type Note struct {
	Title     string    `json:"title"`
	Content   string    `json:"content"`
	Timestamp time.Time `json:"timestamp"`
}

var notes []Note
var storageFile = "notes.json"

func loadNotes() {
	data, err := ioutil.ReadFile(storageFile)
	if err != nil {
		log.Printf("Error reading storage file: %v", err)
		return
	}
	json.Unmarshal(data, &notes)
}

func saveNotes() {
	data, _ := json.Marshal(notes)
	err := ioutil.WriteFile(storageFile, data, 0644)
	if err != nil {
		log.Printf("Error writing storage file: %v", err)
	}
}

func createNote(w http.ResponseWriter, r *http.Request) {
	var note Note
	json.NewDecoder(r.Body).Decode(&note)
	note.Timestamp = time.Now()
	notes = append(notes, note)
	saveNotes()

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(note)
}

func getNotes(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(notes)
}

func updateNote(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	title := params["title"]

	var updatedNote Note
	json.NewDecoder(r.Body).Decode(&updatedNote)

	for i, note := range notes {
		if note.Title == title {
			notes[i].Content = updatedNote.Content
			saveNotes()
			w.Header().Set("Content-Type", "application/json")
			json.NewEncoder(w).Encode(notes[i])
			return
		}
	}

	http.Error(w, "Note not found", http.StatusNotFound)
}

func deleteNote(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	title := params["title"]

	for i, note := range notes {
		if note.Title == title {
			notes = append(notes[:i], notes[i+1:]...)
			saveNotes()
			w.WriteHeader(http.StatusNoContent)
			return
		}
	}

	http.Error(w, "Note not found", http.StatusNotFound)
}

func main() {
	loadNotes()

	router := mux.NewRouter()
	router.HandleFunc("/notes", createNote).Methods("POST")
	router.HandleFunc("/notes", getNotes).Methods("GET")
	router.HandleFunc("/notes/{title}", updateNote).Methods("PUT")
	router.HandleFunc("/notes/{title}", deleteNote).Methods("DELETE")

	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
	}

	log.Printf("Starting server on port %s...", port)
	log.Fatal(http.ListenAndServe(fmt.Sprintf(":%s", port), router))
}
```

