```

To run the server, simply execute `go run main.go`. The API will be available at `http://localhost:8080/notes`.

Remember to replace the storageFile variable with the path of your JSON file if you want to use a different file.

const Memcached = require('memcached');
const axios = require('axios');
const yargs = require('yargs/yargs');
const { hideBin } = require('yargs/helpers');

const argv = yargs(hideBin(process.argv))
  .option('timeout', {
    alias: 't',
    description: 'Cache timeout in seconds',
    type: 'number',
    default: 60,
  })
  .option('maxItems', {
    alias: 'm',
    description: 'Maximum number of items stored in cache',
    type: 'number',
    default: 100,
  }).argv;

const memcached = new Memcached('localhost:11211');

const cacheSettings = {
  timeout: argv.timeout,
  maxItems: argv.maxItems,
};

console.log(`Cache settings: ${JSON.stringify(cacheSettings)}`);

async function fetchDataWithCache(url) {
  return new Promise(async (resolve, reject) => {
    memcached.get(url, async (err, data) => {
      if (err) {
        console.error(`Error fetching from cache: ${err}`);
        reject(err);
      }

      if (data) {
        console.log('Data fetched from cache');
        resolve(data);
      } else {
        try {
          const response = await axios.get(url);
          memcached.set(
            url,
            response.data,
            cacheSettings.timeout,
            (err) => {
              if (err) {
                console.error(`Error setting cache: ${err}`);
              }
            }
          );
          console.log('Data fetched from API and cached');
          resolve(response.data);
        } catch (error) {
          console.error(`Error fetching from API: ${error}`);
          reject(error);
        }
      }
    });
  });
}

async function main() {
  const exampleApiUrl = 'https://jsonplaceholder.typicode.com/todos/1';

  try {
    const data = await fetchDataWithCache(exampleApiUrl);
    console.log('Fetched data:', data);
  } catch (error) {
    console.error('Failed to fetch data:', error);
  }
}

