	"net/http"

	"github.com/gorilla/mux"
	_ "github.com/mattn/go-sqlite3"
)

type Book struct {
	ID     string `json:"id"`
	Title  string `json:"title"`
	Author string `json:"author"`
}

var db *sql.DB
var err error

func main() {
	db, err = sql.Open("sqlite3", "./books.db")
	if err != nil {
		log.Fatal(err)
	}
	defer db.Close()

	router := mux.NewRouter()
	router.HandleFunc("/books", getBooks).Methods("GET")
	router.HandleFunc("/books/{id}", getBook).Methods("GET")
	router.HandleFunc("/books", createBook).Methods("POST")
	router.HandleFunc("/books/{id}", updateBook).Methods("PUT")
	router.HandleFunc("/books/{id}", deleteBook).Methods("DELETE")

	log.Fatal(http.ListenAndServe(":8000", router))
}

func getBooks(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	var books []Book

	result, err := db.Query("SELECT id, title, author from books")
	if err != nil {
		panic(err.Error())
	}

	defer result.Close()

	for result.Next() {
		var book Book
		err := result.Scan(&book.ID, &book.Title, &book.Author)
		if err != nil {
			panic(err.Error())
		}
		books = append(books, book)
	}

	json.NewEncoder(w).Encode(books)
}

func getBook(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)

	result, err := db.Query("SELECT id, title, author FROM books WHERE id = ?", params["id"])
	if err != nil {
		panic(err.Error())
	}

	defer result.Close()

	var book Book

	for result.Next() {
		err := result.Scan(&book.ID, &book.Title, &book.Author)
		if err != nil {
			panic(err.Error())
		}
	}

	json.NewEncoder(w).Encode(book)
}

func createBook(w http.ResponseWriter, r *http.Request) {
	stmt, err := db.Prepare("INSERT INTO books(id, title, author) VALUES(?,?,?)")
	if err != nil {
		panic(err.Error())
	}

	body := json.NewDecoder(r.Body)
	var book Book
	body.Decode(&book)

	_, err = stmt.Exec(book.ID, book.Title, book.Author)
	if err != nil {
		panic(err.Error())
	}

	fmt.Fprintf(w, "New book was created")
}

func updateBook(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)

	stmt, err := db.Prepare("UPDATE books SET title = ?, author = ? WHERE id = ?")
	if err != nil {
		panic(err.Error())
	}

	body := json.NewDecoder(r.Body)
	var book Book
	body.Decode(&book)

	_, err = stmt.Exec(book.Title, book.Author, params["id"])
	if err != nil {
		panic(err.Error())
	}

	fmt.Fprintf(w, "Book with ID = %s was updated", params["id"])
}

func deleteBook(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	stmt, err := db.Prepare("DELETE FROM books WHERE id = ?")

	if err != nil {
		panic(err.Error())
	}

	_, err = stmt.Exec(params["id"])
	if err != nil {
		panic(err.Error())
	}

	fmt.Fprintf(w, "Book with ID = %s was deleted", params["id"])
}

package main

import (
	"fmt"
	"log"
	"os"
	"strings"

	"github.com/cjhutto/golang-sentiment/sentiment"
	"github.com/dghubble/go-twitter/twitter"
	"github.com/dghubble/oauth1"
)

func main() {
	if len(os.Args) < 2 {
		log.Fatal("Please provide a keyword to search for.")
	}

	keyword := os.Args[1]

	config := oauth1.NewConfig("<consumer-key>", "<consumer-secret>")
	token := oauth1.NewToken("<access-token>", "<access-token-secret>")
	httpClient := config.Client(oauth1.NoContext, token)

	client := twitter.NewClient(httpClient)
	searchParams := &twitter.SearchTweetParams{
		Query:      keyword,
		ResultType: "recent",
		Count:      100,
		Lang:       "en",
	}

	tweets, _, err := client.Search.Tweets(searchParams)
	if err != nil {
		log.Fatal(err)
	}

	wordCounts := make(map[string]int)
	totalSentiment := 0.0
	analyzer := sentiment.NewAnalyzer()

	for _, tweet := range tweets.Statuses {
		score, _ := analyzer.Analyze(tweet.Text)
		totalSentiment += score.Score

		words := strings.Split(strings.ToLower(tweet.Text), " ")
		for _, word := range words {
			wordCounts[word]++
		}
	}

	fmt.Printf("Total tweets analyzed: %d\n", len(tweets.Statuses))
	fmt.Printf("Average sentiment score: %.2f\n", totalSentiment/float64(len(tweets.Statuses)))

	fmt.Println("Most common words:")
	for word, count := range wordCounts {
		if count > 1 {
			fmt.Printf("%s: %d\n", word, count)
		}
	}
}

import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.SQLException;

public class CsvToDatabase {

    private static final String DB_URL = "jdbc:sqlite:user_data.db";
    private static final String CREATE_TABLE_SQL =
            "CREATE TABLE IF NOT EXISTS users (" +
                    "id INTEGER PRIMARY KEY AUTOINCREMENT," +
                    "name TEXT NOT NULL," +
                    "age INTEGER NOT NULL," +
                    "email TEXT UNIQUE NOT NULL" +
                    ");";

    public static void main(String[] args) {
        if (args.length != 1) {
            System.err.println("Usage: java CsvToDatabase <csv_file_path>");
            return;
        }

        try (Connection connection = DriverManager.getConnection(DB_URL)) {
            createTable(connection);

            try (BufferedReader reader = new BufferedReader(new FileReader(args[0]))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    String[] values = line.split(",");
                    if (values.length != 3) {
                        System.err.println("Invalid input format: " + line);
                        continue;
                    }

                    String name = values[0].trim();
                    int age;
                    try {
                        age = Integer.parseInt(values[1].trim());
                    } catch (NumberFormatException e) {
                        System.err.println("Invalid age value: " + values[1]);
                        continue;
                    }
                    String email = values[2].trim();

                    addUser(connection, name, age, email);
                }
            } catch (IOException e) {
                System.err.println("Error reading CSV file: " + e.getMessage());
            }
        } catch (SQLException e) {
            System.err.println("Error connecting to the database: " + e.getMessage());
        }
    }

    private static void createTable(Connection connection) throws SQLException {
        try (PreparedStatement statement = connection.prepareStatement(CREATE_TABLE_SQL)) {
            statement.executeUpdate();
        }
    }

    private static void addUser(Connection connection, String name, int age, String email) {
        String sql = "INSERT INTO users(name, age, email) VALUES(?, ?, ?)";

        try (PreparedStatement statement = connection.prepareStatement(sql)) {
            statement.setString(1, name);
            statement.setInt(2, age);
            statement.setString(3, email);

            statement.executeUpdate();
            System.out.println("Added user: " + name + ", " + age + ", " + email);
        } catch (SQLException e) {
            if (e.getErrorCode() == 19) { // SQLITE_CONSTRAINT error code
                System.err.println("Duplicate entry for email: " + email);
            } else {
                System.err.println("Error adding user: " + e.getMessage());
            }
        }
    }
}

class Node:
    def __init__(self, data=None):
        self.data = data
        self.next = None

class SinglyLinkedList:
    def __init__(self):
        self.head = None

    def add_at_beginning(self, data):
        new_node = Node(data)
        new_node.next = self.head
        self.head = new_node

    def add_at_end(self, data):
        new_node = Node(data)

        if not self.head:
            self.head = new_node
            return

        last_node = self.head
        while last_node.next:
            last_node = last_node.next

        last_node.next = new_node

    def add_at_index(self, index, data):
        if index < 0:
            raise ValueError("Index must be non-negative")

        if index == 0:
            self.add_at_beginning(data)
            return

        new_node = Node(data)
        current_node = self.head
        for i in range(index - 1):
            if not current_node:
                raise IndexError("List index out of range")
            current_node = current_node.next

        new_node.next = current_node.next
        current_node.next = new_node

    def delete_by_value(self, value):
        if not self.head:
            raise ValueError("List is empty")

        if self.head.data == value:
            self.head = self.head.next
            return

        current_node = self.head
        while current_node.next and current_node.next.data != value:
            current_node = current_node.next

        if not current_node.next:
            raise ValueError(f"Value {value} not found in the list")

        current_node.next = current_node.next.next

    def delete_by_index(self, index):
        if index < 0:
            raise ValueError("Index must be non-negative")

        if not self.head:
            raise IndexError("List is empty")

        if index == 0:
            self.head = self.head.next
            return

        current_node = self.head
        for i in range(index - 1):
            if not current_node.next:
                raise IndexError("List index out of range")
            current_node = current_node.next

        if not current_node.next:
            raise IndexError("List index out of range")

        current_node.next = current_node.next.next

    def __str__(self):
        result = []
        current_node = self.head
        while current_node:
            result.append(str(current_node.data))
            current_node = current_node.next
        return " -> ".join(result)

if __name__ == "__main__":
    sll = SinglyLinkedList()
    sll.add_at_beginning(3)
    sll.add_at_beginning(2)
    sll.add_at_end(4)
    sll.add_at_index(1, 10)
    print(sll) # Output: 2 -> 10 -> 3 -> 4

    sll.delete_by_value(10)
    print(sll) # Output: 2 -> 3 -> 4

    sll.delete_by_index(1)
    print(sll) # Output: 2 -> 4

