5. Implement JWT-based authentication middleware.

Create a new folder named `middlewares` and inside that folder, create a file named `auth.js`. In this file, implement the authentication middleware using JSON Web Tokens:

```javascript
const jwt = require('jsonwebtoken');
const dotenv = require('dotenv');

dotenv.config();

function authenticate(req, res, next) {
  const token = req.header('Authorization').split(' ')[1];
  if (!token) return res.status(401).send('Access denied.');

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded;
    next();
  } catch (error) {
    res.status(400).send('Invalid token.');
  }
}

function authorize(role) {
  return (req, res, next) => {
    if (req.user.role !== role)
      return res.status(403).send('Forbidden: Insufficient permissions.');
    next();
  };
}

module.exports = { authenticate, authorize };
```

