package main

import (
	"encoding/json"
	"log"
	"net/http"

	"github.com/gocql/gocql"
	"github.com/gorilla/mux"
)

// User struct (Model)
type User struct {
	ID       gocql.UUID `json:"id"`
	Name     string     `json:"name"`
	Email    string     `json:"email"`
	Password string     `json:"password"`
}

var session *gocql.Session // Cassandra session global variable

func init() {
	var err error

	// Connect to the cluster
	cluster := gocql.NewCluster("127.0.0.1")
	cluster.Keyspace = "test"
	session, err = cluster.CreateSession()
	if err != nil {
		panic(err)
	}
	log.Println("cassandra init done")
}

// Get all users from the DB and return them
func getUsers(w http.ResponseWriter, r *http.Request) {
	var userList []User
	m := map[string]interface{}{}

	query := "SELECT id, name, email, password FROM users"
	iterable := session.Query(query).Iter()
	for iterable.MapScan(m) {
		userList = append(userList, User{
			ID:       m["id"].(gocql.UUID),
			Name:     m["name"].(string),
			Email:    m["email"].(string),
			Password: m["password"].(string),
		})
		m = map[string]interface{}{}
	}
	json.NewEncoder(w).Encode(userList)
}

// Insert a new user into the database
func createUser(w http.ResponseWriter, r *http.Request) {
	var user User
	_ = json.NewDecoder(r.Body).Decode(&user)
	user.ID = gocql.TimeUUID()

	if err := session.Query(`INSERT INTO users (id, name, email, password) VALUES (?, ?, ?, ?)`,
		user.ID, user.Name, user.Email, user.Password).Exec(); err != nil {
		log.Fatal(err)
	}

	json.NewEncoder(w).Encode(user)
}

// Update an existing user in the database
func updateUser(w http.ResponseWriter, r *http.Request) {
	var user User
	params := mux.Vars(r)
	_ = json.NewDecoder(r.Body).Decode(&user)

	if err := session.Query(`UPDATE users SET name = ?, email = ?, password = ? WHERE id = ?`,
		user.Name, user.Email, user.Password, params["id"]).Exec(); err != nil {
		log.Fatal(err)
	}

	json.NewEncoder(w).Encode(user)
}

// Delete a user from the database
func deleteUser(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)

	if err := session.Query(`DELETE FROM users WHERE id = ?`, params["id"]).Exec(); err != nil {
		log.Fatal(err)
	}

	json.NewEncoder(w).Encode(params["id"])
}

func main() {
	router := mux.NewRouter()

	// Route handles & endpoints
	router.HandleFunc("/users", getUsers).Methods("GET")
	router.HandleFunc("/users", createUser).Methods("POST")
	router.HandleFunc("/users/{id}", updateUser).Methods("PUT")
	router.HandleFunc("/users/{id}", deleteUser).Methods("DELETE")

	// Start server
	log.Fatal(http.ListenAndServe(":8000", router))
}

To create a real-time chat server using Gorilla WebSocket library in Golang, follow the steps below:

1. Install the Gorilla WebSocket library by running the following command:
```bash
