#include <iostream>

class Node {
public:
    int data;
    Node* left;
    Node* right;

    Node(int data) : data(data), left(nullptr), right(nullptr) {}
};

class BinarySearchTree {
private:
    Node* root;

    Node* insert(Node* node, int data) {
        if (node == nullptr) {
            return new Node(data);
        }

        if (data < node->data) {
            node->left = insert(node->left, data);
        } else if (data > node->data) {
            node->right = insert(node->right, data);
        }

        return node;
    }

    Node* search(Node* node, int data) {
        if (node == nullptr || node->data == data) {
            return node;
        }

        if (data < node->data) {
            return search(node->left, data);
        } else {
            return search(node->right, data);
        }
    }

    Node* findMin(Node* node) {
        while (node->left != nullptr) {
            node = node->left;
        }
        return node;
    }

    Node* remove(Node* node, int data) {
        if (node == nullptr) {
            return node;
        }

        if (data < node->data) {
            node->left = remove(node->left, data);
        } else if (data > node->data) {
            node->right = remove(node->right, data);
        } else {
            if (node->left == nullptr) {
                Node* temp = node->right;
                delete node;
                return temp;
            } else if (node->right == nullptr) {
                Node* temp = node->left;
                delete node;
                return temp;
            }

            Node* temp = findMin(node->right);
            node->data = temp->data;
            node->right = remove(node->right, temp->data);
        }

        return node;
    }

public:
    BinarySearchTree() : root(nullptr) {}

    void insert(int data) {
        root = insert(root, data);
    }

    bool search(int data) {
        Node* result = search(root, data);
        return result != nullptr;
    }

    int findMin() {
        if (root == nullptr) {
            throw std::runtime_error("Tree is empty");
        }
        return findMin(root)->data;
    }

    int findMax() {
        if (root == nullptr) {
            throw std::runtime_error("Tree is empty");
        }
        Node* node = root;
        while (node->right != nullptr) {
            node = node->right;
        }
        return node->data;
    }

    void remove(int data) {
        root = remove(root, data);
    }
};

int main() {
    BinarySearchTree bst;

    bst.insert(50);
    bst.insert(30);
    bst.insert(20);
    bst.insert(40);
    bst.insert(70);
    bst.insert(60);
    bst.insert(80);

    std::cout << "Searching for 20: " << (bst.search(20) ? "Found" : "Not found") << std::endl;
    std::cout << "Searching for 100: " << (bst.search(100) ? "Found" : "Not found") << std::endl;

    std::cout << "Minimum value: " << bst.findMin() << std::endl;
    std::cout << "Maximum value: " << bst.findMax() << std::endl;

    bst.remove(20);
    std::cout << "Searching for 20 after removal: " << (bst.search(20) ? "Found" : "Not found") << std::endl;

    return 0;
}

