int main(int argc, char* argv[]) {
    if (argc != 3) {
        std::cerr << "Usage: upload_to_gcs <bucket_name> <local_file_path>\n";
        return 1;
    }

    std::string bucket_name = argv[1];
    std::string local_file_path = argv[2];

    try {
        // Initialize the Google Cloud Storage client
        auto client = gcs::Client::CreateDefaultClient().value();

        // Upload the local file to the specified bucket
        std::ifstream input_file(local_file_path, std::ios::binary);
        auto object_name = "uploaded_" + std::to_string(std::time(nullptr));
        auto metadata = client.InsertObject(bucket_name, object_name, input_file, gcs::IfGenerationMatch(0)).value();
        std::cout << "File uploaded successfully: " << metadata.name() << "\n";

        // Generate a signed URL for the uploaded object with an expiration time of 1 hour
        auto expiration_time = std::chrono::system_clock::now() + std::chrono::hours(1);
        auto signed_url_options = gcs::SignedUrlOptions()
                                      .set_method("GET")
                                      .set_expiration_time(expiration_time);

        auto signed_url = client.CreateV4SignedUrl(bucket_name, object_name, signed_url_options).value();
        std::cout << "Signed URL: " << signed_url << "\n";
    } catch (const std::exception& ex) {
        std::cerr << "Error: " << ex.what() << "\n";
        return 1;
    }

    return 0;
}

