package main

import (
	"fmt"
	"math/rand"
	"time"
)

type Problem struct {
	a, b     int
	operator string
}

// Calculate the result of the problem based on the operator
func (p *Problem) calculate() int {
	switch p.operator {
	case "+":
		return p.a + p.b
	case "-":
		return p.a - p.b
	case "*":
		return p.a * p.b
	case "/":
		return p.a / p.b
	default:
		return 0
	}
}

// Generate a random operator for the math problem
func generateRandomOperator() string {
	operators := []string{"+", "-", "*", "/"}
	return operators[rand.Intn(len(operators))]
}

// Generate a random number based on the difficulty level
func generateRandomNumber(difficulty int) int {
	return rand.Intn(difficulty*10) + 1
}

// Generate a math problem with the given difficulty level
func generateProblem(difficulty int) Problem {
	return Problem{
		a:        generateRandomNumber(difficulty),
		b:        generateRandomNumber(difficulty),
		operator: generateRandomOperator(),
	}
}

func main() {
	rand.Seed(time.Now().UnixNano())

	var difficulty int
	fmt.Print("Enter the difficulty level (1-5): ")
	fmt.Scan(&difficulty)

	if difficulty < 1 || difficulty > 5 {
		fmt.Println("Invalid difficulty level. Please enter a number between 1 and 5.")
		return
	}

	problem := generateProblem(difficulty)
	fmt.Printf("Solve this problem: %d %s %d = ", problem.a, problem.operator, problem.b)

	var answer int
	fmt.Scan(&answer)

	correctAnswer := problem.calculate()
	if answer == correctAnswer {
		fmt.Println("Correct!")
	} else {
		fmt.Printf("Incorrect! The correct answer is %d.\n", correctAnswer)
	}
}

