import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.jsoup.select.Elements;

import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class GoogleScraper {

    public static void main(String[] args) throws IOException {
        String query = "web scraping";
        List<Map<String, String>> results = scrapeGoogle(query);
        saveResultsAsJson(results, "results.json");
    }

    private static List<Map<String, String>> scrapeGoogle(String query) throws IOException {
        String url = "https://www.google.com/search?q=" + query.replace(" ", "+");
        Document doc = Jsoup.connect(url).userAgent("Mozilla/5.0").get();

        Elements searchResults = doc.select(".tF2Cxc");

        List<Map<String, String>> results = new ArrayList<>();
        for (Element result : searchResults) {
            Map<String, String> resultMap = new HashMap<>();
            resultMap.put("title", result.select(".LC20lb.DKV0Md").text());
            resultMap.put("url", result.select(".yuRUbf > a").attr("href"));
            results.add(resultMap);

            if (results.size() >= 10) {
                break;
            }
        }

        return results;
    }

    private static void saveResultsAsJson(List<Map<String, String>> results, String fileName) throws IOException {
        FileWriter fileWriter = new FileWriter(fileName);
        fileWriter.write("[\n");

        for (int i = 0; i < results.size(); i++) {
            Map<String, String> result = results.get(i);
            fileWriter.write("  {\n");
            fileWriter.write("    \"title\": \"" + result.get("title") + "\",\n");
            fileWriter.write("    \"url\": \"" + result.get("url") + "\"\n");

            if (i == results.size() - 1) {
                fileWriter.write("  }\n");
            } else {
                fileWriter.write("  },\n");
            }
        }

        fileWriter.write("]");
        fileWriter.close();
    }
}

