import com.opencsv.CSVReader;
import com.opencsv.exceptions.CsvValidationException;

import java.io.FileReader;
import java.io.IOException;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.SQLException;

public class CsvToDatabase {

    public static void main(String[] args) {
        String csvFile = "users.csv";

        try (Connection conn = connect()) {
            createTable(conn);
            readCsvAndInsertData(csvFile, conn);
        } catch (SQLException e) {
            System.out.println("Error connecting to the database: " + e.getMessage());
        }
    }

    private static Connection connect() throws SQLException {
        return DriverManager.getConnection("jdbc:sqlite:user_data.db");
    }

    private static void createTable(Connection conn) throws SQLException {
        String sql = "CREATE TABLE IF NOT EXISTS users (" +
                "id INTEGER PRIMARY KEY AUTOINCREMENT," +
                "first_name TEXT NOT NULL," +
                "last_name TEXT NOT NULL," +
                "email TEXT NOT NULL UNIQUE," +
                "age INTEGER NOT NULL" +
                ");";
        try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
            pstmt.execute();
        }
    }

    private static void readCsvAndInsertData(String csvFile, Connection conn) {
        try (CSVReader reader = new CSVReader(new FileReader(csvFile))) {
            String[] line;
            while ((line = reader.readNext()) != null) {
                if (line.length != 4) {
                    System.out.println("Invalid data format: " + String.join(",", line));
                    continue;
                }

                try {
                    User user = new User(line[0], line[1], line[2], Integer.parseInt(line[3]));
                    insertUser(conn, user);
                } catch (NumberFormatException e) {
                    System.out.println("Invalid age value: " + line[3]);
                }
            }
        } catch (IOException | CsvValidationException e) {
            System.out.println("Error reading CSV file: " + e.getMessage());
        }
    }

    private static void insertUser(Connection conn, User user) {
        String sql = "INSERT INTO users(first_name, last_name, email, age) VALUES(?,?,?,?)";
        try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
            pstmt.setString(1, user.getFirstName());
            pstmt.setString(2, user.getLastName());
            pstmt.setString(3, user.getEmail());
            pstmt.setInt(4, user.getAge());
            pstmt.executeUpdate();
        } catch (SQLException e) {
            System.out.println("Error inserting user: " + e.getMessage());
        }
    }

    static class User {
        private final String firstName;
        private final String lastName;
        private final String email;
        private final int age;

        public User(String firstName, String lastName, String email, int age) {
            this.firstName = firstName;
            this.lastName = lastName;
            this.email = email;
            this.age = age;
        }

        public String getFirstName() {
            return firstName;
        }

        public String getLastName() {
            return lastName;
        }

        public String getEmail() {
{
            return email;
        }

        public int getAge() {
            return age;
        }
    }
}

