using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Net.Http;
using System.Threading.Tasks;
using Newtonsoft.Json;

namespace UrlDownloader
{
    class Program
    {
        static async Task Main(string[] args)
        {
            if (args.Length == 0)
            {
                Console.WriteLine("Please provide the path to the JSON configuration file.");
                return;
            }

            string configFilePath = args[0];
            List<string> urls = ReadUrlsFromJsonFile(configFilePath);

            await DownloadAndSaveFilesAsync(urls);
            Console.WriteLine("All files downloaded successfully.");
        }

        private static List<string> ReadUrlsFromJsonFile(string filePath)
        {
            string jsonContent = File.ReadAllText(filePath);
            return JsonConvert.DeserializeObject<List<string>>(jsonContent);
        }

        private static async Task DownloadAndSaveFilesAsync(List<string> urls)
        {
            var tasks = urls.Select(DownloadAndSaveFileAsync).ToList();
            await Task.WhenAll(tasks);
        }

        private static async Task DownloadAndSaveFileAsync(string url)
        {
            try
            {
                using HttpClient httpClient = new HttpClient();
                HttpResponseMessage response = await httpClient.GetAsync(url);

                if (!response.IsSuccessStatusCode)
                {
                    Console.WriteLine($"Failed to download {url}: {response.StatusCode}");
                    return;
                }

                string content = await response.Content.ReadAsStringAsync();
                string fileName = GetFileNameFromUrl(url);
                File.WriteAllText(fileName, content);

                Console.WriteLine($"Downloaded and saved {url} to {fileName}");
            }
            catch (Exception ex)
            {
                Console.WriteLine($"Error downloading {url}: {ex.Message}");
            }
        }

        private static string GetFileNameFromUrl(string url)
        {
            Uri uri = new Uri(url);
            return $"{uri.Host}.html";
        }
    }
}

