#include <iostream>
#include <cmath>

class Vector3D {
private:
    double x, y, z;

public:
    // Constructors
    Vector3D() : x(0), y(0), z(0) {}
    Vector3D(double x, double y, double z) : x(x), y(y), z(z) {}

    // Getters and Setters
    double getX() const { return x; }
    double getY() const { return y; }
    double getZ() const { return z; }

    void setX(double x) { this->x = x; }
    void setY(double y) { this->y = y; }
    void setZ(double z) { this->z = z; }

    // Addition
    Vector3D operator+(const Vector3D& other) const {
        return Vector3D(x + other.x, y + other.y, z + other.z);
    }

    // Subtraction
    Vector3D operator-(const Vector3D& other) const {
        return Vector3D(x - other.x, y - other.y, z - other.z);
    }

    // Dot product
    double dot(const Vector3D& other) const {
        return x * other.x + y * other.y + z * other.z;
    }

    // Cross product
    Vector3D cross(const Vector3D& other) const {
        return Vector3D(
            y * other.z - z * other.y,
            z * other.x - x * other.z,
            x * other.y - y * other.x
        );
    }

    // Magnitude
    double magnitude() const {
        return std::sqrt(x * x + y * y + z * z);
    }

    // Normalization
    Vector3D normalize() const {
        double mag = magnitude();
        return Vector3D(x / mag, y / mag, z / mag);
    }

    // Angle between vectors (in radians)
    double angle(const Vector3D& other) const {
        return std::acos(dot(other) / (magnitude() * other.magnitude()));
    }
};

int main() {
    Vector3D v1(1, 2, 3);
    Vector3D v2(4, 5, 6);

    Vector3D sum = v1 + v2;
    std::cout << "Sum: (" << sum.getX() << ", " << sum.getY() << ", " << sum.getZ() << ")" << std::endl;

    Vector3D diff = v1 - v2;
    std::cout << "Difference: (" << diff.getX() << ", " << diff.getY() << ", " << diff.getZ() << ")" << std::endl;

    double dotProduct = v1.dot(v2);
    std::cout << "Dot product: " << dotProduct << std::endl;

    Vector3D crossProduct = v1.cross(v2);
    std::cout << "Cross product: (" << crossProduct.getX() << ", " << crossProduct.getY() << ", " << crossProduct.getZ() << ")" << std::endl;

    double magnitudeV1 = v1.magnitude();
    std::cout << "Magnitude of v1: " << magnitudeV1 << std::endl;

    Vector3D normalizedV1 = v1.normalize();
    std::cout << "Normalized v1: (" << normalizedV1.getX() << ", " << normalizedV1.getY() << ", " << normalizedV1.getZ() << ")" << std::endl;

    double angleBetweenVectors = v1.angle(v2);
    std::cout << "Angle between v1 and v2 (in radians): " << angleBetweenVectors << std::endl;

    return 0;
}

package cmd

import (
	"fmt"
	"io/ioutil"
	"os"
	"path/filepath"

	"github.com/spf13/cobra"
)

var syncFlag bool

func init() {
	rootCmd.AddCommand(compareCmd)
	compareCmd.Flags().BoolVarP(&syncFlag, "sync", "s", false, "Synchronize the content of the two directories")
}

var compareCmd = &cobra.Command{
	Use:   "compare [dir1] [dir2]",
	Short: "Compare and optionally synchronize the contents of two directories",
	Long:  `This command compares the contents of two directories recursively and reports any differences.`,
	Args:  cobra.ExactArgs(2),
	Run: func(cmd *cobra.Command, args []string) {
		dir1 := args[0]
		dir2 := args[1]

		err := compareDirectories(dir1, dir2, syncFlag)
		if err != nil {
			fmt.Println("Error:", err)
			os.Exit(1)
		}
	},
}

func compareDirectories(dir1, dir2 string, syncDirs bool) error {
	filepath.Walk(dir1, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}

		relPath, _ := filepath.Rel(dir1, path)
		pathInDir2 := filepath.Join(dir2, relPath)

		info2, err := os.Stat(pathInDir2)
		if os.IsNotExist(err) {
			fmt.Printf("Missing in %s: %s\n", dir2, relPath)
			if syncDirs {
				err = copyFileOrDirectory(path, pathInDir2)
				if err != nil {
					return err
				}
			}
		} else if info.IsDir() != info2.IsDir() {
			fmt.Printf("Type mismatch: %s\n", relPath)
		} else if !info.IsDir() && !info2.IsDir() {
			same, err := compareFiles(path, pathInDir2)
			if err != nil {
				return err
			}
			if !same {
				fmt.Printf("Modified: %s\n", relPath)
				if syncDirs {
					err = copyFileOrDirectory(path, pathInDir2)
					if err != nil {
						return err
					}
				}
			}
		}

		return nil
	})

	return nil
}

func compareFiles(file1, file2 string) (bool, error) {
	data1, err := ioutil.ReadFile(file1)
	if err != nil {
		return false, err
	}

	data2, err := ioutil.ReadFile(file2)
	if err != nil {
		return false, err
	}

	return string(data1) == string(data2), nil
}

func copyFileOrDirectory(src, dst string) error {
	srcInfo, err := os.Stat(src)
	if err != nil {
		return err
	}

	if srcInfo.IsDir() {
		return copyDirectory(src, dst)
	} else {
		return copyFile(src, dst)
	}
}

func copyFile(src, dst string) error {
	data, err := ioutil.ReadFile(src)
	if err != nil {
		return err
	}

	err = ioutil.WriteFile(dst, data, 0644)
	if err != nil {
		return err
	}

	return nil
}

func copyDirectory(src, dst string) error {
	err := os.MkdirAll(dst, 0755)
	if err != nil {
		return err
	}

	files, err := ioutil.ReadDir(src)
	if err != nil {
		return err
	}

	for _, file := range files {
		srcPath := filepath.Join(src, file.Name())
		dstPath := filepath.Join(dst, file.Name())

		err = copyFileOrDirectory(srcPath, dstPath)
		if err != nil {
			return err
		}
	}

	return nil
}

