	sqlStatement := `
	INSERT INTO users (name, email, age)
	VALUES ($1, $2, $3)
	RETURNING id`
	err := db.QueryRow(sqlStatement, user.Name, user.Email, user.Age).Scan(&user.ID)

	if err != nil {
		return err
	}

	fmt.Println("New record ID is:", user.ID)
	return nil
}

