using System;
using System.Drawing;
using System.Windows.Forms;

public class TicTacToe : Form
{
    private Button[] buttons = new Button[9];
    private bool turn = true; // true = X turn, false = O turn

    public TicTacToe()
    {
        for (int i = 0; i < 9; i++)
        {
            buttons[i] = new Button();
            buttons[i].Font = new Font("Arial", 24);
            buttons[i].Click += button_Click;
            Controls.Add(buttons[i]);
        }
        InitializeComponent();
    }

    private void InitializeComponent()
    {
        this.Text = "Tic Tac Toe";
        this.Size = new Size(300, 330);

        int x = 10, y = 10;
        for (int i = 0; i < 9; i++)
        {
            if (i == 3 || i == 6)
            {
                x = 10;
                y += 100;
            }
            buttons[i].Location = new Point(x, y);
            buttons[i].Size = new Size(90, 90);
            x += 100;
        }
    }

    private void button_Click(object sender, EventArgs e)
    {
        Button buttonClicked = (Button)sender;
        buttonClicked.Text = turn ? "X" : "O";
        buttonClicked.Enabled = false;
        turn = !turn;
        CheckForWinner();
    }

    private void CheckForWinner()
    {
        string winner = "";
        string[] results = new string[8];

        // Rows
        results[0] = buttons[0].Text + buttons[1].Text + buttons[2].Text;
        results[1] = buttons[3].Text + buttons[4].Text + buttons[5].Text;
        results[2] = buttons[6].Text + buttons[7].Text + buttons[8].Text;

        // Columns
        results[3] = buttons[0].Text + buttons[3].Text + buttons[6].Text;
        results[4] = buttons[1].Text + buttons[4].Text + buttons[7].Text;
        results[5] = buttons[2].Text + buttons[5].Text + buttons[8].Text;

        // Diagonals
        results[6] = buttons[0].Text + buttons[4].Text + buttons[8].Text;
        results[7] = buttons[2].Text + buttons[4].Text + buttons[6].Text;

        foreach (string result in results)
        {
            if (result == "XXX")
            {
                winner = "X";
                break;
            }
            else if (result == "OOO")
            {
                winner = "O";
                break;
            }
        }

        if (!String.IsNullOrEmpty(winner))
        {
            MessageBox.Show(winner + " wins!");
            Application.Restart();
        }
        else if (Array.TrueForAll(buttons, b => b.Enabled == false)) // All buttons are disabled, game is a tie
        {
            MessageBox.Show("It's a tie!");
            Application.Restart();
        }
    }

    [STAThread]
    static void Main()
    {
        Application.EnableVisualStyles();
        Application.SetCompatibleTextRenderingDefault(false);
        Application.Run(new TicTacToe());
    }
}

