const http = require('http');
const url = require('url');
const { argv } = require('yargs');

// Parse command line arguments
const listenIP = argv.listenIP || '127.0.0.1';
const listenPort = argv.listenPort || 8080;
const backendServerAddress = argv.backendServerAddress || 'http://localhost:3000';

// Create a proxy server
const proxyServer = http.createServer((req, res) => {
  // Forward request to the backend server
  const requestOptions = {
    ...url.parse(backendServerAddress),
    method: req.method,
    headers: req.headers,
    path: req.url,
  };

  const backendRequest = http.request(requestOptions, (backendResponse) => {
    // Return response from the backend server to the client
    res.writeHead(backendResponse.statusCode, backendResponse.headers);
    backendResponse.pipe(res);
  });

  // Handle errors
  backendRequest.on('error', (err) => {
    console.error(`Error forwarding request: ${err.message}`);
    res.writeHead(500);
    res.end();
  });

  // Forward POST data
  if (req.method === 'POST') {
    req.pipe(backendRequest);
  } else {
    backendRequest.end();
  }
});

// Start listening for incoming requests
proxyServer.listen(listenPort, listenIP, () => {
  console.log(`Proxy server is listening on ${listenIP}:${listenPort}`);
  console.log(`Forwarding requests to ${backendServerAddress}`);
});

function sieveOfEratosthenes(arr) {
    // Create a new array with all elements set to true.
    let primes = Array(arr.length).fill(true);

    for (let i = 2; i <= Math.sqrt(arr.length); i++) {
        if (primes[i]) {
            // If the number is prime, then go through all its multiples and mark them as composite.
            for (let j = i * i; j < arr.length; j += i) {
                primes[j] = false;
            }
        }
    }

    // Filter out non-prime numbers from the original array.
    return arr.filter((num, index) => primes[num] && num > 1);
}

package main

import (
	"crypto/md5"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"io/ioutil"
	"os"
	"path/filepath"
)

type FileChecksum struct {
	Path     string `json:"path"`
	Checksum string `json:"checksum"`
}

// calculateMD5 calculates the MD5 checksum of a file
func calculateMD5(filePath string) (string, error) {
	data, err := ioutil.ReadFile(filePath)
	if err != nil {
		return "", err
	}
	hasher := md5.New()
	hasher.Write(data)
	checksum := hex.EncodeToString(hasher.Sum(nil))
	return checksum, nil
}

// scanDirectory recursively scans all files and folders within a directory
func scanDirectory(dirPath string) ([]FileChecksum, error) {
	var result []FileChecksum
	err := filepath.Walk(dirPath, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if !info.IsDir() {
			checksum, err := calculateMD5(path)
			if err != nil {
				return err
			}
			result = append(result, FileChecksum{Path: path, Checksum: checksum})
		}
		return nil
	})
	if err != nil {
		return nil, err
	}
	return result, nil
}

func main() {
	if len(os.Args) < 2 {
		fmt.Println("Usage: go run main.go [directory_path]")
		os.Exit(1)
	}

	dirPath := os.Args[1]
	fileChecksums, err := scanDirectory(dirPath)
	if err != nil {
		fmt.Printf("Error scanning directory: %v\n", err)
		os.Exit(1)
	}

	jsonData, err := json.MarshalIndent(fileChecksums, "", "  ")
	if err != nil {
		fmt.Printf("Error encoding JSON: %v\n", err)
		os.Exit(1)
	}

	fmt.Println(string(jsonData))
}

