Now, let's create a simple Java program that demonstrates how to create, update, and delete deployments within a specified namespace using the Kubernetes API.

```java
import io.kubernetes.client.openapi.ApiClient;
import io.kubernetes.client.openapi.Configuration;
import io.kubernetes.client.openapi.apis.AppsV1Api;
import io.kubernetes.client.openapi.models.*;
import io.kubernetes.client.util.Config;

import java.io.IOException;

public class K8sDeploymentManager {

    public static void main(String[] args) throws IOException {
        // Load the default kubeconfig
        ApiClient client = Config.defaultClient();
        Configuration.setDefaultApiClient(client);

        // Create an instance of the AppsV1Api
        AppsV1Api api = new AppsV1Api();

        // Define the deployment details
        String namespace = "default";
        String deploymentName = "my-deployment";

        // Create the deployment
        System.out.println("Creating deployment...");
        V1Deployment createdDeployment = createDeployment(api, namespace, deploymentName);
        System.out.println("Created deployment: " + createdDeployment.getMetadata().getName());

        // Update the deployment
        System.out.println("Updating deployment...");
        V1Deployment updatedDeployment = updateDeployment(api, namespace, deploymentName);
        System.out.println("Updated deployment: " + updatedDeployment.getMetadata().getName());

        // Delete the deployment
        System.out.println("Deleting deployment...");
        deleteDeployment(api, namespace, deploymentName);
        System.out.println("Deleted deployment: " + deploymentName);
    }

    private static V1Deployment createDeployment(AppsV1Api api, String namespace, String deploymentName) throws IOException {
        // Define the container
        V1Container container = new V1Container()
                .name("nginx")
                .image("nginx:1.14.2")
                .ports(new V1ContainerPort().containerPort(80));

        // Define the pod spec
        V1PodSpec podSpec = new V1PodSpec().containers(container);

        // Define the pod template
        V1PodTemplateSpec podTemplateSpec = new V1PodTemplateSpec()
                .metadata(new V1ObjectMeta().labels(Map.of("app", "nginx")))
                .spec(podSpec);

        // Define the deployment spec
        V1DeploymentSpec deploymentSpec = new V1DeploymentSpec()
                .replicas(3)
                .selector(new V1LabelSelector().matchLabels(Map.of("app", "nginx")))
                .template(podTemplateSpec);

        // Create the deployment object
        V1Deployment deployment = new V1Deployment()
                .metadata(new V1ObjectMeta().name(deploymentName))
                .spec(deploymentSpec);

        // Call the Kubernetes API to create the deployment
        return api.createNamespacedDeployment(namespace, deployment, null, null, null);
    }

    private static V1Deployment updateDeployment(AppsV1Api api, String namespace, String deploymentName) throws IOException {
        // Get the existing deployment
        V1Deployment existingDeployment = api.readNamespacedDeployment(deploymentName, namespace, null, null, null);

        // Update the number of replicas
        existingDeployment.getSpec().setReplicas(5);

        // Call the Kubernetes API to update the deployment
        return api.replaceNamespacedDeployment(deploymentName, namespace, existingDeployment, null, null, null);
    }

    private static void deleteDeployment(AppsV1Api api, String namespace, String deploymentName) throws IOException {
        // Define the delete options
        V1DeleteOptions deleteOptions = new V1DeleteOptions();

        // Call the Kubernetes API to delete the deployment
        api.deleteNamespacedDeployment(deploymentName, namespace, null, null, null, null, null, deleteOptions);
    }
}
```

This program demonstrates how to create a simple Nginx deployment with 3 replicas, update it to have 5 replicas, and then delete it. Make sure you have your `kubeconfig` file properly configured for the cluster you want to interact with.

Note that this example assumes you have permission to perform these actions on the specified namespace. You may need to configure RBAC rules or use a service account with appropriate permissions if necessary.

// Function to capitalize the first letter of every word in a string
function capitalizeFirstLetterOfEveryWord(str) {
    // Split the string into an array of words
    let words = str.split(' ');

    // Iterate over each word
    for(let i = 0; i < words.length; i++) {
        // Capitalize the first letter of the word and add the rest of the word
