type Product struct {
	ID       int    `json:"id"`
	Name     string `json:"name"`
	Price    float64 `json:"price"`
}

var db *sql.DB

func main() {
	connStr := os.Getenv("POSTGRES_CONNECTION_STRING")
	var err error
	db, err = sql.Open("postgres", connStr)
	if err != nil {
		log.Fatal(err)
	}
	defer db.Close()

	router := mux.NewRouter()
	router.HandleFunc("/products", getProducts).Methods("GET")
	router.HandleFunc("/products/{id}", getProduct).Methods("GET")
	router.HandleFunc("/products", createProduct).Methods("POST")
	router.HandleFunc("/products/{id}", updateProduct).Methods("PUT")
	router.HandleFunc("/products/{id}", deleteProduct).Methods("DELETE")

	http.ListenAndServe(":8000", router)
}

func getProducts(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	limit, _ := strconv.Atoi(r.URL.Query().Get("limit"))
	offset, _ := strconv.Atoi(r.URL.Query().Get("offset"))

	rows, err := db.Query("SELECT id, name, price FROM products LIMIT $1 OFFSET $2", limit, offset)
	if err != nil {
		log.Fatal(err)
	}
	defer rows.Close()

	var products []Product
	for rows.Next() {
		var p Product
		err := rows.Scan(&p.ID, &p.Name, &p.Price)
		if err != nil {
			log.Fatal(err)
		}
		products = append(products, p)
	}

	json.NewEncoder(w).Encode(products)
}

func getProduct(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)

	id, _ := strconv.Atoi(params["id"])

	row := db.QueryRow("SELECT id, name, price FROM products WHERE id=$1", id)

	var p Product
	err := row.Scan(&p.ID, &p.Name, &p.Price)
	if err == sql.ErrNoRows {
		w.WriteHeader(http.StatusNotFound)
		return
	} else if err != nil {
		log.Fatal(err)
	}

	json.NewEncoder(w).Encode(p)
}

func createProduct(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	var p Product
	json.NewDecoder(r.Body).Decode(&p)

	err := db.QueryRow("INSERT INTO products (name, price) VALUES ($1, $2) RETURNING id", p.Name, p.Price).Scan(&p.ID)
	if err != nil {
		log.Fatal(err)
	}

	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(p)
}

func updateProduct(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)

	id, _ := strconv.Atoi(params["id"])

	var p Product
	json.NewDecoder(r.Body).Decode(&p)

	res, err := db.Exec("UPDATE products SET name=$1, price=$2 WHERE id=$3", p.Name, p.Price, id)
	if err != nil {
		log.Fatal(err)
	}

	count, _ := res.RowsAffected()
	if count == 0 {
		w.WriteHeader(http.StatusNotFound)
		return
	}

	p.ID = id
	json.NewEncoder(w).Encode(p)
}

func deleteProduct(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)

	id, _ := strconv.Atoi(params["id"])

	res, err := db.Exec("DELETE FROM products WHERE id=$1", id)
	if err != nil {
		log.Fatal(err)
	}

	count, _ := res.RowsAffected()
	if count == 0 {
		w.WriteHeader(http.StatusNotFound)
		return
	}

	w.WriteHeader(http.StatusNoContent)
}

import json

class Game:
    def __init__(self):
        self.rooms = {
            "start": {
                "description": "You are in the starting room. There is a door to the east.",
                "exits": {"east": "room1"},
                "items": [],
                "enemies": []
            },
            "room1": {
                "description": "You are in room 1. There are doors to the west and east.",
                "exits": {"west": "start", "east": "room2"},
                "items": ["sword"],
                "enemies": []
            },
            "room2": {
                "description": "You are in room 2. There is a door to the west.",
                "exits": {"west": "room1"},
                "items": [],
                "enemies": ["goblin"]
            }
        }
        self.player = {
            "location": "start",
            "inventory": [],
            "health": 100
        }

    def describe_room(self, room_name):
        room = self.rooms[room_name]
        print(room["description"])

        if room["items"]:
            print("Items here:", ", ".join(room["items"]))

        if room["enemies"]:
            print("Enemies here:", ", ".join(room["enemies"]))

    def move(self, direction):
        current_room = self.player["location"]
        next_room = self.rooms[current_room]["exits"].get(direction)

        if next_room:
            self.player["location"] = next_room
            self.describe_room(next_room)
        else:
            print("There is no exit in that direction.")

    def take_item(self, item):
        current_room = self.player["location"]

        if item in self.rooms[current_room]["items"]:
            self.rooms[current_room]["items"].remove(item)
            self.player["inventory"].append(item)
            print(f"You picked up the {item}.")
        else:
            print("There is no such item here.")

    def attack_enemy(self, enemy):
        current_room = self.player["location"]

        if enemy in self.rooms[current_room]["enemies"]:
            if "sword" in self.player["inventory"]:
                self.rooms[current_room]["enemies"].remove(enemy)
                print(f"You defeated the {enemy}!")
            else:
                print("You don't have a weapon to fight with.")
        else:
            print("There is no such enemy here.")

    def save_game(self, filename):
        game_data = {
            "rooms": self.rooms,
            "player": self.player
        }

        with open(filename, "w") as f:
            json.dump(game_data, f)

        print("Game saved.")

    def load_game(self, filename):
        try:
            with open(filename, "r") as f:
                game_data = json.load(f)

            self.rooms = game_data["rooms"]
            self.player = game_data["player"]

            print("Game loaded.")
            self.describe_room(self.player["location"])
        except FileNotFoundError:
            print("Save file not found.")

def main():
    game = Game()
    game.describe_room(game.player["location"])

    while True:
        command = input("> ").split()

        if len(command) == 0:
            continue

        action = command[0].lower()

        if action == "quit":
            break
        elif action == "move":
            direction = command[1]
            game.move(direction)
        elif action == "take":
            item = command[1]
            game.take_item(item)
        elif action == "attack":
            enemy = command[1]
            game.attack_enemy(enemy)
        elif action == "save":
            filename = command[1]
            game.save_game(filename)
        elif action == "load":
            filename = command[1]
            game.load_game(filename)
        else:
            print("Unknown command.")

