To create a chat server using WebSocket protocol in Node.js, you'll need to install the `ws` package. You can do this by running:

```bash
npm init -y
npm install ws
```

Now that you have the required package installed, let's create the chat server.

Create a new file called `chat-server.js` and add the following code:

```javascript
const WebSocket = require('ws');

// Create a WebSocket server on port 8080
const server = new WebSocket.Server({ port: 8080 });

// Store all connected clients
const clients = new Set();

// Broadcast function to send messages to all connected clients
function broadcast(message) {
  for (const client of clients) {
    if (client.readyState === WebSocket.OPEN) {
      client.send(message);
    }
  }
}

// Listen for connection events
server.on('connection', (socket) => {
  console.log('Client connected');

  // Add the connected socket to the clients set
  clients.add(socket);

  // Send a welcome message to the newly connected client
  socket.send('Welcome to the chat server!');

  // Listen for message events from the connected client
  socket.on('message', (message) => {
    console.log(`Received message: ${message}`);

    // Broadcast the received message to all connected clients
    broadcast(`${socket._socket.remoteAddress}: ${message}`);
  });

  // Listen for close events from the connected client
  socket.on('close', () => {
    console.log('Client disconnected');

    // Remove the disconnected socket from the clients set
    clients.delete(socket);
  });
});

console.log('Chat server is running on port 8080');
```

You can run the chat server with the following command:

```bash
node chat-server.js
```

The chat server will now be listening for connections on port 8080.

