<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>WebRTC Video Chat</title>
  <style>
    #localVideo, #remoteVideo {
      width: 100%;
      max-width: 400px;
      height: auto;
    }
  </style>
</head>
<body>
  <video id="localVideo" autoplay muted></video>
  <video id="remoteVideo" autoplay></video>

  <button id="muteAudio">Mute Audio</button>
  <button id="pauseVideo">Pause Video</button>
  <button id="endCall">End Call</button>

  <script src="/socket.io/socket.io.js"></script>
  <script>
    const socket = io();
    const localVideo = document.getElementById('localVideo');
    const remoteVideo = document.getElementById('remoteVideo');
    const muteAudioButton = document.getElementById('muteAudio');
    const pauseVideoButton = document.getElementById('pauseVideo');
    const endCallButton = document.getElementById('endCall');

    let localStream;
    let peerConnection;

    navigator.mediaDevices.getUserMedia({ video: true, audio: true })
      .then(stream => {
        localStream = stream;
        localVideo.srcObject = stream;

        peerConnection = new RTCPeerConnection({
          iceServers: [{ urls: 'stun:stun.l.google.com:19302' }]
        });

        peerConnection.onicecandidate = handleIceCandidate;
        peerConnection.ontrack = handleTrackEvent;

        localStream.getTracks().forEach(track => {
          peerConnection.addTrack(track, localStream);
        });

        if (location.hash === '#init') {
          peerConnection.createOffer()
            .then(offer => {
              return peerConnection.setLocalDescription(offer);
            })
            .then(() => {
              socket.emit('offer', peerConnection.localDescription);
            });
        }
      })
      .catch(error => {
        console.error('Error accessing media devices.', error);
      });

    socket.on('offer', (offer) => {
      peerConnection.setRemoteDescription(new RTCSessionDescription(offer))
        .then(() => {
          return peerConnection.createAnswer();
        })
        .then(answer => {
          return peerConnection.setLocalDescription(answer);
        })
        .then(() => {
          socket.emit('answer', peerConnection.localDescription);
        });
    });

    socket.on('answer', (answer) => {
      peerConnection.setRemoteDescription(new RTCSessionDescription(answer));
    });

    socket.on('candidate', (candidate) => {
      const iceCandidate = new RTCIceCandidate(candidate);
      peerConnection.addIceCandidate(iceCandidate);
    });

    function handleIceCandidate(event) {
      if (event.candidate) {
        socket.emit('candidate', event.candidate);
      }
    }

    function handleTrackEvent(event) {
      remoteVideo.srcObject = event.streams[0];
    }

    muteAudioButton.addEventListener('click', () => {
      localStream.getAudioTracks()[0].enabled = !localStream.getAudioTracks()[0].enabled;
      muteAudioButton.textContent = localStream.getAudioTracks()[0].enabled ? 'Mute Audio' : 'Unmute Audio';
    });

    pauseVideoButton.addEventListener('click', () => {
      localStream.getVideoTracks()[0].enabled = !localStream.getVideoTracks()[0].enabled;
      pauseVideoButton.textContent = localStream.getVideoTracks()[0].enabled ? 'Pause Video' : 'Resume Video';
    });

    endCallButton.addEventListener('click', () => {
      peerConnection.close();
      localStream.getTracks().forEach(track => track.stop());
      window.location.reload();
    });
  </script>
</body>
</html>

