import (
	"flag"
	"fmt"
	"github.com/fsnotify/fsnotify"
	"log"
	"os"
	"time"
)

func main() {
	dirPtr := flag.String("dir", ".", "The target directory to monitor")
	logFilePtr := flag.String("log", "monitor.log", "The output log file path")

	flag.Parse()

	watcher, err := fsnotify.NewWatcher()
	if err != nil {
		log.Fatal(err)
	}
	defer watcher.Close()

	done := make(chan bool)
	go func() {
		for {
			select {
			case event, ok := <-watcher.Events:
				if !ok {
					return
				}

				timestamp := time.Now().Format(time.RFC3339)
				eventStr := fmt.Sprintf("%s: %s\n", timestamp, event)
				fmt.Print(eventStr)

				f, err := os.OpenFile(*logFilePtr, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
				if err != nil {
					log.Println("Error opening log file:", err)
				} else {
					if _, err := f.WriteString(eventStr); err != nil {
						log.Println("Error writing to log file:", err)
					}
					f.Close()
				}

			case err, ok := <-watcher.Errors:
				if !ok {
					return
				}
				log.Println("Error:", err)
			}
		}
	}()

	err = watcher.Add(*dirPtr)
	if err != nil {
		log.Fatal(err)
	}
	<-done
}

Here's a simple command-line calculator in Java that supports addition, subtraction, multiplication, and division operations on two numbers entered by the user:

```java
import java.util.Scanner;

public class SimpleCalculator {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter first number: ");
        double num1 = scanner.nextDouble();

        System.out.print("Enter second number: ");
        double num2 = scanner.nextDouble();

        System.out.println("Choose an operation (+, -, *, /):");
        char operation = scanner.next().charAt(0);

        double result = 0;
        switch (operation) {
            case '+':
                result = num1 + num2;
                break;
            case '-':
                result = num1 - num2;
                break;
            case '*':
                result = num1 * num2;
                break;
            case '/':
                if (num2 == 0) {
                    System.out.println("Error: Division by zero is not allowed.");
                    return;
                }
                result = num1 / num2;
                break;
            default:
                System.out.println("Invalid operation. Please choose from (+, -, *, /).");
                return;
        }

        System.out.printf("Result: %.2f %c %.2f = %.2f%n", num1, operation, num2, result);
    }
}
