Here's a Golang program that implements the Sieve of Eratosthenes algorithm for finding prime numbers up to a given limit:

```go
package main

import (
	"fmt"
	"os"
	"strconv"
)

func sieveOfEratosthenes(limit int) []int {
	isPrime := make([]bool, limit+1)
	for i := 2; i <= limit; i++ {
		isPrime[i] = true
	}

	for p := 2; p*p <= limit; p++ {
		if isPrime[p] {
			for i := p * p; i <= limit; i += p {
				isPrime[i] = false
			}
		}
	}

	primes := []int{}
	for i := 2; i <= limit; i++ {
		if isPrime[i] {
			primes = append(primes, i)
		}
	}

	return primes
}

func main() {
	if len(os.Args) != 2 {
		fmt.Println("Usage: go run sieve.go <limit>")
		os.Exit(1)
	}

	limit, err := strconv.Atoi(os.Args[1])
	if err != nil || limit < 2 {
		fmt.Println("Please provide a valid integer greater than or equal to 2")
		os.Exit(1)
	}

	primeNumbers := sieveOfEratosthenes(limit)
	fmt.Printf("Prime numbers less than or equal to %d:\n", limit)
	for _, prime := range primeNumbers {
		fmt.Printf("%d ", prime)
	}
	fmt.Println()
}
```

To run this program, save it in a file named `sieve.go` and then execute the following command:

```sh
$ go run sieve.go <limit>
```

Replace `<limit>` with the desired upper bound for prime numbers. The program will output all prime numbers less than or equal to the input.

