        } catch (Exception e) {
            System.err.println("Error: Unable to connect to Redis server at " + ipAddress + ":" + portNumber);
            return;
        }

        Scanner scanner = new Scanner(System.in);

        while (true) {
            System.out.println("\nChoose an option:");
            System.out.println("1. Store key-value pair");
            System.out.println("2. Retrieve value by key");
            System.out.println("3. Exit");

            int choice = scanner.nextInt();
            scanner.nextLine(); // Consume newline character

            switch (choice) {
                case 1:
                    System.out.print("Enter key: ");
                    String key = scanner.nextLine();

                    System.out.print("Enter value: ");
                    String value = scanner.nextLine();

                    jedis.set(key, value);
                    System.out.println("Key-value pair stored successfully.");
                    break;

                case 2:
                    System.out.print("Enter key: ");
                    key = scanner.nextLine();

                    value = jedis.get(key);

                    if (value == null) {
                        System.out.println("No value found for the given key.");
                    } else {
                        System.out.println("Value: " + value);
                    }
                    break;

                case 3:
                    scanner.close();
                    jedis.close();
                    return;

                default:
                    System.out.println("Invalid option. Please try again.");
            }
        }
    }
}

using System;
using System.IO;
using System.Threading.Tasks;
using Azure.Storage.Blobs;

class Program
{
    static string connectionString = "<your-connection-string>";
    static string containerName = "<your-container-name>";

    static async Task Main(string[] args)
    {
        // Upload a file to the blob storage
        await UploadBlobAsync("test.txt");

        // List all blobs in the container
        await ListBlobsAsync();

        // Download a blob to local storage
        await DownloadBlobAsync("test.txt", "downloaded_test.txt");

        // Delete a blob from the container
        await DeleteBlobAsync("test.txt");
    }

    // Method to upload a file to blob storage
    static async Task UploadBlobAsync(string filePath)
    {
        BlobContainerClient container = new BlobContainerClient(connectionString, containerName);
        BlobClient blob = container.GetBlobClient(Path.GetFileName(filePath));
        using var fileStream = File.OpenRead(filePath);
        await blob.UploadAsync(fileStream);
    }

    // Method to list all blobs in a container
    static async Task ListBlobsAsync()
    {
        BlobContainerClient container = new BlobContainerClient(connectionString, containerName);
        await foreach (var blobItem in container.GetBlobsAsync())
        {
            Console.WriteLine(blobItem.Name);
        }
    }

    // Method to download a blob to local storage
    static async Task DownloadBlobAsync(string blobName, string downloadPath)
    {
        BlobContainerClient container = new BlobContainerClient(connectionString, containerName);
        BlobClient blob = container.GetBlobClient(blobName);
        BlobDownloadInfo download = await blob.DownloadAsync();
        using (FileStream file = File.OpenWrite(downloadPath))
        {
            await download.Content.CopyToAsync(file);
        }
    }

    // Method to delete a blob from the container
    static async Task DeleteBlobAsync(string blobName)
    {
        BlobContainerClient container = new BlobContainerClient(connectionString, containerName);
        BlobClient blob = container.GetBlobClient(blobName);
        await blob.DeleteIfExistsAsync();
    }
}

