import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.SQLException;

public class CsvToSQLite {

    public static void main(String[] args) {
        if (args.length != 2) {
            System.out.println("Usage: java CsvToSQLite <input_csv_file> <output_sqlite_db>");
            return;
        }

        String csvFilePath = args[0];
        String sqliteDbPath = args[1];

        try {
            Class.forName("org.sqlite.JDBC");
        } catch (ClassNotFoundException e) {
            System.err.println("Failed to load SQLite JDBC driver.");
            e.printStackTrace();
            return;
        }

        try (Connection connection = DriverManager.getConnection("jdbc:sqlite:" + sqliteDbPath)) {
            createTable(connection);
            readCsvAndInsertData(csvFilePath, connection);
        } catch (SQLException | IOException e) {
            System.err.println("Error processing CSV or SQLite database.");
            e.printStackTrace();
        }
    }

    private static void createTable(Connection connection) throws SQLException {
        String sql = "CREATE TABLE IF NOT EXISTS users (" +
                "id INTEGER PRIMARY KEY AUTOINCREMENT," +
                "name TEXT NOT NULL," +
                "age INTEGER NOT NULL," +
                "email TEXT NOT NULL)";
        try (PreparedStatement stmt = connection.prepareStatement(sql)) {
            stmt.execute();
        }
    }

    private static void readCsvAndInsertData(String csvFilePath, Connection connection) throws IOException, SQLException {
        try (BufferedReader br = new BufferedReader(new FileReader(csvFilePath))) {
            String line;
            boolean header = true;
            while ((line = br.readLine()) != null) {
                if (header) {
                    header = false;
                    continue;
                }
                String[] values = line.split(",");
                if (values.length == 3) {
                    insertUser(connection, values[0], Integer.parseInt(values[1]), values[2]);
                } else {
                    System.err.println("Invalid CSV format: " + line);
                }
            }
        }
    }

    private static void insertUser(Connection connection, String name, int age, String email) throws SQLException {
        String sql = "INSERT INTO users (name, age, email) VALUES (?, ?, ?)";
        try (PreparedStatement stmt = connection.prepareStatement(sql)) {
            stmt.setString(1, name);
            stmt.setInt(2, age);
            stmt.setString(3, email);
            stmt.executeUpdate();
        }
    }
}

To create a Node.js Express server with two endpoints, you'll need to install the following dependencies:

1. express: A web framework for Node.js
2. mongodb: The official MongoDB driver for Node.js
3. body-parser: Middleware to parse incoming request bodies

You can install these packages using npm or yarn:

```bash
npm install express mongodb body-parser
```

Now, let's write the code for our server:

```javascript
// Import required modules
const express = require('express');
const bodyParser = require('body-parser');
const MongoClient = require('mongodb').MongoClient;

// Initialize the app and set up middleware
const app = express();
app.use(bodyParser.json());

// Connect to MongoDB
const url = 'mongodb://localhost:27017';
const dbName = 'userProfilesDB';
let db;
MongoClient.connect(url, { useUnifiedTopology: true }, (err, client) => {
  if (err) throw err;
  console.log('Connected successfully to MongoDB');
  db = client.db(dbName);
});

// POST endpoint to save user profile data
app.post('/api/user-profiles', async (req, res) => {
  try {
    const userProfile = req.body;
    const result = await db.collection('userProfiles').insertOne(userProfile);
    res.status(201).json({ id: result.insertedId });
  } catch (error) {
    res.status(500).json({ error: 'An error occurred while saving the user profile' });
  }
});

// GET endpoint to retrieve user profile by ID
app.get('/api/user-profiles/:id', async (req, res) => {
  try {
    const { ObjectId } = require('mongodb');
    const id = req.params.id;

    if (!ObjectId.isValid(id)) {
      return res.status(400).json({ error: 'Invalid ID format' });
    }

    const userProfile = await db.collection('userProfiles').findOne({ _id: new ObjectId(id) });

    if (!userProfile) {
      return res.status(404).json({ error: 'User profile not found' });
    }

    res.json(userProfile);
  } catch (error) {
    res.status(500).json({ error: 'An error occurred while retrieving the user profile' });
  }
});

// Start the server
const port = process.env.PORT || 3000;
app.listen(port, () => console.log(`Server running on port ${port}`));
```

