package main

import (
	"crypto/sha256"
	"encoding/hex"
	"fmt"
	"io"
	"io/ioutil"
	"os"
	"path/filepath"

	"github.com/aws/aws-sdk-go/aws"
	"github.com/aws/aws-sdk-go/aws/session"
	"github.com/aws/aws-sdk-go/service/s3"
)

func main() {
	dir := "./test" // Replace this with the desired directory path
	duplicatesDir := "./duplicates" // Replace this with the desired duplicates directory path
	bucketName := "your-bucket-name" // Replace this with your Amazon S3 bucket name

	files, err := ioutil.ReadDir(dir)
	if err != nil {
		fmt.Println("Error reading directory:", err)
		return
	}

	hashes := make(map[string]string)
	duplicates := make(map[string][]string)

	for _, file := range files {
		if !file.IsDir() {
			filePath := filepath.Join(dir, file.Name())
			hash, err := calculateSHA256(filePath)
			if err != nil {
				fmt.Println("Error calculating hash:", err)
				continue
			}

			if val, ok := hashes[hash]; ok {
				duplicates[val] = append(duplicates[val], filePath)
			} else {
				hashes[hash] = filePath
			}
		}
	}

	if len(duplicates) == 0 {
		fmt.Println("No duplicate files found.")
		return
	}

	err = os.MkdirAll(duplicatesDir, os.ModePerm)
	if err != nil {
		fmt.Println("Error creating duplicates directory:", err)
		return
	}

	sess, err := session.NewSession(&aws.Config{
		Region: aws.String("us-west-2")}, // Replace this with your desired AWS region
	)
	if err != nil {
		fmt.Println("Error creating AWS session:", err)
		return
	}

	svc := s3.New(sess)

	for original, dupes := range duplicates {
		fmt.Printf("Original file: %s\n", original)
		for _, dupe := range dupes {
			fmt.Printf("\tDuplicate: %s\n", dupe)

			// Uncomment the following line to delete duplicate files
			// os.Remove(dupe)

			// Move duplicate files to another folder
			newPath := filepath.Join(duplicatesDir, filepath.Base(dupe))
			err = os.Rename(dupe, newPath)
			if err != nil {
				fmt.Printf("\t\tError moving file: %v\n", err)
				continue
			}

			// Upload duplicate files to Amazon S3
			file, err := os.Open(newPath)
			if err != nil {
				fmt.Printf("\t\tError opening file for upload: %v\n", err)
				continue
			}
			defer file.Close()

			_, err = svc.PutObject(&s3.PutObjectInput{
				Bucket: aws.String(bucketName),
				Key:    aws.String(filepath.Base(newPath)),
				Body:   file,
			})
			if err != nil {
				fmt.Printf("\t\tError uploading file to S3: %v\n", err)
				continue
			}

			fmt.Printf("\t\tMoved and uploaded to S3: %s\n", newPath)
		}
	}
}

func calculateSHA256(filePath string) (string, error) {
	file, err := os.Open(filePath)
	if err != nil {
		return "", err
	}
	defer file.Close()

	hasher := sha256.New()
	if _, err := io.Copy(hasher, file); err != nil {
		return "", err
	}

	return hex.EncodeToString(hasher.Sum(nil)), nil
}

