import (
	"fmt"
	"io/fs"
	"os"
	"path/filepath"
)

func main() {
	var dirPath string

	fmt.Print("Enter the directory path: ")
	fmt.Scanln(&dirPath)

	fileCount, dirCount, totalSize, err := countFilesAndDirs(dirPath)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	fmt.Printf("Total Files: %d\n", fileCount)
	fmt.Printf("Total Directories: %d\n", dirCount)
	fmt.Printf("Total Size (bytes): %d\n", totalSize)
}

// countFilesAndDirs function takes a root directory and returns the number of files,
// directories, and the total size of all files in bytes.
func countFilesAndDirs(root string) (int, int, int64, error) {
	var fileCount, dirCount int
	var totalSize int64

	err := filepath.WalkDir(root, func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			return err
		}
		if d.IsDir() {
			dirCount++
		} else {
			fileCount++
			info, err := d.Info()
			if err != nil {
				return err
			}
			totalSize += info.Size()
		}
		return nil
	})

	if err != nil {
		return 0, 0, 0, err
	}

	return fileCount, dirCount, totalSize, nil
}

package main

import (
	"fmt"
	"math"
)

// Define the maximum number of vertices in the graph
const MaxVertices = 1000

func minDistance(dist []int, visited []bool) int {
	min := math.MaxInt32
	minIndex := -1

	for v := 0; v < len(dist); v++ {
		if !visited[v] && dist[v] <= min {
			min = dist[v]
			minIndex = v
		}
	}

	return minIndex
}

func dijkstra(graph [][]int, src, dest int) int {
	numVertices := len(graph)
	dist := make([]int, numVertices)
	visited := make([]bool, numVertices)

	for i := 0; i < numVertices; i++ {
		dist[i] = math.MaxInt32
		visited[i] = false
	}

	dist[src] = 0

	for count := 0; count < numVertices-1; count++ {
		u := minDistance(dist, visited)
		visited[u] = true

		for v := 0; v < numVertices; v++ {
			if !visited[v] && graph[u][v] != 0 &&
				dist[u] != math.MaxInt32 &&
				dist[u]+graph[u][v] < dist[v] {
				dist[v] = dist[u] + graph[u][v]
			}
		}
	}

	return dist[dest]
}

func main() {
	var numVertices, numEdges, src, dest int

	fmt.Println("Enter the number of vertices:")
	fmt.Scan(&numVertices)

	graph := make([][]int, numVertices)
	for i := range graph {
		graph[i] = make([]int, numVertices)
	}

	fmt.Println("Enter the number of edges:")
	fmt.Scan(&numEdges)

	fmt.Println("Enter the edges and their weights (u v w):")
	for i := 0; i < numEdges; i++ {
		var u, v, w int
		fmt.Scan(&u, &v, &w)
		graph[u][v] = w
		graph[v][u] = w
	}

	fmt.Println("Enter the source vertex:")
	fmt.Scan(&src)

	fmt.Println("Enter the destination vertex:")
	fmt.Scan(&dest)

	shortestPath := dijkstra(graph, src, dest)
	fmt.Printf("The shortest path between %d and %d is: %d\n", src, dest, shortestPath)
}

#include <iostream>

class Node {
public:
    int data;
    Node* left;
    Node* right;

    Node(int value) : data(value), left(nullptr), right(nullptr) {}
};

class BinarySearchTree {
public:
    Node* root;

    BinarySearchTree() : root(nullptr) {}

    void insert(int value) {
        root = insert(root, value);
    }

    void remove(int value) {
        root = remove(root, value);
    }

    bool search(int value) {
        return search(root, value);
    }

    void inorderTraversal() {
        inorderTraversal(root);
        std::cout << std::endl;
    }

    void preorderTraversal() {
        preorderTraversal(root);
        std::cout << std::endl;
    }

    void postorderTraversal() {
        postorderTraversal(root);
        std::cout << std::endl;
    }

private:
    Node* insert(Node* node, int value) {
        if (node == nullptr) {
            return new Node(value);
        }
        if (value < node->data) {
            node->left = insert(node->left, value);
        } else {
            node->right = insert(node->right, value);
        }
        return node;
    }

    Node* minValueNode(Node* node) {
        while (node->left != nullptr) {
            node = node->left;
        }
        return node;
    }

    Node* remove(Node* node, int value) {
        if (node == nullptr) {
            return node;
        }
        if (value < node->data) {
            node->left = remove(node->left, value);
        } else if (value > node->data) {
            node->right = remove(node->right, value);
        } else {
            if (node->left == nullptr) {
                Node* temp = node->right;
                delete node;
                return temp;
            } else if (node->right == nullptr) {
                Node* temp = node->left;
                delete node;
                return temp;
            }
            Node* temp = minValueNode(node->right);
            node->data = temp->data;
            node->right = remove(node->right, temp->data);
        }
        return node;
    }

    bool search(Node* node, int value) {
        if (node == nullptr) {
            return false;
        }
        if (value < node->data) {
            return search(node->left, value);
        } else if (value > node->data) {
            return search(node->right, value);
        } else {
            return true;
        }
    }

    void inorderTraversal(Node* node) {
        if (node != nullptr) {
            inorderTraversal(node->left);
            std::cout << node->data << " ";
            inorderTraversal(node->right);
        }
    }

    void preorderTraversal(Node* node) {
        if (node != nullptr) {
            std::cout << node->data << " ";
            preorderTraversal(node->left);
            preorderTraversal(node->right);
        }
    }

    void postorderTraversal(Node* node) {
        if (node != nullptr) {
            postorderTraversal(node->left);
            postorderTraversal(node->right);
            std::cout << node->data << " ";
        }
    }
};

int main() {
    BinarySearchTree bst;

    // Insert test
    bst.insert(50);
    bst.insert(30);
    bst.insert(20);
    bst.insert(40);
    bst.insert(70);
    bst.insert(60);
    bst.insert(80);

    // Traverse tests
    std::cout << "In-order traversal: ";
    bst.inorderTraversal(); // 20 30 40 50 60 70 80

    std::cout << "Pre-order traversal: ";
    bst.preorderTraversal(); // 50 30 20 40 70 60 80

    std::cout << "Post-order traversal: ";
    bst.postorderTraversal(); // 20 40 30 60 80 70 50

    // Search test
    std::cout << "Search for 60: " << (bst.search(60) ? "Found" : "Not found") << std::endl; // Found
    std::cout << "Search for 100: " << (bst.search(100) ? "Found" : "Not found") << std::endl; // Not found

    // Delete test
    bst.remove(20);
    bst.remove(30);
    bst.remove(50);

    std::cout << "In-order traversal after deletion: ";
    bst.inorderTraversal(); // 40 60 70 80

    return 0;
}

package main

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"

	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
)

const (
	host     = "localhost"
	port     = 5432
	user     = "postgres"
	password = "your-password"
	dbname   = "your-db-name"
)

type Product struct {
	ID    int    `json:"id"`
	Name  string `json:"name"`
	Price int    `json:"price"`
}

var db *sql.DB

func main() {
	psqlInfo := fmt.Sprintf("host=%s port=%d user=%s password=%s dbname=%s sslmode=disable",
		host, port, user, password, dbname)

	var err error
	db, err = sql.Open("postgres", psqlInfo)
	if err != nil {
		panic(err)
	}
	defer db.Close()

	err = db.Ping()
	if err != nil {
		panic(err)
	}

	router := mux.NewRouter()
	router.HandleFunc("/products", getProducts).Methods("GET")
	router.HandleFunc("/products/{id}", getProduct).Methods("GET")
	router.HandleFunc("/products", createProduct).Methods("POST")
	router.HandleFunc("/products/{id}", updateProduct).Methods("PUT")
	router.HandleFunc("/products/{id}", deleteProduct).Methods("DELETE")

	log.Fatal(http.ListenAndServe(":8000", router))
}

func getProducts(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	var products []Product

	rows, err := db.Query("SELECT id, name, price FROM products")
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer rows.Close()

	for rows.Next() {
		var p Product
		err := rows.Scan(&p.ID, &p.Name, &p.Price)
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		products = append(products, p)
	}

	json.NewEncoder(w).Encode(products)
}

func getProduct(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)

	id := params["id"]

	row := db.QueryRow("SELECT id, name, price FROM products WHERE id=$1", id)

	var p Product
	err := row.Scan(&p.ID, &p.Name, &p.Price)
	if err == sql.ErrNoRows {
		http.Error(w, "Product not found", http.StatusNotFound)
		return
	} else if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	json.NewEncoder(w).Encode(p)
}

func createProduct(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	var p Product
	err := json.NewDecoder(r.Body).Decode(&p)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	sqlStatement := `INSERT INTO products (name, price) VALUES ($1, $2) RETURNING id`
	err = db.QueryRow(sqlStatement, p.Name, p.Price).Scan(&p.ID)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(p)
}

func updateProduct(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)

	var p Product
	err := json.NewDecoder(r.Body).Decode(&p)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	sqlStatement := `UPDATE products SET name=$1, price=$2 WHERE id=$3 RETURNING id`
	err = db.QueryRow(sqlStatement, p.Name, p.Price, params["id"]).Scan(&p.ID)
	if err == sql.ErrNoRows {
		http.Error(w, "Product not found", http.StatusNotFound)
		return
	} else if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	json.NewEncoder(w).Encode(p)
}

func deleteProduct(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)

	id := params["id"]

	sqlStatement := `DELETE FROM products WHERE id=$1`
	res, err := db.Exec(sqlStatement, id)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	count, err := res.RowsAffected()
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	if count == 0 {
		http.Error(w, "Product not found", http.StatusNotFound)
		return
	}

	w.WriteHeader(http.StatusNoContent)
}

import java.util.Scanner;

public class FactorialRecursion {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a non-negative integer: ");
        int number = scanner.nextInt();

        if (number < 0) {
            System.out.println("Invalid input. Please enter a non-negative integer.");
        } else {
            long result = factorial(number);
            System.out.printf("The factorial of %d is: %d%n", number, result);
        }
    }

    // Recursive method to calculate the factorial of a given non-negative integer
    public static long factorial(int n) {
        if (n == 0 || n == 1) {
            return 1;
        } else {
            return n * factorial(n - 1);
        }
    }
}

