import java.util.Scanner;

public class Calculator {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        boolean keepRunning = true;

        while (keepRunning) {
            System.out.print("Enter an expression or type 'exit' to quit: ");
            String input = scanner.nextLine();

            if ("exit".equalsIgnoreCase(input)) {
                keepRunning = false;
            } else {
                try {
                    // Split the input into tokens
                    String[] tokens = input.split(" ");
                    double num1 = Double.parseDouble(tokens[0]);
                    String operator = tokens[1];
                    double num2 = Double.parseDouble(tokens[2]);

                    // Perform the appropriate arithmetic operation based on the operator
                    switch (operator) {
                        case "+":
                            System.out.println(num1 + num2);
                            break;
                        case "-":
                            System.out.println(num1 - num2);
                            break;
                        case "*":
                            System.out.println(num1 * num2);
                            break;
                        case "/":
                            if (num2 == 0) {
                                throw new ArithmeticException("Division by zero is not allowed.");
                            }
                            System.out.println(num1 / num2);
                            break;
                        default:
                            System.out.println("Invalid operator. Please use +, -, *, or /.");
                    }
                } catch (NumberFormatException e) {
                    System.out.println("Invalid number format. Please enter a valid expression.");
                } catch (ArithmeticException e) {
                    System.out.println(e.getMessage());
                } catch (ArrayIndexOutOfBoundsException e) {
                    System.out.println("Invalid input format. Please enter an expression in the format: number operator number");
                } catch (Exception e) {
                    System.out.println("An error occurred while processing your input. Please try again.");
                }
            }
        }

        scanner.close();
    }
}

import javax.websocket.*;
import javax.websocket.server.ServerEndpoint;
import java.io.IOException;
import java.util.HashSet;
import java.util.Set;

@ServerEndpoint("/chat")
public class ChatServer {

    private static final Set<Session> sessions = new HashSet<>();

    @OnOpen
    public void onOpen(Session session) {
        System.out.println("New user connected: " + session.getId());
        sessions.add(session);
    }

    @OnMessage
    public void onMessage(String message, Session sender) throws IOException {
        System.out.println("Received message from " + sender.getId() + ": " + message);

        for (Session session : sessions) {
            if (!session.equals(sender)) {
                session.getBasicRemote().sendText(message);
            }
        }
    }

    @OnClose
    public void onClose(Session session) {
        System.out.println("User disconnected: " + session.getId());
        sessions.remove(session);
    }

    @OnError
    public void onError(Throwable error) {
        System.err.println("Error occurred: " + error.getMessage());
    }
}

