public class OpenSearchExample {

    public static void main(String[] args) throws IOException {
        // Replace these values with your OpenSearch instance details
        String hostname = "localhost";
        int port = 9200;
        String scheme = "http";

        // Create a client to connect to OpenSearch
        RestHighLevelClient client = new RestHighLevelClient(
                RestClient.builder(new HttpHost(hostname, port, scheme)));

        // Define the index name and document type
        String indexName = "example_index";
        String docType = "_doc";

        // Delete the index if it already exists
        if (client.indices().exists(new GetIndexRequest(indexName), RequestOptions.DEFAULT)) {
            client.indices().delete(new DeleteIndexRequest(indexName), RequestOptions.DEFAULT);
        }

        // Create an index with default settings
        client.indices().create(new CreateIndexRequest(indexName).settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 0)), RequestOptions.DEFAULT);

        // Add documents to the index
        String[] documents = {
                "{\"title\": \"Document 1\", \"content\": \"This is the content of document 1.\"}",
                "{\"title\": \"Document 2\", \"content\": \"This is the content of document 2.\"}",
                "{\"title\": \"Document 3\", \"content\": \"This is the content of document 3.\"}"
        };

        for (String document : documents) {
            IndexRequest request = new IndexRequest(indexName, docType).source(document, XContentType.JSON);
            client.index(request, RequestOptions.DEFAULT);
        }

        // Refresh the index to make the documents searchable
        client.indices().refresh(new RefreshRequest(indexName), RequestOptions.DEFAULT);

        // Ask the user for a search query
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your search query: ");
        String query = scanner.nextLine();

        // Perform a simple query on the "content" field
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder()
                .query(QueryBuilders.matchQuery("content", query));
        SearchRequest searchRequest = new SearchRequest(indexName).source(sourceBuilder);
        SearchResponse searchResponse = client.search(searchRequest, RequestOptions.DEFAULT);

        // Print the results
        if (searchResponse.status() == RestStatus.OK) {
            System.out.println("Search results:");
            for (SearchHit hit : searchResponse.getHits()) {
                System.out.println(hit.getSourceAsString());
            }
        } else {
            System.err.println("Error executing search: " + searchResponse.status());
        }

        // Close the client and exit
        client.close();
    }
}

