interface Item {
  id: number;
  name: string;
  price: number;
}

class ShoppingCart {
  private items: Item[];

  constructor() {
    this.items = [];
  }

  // Add an item to the cart
  addItem(item: Item): void {
    this.items.push(item);
  }

  // Remove an item from the cart by its ID
  removeItem(itemId: number): void {
    this.items = this.items.filter((item) => item.id !== itemId);
  }

  // Calculate the total price of all items in the cart
  getTotalPrice(): number {
    return this.items.reduce((total, item) => total + item.price, 0);
  }

  // Apply a discount percentage to all items in the cart
  applyDiscount(discountPercentage: number): void {
    if (discountPercentage < 0 || discountPercentage > 100) {
      throw new Error("Invalid discount percentage");
    }
    this.items = this.items.map((item) => ({
      ...item,
      price: item.price * (1 - discountPercentage / 100),
    }));
  }

  // Apply a discount percentage to specific items based on a condition
  applySpecificConditionDiscount(condition: (item: Item) => boolean, discountPercentage: number): void {
    if (discountPercentage < 0 || discountPercentage > 100) {
      throw new Error("Invalid discount percentage");
    }
    this.items = this.items.map((item) =>
      condition(item)
        ? { ...item, price: item.price * (1 - discountPercentage / 100) }
        : item
    );
  }
}

