```java
private void createFractal() {
    double xMin = -2.0;
    double xMax = 1.0;
    double yMin = -1.5;
    double yMax = 1.5;

    for (int row = 0; row < HEIGHT; row++) {
        for (int col = 0; col < WIDTH; col++) {
            double x = col * (xMax - xMin) / WIDTH + xMin;
            double y = row * (yMax - yMin) / HEIGHT + yMin;

            int iterations = mandelbrotIterations(x, y);

            if (iterations == MAX_ITERATIONS) {
                image.setRGB(col, row, 0);
            } else {
                image.setRGB(col, row, Color.HSBtoRGB(iterations / 256f, 1, iterations / (iterations + 8f)));
            }
        }
    }
}

private int mandelbrotIterations(double x, double y) {
    double real = 0;
    double imaginary = 0;
    int iterations = 0;

    while (real * real + imaginary * imaginary <= 4 && iterations < MAX_ITERATIONS) {
        double tempReal = real * real - imaginary * imaginary + x;
        imaginary = 2 * real * imaginary + y;
        real = tempReal;
        iterations++;
    }

    return iterations;
}
```

