class Node:
    def __init__(self, data=None):
        self.data = data
        self.next = None

class SinglyLinkedList:
    def __init__(self):
        self.head = None

    def insert(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
        else:
            current = self.head
            while current.next:
                current = current.next
            current.next = new_node

    def delete(self, data):
        if not self.head:
            return "List is empty"

        if self.head.data == data:
            self.head = self.head.next
            return f"Deleted {data} from the list"

        current = self.head
        while current.next and current.next.data != data:
            current = current.next

        if not current.next:
            return f"{data} not found in the list"

        current.next = current.next.next
        return f"Deleted {data} from the list"

    def search(self, data):
        current = self.head
        index = 0
        while current:
            if current.data == data:
                return f"{data} found at position {index}"
            current = current.next
            index += 1
        return f"{data} not found in the list"

    def print_list(self):
        elements = []
        current = self.head
        while current:
            elements.append(current.data)
            current = current.next
        return elements

