class Node {
  constructor(value) {
    this.value = value;
    this.left = null;
    this.right = null;
  }
}

class BinarySearchTree {
  constructor() {
    this.root = null;
  }

  insert(value) {
    const newNode = new Node(value);

    if (!this.root) {
      this.root = newNode;
      return this;
    } else {
      let currentNode = this.root;

      while (true) {
        if (value < currentNode.value) {
          if (!currentNode.left) {
            currentNode.left = newNode;
            return this;
          }
          currentNode = currentNode.left;
        } else {
          if (!currentNode.right) {
            currentNode.right = newNode;
            return this;
          }
          currentNode = currentNode.right;
        }
      }
    }
  }

  find(value) {
    if (!this.root) return false;

    let currentNode = this.root;

    while (currentNode) {
      if (value === currentNode.value) {
        return true;
      } else if (value < currentNode.value) {
        currentNode = currentNode.left;
      } else {
        currentNode = currentNode.right;
      }
    }

    return false;
  }

  remove(value) {
    if (!this.root) return false;

    let parentNode = null;
    let currentNode = this.root;

    while (currentNode) {
      if (value < currentNode.value) {
        parentNode = currentNode;
        currentNode = currentNode.left;
      } else if (value > currentNode.value) {
        parentNode = currentNode;
        currentNode = currentNode.right;
      } else {
        // Found the node to be removed

        // Case 1: No children
        if (!currentNode.left && !currentNode.right) {
          if (parentNode.left === currentNode) {
            parentNode.left = null;
          } else {
            parentNode.right = null;
          }
        }

        // Case 2: One child
        else if (!currentNode.left) {
          if (parentNode.left === currentNode) {
            parentNode.left = currentNode.right;
          } else {
            parentNode.right = currentNode.right;
          }
        } else if (!currentNode.right) {
          if (parentNode.left === currentNode) {
            parentNode.left = currentNode.left;
          } else {
            parentNode.right = currentNode.left;
          }
        }

        // Case 3: Two children
        else {
          let minRightNode = currentNode.right;
          let minRightParent = currentNode;

          while (minRightNode.left) {
            minRightParent = minRightNode;
            minRightNode = minRightNode.left;
          }

          currentNode.value = minRightNode.value;

          if (minRightParent.left === minRightNode) {
            minRightParent.left = minRightNode.right;
          } else {
            minRightParent.right = minRightNode.right;
          }
        }

        return true;
      }
    }

    return false;
  }
}

