class Vector3D {
private:
    double x, y, z;

public:
    // Constructors
    Vector3D() : x(0), y(0), z(0) {}
    Vector3D(double x, double y, double z) : x(x), y(y), z(z) {}

    // Getters and Setters
    double getX() const { return x; }
    double getY() const { return y; }
    double getZ() const { return z; }

    void setX(double x) { this->x = x; }
    void setY(double y) { this->y = y; }
    void setZ(double z) { this->z = z; }

    // Addition
    Vector3D operator+(const Vector3D& other) const {
        return Vector3D(x + other.x, y + other.y, z + other.z);
    }

    // Subtraction
    Vector3D operator-(const Vector3D& other) const {
        return Vector3D(x - other.x, y - other.y, z - other.z);
    }

    // Dot product
    double dot(const Vector3D& other) const {
        return x * other.x + y * other.y + z * other.z;
    }

    // Cross product
    Vector3D cross(const Vector3D& other) const {
        return Vector3D(
            y * other.z - z * other.y,
            z * other.x - x * other.z,
            x * other.y - y * other.x
        );
    }

    // Magnitude
    double magnitude() const {
        return std::sqrt(x * x + y * y + z * z);
    }

    // Normalization
    Vector3D normalize() const {
        double mag = magnitude();
        return Vector3D(x / mag, y / mag, z / mag);
    }

    // Angle between vectors (in radians)
    double angle(const Vector3D& other) const {
        return std::acos(dot(other) / (magnitude() * other.magnitude()));
    }
};

int main() {
    Vector3D v1(1, 2, 3);
    Vector3D v2(4, 5, 6);

    Vector3D sum = v1 + v2;
    std::cout << "Sum: (" << sum.getX() << ", " << sum.getY() << ", " << sum.getZ() << ")" << std::endl;

    Vector3D diff = v1 - v2;
    std::cout << "Difference: (" << diff.getX() << ", " << diff.getY() << ", " << diff.getZ() << ")" << std::endl;

    double dotProduct = v1.dot(v2);
    std::cout << "Dot product: " << dotProduct << std::endl;

    Vector3D crossProduct = v1.cross(v2);
    std::cout << "Cross product: (" << crossProduct.getX() << ", " << crossProduct.getY() << ", " << crossProduct.getZ() << ")" << std::endl;

    double magnitudeV1 = v1.magnitude();
    std::cout << "Magnitude of v1: " << magnitudeV1 << std::endl;

    Vector3D normalizedV1 = v1.normalize();
    std::cout << "Normalized v1: (" << normalizedV1.getX() << ", " << normalizedV1.getY() << ", " << normalizedV1.getZ() << ")" << std::endl;

    double angleBetweenVectors = v1.angle(v2);
    std::cout << "Angle between v1 and v2 (in radians): " << angleBetweenVectors << std::endl;

    return 0;
}
