package main

import (
	"fmt"
	"image"
	"image/jpeg"
	"io/ioutil"
	"net/http"
	"os"

	"github.com/gin-gonic/gin"
	"github.com/nfnt/resize"
)

func main() {
	router := gin.Default()

	router.LoadHTMLGlob("templates/*")
	router.GET("/", func(c *gin.Context) {
		c.HTML(http.StatusOK, "index.html", nil)
	})

	router.POST("/upload", func(c *gin.Context) {
		file, err := c.FormFile("file")
		if err != nil {
			c.String(http.StatusBadRequest, fmt.Sprintf("Error uploading file: %s", err.Error()))
			return
		}

		src, err := file.Open()
		defer src.Close()
		if err != nil {
			c.String(http.StatusInternalServerError, fmt.Sprintf("Error opening file: %s", err.Error()))
			return
		}

		img, _, err := image.Decode(src)
		if err != nil {
			c.String(http.StatusInternalServerError, fmt.Sprintf("Error decoding image: %s", err.Error()))
			return
		}

		resizedImg := resize.Resize(100, 0, img, resize.Lanczos3)

		tempFile, err := ioutil.TempFile("uploads", "resized_*.jpg")
		defer tempFile.Close()
		if err != nil {
			c.String(http.StatusInternalServerError, fmt.Sprintf("Error creating temporary file: %s", err.Error()))
			return
		}

		err = jpeg.Encode(tempFile, resizedImg, &jpeg.Options{Quality: 80})
		if err != nil {
			c.String(http.StatusInternalServerError, fmt.Sprintf("Error encoding image: %s", err.Error()))
			return
		}

		c.String(http.StatusOK, fmt.Sprintf("Image uploaded and resized successfully. Saved as %s.", tempFile.Name()))
	})

	router.Run(":8080")
}

