class Program
{
    static void Main(string[] args)
    {
        string excelFilePath = "path/to/your/excel/file.xlsx";
        string htmlOutputPath = "path/to/output/html/file.html";

        // Load the Excel file using EPPlus
        using (ExcelPackage package = new ExcelPackage(new FileInfo(excelFilePath)))
        {
            // Get the first worksheet
            ExcelWorksheet worksheet = package.Workbook.Worksheets[0];

            // Generate the HTML table
            string htmlTable = GenerateHtmlTable(worksheet);

            // Save the HTML table to a file
            File.WriteAllText(htmlOutputPath, htmlTable);
        }

        Console.WriteLine("HTML table generated successfully!");
    }

    private static string GenerateHtmlTable(ExcelWorksheet worksheet)
    {
        int totalRows = worksheet.Dimension.End.Row;
        int totalCols = worksheet.Dimension.End.Column;

        StringBuilder htmlTableBuilder = new StringBuilder();

        // Start the table tag
        htmlTableBuilder.AppendLine("<table border='1'>");

        // Loop through rows and columns to build the table
        for (int rowNum = 1; rowNum <= totalRows; rowNum++)
        {
            htmlTableBuilder.AppendLine("<tr>");

            for (int colNum = 1; colNum <= totalCols; colNum++)
            {
                string cellValue = worksheet.Cells[rowNum, colNum].Text;
                htmlTableBuilder.AppendFormat("<td>{0}</td>", cellValue);
            }

            htmlTableBuilder.AppendLine("</tr>");
        }

        // Close the table tag
        htmlTableBuilder.AppendLine("</table>");

        return htmlTableBuilder.ToString();
    }
}

