	router.GET("/weather/:city", func(c *gin.Context) {
		city := c.Param("city")
		apiKey := os.Getenv("OPENWEATHERMAP_API_KEY")

		resp, err := http.Get(fmt.Sprintf("http://api.openweathermap.org/data/2.5/weather?q=%s&appid=%s&units=metric", city, apiKey))
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to fetch weather data"})
			return
		}
		defer resp.Body.Close()

		body, err := ioutil.ReadAll(resp.Body)
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to read weather data"})
			return
		}

		var weatherData WeatherResponse
		err = json.Unmarshal(body, &weatherData)
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to parse weather data"})
			return
		}

		c.JSON(http.StatusOK, gin.H{
