)

type Record struct {
	ID    int    `json:"id"`
	Name  string `json:"name"`
	Value string `json:"value"`
}

var db *sql.DB

func main() {
	var err error
	db, err = sql.Open("postgres", "user=your_user password=your_password dbname=your_db sslmode=disable")
	if err != nil {
		log.Fatal(err)
	}
	defer db.Close()

	router := mux.NewRouter()
	router.HandleFunc("/records", createRecord).Methods("POST")
	router.HandleFunc("/records", getRecords).Methods("GET")
	router.HandleFunc("/records/{id}", getRecord).Methods("GET")
	router.HandleFunc("/records/{id}", updateRecord).Methods("PUT")
	router.HandleFunc("/records/{id}", deleteRecord).Methods("DELETE")

	fmt.Println("Server running on port 8000...")
	log.Fatal(http.ListenAndServe(":8000", router))
}

func createRecord(w http.ResponseWriter, r *http.Request) {
	var record Record
	json.NewDecoder(r.Body).Decode(&record)

	stmt, err := db.Prepare("INSERT INTO records (name, value) VALUES ($1, $2) RETURNING id")
	if err != nil {
		log.Fatal(err)
	}
	defer stmt.Close()

	err = stmt.QueryRow(record.Name, record.Value).Scan(&record.ID)
	if err != nil {
		log.Fatal(err)
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(record)
}

func getRecords(w http.ResponseWriter, r *http.Request) {
	rows, err := db.Query("SELECT id, name, value FROM records")
	if err != nil {
		log.Fatal(err)
	}
	defer rows.Close()

	var records []Record
	for rows.Next() {
		var record Record
		err := rows.Scan(&record.ID, &record.Name, &record.Value)
		if err != nil {
			log.Fatal(err)
		}
		records = append(records, record)
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(records)
}

func getRecord(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	id := params["id"]

	var record Record
	stmt, err := db.Prepare("SELECT id, name, value FROM records WHERE id=$1")
	if err != nil {
		log.Fatal(err)
	}
	defer stmt.Close()

	err = stmt.QueryRow(id).Scan(&record.ID, &record.Name, &record.Value)
	if err != nil {
		if err == sql.ErrNoRows {
			http.Error(w, "Record not found", http.StatusNotFound)
			return
		}
		log.Fatal(err)
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(record)
}

func updateRecord(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	id := params["id"]

	var record Record
	json.NewDecoder(r.Body).Decode(&record)

	stmt, err := db.Prepare("UPDATE records SET name=$1, value=$2 WHERE id=$3")
	if err != nil {
		log.Fatal(err)
	}
	defer stmt.Close()

	result, err := stmt.Exec(record.Name, record.Value, id)
	if err != nil {
		log.Fatal(err)
	}

	rowsAffected, err := result.RowsAffected()
	if err != nil {
		log.Fatal(err)
	}

	if rowsAffected == 0 {
		http.Error(w, "Record not found", http.StatusNotFound)
		return
	}

	w.WriteHeader(http.StatusOK)
}

func deleteRecord(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	id := params["id"]

	stmt, err := db.Prepare("DELETE FROM records WHERE id=$1")
	if err != nil {
		log.Fatal(err)
	}
	defer stmt.Close()

	result, err := stmt.Exec(id)
	if err != nil {
		log.Fatal(err)
	}

	rowsAffected, err := result.RowsAffected()
	if err != nil {
		log.Fatal(err)
	}

	if rowsAffected == 0 {
		http.Error(w, "Record not found", http.StatusNotFound)
		return
	}

	w.WriteHeader(http.StatusOK)
}

