using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

namespace ProductApi.Models
{
    public class ProductContext : DbContext
    {
        public ProductContext(DbContextOptions<ProductContext> options)
            : base(options)
        {
        }

        public DbSet<Product> Products { get; set; }
    }

    public class Product
    {
        public long Id { get; set; }
        public string Name { get; set; }
        public string Description { get; set; }
        public decimal Price { get; set; }
    }

    [Route("api/[controller]")]
    [ApiController]
    public class ProductsController : ControllerBase
    {
        private readonly ProductContext _context;

        public ProductsController(ProductContext context)
        {
            _context = context;
        }

        // GET: api/Products
        [HttpGet]
        public async Task<ActionResult<IEnumerable<Product>>> GetProducts()
        {
            return await _context.Products.ToListAsync();
        }

        // GET: api/Products/5
        [HttpGet("{id}")]
        public async Task<ActionResult<Product>> GetProduct(long id)
        {
            var product = await _context.Products.FindAsync(id);

            if (product == null)
            {
                return NotFound();
            }

            return product;
        }

        // PUT: api/Products/5
        [HttpPut("{id}")]
        public async Task<IActionResult> PutProduct(long id, Product product)
        {
            if (id != product.Id)
            {
                return BadRequest();
            }

            _context.Entry(product).State = EntityState.Modified;
            await _context.SaveChangesAsync();

            return NoContent();
        }

        // POST: api/Products
        [HttpPost]
        public async Task<ActionResult<Product>> PostProduct(Product product)
        {
            _context.Products.Add(product);
            await _context.SaveChangesAsync();

            return CreatedAtAction(nameof(GetProduct), new { id = product.Id }, product);
        }

        // DELETE: api/Products/5
        [HttpDelete("{id}")]
        public async Task<IActionResult> DeleteProduct(long id)
        {
            var product = await _context.Products.FindAsync(id);
            if (product == null)
            {
                return NotFound();
            }

            _context.Products.Remove(product);
            await _context.SaveChangesAsync();

            return NoContent();
        }
    }
}

package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"log"
	"net/http"
)

type RequestInfo struct {
	Method  string            `json:"method"`
	URL     string            `json:"url"`
	Headers map[string]string `json:"headers"`
	Body    string            `json:"body"`
}

func handler(w http.ResponseWriter, r *http.Request) {
	// Set custom response header
	w.Header().Set("X-App-Version", "1.0")

	// Read request body
	bodyBytes, err := ioutil.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "Error reading request body", http.StatusInternalServerError)
		return
	}
	defer r.Body.Close()

	// Parse request headers
	headers := make(map[string]string)
	for k, v := range r.Header {
		headers[k] = v[0]
	}

	// Create RequestInfo struct
	requestInfo := &RequestInfo{
		Method:  r.Method,
		URL:     r.URL.String(),
		Headers: headers,
		Body:    string(bodyBytes),
	}

	// Marshal RequestInfo to JSON
	jsonData, err := json.Marshal(requestInfo)
	if err != nil {
		http.Error(w, "Error marshaling JSON", http.StatusInternalServerError)
		return
	}

	// Write JSON data to response
	w.Header().Set("Content-Type", "application/json")
	w.Write(jsonData)
}

func main() {
	http.HandleFunc("/", handler)
	fmt.Println("Starting server on :8080...")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

#include <iostream>
#include <vector>
#include <string>
#include <stdexcept>
#include <pqxx/pqxx>

using namespace std;
using namespace pqxx;

struct Book {
    int id;
    string title;
    string author;
    int publication_year;
    string genre;
};

class BookDatabase {
public:
    BookDatabase(const string& connection_string)
        : conn_(connection_string) {}

    vector<Book> query_books_by_author(const string& author) {
        return query_books("author", author);
    }

    vector<Book> query_books_by_publication_year_range(int start_year, int end_year) {
        stringstream condition;
        condition << "publication_year BETWEEN " << start_year << " AND " << end_year;
        return query_books(condition.str());
    }

    vector<Book> query_books_by_genre(const string& genre) {
        return query_books("genre", genre);
    }

private:
    connection conn_;

    vector<Book> query_books(const string& column, const string& value) {
        stringstream sql;
        sql << "SELECT * FROM books WHERE " << column << " = " << quote(value) << ";";
        return execute_query(sql.str());
    }

    vector<Book> query_books(const string& condition) {
        stringstream sql;
        sql << "SELECT * FROM books WHERE " << condition << ";";
        return execute_query(sql.str());
    }

    vector<Book> execute_query(const string& sql) {
        work txn(conn_);
        result res = txn.exec(sql);
        txn.commit();

        vector<Book> books;
        for (const auto& row : res) {
            books.push_back({
                row["id"].as<int>(),
                row["title"].as<string>(),
                row["author"].as<string>(),
                row["publication_year"].as<int>(),
                row["genre"].as<string>()
            });
        }
        return books;
    }
};

void print_books(const vector<Book>& books) {
    if (books.empty()) {
        cout << "No results found." << endl;
        return;
    }

    for (const auto& book : books) {
        cout << "[" << book.id << "] "
             << book.title << " by " << book.author
             << ", published in " << book.publication_year
             << ", genre: " << book.genre << endl;
    }
}

