// longestIncreasingSubsequence finds the longest increasing subsequence in an array of integers
func longestIncreasingSubsequence(arr []int) []int {
	n := len(arr)
	if n == 0 {
		return arr
	}

	dp := make([]int, n)
	for i := range dp {
		dp[i] = 1
	}
	maxIndex := 0

	for i := 1; i < n; i++ {
		for j := 0; j < i; j++ {
			if arr[i] > arr[j] && dp[i] < dp[j]+1 {
				dp[i] = dp[j] + 1
				if dp[maxIndex] < dp[i] {
					maxIndex = i
				}
			}
		}
	}

	result := make([]int, dp[maxIndex])
	i := maxIndex
	j := dp[maxIndex] - 1
	result[j] = arr[i]
	j--

	for i--; i >= 0; i-- {
		if arr[i] < result[j+1] && dp[i] == dp[maxIndex]-1 {
			result[j] = arr[i]
			j--
			maxIndex = i
		}
	}

	return result
}

func main() {
	testCases := [][]int{
		{10, 22, 9, 33, 21, 50, 41, 60, 80},
		{3, 4, -1, 0, 6, 2, 3},
		{},
		{1, 2, 3, 4, 5},
		{5, 4, 3, 2, 1},
	}

	for _, testCase := range testCases {
		fmt.Printf("Input: %v\n", testCase)
		fmt.Printf("Longest Increasing Subsequence: %v\n\n", longestIncreasingSubsequence(testCase))
	}
}

