const Chat = () => {
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState('');
  const location = useLocation();
  const wsRef = useRef(null);

  useEffect(() => {
    const queryParams = new URLSearchParams(location.search);
    const name = queryParams.get('name');

    wsRef.current = new WebSocket('ws://localhost:3001');

    wsRef.current.onopen = () => {
      console.log('Connected to server');
    };

    wsRef.current.onmessage = (event) => {
      const messageData = JSON.parse(event.data);

      if (messageData.type === 'chatHistory') {
        setMessages(messageData.data);
      } else if (messageData.type === 'newMessage') {
        setMessages((prevMessages) => [...prevMessages, messageData.data]);
      }
    };

    return () => {
      wsRef.current.close();
    };
  }, []);

  const sendMessage = () => {
    if (inputMessage.trim()) {
      const queryParams = new URLSearchParams(location.search);
      const name = queryParams.get('name');
      const newMessage = { id: uuidv4(), name, text: inputMessage };

      wsRef.current.send(JSON.stringify({ type: 'newMessage', data: newMessage }));
      setInputMessage('');
    }
  };

