        if (args.length != 1) {
            System.err.println("Usage: java AverageAgeCalculator <csv-file>");
            System.exit(1);
        }

        String csvFile = args[0];
        double totalAge = 0;
        int count = 0;

        // Read the CSV file line by line
        try (BufferedReader br = new BufferedReader(new FileReader(csvFile))) {
            String line;
            while ((line = br.readLine()) != null) {
                // Split each line into an array of strings
                String[] data = line.split(",");
                if (data.length >= 2) {
                    try {
                        // Parse the second element as an integer representing the person's age
                        int age = Integer.parseInt(data[1].trim());
                        totalAge += age;
                        count++;
                    } catch (NumberFormatException e) {
                        System.err.println("Invalid age value: " + data[1]);
                    }
                }
            }
        } catch (IOException e) {
            System.err.println("Error reading file: " + csvFile);
            e.printStackTrace();
            System.exit(1);
        }

        // Calculate and print the average age
        if (count > 0) {
            double averageAge = totalAge / count;
            System.out.printf("The average age is %.2f%n", averageAge);
