import com.amazonaws.services.lambda.runtime.Context;
import com.amazonaws.services.lambda.runtime.RequestHandler;
import com.amazonaws.services.s3.AmazonS3ClientBuilder;
import com.amazonaws.services.s3.event.S3EventNotification;
import com.amazonaws.services.s3.model.GetObjectRequest;
import com.amazonaws.services.s3.model.ObjectMetadata;
import com.amazonaws.services.s3.model.PutObjectRequest;

import javax.imageio.ImageIO;
import java.awt.*;
import java.awt.image.BufferedImage;
import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.InputStream;

public class ResizeImageLambda implements RequestHandler<S3EventNotification, String> {

    private static final int MAX_WIDTH = 200;
    private static final int MAX_HEIGHT = 200;

    @Override
    public String handleRequest(S3EventNotification s3Event, Context context) {
        s3Event.getRecords().forEach(record -> {
            String srcBucket = record.getS3().getBucket().getName();
            String srcKey = record.getS3().getObject().getUrlDecodedKey();

            try {
                // Get the original image from S3
                InputStream objectData = AmazonS3ClientBuilder.defaultClient()
                        .getObject(new GetObjectRequest(srcBucket, srcKey)).getObjectContent();

                // Resize the image
                BufferedImage resizedImage = resizeImage(objectData);

                // Save the resized image back to S3
                ByteArrayOutputStream os = new ByteArrayOutputStream();
                ImageIO.write(resizedImage, "jpg", os);
                InputStream is = new ByteArrayInputStream(os.toByteArray());
                ObjectMetadata meta = new ObjectMetadata();
                meta.setContentLength(os.size());
                meta.setContentType("image/jpeg");
                String destKey = "resized/" + srcKey;
                AmazonS3ClientBuilder.defaultClient()
                        .putObject(new PutObjectRequest(srcBucket, destKey, is, meta));

            } catch (IOException e) {
                context.getLogger().log("Error resizing image: " + e.getMessage());
            }
        });

        return "Done";
    }

    private BufferedImage resizeImage(InputStream inputStream) throws IOException {
        BufferedImage originalImage = ImageIO.read(inputStream);
        int type = originalImage.getType() == 0 ? BufferedImage.TYPE_INT_ARGB : originalImage.getType();

        int width = originalImage.getWidth();
        int height = originalImage.getHeight();

        if (width > MAX_WIDTH || height > MAX_HEIGHT) {
            double scaleWidth = ((double) MAX_WIDTH) / width;
            double scaleHeight = ((double) MAX_HEIGHT) / height;

            double scaleFactor = Math.min(scaleWidth, scaleHeight);

            width = (int) (scaleFactor * width);
            height = (int) (scaleFactor * height);
        }

        BufferedImage resizedImage = new BufferedImage(width, height, type);
        Graphics2D g = resizedImage.createGraphics();
        g.drawImage(originalImage, 0, 0, width, height, null);
        g.dispose();

        return resizedImage;
    }
}

import com.sun.net.httpserver.*;

import java.io.*;
import java.net.InetSocketAddress;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.security.MessageDigest;
import java.util.concurrent.Executors;

public class SimpleWebServer {

    private static final String UPLOAD_ENDPOINT = "/upload";
    private static final int PORT = 8080;
    private static final File ROOT_DIR = new File("www");

    public static void main(String[] args) throws Exception {
        HttpServer server = HttpServer.create(new InetSocketAddress(PORT), 0);
        server.createContext("/", new StaticFileHandler());
        server.createContext(UPLOAD_ENDPOINT, new UploadHandler());
        server.setExecutor(Executors.newCachedThreadPool());
        server.start();
        System.out.println("Server started on port " + PORT);
    }

    static class StaticFileHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            String path = exchange.getRequestURI().getPath();
            if (path.equals("/")) {
                path = "/index.html";
            }
            File file = new File(ROOT_DIR, path);

            if (!file.exists() || !file.isFile()) {
                sendResponse(exchange, 404, "Not Found");
                return;
            }

            try (InputStream is = new FileInputStream(file)) {
                byte[] content = is.readAllBytes();
                exchange.getResponseHeaders().set("Content-Type", getContentType(path));
                sendResponse(exchange, 200, content);
            }
        }
    }

    static class UploadHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if (!"POST".equalsIgnoreCase(exchange.getRequestMethod())) {
                sendResponse(exchange, 405, "Method Not Allowed");
                return;
            }

            try (InputStream is = exchange.getRequestBody()) {
                byte[] fileContent = is.readAllBytes();
                String md5Hash = getMD5(fileContent);
                Path targetPath = Paths.get(ROOT_DIR.getPath(), md5Hash + ".html");
                Files.write(targetPath, fileContent);

                sendResponse(exchange, 200, "File uploaded successfully: " + md5Hash + ".html");
            } catch (Exception e) {
                sendResponse(exchange, 500, "Internal Server Error");
            }
        }
    }

    private static void sendResponse(HttpExchange exchange, int statusCode, String responseText) throws IOException {
        byte[] responseBytes = responseText.getBytes();
        sendResponse(exchange, statusCode, responseBytes);
    }

    private static void sendResponse(HttpExchange exchange, int statusCode, byte[] responseBytes) throws IOException {
        exchange.sendResponseHeaders(statusCode, responseBytes.length);
        OutputStream os = exchange.getResponseBody();
        os.write(responseBytes);
        os.close();
    }

    private static String getContentType(String path) {
        if (path.endsWith(".html") || path.endsWith(".htm")) {
            return "text/html";
        } else if (path.endsWith(".css")) {
            return "text/css";
        } else if (path.endsWith(".js")) {
            return "application/javascript";
        } else {
            return "application/octet-stream";
        }
    }

    private static String getMD5(byte[] content) throws Exception {
        MessageDigest md = MessageDigest.getInstance("MD5");
        byte[] digest = md.digest(content);
        StringBuilder sb = new StringBuilder();
        for (byte b : digest) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }
}

function separateEvenOdd(arr) {
  // Initialize an object with even and odd properties as empty arrays
  const result = {
    even: [],
    odd: []
  };

  // Iterate through the input array
  arr.forEach(num => {
    // If the number is even, push it to the even array
    if (num % 2 === 0) {
      result.even.push(num);
    } else {
      // Otherwise, push it to the odd array
      result.odd.push(num);
    }
  });

  // Return the resulting object
  return result;
}

