    public RedisClient(String host, int port) {
        this.jedis = new Jedis(host, port);
    }

    public void set(String key, String value) {
        jedis.set(key, value);
    }

    public String get(String key) {
        return jedis.get(key);
    }

    public void delete(String key) {
        jedis.del(key);
    }

    public void close() {
        jedis.close();
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        RedisClient redisClient = new RedisClient("localhost", 6379);

        while (true) {
            System.out.println("\nChoose an operation: set, get, delete, or exit");
            String operation = scanner.nextLine();

            if ("exit".equalsIgnoreCase(operation)) {
                break;
            }

            switch (operation.toLowerCase()) {
                case "set":
                    System.out.print("Enter key: ");
                    String setKey = scanner.nextLine();
                    System.out.print("Enter value: ");
                    String setValue = scanner.nextLine();
                    redisClient.set(setKey, setValue);
                    System.out.println("Value set successfully.");
                    break;
                case "get":
                    System.out.print("Enter key: ");
                    String getKey = scanner.nextLine();
                    String getValue = redisClient.get(getKey);
                    System.out.println("Value: " + getValue);
                    break;
                case "delete":
                    System.out.print("Enter key: ");
                    String delKey = scanner.nextLine();
                    redisClient.delete(delKey);
                    System.out.println("Key deleted successfully.");
                    break;
                default:
                    System.out.println("Invalid operation. Please try again.");
            }
        }

        redisClient.close();
        scanner.close();
    }
}

Here's a Java program that reads a CSV file containing user information (name, age, email) and stores the data in an SQLite database. The program has error handling for invalid input and duplicate entries.

```java
import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.SQLException;

public class CsvToDatabase {

    private static final String DB_URL = "jdbc:sqlite:user_data.db";
    private static final String CREATE_TABLE_SQL =
            "CREATE TABLE IF NOT EXISTS users (" +
                    "id INTEGER PRIMARY KEY AUTOINCREMENT," +
                    "name TEXT NOT NULL," +
                    "age INTEGER NOT NULL," +
                    "email TEXT UNIQUE NOT NULL" +
                    ");";

    public static void main(String[] args) {
        if (args.length != 1) {
            System.err.println("Usage: java CsvToDatabase <csv_file_path>");
            return;
        }

        try (Connection connection = DriverManager.getConnection(DB_URL)) {
            createTable(connection);

            try (BufferedReader reader = new BufferedReader(new FileReader(args[0]))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    String[] values = line.split(",");
                    if (values.length != 3) {
                        System.err.println("Invalid input format: " + line);
                        continue;
                    }

                    String name = values[0].trim();
                    int age;
                    try {
                        age = Integer.parseInt(values[1].trim());
                    } catch (NumberFormatException e) {
                        System.err.println("Invalid age value: " + values[1]);
                        continue;
                    }
                    String email = values[2].trim();

                    addUser(connection, name, age, email);
                }
            } catch (IOException e) {
                System.err.println("Error reading CSV file: " + e.getMessage());
            }
        } catch (SQLException e) {
            System.err.println("Error connecting to the database: " + e.getMessage());
        }
    }

    private static void createTable(Connection connection) throws SQLException {
        try (PreparedStatement statement = connection.prepareStatement(CREATE_TABLE_SQL)) {
            statement.executeUpdate();
        }
    }

    private static void addUser(Connection connection, String name, int age, String email) {
        String sql = "INSERT INTO users(name, age, email) VALUES(?, ?, ?)";

        try (PreparedStatement statement = connection.prepareStatement(sql)) {
            statement.setString(1, name);
            statement.setInt(2, age);
            statement.setString(3, email);

            statement.executeUpdate();
            System.out.println("Added user: " + name + ", " + age + ", " + email);
        } catch (SQLException e) {
            if (e.getErrorCode() == 19) { // SQLITE_CONSTRAINT error code
                System.err.println("Duplicate entry for email: " + email);
            } else {
                System.err.println("Error adding user: " + e.getMessage());
            }
        }
    }
}
```

