function evenSumOddProduct(arr) {
  let sum = 0;
  let product = 1;

  for (let i = 0; i < arr.length; i++) {
    if (arr[i] % 2 === 0) {
      sum += arr[i];
    } else {
      product *= arr[i];
    }
  }

  return {evenSum: sum, oddProduct: product};
}

const inputArray = [1, 2, 3, 4, 5, 6];
