package main

import (
	"bufio"
	"fmt"
	"io/ioutil"
	"net/http"
	"sort"
	"strings"
)

func main() {
	url := "https://raw.githubusercontent.com/dwyl/english-words/master/words.txt"

	resp, err := http.Get(url)
	if err != nil {
		fmt.Println("Error fetching URL:", err)
		return
	}
	defer resp.Body.Close()

	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		fmt.Println("Error reading response body:", err)
		return
	}

	text := string(body)
	wordFrequencies := countWords(text)

	topWords := getTopNWords(wordFrequencies, 10)

	for i, word := range topWords {
		fmt.Printf("%d. %s: %d\n", i+1, word.word, word.frequency)
	}
}

type WordFrequency struct {
	word      string
	frequency int
}

func countWords(text string) map[string]int {
	frequencies := make(map[string]int)
	scanner := bufio.NewScanner(strings.NewReader(text))
	scanner.Split(bufio.ScanWords)

	for scanner.Scan() {
		word := strings.ToLower(scanner.Text())
		frequencies[word]++
	}

	return frequencies
}

func getTopNWords(frequencies map[string]int, n int) []WordFrequency {
	wordList := make([]WordFrequency, 0, len(frequencies))

	for word, freq := range frequencies {
		wordList = append(wordList, WordFrequency{word, freq})
	}

	sort.Slice(wordList, func(i, j int) bool {
		return wordList[i].frequency > wordList[j].frequency
	})

	return wordList[:n]
}

import java.io.*;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import javax.xml.bind.DatatypeConverter;

public class ChecksumUtility {

    public static void main(String[] args) {
        if (args.length < 3) {
            System.out.println("Usage: java ChecksumUtility <file> <md5|sha1|sha256> <reference_checksum> [output_format]");
            return;
        }

        String filePath = args[0];
        String algorithm = args[1].toUpperCase();
        String referenceChecksum = args[2];
        String outputFormat = "text";
        if (args.length > 3) {
            outputFormat = args[3].toLowerCase();
        }

        try {
            MessageDigest md = MessageDigest.getInstance(algorithm);
            byte[] fileBytes = Files.readAllBytes(Paths.get(filePath));
            md.update(fileBytes);
            byte[] digest = md.digest();
            String calculatedChecksum = DatatypeConverter.printHexBinary(digest).toLowerCase();

            boolean match = calculatedChecksum.equalsIgnoreCase(referenceChecksum);

            if ("json".equals(outputFormat)) {
                System.out.printf("{\"algorithm\":\"%s\",\"calculated_checksum\":\"%s\",\"reference_checksum\":\"%s\",\"match\":%b}%n",
                        algorithm, calculatedChecksum, referenceChecksum, match);
            } else {
                System.out.printf("%s checksum%nCalculated: %s%nReference : %s%nMatch     : %b%n",
                        algorithm, calculatedChecksum, referenceChecksum, match);
            }
        } catch (NoSuchAlgorithmException | IOException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}

