    // Add accounts to customers
    alice.addAccount(alicesAccount);
    bob.addAccount(bobsAccount);

    // Perform transactions
    Transaction::deposit(alice, 1001, 200.0);
    Transaction::withdraw(bob, 1002, 150.0);
    Transaction::transfer(alice, 1001, bob, 1002, 250.0);

