}

public class BankAccountSystem {
    public static void main(String[] args) {
        SavingsAccount savings = new SavingsAccount(1000);
        CheckingAccount checking = new CheckingAccount(500);

        System.out.println("Initial balances:");
        System.out.println("Savings: " + savings.getBalance());
        System.out.println("Checking: " + checking.getBalance());

        try {
            savings.withdraw(200);
            checking.deposit(200);
            savings.transferTo(checking, 300);
        } catch (InsufficientBalanceException e) {
            System.err.println(e.getMessage());
        }

        System.out.println("\nFinal balances:");
        System.out.println("Savings: " + savings.getBalance());
        System.out.println("Checking: " + checking.getBalance());
    }
}

class InsufficientBalanceException extends Exception {
    public InsufficientBalanceException(String message) {
        super(message);
    }
}

abstract class Account {
    protected double balance;

    public Account(double initialBalance) {
        this.balance = initialBalance;
    }

    public double getBalance() {
        return balance;
    }

    public void deposit(double amount) {
        balance += amount;
    }

    public void withdraw(double amount) throws InsufficientBalanceException {
        if (amount > balance) {
            throw new InsufficientBalanceException("Insufficient balance");
        }
        balance -= amount;
    }

    public void transferTo(Account target, double amount) throws InsufficientBalanceException {
        withdraw(amount);
        target.deposit(amount);
    }
}

class SavingsAccount extends Account {
    public SavingsAccount(double initialBalance) {
        super(initialBalance);
    }
}

class CheckingAccount extends Account {
    public CheckingAccount(double initialBalance) {
        super(initialBalance);
    }
}

