#include <iostream>

class Node {
public:
    int data;
    Node* left;
    Node* right;

    Node(int data) : data(data), left(nullptr), right(nullptr) {}
};

class BinarySearchTree {
public:
    Node* root;

    BinarySearchTree() : root(nullptr) {}

    void insert(int data) {
        if (root == nullptr) {
            root = new Node(data);
        } else {
            insertHelper(root, data);
        }
    }

    bool search(int data) {
        return searchHelper(root, data);
    }

    void remove(int data) {
        root = removeHelper(root, data);
    }

    void inOrderTraversal() {
        inOrderTraversalHelper(root);
        std::cout << std::endl;
    }

private:
    void insertHelper(Node* node, int data) {
        if (data < node->data) {
            if (node->left == nullptr) {
                node->left = new Node(data);
            } else {
                insertHelper(node->left, data);
            }
        } else {
            if (node->right == nullptr) {
                node->right = new Node(data);
            } else {
                insertHelper(node->right, data);
            }
        }
    }

    bool searchHelper(Node* node, int data) {
        if (node == nullptr) {
            return false;
        }

        if (data == node->data) {
            return true;
        } else if (data < node->data) {
            return searchHelper(node->left, data);
        } else {
            return searchHelper(node->right, data);
        }
    }

    Node* removeHelper(Node* node, int data) {
        if (node == nullptr) {
            return node;
        }

        if (data < node->data) {
            node->left = removeHelper(node->left, data);
        } else if (data > node->data) {
            node->right = removeHelper(node->right, data);
        } else {
            if (node->left == nullptr) {
                Node* temp = node->right;
                delete node;
                return temp;
            } else if (node->right == nullptr) {
                Node* temp = node->left;
                delete node;
                return temp;
            }

            node->data = minValue(node->right);
            node->right = removeHelper(node->right, node->data);
        }
        return node;
    }

    int minValue(Node* node) {
        int minValue = node->data;
        while (node->left != nullptr) {
            minValue = node->left->data;
            node = node->left;
        }
        return minValue;
    }

    void inOrderTraversalHelper(Node* node) {
        if (node != nullptr) {
            inOrderTraversalHelper(node->left);
            std::cout << node->data << " ";
            inOrderTraversalHelper(node->right);
        }
    }
};

int main() {
    BinarySearchTree bst;

    bst.insert(50);
    bst.insert(30);
    bst.insert(20);
    bst.insert(40);
    bst.insert(70);
    bst.insert(60);
    bst.insert(80);

    std::cout << "In-order traversal: ";
    bst.inOrderTraversal();

    std::cout << "Search 40: " << (bst.search(40) ? "Found" : "Not Found") << std::endl;
    std::cout << "Search 90: " << (bst.search(90) ? "Found" : "Not Found") << std::endl;

    bst.remove(20);
    std::cout << "After deleting 20: ";
    bst.inOrderTraversal();

    bst.remove(30);
    std::cout << "After deleting 30: ";
    bst.inOrderTraversal();

    bst.remove(50);
    std::cout << "After deleting 50: ";
    bst.inOrderTraversal();

    return 0;
}

