// LogRequest is an HTTP middleware that logs incoming requests.
func LogRequest(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		log.Printf("HTTP %s - %s", r.Method, r.URL.Path)
		next.ServeHTTP(w, r)
	})
}

// LoggingResponseWriter wraps an http.ResponseWriter to capture the status code.
type LoggingResponseWriter struct {
	http.ResponseWriter
	statusCode int
}

// WriteHeader captures the status code before writing it.
func (lrw *LoggingResponseWriter) WriteHeader(statusCode int) {
	lrw.statusCode = statusCode
	lrw.ResponseWriter.WriteHeader(statusCode)
}

func main() {
	port := "8080"
	dir := "./static" // Change this to the desired directory containing your static files.

	fs := http.FileServer(http.Dir(dir))
	http.Handle("/", LogRequest(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		lrw := &LoggingResponseWriter{w, http.StatusOK}
		fs.ServeHTTP(lrw, r)
		log.Printf("Status Code: %d", lrw.statusCode)
	})))

	fmt.Printf("Serving %s on port %s...\n", dir, port)
	err := http.ListenAndServe(":"+port, nil)
	if err != nil {
		log.Fatal("ListenAndServe: ", err)
	}
}

package main

import (
	"bufio"
	"fmt"
	"os"
	"sort"
	"strings"
)

type WordCount struct {
	Word  string
	Count int
}

func main() {
	if len(os.Args) < 2 {
		fmt.Println("Please provide a text file as an argument.")
		return
	}

	filePath := os.Args[1]
	file, err := os.Open(filePath)
	if err != nil {
		fmt.Printf("Error opening file: %v\n", err)
		return
	}
	defer file.Close()

	wordCounts := make(map[string]int)
	scanner := bufio.NewScanner(file)
	scanner.Split(bufio.ScanWords)

	for scanner.Scan() {
		word := strings.ToLower(scanner.Text())
		wordCounts[word]++
	}

	if err := scanner.Err(); err != nil {
		fmt.Printf("Error scanning file: %v\n", err)
		return
	}

	wordList := make([]WordCount, 0, len(wordCounts))
	for word, count := range wordCounts {
		wordList = append(wordList, WordCount{word, count})
	}

	sort.Slice(wordList, func(i, j int) bool {
		return wordList[i].Count > wordList[j].Count
	})

	topN := 10
	if len(wordList) < topN {
		topN = len(wordList)
	}

	fmt.Printf("Top %d most frequent words:\n", topN)
	for i := 0; i < topN; i++ {
		fmt.Printf("%s: %d\n", wordList[i].Word, wordList[i].Count)
	}
}

