Here's a Golang function that checks if the input string has balanced parentheses:

```go
package main

import (
	"fmt"
)

func isBalanced(s string) bool {
	stack := make([]rune, 0)
	for _, c := range s {
		if c == '(' {
			stack = append(stack, c)
		} else if c == ')' {
			if len(stack) == 0 || stack[len(stack)-1] != '(' {
				return false
			}
			stack = stack[:len(stack)-1]
		}
	}
	return len(stack) == 0
}

func main() {
	fmt.Println(isBalanced("((()))"))      // true
	fmt.Println(isBalanced("(())"))        // true
	fmt.Println(isBalanced("()"))          // true
	fmt.Println(isBalanced("(()))"))       // false
	fmt.Println(isBalanced("(((())"))      // false
	fmt.Println(isBalanced(")("))          // false
	fmt.Println(isBalanced("hello(world)")) // true
}
```

This function uses a stack to keep track of the opening parentheses. It iterates through each character in the input string and performs the following actions:

- If it encounters an opening parenthesis `(`, it pushes it onto the stack.
- If it encounters a closing parenthesis `)`, it checks if the stack is empty or if the top element on the stack is not an opening parenthesis `(`. If either condition is true, it returns `false` because the parentheses are unbalanced. Otherwise, it pops the top element from the stack.

After iterating through all characters, the function checks if the stack is empty. If it is, the parentheses are balanced, and it returns `true`. Otherwise, it returns `false`.

```cpp
#include <iostream>

class Node {
public:
    int data;
    Node* next;

    Node(int data) : data(data), next(nullptr) {}
};

class SinglyLinkedList {
private:
    Node* head;

public:
    SinglyLinkedList() : head(nullptr) {}

    ~SinglyLinkedList() {
        while (head != nullptr) {
            Node* temp = head;
            head = head->next;
            delete temp;
        }
    }

    void addElement(int value) {
        if (head == nullptr) {
            head = new Node(value);
        } else {
            Node* current = head;
            while (current->next != nullptr) {
                current = current->next;
            }
            current->next = new Node(value);
        }
    }

    bool deleteElement(int value) {
        if (head == nullptr) {
            return false;
        }

        if (head->data == value) {
            Node* temp = head;
            head = head->next;
            delete temp;
            return true;
        }

        Node* current = head;
        while (current->next != nullptr && current->next->data != value) {
            current = current->next;
        }

        if (current->next == nullptr) {
            return false;
        }

        Node* temp = current->next;
        current->next = current->next->next;
        delete temp;
        return true;
    }

    Node* searchElement(int value) {
        Node* current = head;
        while (current != nullptr) {
            if (current->data == value) {
                return current;
            }
            current = current->next;
        }
        return nullptr;
    }

    void printList() {
        Node* current = head;
        while (current != nullptr) {
            std::cout << current->data << " -> ";
            current = current->next;
        }
        std::cout << "nullptr" << std::endl;
    }
};

int main() {
    SinglyLinkedList list;

    list.addElement(1);
    list.addElement(2);
    list.addElement(3);

    list.printList();

    list.deleteElement(2);

    list.printList();

    Node* foundNode = list.searchElement(3);
    if (foundNode != nullptr) {
        std::cout << "Found node with value: " << foundNode->data << std::endl;
    } else {
        std::cout << "Node not found." << std::endl;
    }

    return 0;
}
```

