```javascript
const fs = require('fs');
const path = require('path');

function readDir(dirPath) {
  return new Promise((resolve, reject) => {
    fs.readdir(dirPath, (err, files) => {
      if (err) {
        reject(err);
      } else {
        resolve(files);
      }
    });
  });
}

function getFileStats(filePath) {
  return new Promise((resolve, reject) => {
    fs.stat(filePath, (err, stats) => {
      if (err) {
        reject(err);
      } else {
        resolve(stats);
      }
    });
  });
}

async function calculateTotalSize(dirPath) {
  try {
    const files = await readDir(dirPath);
    let totalSize = 0;

    for (const file of files) {
      const filePath = path.join(dirPath, file);
      const stats = await getFileStats(filePath);

      if (stats.isFile()) {
        totalSize += stats.size;
      }
    }

    console.log(`Total size in bytes: ${totalSize}`);
    console.log(`Total size in kilobytes: ${(totalSize / 1024).toFixed(2)} KB`);
    console.log(`Total size in megabytes: ${(totalSize / (1024 * 1024)).toFixed(2)} MB`);

  } catch (error) {
    console.error(`Error calculating total size: ${error.message}`);
  }
}

