```javascript
const apiUrl = 'https://jsonplaceholder.typicode.com/posts';
const userIdInput = document.getElementById('userId');
const postsTableBody = document.getElementById('postsTable').getElementsByTagName('tbody')[0];

async function fetchData(url) {
    const response = await fetch(url);
    return await response.json();
}

function createTableRow(post) {
    const row = document.createElement('tr');

    const idCell = document.createElement('td');
    idCell.textContent = post.id;
    row.appendChild(idCell);

    const userIdCell = document.createElement('td');
    userIdCell.textContent = post.userId;
    row.appendChild(userIdCell);

    const titleCell = document.createElement('td');
    titleCell.textContent = post.title;
    row.appendChild(titleCell);

    const bodyCell = document.createElement('td');
    bodyCell.textContent = post.body;
    row.appendChild(bodyCell);

    return row;
}

function displayPosts(posts) {
    postsTableBody.innerHTML = '';
    for (const post of posts) {
        const row = createTableRow(post);
        postsTableBody.appendChild(row);
    }
}

async function fetchAndDisplayPosts() {
    const posts = await fetchData(apiUrl);
    displayPosts(posts);
}

userIdInput.addEventListener('input', async () => {
    const userId = parseInt(userIdInput.value, 10);
    if (!isNaN(userId)) {
        const filteredPosts = await fetchData(`${apiUrl}?userId=${userId}`);
        displayPosts(filteredPosts);
    } else {
        fetchAndDisplayPosts();
    }
});

fetchAndDisplayPosts();
```

