#include <iostream>
#include <fstream>
#include <string>
#include <algorithm>

// Function to check if a given word is palindrome
bool isPalindrome(const std::string &word) {
    int start = 0;
    int end = word.length() - 1;

    while (start < end) {
        if (word[start] != word[end]) {
            return false;
        }
        start++;
        end--;
    }

    return true;
}

// Function to convert a string to lowercase
void toLowerCase(std::string &word) {
    std::transform(word.begin(), word.end(), word.begin(), ::tolower);
}

int main() {
    std::ifstream inputFile("words.txt");
    std::string longestPalindrome = "";
    std::string currentWord;

    // Check if the input file is open
    if (!inputFile.is_open()) {
        std::cerr << "Error opening input file." << std::endl;
        return 1;
    }

    // Read words from the file and find the longest palindrome
    while (inputFile >> currentWord) {
        toLowerCase(currentWord); // Convert the word to lowercase
        if (isPalindrome(currentWord) && currentWord.length() > longestPalindrome.length()) {
            longestPalindrome = currentWord;
        }
    }

    inputFile.close();

    // Output the result
    if (longestPalindrome.empty()) {
        std::cout << "No palindromes found in the file." << std::endl;
    } else {
        std::cout << "Longest palindrome: " << longestPalindrome << std::endl;
    }

    return 0;
}

