Here's a Java program that reads a CSV file containing information about students and stores it in an ArrayList of custom Student objects. The program also provides methods to sort the list by name, age, or grade, and display the sorted list.

```java
import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;

class Student {
    String name;
    int age;
    double grade;

    public Student(String name, int age, double grade) {
        this.name = name;
        this.age = age;
        this.grade = grade;
    }

    @Override
    public String toString() {
        return "Student{" +
                "name='" + name + '\'' +
                ", age=" + age +
                ", grade=" + grade +
                '}';
    }
}

public class StudentCSVReader {

    public static void main(String[] args) {
        ArrayList<Student> students = readStudentsFromCSV("students.csv");

        System.out.println("Original List:");
        printStudents(students);

        System.out.println("\nSorted by Name:");
        sortByName(students);
        printStudents(students);

        System.out.println("\nSorted by Age:");
        sortByAge(students);
        printStudents(students);

        System.out.println("\nSorted by Grade:");
        sortByGrade(students);
        printStudents(students);
    }

    private static ArrayList<Student> readStudentsFromCSV(String fileName) {
        ArrayList<Student> students = new ArrayList<>();
        try (BufferedReader br = new BufferedReader(new FileReader(fileName))) {
            String line;
            while ((line = br.readLine()) != null) {
                String[] values = line.split(",");
                String name = values[0];
                int age = Integer.parseInt(values[1]);
                double grade = Double.parseDouble(values[2]);
                students.add(new Student(name, age, grade));
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
        return students;
    }

    private static void printStudents(ArrayList<Student> students) {
        for (Student student : students) {
            System.out.println(student);
        }
    }

    private static void sortByName(ArrayList<Student> students) {
        Collections.sort(students, Comparator.comparing(student -> student.name));
    }

    private static void sortByAge(ArrayList<Student> students) {
        Collections.sort(students, Comparator.comparingInt(student -> student.age));
    }

    private static void sortByGrade(ArrayList<Student> students) {
        Collections.sort(students, Comparator.comparingDouble(student -> student.grade));
    }
}
```

