package main

import (
	"context"
	"fmt"
	"log"
	"os"
	"syscall"

	"github.com/dghubble/go-twitter/twitter"
	"github.com/dghubble/oauth1"
	"github.com/olivere/elastic/v7"
)

type Tweet struct {
	ID        int64  `json:"id"`
	Text      string `json:"text"`
	Timestamp string `json:"timestamp"`
}

func main() {
	// Set up Twitter API client
	config := oauth1.NewConfig(os.Getenv("CONSUMER_KEY"), os.Getenv("CONSUMER_SECRET"))
	token := oauth1.NewToken(os.Getenv("ACCESS_TOKEN"), os.Getenv("ACCESS_TOKEN_SECRET"))
	httpClient := config.Client(oauth1.NoContext, token)
	client := twitter.NewClient(httpClient)

	// Set up Elasticsearch client
	esClient, err := elastic.NewClient()
	if err != nil {
		log.Fatal(err)
	}

	// Define the keywords to track
	keywords := "golang,go"

	params := &twitter.StreamFilterParams{
		Track:         []string{keywords},
		StallWarnings: twitter.Bool(true),
	}
	stream, err := client.Streams.Filter(params)
	if err != nil {
		log.Fatal(err)
	}

	demux := twitter.NewSwitchDemux()
	demux.Tweet = func(tweet *twitter.Tweet) {
		fmt.Println(tweet.Text)
		storeTweet(esClient, tweet)
	}

	go demux.HandleChan(stream.Messages)

	// Wait for SIGINT or SIGTERM signal
	ch := make(chan os.Signal, 1)
	signal.Notify(ch, syscall.SIGINT, syscall.SIGTERM)
	log.Println(<-ch)

	stream.Stop()
}

func storeTweet(client *elastic.Client, tweet *twitter.Tweet) {
	ctx := context.Background()

	t := Tweet{
		ID:        tweet.ID,
		Text:      tweet.Text,
		Timestamp: tweet.CreatedAt,
	}

	_, err := client.Index().
		Index("tweets").
		Id(fmt.Sprintf("%d", t.ID)).
		BodyJson(t).
		Do(ctx)

	if err != nil {
		log.Printf("Failed to index tweet %d: %v", t.ID, err)
	}
}
```

To create a Java program that connects to a MariaDB database, reads data from multiple tables using JOIN operations, and generates a report based on specific criteria, follow these steps:

1. Install the MariaDB JDBC connector
Add the following dependency in your `pom.xml` file if you are using Maven:

```xml
<dependency>
    <groupId>org.mariadb.jdbc</groupId>
    <artifactId>mariadb-java-client</artifactId>
    <version>2.7.3</version>
</dependency>
```

Or download the JAR file directly from https://mariadb.com/downloads/#connectors.

2. Create a sample MariaDB database with two tables

For this example, let's assume we have a database named "company" with two tables: "employees" and "departments".

Create the tables using the following SQL commands:

```sql
CREATE TABLE departments (
  id INT PRIMARY KEY,
  name VARCHAR(255) NOT NULL
);

CREATE TABLE employees (
  id INT PRIMARY KEY,
  name VARCHAR(255) NOT NULL,
  department_id INT,
  FOREIGN KEY (department_id) REFERENCES departments(id)
);
```

Insert some sample data into the tables:

```sql
INSERT INTO departments (id, name) VALUES (1, 'HR');
INSERT INTO departments (id, name) VALUES (2, 'IT');

INSERT INTO employees (id, name, department_id) VALUES (1, 'Alice', 1);
INSERT INTO employees (id, name, department_id) VALUES (2, 'Bob', 2);
INSERT INTO employees (id, name, department_id) VALUES (3, 'Charlie', 2);
```

3. Write the Java program

Here is a complete Java program that connects to the MariaDB database, reads data from the "employees" and "departments" tables using a JOIN operation, and generates a report based on specific criteria (in this case, employees in the IT department). The program outputs the generated report as a formatted text file.

```java
import java.io.FileWriter;
import java.io.IOException;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Statement;

public class MariaDBReportGenerator {

    public static void main(String[] args) {
        String url = "jdbc:mariadb://localhost:3306/company";
        String user = "your_username";
        String password = "your_password";

        try (Connection connection = DriverManager.getConnection(url, user, password)) {
            String query = "SELECT e.name AS employee_name, d.name AS department_name "
                    + "FROM employees e "
                    + "JOIN departments d ON e.department_id = d.id "
                    + "WHERE d.name = 'IT'";

            try (Statement statement = connection.createStatement();
                 ResultSet resultSet = statement.executeQuery(query);
                 FileWriter fileWriter = new FileWriter("report.txt")) {

                while (resultSet.next()) {
                    String employeeName = resultSet.getString("employee_name");
                    String departmentName = resultSet.getString("department_name");

                    String line = String.format("%s works in %s%n", employeeName, departmentName);
                    fileWriter.write(line);
                }

                System.out.println("Report generated successfully!");

            } catch (SQLException | IOException e) {
                System.err.println("Error generating report: " + e.getMessage());
            }
        } catch (SQLException e) {
            System.err.println("Error connecting to database: " + e.getMessage());
        }
    }
}
```

Replace `your_username` and `your_password` with your actual MariaDB username and password. Run the Java program, and it will generate a "report.txt" file containing the names of employees who work in the IT department.

