import java.util.HashMap;
import java.util.Map;

public class Bank {
    private Map<String, Branch> branches;

    public Bank() {
        this.branches = new HashMap<>();
    }

    public void createBranch(String name) {
        Branch branch = new Branch(name, this);
        branches.put(name, branch);
        Thread branchThread = new Thread(branch);
        branchThread.start();
    }

    public void addAccountToBranch(String branchName, Account account) {
        Branch branch = branches.get(branchName);
        if (branch != null) {
            branch.addAccount(account);
        }
    }

    public boolean transferFunds(int fromAccountId, int toAccountId, double amount) {
        for (Branch branch : branches.values()) {
            Account fromAccount = branch.getAccount(fromAccountId);
            Account toAccount = branch.getAccount(toAccountId);

            if (fromAccount != null && toAccount != null) {
                synchronized (fromAccount) {
                    synchronized (toAccount) {
                        if (fromAccount.withdraw(amount)) {
                            toAccount.deposit(amount);
                            return true;
                        }
                    }
                }
            }
        }
        return false;
    }
}

