import (
	"fmt"
	"log"
	"os"
	"time"

	"github.com/fsnotify/fsnotify"
)

func main() {
	if len(os.Args) != 2 {
		fmt.Println("Usage: go run main.go <directory_to_watch>")
		os.Exit(1)
	}

	dirToWatch := os.Args[1]
	err := watchDirectory(dirToWatch)
	if err != nil {
		log.Fatal(err)
	}
}

func watchDirectory(dir string) error {
	watcher, err := fsnotify.NewWatcher()
	if err != nil {
		return err
	}
	defer watcher.Close()

	done := make(chan bool)

	go func() {
		for {
			select {
			case event := <-watcher.Events:
				eventType := ""
				switch {
				case event.Op&fsnotify.Create == fsnotify.Create:
					eventType = "created"
				case event.Op&fsnotify.Write == fsnotify.Write:
					eventType = "modified"
				case event.Op&fsnotify.Remove == fsnotify.Remove:
					eventType = "deleted"
				}
				if eventType != "" {
					timestamp := time.Now().Format(time.RFC3339)
					logToFile(fmt.Sprintf("%s: %s - %s\n", eventType, event.Name, timestamp))
				}
			case err := <-watcher.Errors:
				log.Println("error:", err)
			}
		}
	}()

	err = watcher.Add(dir)
	if err != nil {
		return err
	}

	<-done
	return nil
}

func logToFile(message string) {
	fileName := "file_changes.log"
	f, err := os.OpenFile(fileName, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
	if err != nil {
		log.Println(err)
		return
	}
	defer f.Close()

	if _, err := f.WriteString(message); err != nil {
		log.Println(err)
	}
}

