package main

import (
	"container/heap"
	"fmt"
)

type Edge struct {
	to, cost int
}

type Graph [][]Edge

func (g *Graph) addEdge(from, to, cost int) {
	(*g)[from] = append((*g)[from], Edge{to, cost})
}

type State struct {
	node, cost int
}

type PriorityQueue []State

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(State)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func dijkstra(graph *Graph, start int) []int {
	const INF = 1 << 60
	dist := make([]int, len(*graph))
	for i := range dist {
		dist[i] = INF
	}
	dist[start] = 0

	pq := &PriorityQueue{}
	heap.Init(pq)
	heap.Push(pq, State{start, 0})

	for pq.Len() > 0 {
		cur := heap.Pop(pq).(State)
		if dist[cur.node] < cur.cost {
			continue
		}
		for _, edge := range (*graph)[cur.node] {
			nextCost := cur.cost + edge.cost
			if nextCost < dist[edge.to] {
				dist[edge.to] = nextCost
				heap.Push(pq, State{edge.to, nextCost})
			}
		}
	}

	return dist
}

func main() {
	graph := make(Graph, 6)
	graph.addEdge(0, 1, 7)
	graph.addEdge(0, 2, 9)
	graph.addEdge(0, 5, 14)
	graph.addEdge(1, 2, 10)
	graph.addEdge(1, 3, 15)
	graph.addEdge(2, 3, 11)
	graph.addEdge(2, 5, 2)
	graph.addEdge(3, 4, 6)
	graph.addEdge(4, 5, 9)

	start := 0
	end := 4

	distances := dijkstra(&graph, start)
	fmt.Printf("Shortest path from node %d to node %d is: %d\n", start, end, distances[end])
}
```

This program creates a weighted graph with 6 nodes and implements Dijkstra's shortest path algorithm. The `main` function adds edges between the nodes with their corresponding weights, then calls the `dijkstra` function to find the shortest path between two nodes (in this case, nodes 0 and 4). Finally, it prints out the result of the shortest path.

Here is a simple implementation of a doubly linked list in C with insertion, deletion and display operations:

```c
#include <stdio.h>
#include <stdlib.h>

// Define structure for a node
struct Node {
    int data;
    struct Node* next; 
    struct Node* prev; 
};

void insertAtTheBegin(struct Node** start_ref, int data);
void insertAfter(struct Node* prev_node, int data);
void append(struct Node** head_ref, int data);
void deleteNode(struct Node **head_ref, struct Node *del);
void printList(struct Node* node);

int main() {
    struct Node* head = NULL;

    // Insert 7 at the beginning.
    insertAtTheBegin(&head, 7);

    // Insert 1 at the beginning.
    insertAtTheBegin(&head, 1);

    // Insert 6 at the end.
    append(&head, 6);

    // Insert 4 after 7.
    insertAfter(head->next, 4);

    printf("Created DLL is: ");
    printList(head);

    // Delete node which has data as 1.
    deleteNode(&head, head);
    printf("\nList after deleting first node: ");
    printList(head);

    return 0;
}

void insertAtTheBegin(struct Node** start_ref, int data) {
    struct Node* new_node = (struct Node*)malloc(sizeof(struct Node));
    new_node->data = data;
    new_node->next = (*start_ref);
    new_node->prev = NULL;

    if ((*start_ref) != NULL)
        (*start_ref)->prev = new_node;

    (*start_ref) = new_node;
}

void insertAfter(struct Node* prev_node, int data) {
    if (prev_node == NULL) {
        printf("the given previous node cannot be NULL");
        return;
    }

    struct Node* new_node =(struct Node*) malloc(sizeof(struct Node));

    new_node->data = data;
    new_node->next = prev_node->next;
    prev_node->next = new_node;
    new_node->prev = prev_node;

    if(new_node->next != NULL)
        new_node->next->prev = new_node;
}

void append(struct Node** head_ref, int data) {
    struct Node* new_node = (struct Node*) malloc(sizeof(struct Node));
    struct Node* last = *head_ref;

    new_node->data = data;
    new_node->next = NULL;

    if (*head_ref == NULL) {
        new_node->prev = NULL;
        *head_ref = new_node;
        return;
    }

    while (last->next != NULL)
        last = last->next;

    last->next = new_node;
    new_node->prev = last;

    return;
}

void deleteNode(struct Node **head_ref, struct Node *del) {
    if(*head_ref == NULL || del == NULL)
        return;

    if(*head_ref == del)
        *head_ref = del->next;

    if(del->next != NULL)
        del->next->prev = del->prev;

    if(del->prev != NULL)
        del->prev->next = del->next;

    free(del);
    return;
}

void printList(struct Node* node) {
    struct Node* last;
    while (node != NULL) {
        printf(" %d ", node->data);
        last = node;
        node = node->next;
    }
}
```

This program creates a doubly linked list and provides functions to insert a new node at the beginning, after a given node, and at the end. It also provides a function to delete a node and to print the entire list.

Here is a simple implementation of a banking system console application in C#. It includes classes for Account and Bank, as well as exception handling for overdrafts.

```csharp
using System;
using System.Collections.Generic;

public class Account
{
    public string Id { get; }
    public string Owner { get; }
    public decimal Balance { get; private set; }

    public Account(string id, string owner, decimal initialBalance)
    {
        Id = id;
        Owner = owner;
        Balance = initialBalance;
    }

    public void Deposit(decimal amount)
    {
        if (amount < 0)
            throw new ArgumentOutOfRangeException(nameof(amount), "Deposit amount must be positive");

        Balance += amount;
    }

    public void Withdraw(decimal amount)
    {
        if (amount < 0)
            throw new ArgumentOutOfRangeException(nameof(amount), "Withdrawal amount must be positive");
        if (amount > Balance)
            throw new InvalidOperationException("Not sufficient funds for this withdrawal");

        Balance -= amount;
    }
}

public class Bank
{
    private readonly Dictionary<string, Account> accounts = new Dictionary<string, Account>();

    public void CreateAccount(string id, string owner, decimal initialBalance)
    {
        if (accounts.ContainsKey(id))
            throw new ArgumentException("An account with this ID already exists", nameof(id));

        var account = new Account(id, owner, initialBalance);
        accounts.Add(id, account);
    }

    public void ProcessDeposit(string id, decimal amount)
    {
        if (!accounts.TryGetValue(id, out var account))
            throw new ArgumentException("Account not found", nameof(id));

        account.Deposit(amount);
    }

    public void ProcessWithdrawal(string id, decimal amount)
    {
        if (!accounts.TryGetValue(id, out var account))
            throw new ArgumentException("Account not found", nameof(id));

        account.Withdraw(amount);
    }

    public void Transfer(string fromId, string toId, decimal amount)
    {
        if (!accounts.TryGetValue(fromId, out var fromAccount))
            throw new ArgumentException("Account not found", nameof(fromId));
        if (!accounts.TryGetValue(toId, out var toAccount))
            throw new ArgumentException("Account not found", nameof(toId));

        fromAccount.Withdraw(amount);
        toAccount.Deposit(amount);
    }
}

class Program
{
    static void Main()
    {
        var bank = new Bank();
        bank.CreateAccount("123", "John Doe", 1000);
        bank.CreateAccount("456", "Jane Doe", 500);

        bank.ProcessDeposit("123", 200);
        bank.ProcessWithdrawal("456", 50);
        bank.Transfer("123", "456", 300);

        // Catching exceptions
        try
        {
            bank.ProcessWithdrawal("123", 2000); // This will fail
        }
        catch (InvalidOperationException e)
        {
            Console.WriteLine(e.Message);
        }
    }
}
```

This program creates two accounts, processes some deposits and withdrawals, and performs a transfer. If an attempt is made to withdraw more money than available in the account, it catches the resulting `InvalidOperationException` and writes its message to the console.

import java.util.Random;
import java.util.Scanner;

public class MathProblemGenerator {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        Random random = new Random();
        int score = 0;
        int numberOfQuestions = 10;

        for (int i = 0; i < numberOfQuestions; i++) {
            int num1 = random.nextInt(50) + 1;
            int num2 = random.nextInt(50) + 1;
            int operation = random.nextInt(4);

            System.out.println("Question " + (i + 1) + ":");
            double correctAnswer = 0;
            switch (operation) {
                case 0:
                    System.out.print(num1 + " + " + num2 + " = ");
                    correctAnswer = num1 + num2;
                    break;
                case 1:
                    System.out.print(num1 + " - " + num2 + " = ");
                    correctAnswer = num1 - num2;
                    break;
                case 2:
                    System.out.print(num1 + " * " + num2 + " = ");
                    correctAnswer = num1 * num2;
                    break;
                case 3:
                    System.out.print(num1 + " / " + num2 + " = ");
                    correctAnswer = (double) num1 / num2;
                    break;
            }

            double userAnswer = scanner.nextDouble();

            if (Math.abs(userAnswer - correctAnswer) <= 0.001) {
                System.out.println("Correct!");
                score++;
