Here is a simple GoLang server that accepts JSON payloads via HTTP POST requests and stores them into a local file. The server checks the size of the file after each write operation, if it exceeds 10MB (10485760 bytes), it creates a new file to store subsequent data.

```go
package main

import (
	"fmt"
	"io/ioutil"
	"log"
	"net/http"
	"os"
	"strconv"
)

var currentFile *os.File
var currentFileSize int64
var fileCounter = 0

func main() {
	http.HandleFunc("/", handleRequest)
	log.Fatal(http.ListenAndServe(":8080", nil))
}

func handleRequest(w http.ResponseWriter, r *http.Request) {
	if r.Method != "POST" {
		http.Error(w, "Invalid request method.", http.StatusMethodNotAllowed)
		return
	}

	body, err := ioutil.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "Error reading request body.",
			http.StatusInternalServerError)
		return
	}

	writeToFile(body)

	fmt.Fprintf(w, "Payload received.")
}

func writeToFile(data []byte) {
	const MaxSize = 10485760 // 10 MB

	if currentFile == nil || currentFileSize >= MaxSize {
		createNewFile()
	}

	n, err := currentFile.Write(data)
	if err != nil {
		log.Fatalf("Failed to write to file: %v", err)
	}
	currentFileSize += int64(n)
}

func createNewFile() {
	if currentFile != nil {
		currentFile.Close()
	}

	fileName := "data" + strconv.Itoa(fileCounter) + ".txt"
	var err error
	currentFile, err = os.Create(fileName)
	if err != nil {
		log.Fatalf("Failed to create file: %v", err)
	}
	fileCounter++
	currentFileSize = 0
}
```

This code will start an HTTP server on port 8080. It only responds to POST requests, for other types of requests it will return an HTTP 405 'Method Not Allowed' status. For each POST request, it reads the request body and writes it to the current file. If the size of the current file reaches or exceeds 10MB after a write operation, it closes the current file and opens a new one. The files are named `data0.txt`, `data1.txt`, etc., in the order they are created.

```go
package main

import (
	"fmt"
	"math/rand"
	"time"
)

func quickSort(arr []int) []int {
	if len(arr) <= 1 {
		return arr
	}

	pivotIndex := rand.Intn(len(arr))
	arr = swap(arr, pivotIndex, len(arr)-1)
	left, right := partition(arr)

	quickSort(arr[:left])
	quickSort(arr[right:])

	return arr
}

func partition(arr []int) (int, int) {
	pivot := arr[len(arr)-1]
	lowerBound := -1
	for i := range arr {
		if arr[i] < pivot {
			lowerBound++
			arr = swap(arr, lowerBound, i)
		}
	}
	firstEqual := lowerBound + 1
	for i := firstEqual; i < len(arr); i++ {
		if arr[i] == pivot {
			firstEqual++
			arr = swap(arr, firstEqual, i)
		}
	}
	return lowerBound + 1, firstEqual + 1
}

func swap(arr []int, i, j int) []int {
	arr[i], arr[j] = arr[j], arr[i]
	return arr
}

func main() {
	rand.Seed(time.Now().UnixNano())
	arr := []int{10, 5, 3, 8, 2, 6, 4, 7, 9, 1}
	fmt.Println("Before sorting:", arr)
	sortedArr := quickSort(arr)
	fmt.Println("After sorting:", sortedArr)
}
```

This Golang program implements the QuickSort algorithm for sorting an array of integers. The `quickSort` function is a recursive function that sorts the input array by selecting a random pivot element and then partitioning the array into two parts - elements less than the pivot and elements greater than or equal to the pivot. The function then calls itself recursively on these two parts until the base case is reached (i.e., when the length of the array is less than or equal to 1).

The `partition` function takes an input array and returns two indices - one for elements less than the pivot and another for elements greater than or equal to the pivot. This function uses a variation of the Lomuto partition scheme, which iterates through the array and swaps elements in such a way that all elements less than the pivot come before all elements greater than or equal to the pivot.

The `swap` function simply swaps two elements in the input array at the given indices.

Finally, the `main` function initializes a random seed based on the current time, creates an example array of integers, prints the array before sorting, sorts it using the `quickSort` function, and then prints the sorted array.

#include <iostream>

class SimpleCalculator {
public:
    // Enumeration for the supported operations
    enum Operation { ADD, SUBTRACT, MULTIPLY, DIVIDE };

    // Setters for the operands
    void setFirstOperand(double value) {
        first_operand = value;
    }

    void setSecondOperand(double value) {
        second_operand = value;
    }

    // Setter for the operation
    void setOperation(Operation op) {
        operation = op;
    }

    // Method to calculate the result based on the selected operation
    double calculate() {
        switch (operation) {
            case ADD:
                return first_operand + second_operand;
            case SUBTRACT:
                return first_operand - second_operand;
            case MULTIPLY:
                return first_operand * second_operand;
            case DIVIDE:
                if (second_operand == 0) {
                    std::cerr << "Error: Division by zero" << std::endl;
                    return 0;
                }
                return first_operand / second_operand;
            default:
                std::cerr << "Error: Invalid operation" << std::endl;
                return 0;
        }
    }

private:
    double first_operand;
    double second_operand;
    Operation operation;
};

