package main

import (
	"fmt"
)

type Node struct {
	data int
	next *Node
}

type LinkedList struct {
	head *Node
	size int
}

func (l *LinkedList) AddAtBeginning(value int) {
	newNode := &Node{data: value}
	if l.head == nil {
		l.head = newNode
	} else {
		newNode.next = l.head
		l.head = newNode
	}
	l.size++
}

func (l *LinkedList) AddAtEnd(value int) {
	newNode := &Node{data: value}
	if l.head == nil {
		l.head = newNode
	} else {
		current := l.head
		for current.next != nil {
			current = current.next
		}
		current.next = newNode
	}
	l.size++
}

func (l *LinkedList) AddAtPosition(position, value int) error {
	if position < 0 || position > l.size {
		return fmt.Errorf("Invalid position")
	}

	if position == 0 {
		l.AddAtBeginning(value)
		return nil
	}

	newNode := &Node{data: value}
	current := l.head
	for i := 1; i < position; i++ {
		current = current.next
	}
	newNode.next = current.next
	current.next = newNode
	l.size++

	return nil
}

func (l *LinkedList) RemoveByValue(value int) error {
	if l.head == nil {
		return fmt.Errorf("List is empty")
	}

	if l.head.data == value {
		l.head = l.head.next
		l.size--
		return nil
	}

	current := l.head
	for current.next != nil && current.next.data != value {
		current = current.next
	}

	if current.next == nil {
		return fmt.Errorf("Value not found in the list")
	}

	current.next = current.next.next
	l.size--
	return nil
}

func (l *LinkedList) RemoveByPosition(position int) error {
	if position < 0 || position >= l.size {
		return fmt.Errorf("Invalid position")
	}

	if position == 0 {
		l.head = l.head.next
	} else {
		current := l.head
		for i := 1; i < position; i++ {
			current = current.next
		}
		current.next = current.next.next
	}
	l.size--

	return nil
}

func (l *LinkedList) Display() {
	current := l.head
	for current != nil {
		fmt.Printf("%d -> ", current.data)
		current = current.next
	}
	fmt.Println("nil")
}

func main() {
	list := &LinkedList{}
	list.AddAtBeginning(3)
	list.AddAtBeginning(2)
	list.AddAtEnd(4)
	list.AddAtEnd(5)
	list.Display()

	err := list.AddAtPosition(2, 6)
	if err != nil {
		fmt.Println(err)
	}
	list.Display()

	err = list.RemoveByValue(6)
	if err != nil {
		fmt.Println(err)
	}
	list.Display()

	err = list.RemoveByPosition(2)
	if err != nil {
		fmt.Println(err)
	}
	list.Display()
}

