```go
package main

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strconv"

	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
)

// Constants for PostgreSQL connection
const (
	host     = "localhost"
	port     = 5432
	user     = "postgres"
	password = "your-password"
	dbname   = "your-db-name"
)

// Product struct represents a product entity
type Product struct {
	ID          int     `json:"id"`
	Name        string  `json:"name"`
	Description string  `json:"description"`
	Price       float64 `json:"price"`
	Quantity    int     `json:"quantity"`
}

// Open database connection
func openDBConnection() *sql.DB {
	psqlInfo := fmt.Sprintf("host=%s port=%d user=%s password=%s dbname=%s sslmode=disable",
		host, port, user, password, dbname)

	db, err := sql.Open("postgres", psqlInfo)
	if err != nil {
		log.Fatal(err)
	}

	err = db.Ping()
	if err != nil {
		log.Fatal(err)
	}

	return db
}

// Get a single product from the database
func (p *Product) getProduct(db *sql.DB) error {
	return db.QueryRow("SELECT name, description, price, quantity FROM products WHERE id=$1",
		p.ID).Scan(&p.Name, &p.Description, &p.Price, &p.Quantity)
}

// Update a product in the database
func (p *Product) updateProduct(db *sql.DB) error {
	_, err :=
		db.Exec("UPDATE products SET name=$1, description=$2, price=$3, quantity=$4 WHERE id=$5",
			p.Name, p.Description, p.Price, p.Quantity, p.ID)

	return err
}

// Delete a product from the database
func (p *Product) deleteProduct(db *sql.DB) error {
	_, err := db.Exec("DELETE FROM products WHERE id=$1", p.ID)

	return err
}

// Create a new product in the database
func (p *Product) createProduct(db *sql.DB) error {
	err := db.QueryRow(
		"INSERT INTO products(name, description, price, quantity) VALUES($1, $2, $3, $4) RETURNING id",
		p.Name, p.Description, p.Price, p.Quantity).Scan(&p.ID)

	if err != nil {
		return err
	}

	return nil
}

// Get multiple products from the database with pagination
func getProducts(db *sql.DB, start, count int) ([]Product, error) {
	rows, err := db.Query(
		"SELECT id, name, description, price, quantity FROM products LIMIT $1 OFFSET $2",
		count, start)

	if err != nil {
		return nil, err
	}

	defer rows.Close()

	products := []Product{}

	for rows.Next() {
		var p Product
		if err := rows.Scan(&p.ID, &p.Name, &p.Description, &p.Price, &p.Quantity); err != nil {
			return nil, err
		}
		products = append(products, p)
	}

	return products, nil
}

// HTTP handler for getting a single product
func getProduct(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	id, _ := strconv.Atoi(vars["id"])

	product := Product{ID: id}
	db := openDBConnection()
	defer db.Close()

	if err := product.getProduct(db); err != nil {
		switch err {
		case sql.ErrNoRows:
			http.Error(w, "Product not found", http.StatusNotFound)
		default:
			http.Error(w, http.StatusText(http.StatusInternalServerError), http.StatusInternalServerError)
		}
		return
	}

	json.NewEncoder(w).Encode(product)
}

// HTTP handler for getting multiple products with pagination
func getProductsHandler(w http.ResponseWriter, r *http.Request) {
	count, _ := strconv.Atoi(r.FormValue("count"))
	start, _ := strconv.Atoi(r.FormValue("start"))

	if count > 10 || count < 1 {
		count = 10
	}
	if start < 0 {
		start = 0
	}

	db := openDBConnection()
	defer db.Close()

	products, err := getProducts(db, start, count)
	if err != nil {
		http.Error(w, http.StatusText(http.StatusInternalServerError), http.StatusInternalServerError)
		return
	}

	json.NewEncoder(w).Encode(products)
}

// HTTP handler for creating a new product
func createProductHandler(w http.ResponseWriter, r *http.Request) {
	var p Product

	err := json.NewDecoder(r.Body).Decode(&p)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	db := openDBConnection()
	defer db.Close()

	if err := p.createProduct(db); err != nil {
		http.Error(w, http.StatusText(http.StatusInternalServerError), http.StatusInternalServerError)
		return
	}

	w.Header().Set("Location", "/products/"+strconv.Itoa(p.ID))
	w.WriteHeader(http.StatusCreated)
}

// HTTP handler for updating an existing product
func updateProductHandler(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	id, _ := strconv.Atoi(vars["id"])

	var p Product
	err := json.NewDecoder(r.Body).Decode(&p)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	p.ID = id

	db := openDBConnection()
	defer db.Close()

	if err := p.updateProduct(db); err != nil {
		http.Error(w, http.StatusText(http.StatusInternalServerError), http.StatusInternalServerError)
		return
	}

	w.WriteHeader(http.StatusOK)
}

// HTTP handler for deleting a product
func deleteProductHandler(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	id, _ := strconv.Atoi(vars["id"])

	product := Product{ID: id}
	db := openDBConnection()
	defer db.Close()

	if err := product.deleteProduct(db); err != nil {
		http.Error(w, http.StatusText(http.StatusInternalServerError), http.StatusInternalServerError)
		return
	}

	w.WriteHeader(http.StatusOK)
}

func main() {
	r := mux.NewRouter()

	r.HandleFunc("/products", getProductsHandler).Methods("GET")
	r.HandleFunc("/products/{id:[0-9]+}", getProduct).Methods("GET")
	r.HandleFunc("/products", createProductHandler).Methods("POST")
	r.HandleFunc("/products/{id:[0-9]+}", updateProductHandler).Methods("PUT")
	r.HandleFunc("/products/{id:[0-9]+}", deleteProductHandler).Methods("DELETE")

	log.Fatal(http.ListenAndServe(":8080", r))
}
```
